const KURAL_MEDIA = [
{"n":1,"id":"TK-0001","ta":"அகர முதல எழுத்தெல்லாம் ஆதி பகவன் முதற்றே உலகு.","en":"'A' leads letters; the Ancient Lord Leads and lords the entire world","ch":"கடவுள் வாழ்த்து","chEn":"The Praise of God","chNo":1,"sec":"Virtue"},
{"n":2,"id":"TK-0002","ta":"கற்றதனால் ஆய பயனென்கொல் வாலறிவன் நற்றாள் தொழாஅர் எனின்.","en":"That lore is vain which does not fall  At His good feet who knoweth all","ch":"கடவுள் வாழ்த்து","chEn":"The Praise of God","chNo":1,"sec":"Virtue"},
{"n":3,"id":"TK-0003","ta":"மலர்மிசை ஏகினான் மாணடி சேர்ந்தார் நிலமிசை நீடுவாழ் வார்.","en":"Long they live on earth who gain The feet of God in florid brain","ch":"கடவுள் வாழ்த்து","chEn":"The Praise of God","chNo":1,"sec":"Virtue"},
{"n":4,"id":"TK-0004","ta":"வேண்டுதல் வேண்டாமை இலானடி சேர்ந்தார்க்கு யாண்டும் இடும்பை இல.","en":"Who hold His feet who likes nor loathes Are free from woes of human births","ch":"கடவுள் வாழ்த்து","chEn":"The Praise of God","chNo":1,"sec":"Virtue"},
{"n":5,"id":"TK-0005","ta":"இருள்சேர் இருவினையும் சேரா இறைவன் பொருள்சேர் புகழ்புரிந்தார் மாட்டு.","en":"God's praise who tell, are free from right  And wrong, the twins of dreaming night","ch":"கடவுள் வாழ்த்து","chEn":"The Praise of God","chNo":1,"sec":"Virtue"},
{"n":6,"id":"TK-0006","ta":"பொறிவாயில் ஐந்தவித்தான் பொய்தீர் ஒழுக்க நெறிநின்றார் நீடுவாழ் வார்.","en":"They prosper long who walk His way Who has the senses signed away","ch":"கடவுள் வாழ்த்து","chEn":"The Praise of God","chNo":1,"sec":"Virtue"},
{"n":7,"id":"TK-0007","ta":"தனக்குவமை இல்லாதான் தாள்சேர்ந்தார்க் கல்லால் மனக்கவலை மாற்றல் அரிது.","en":"His feet, whose likeness none can find, Alone can ease the anxious mind","ch":"கடவுள் வாழ்த்து","chEn":"The Praise of God","chNo":1,"sec":"Virtue"},
{"n":8,"id":"TK-0008","ta":"அறவாழி அந்தணன் தாள்சேர்ந்தார்க் கல்லால் பிறவாழி நீந்தல் அரிது.","en":"Who swims the sea of vice is he Who clasps the feet of Virtue's sea","ch":"கடவுள் வாழ்த்து","chEn":"The Praise of God","chNo":1,"sec":"Virtue"},
{"n":9,"id":"TK-0009","ta":"கோளில் பொறியின் குணமிலவே எண்குணத்தான் தாளை வணங்காத் தலை.","en":"Like senses stale that head is vain Which bows not to Eight-Virtued Divine","ch":"கடவுள் வாழ்த்து","chEn":"The Praise of God","chNo":1,"sec":"Virtue"},
{"n":10,"id":"TK-0010","ta":"பிறவிப் பெருங்கடல் நீந்துவர் நீந்தார் இறைவன் அடிசேரா தார்.","en":"The sea of births they alone swim Who clench His feet and cleave to Him","ch":"கடவுள் வாழ்த்து","chEn":"The Praise of God","chNo":1,"sec":"Virtue"},
{"n":11,"id":"TK-0011","ta":"வான்நின்று உலகம் வழங்கி வருதலால் தான்அமிழ்தம் என்றுணரற் பாற்று.","en":"The genial rain ambrosia call: The world but lasts while rain shall fall","ch":"வான்சிறப்பு","chEn":"The Blessing of Rain","chNo":2,"sec":"Virtue"},
{"n":12,"id":"TK-0012","ta":"துப்பார்க்குத் துப்பாய துப்பாக்கித் துப்பார்க்குத் துப்பாய தூஉம் மழை.","en":"The rain begets the food we eat","ch":"வான்சிறப்பு","chEn":"The Blessing of Rain","chNo":2,"sec":"Virtue"},
{"n":13,"id":"TK-0013","ta":"விண்இன்று பொய்ப்பின் விரிநீர் வியனுலகத்து உள்நின்று உடற்றும் பசி.","en":"Let clouds their visits stay, and dearth Distresses all the sea-girt earth","ch":"வான்சிறப்பு","chEn":"The Blessing of Rain","chNo":2,"sec":"Virtue"},
{"n":14,"id":"TK-0014","ta":"ஏரின் உழாஅர் உழவர் புயல்என்னும் வாரி வளங்குன்றிக் கால்.","en":"Unless the fruitful shower descend, The ploughman's sacred toil must end","ch":"வான்சிறப்பு","chEn":"The Blessing of Rain","chNo":2,"sec":"Virtue"},
{"n":15,"id":"TK-0015","ta":"கெடுப்பதூஉம் கெட்டார்க்குச் சார்வாய்மற் றாங்கே எடுப்பதூஉம் எல்லாம் மழை.","en":"Destruction it may sometimes pour But only rain can life restore","ch":"வான்சிறப்பு","chEn":"The Blessing of Rain","chNo":2,"sec":"Virtue"},
{"n":16,"id":"TK-0016","ta":"விசும்பின் துளிவீழின் அல்லால்மற் றாங்கே பசும்புல் தலைகாண்பு அரிது.","en":"No grassy blade its head will rear, If from the cloud no drop appear","ch":"வான்சிறப்பு","chEn":"The Blessing of Rain","chNo":2,"sec":"Virtue"},
{"n":17,"id":"TK-0017","ta":"நெடுங்கடலும் தன்நீர்மை குன்றும் தடிந்தெழிலி தான்நல்கா தாகி விடின்.","en":"The ocean's wealth will waste away, Except the cloud its stores repay","ch":"வான்சிறப்பு","chEn":"The Blessing of Rain","chNo":2,"sec":"Virtue"},
{"n":18,"id":"TK-0018","ta":"சிறப்பொடு பூசனை செல்லாது வானம் வறக்குமேல் வானோர்க்கும் ஈண்டு.","en":"The earth, beneath a barren sky, Would offerings for the gods deny","ch":"வான்சிறப்பு","chEn":"The Blessing of Rain","chNo":2,"sec":"Virtue"},
{"n":19,"id":"TK-0019","ta":"தானம் தவம்இரண்டும் தங்கா வியன்உலகம் வானம் வழங்கா தெனின்.","en":"Were heaven above to fail below Nor alms nor penance earth would show","ch":"வான்சிறப்பு","chEn":"The Blessing of Rain","chNo":2,"sec":"Virtue"},
{"n":20,"id":"TK-0020","ta":"நீர்இன்று அமையாது உலகெனின் யார்யார்க்கும் வான்இன்று அமையாது ஒழுக்கு.","en":"Water is life that comes from rain Sans rain our duties go in vain","ch":"வான்சிறப்பு","chEn":"The Blessing of Rain","chNo":2,"sec":"Virtue"},
{"n":21,"id":"TK-0021","ta":"ஒழுக்கத்து நீத்தார் பெருமை விழுப்பத்து வேண்டும் பனுவல் துணிவு.","en":"No merit can be held so high As theirs who sense and self deny","ch":"நீத்தார் பெருமை","chEn":"The Greatness of Ascetics","chNo":3,"sec":"Virtue"},
{"n":22,"id":"TK-0022","ta":"துறந்தார் பெருமை துணைக்கூறின் வையத்து இறந்தாரை எண்ணிக்கொண் டற்று.","en":"To con ascetic glory here Is to count the dead upon the sphere","ch":"நீத்தார் பெருமை","chEn":"The Greatness of Ascetics","chNo":3,"sec":"Virtue"},
{"n":23,"id":"TK-0023","ta":"இருமை வகைதெரிந்து ஈண்டுஅறம் பூண்டார் பெருமை பிறங்கிற்று உலகு.","en":"No lustre can with theirs compare Who know the right and virtue wear","ch":"நீத்தார் பெருமை","chEn":"The Greatness of Ascetics","chNo":3,"sec":"Virtue"},
{"n":24,"id":"TK-0024","ta":"உரனென்னும் தோட்டியான் ஓரைந்தும் காப்பான் வரனென்னும் வைப்பிற்கோர் வித்து.","en":"With hook of firmness to restrain The senses five, is heaven to gain","ch":"நீத்தார் பெருமை","chEn":"The Greatness of Ascetics","chNo":3,"sec":"Virtue"},
{"n":25,"id":"TK-0025","ta":"ஐந்தவித்தான் ஆற்றல் அகல்விசும்பு ளார்கோமான் இந்திரனே சாலுங் கரி.","en":"Indra himself has cause to say How great the power ascetics' sway","ch":"நீத்தார் பெருமை","chEn":"The Greatness of Ascetics","chNo":3,"sec":"Virtue"},
{"n":26,"id":"TK-0026","ta":"செயற்கரிய செய்வார் பெரியர் சிறியர் செயற்கரிய செய்கலா தார்.","en":"The small the paths of ease pursue The great achieve things rare to do","ch":"நீத்தார் பெருமை","chEn":"The Greatness of Ascetics","chNo":3,"sec":"Virtue"},
{"n":27,"id":"TK-0027","ta":"சுவைஒளி ஊறுஓசை நாற்றமென ஐந்தின் வகைதெரிவான் கட்டே உலகு.","en":"They gain the world, who grasp and tell Of taste, sight, hearing, touch and smell","ch":"நீத்தார் பெருமை","chEn":"The Greatness of Ascetics","chNo":3,"sec":"Virtue"},
{"n":28,"id":"TK-0028","ta":"நிறைமொழி மாந்தர் பெருமை நிலத்து மறைமொழி காட்டி விடும்.","en":"Full-worded men by what they say, Their greatness to the world display","ch":"நீத்தார் பெருமை","chEn":"The Greatness of Ascetics","chNo":3,"sec":"Virtue"},
{"n":29,"id":"TK-0029","ta":"குணமென்னும் குன்றேறி நின்றார் வெகுளி கணமேயும் காத்தல் அரிது.","en":"Their wrath, who've climb'd the mount of good, Though transient, cannot be withstood","ch":"நீத்தார் பெருமை","chEn":"The Greatness of Ascetics","chNo":3,"sec":"Virtue"},
{"n":30,"id":"TK-0030","ta":"அந்தணர் என்போர் அறவோர்மற் றெவ்வுயிர்க்கும் செந்தண்மை பூண்டொழுக லான்.","en":"With gentle mercy towards all, The sage fulfils the vitue's call","ch":"நீத்தார் பெருமை","chEn":"The Greatness of Ascetics","chNo":3,"sec":"Virtue"},
{"n":31,"id":"TK-0031","ta":"சிறப்புஈனும் செல்வமும் ஈனும் அறத்தினூஉங்கு ஆக்கம் எவனோ உயிர்க்கு.","en":"From virtue weal and wealth outflow; What greater good can mankind know?","ch":"அறன் வலியுறுத்தல்","chEn":"Assertion of the Strength of Virtue","chNo":4,"sec":"Virtue"},
{"n":32,"id":"TK-0032","ta":"அறத்தினூஉங்கு ஆக்கமும் இல்லை அதனை மறத்தலின் ஊங்கில்லை கேடு.","en":"Virtue enhances joy and gain; Forsaking it is fall and pain","ch":"அறன் வலியுறுத்தல்","chEn":"Assertion of the Strength of Virtue","chNo":4,"sec":"Virtue"},
{"n":33,"id":"TK-0033","ta":"ஒல்லும் வகையான் அறவினை ஓவாதே செல்லும்வாய் எல்லாஞ் செயல்.","en":"Perform good deeds as much you can Always and everywhere, o man!","ch":"அறன் வலியுறுத்தல்","chEn":"Assertion of the Strength of Virtue","chNo":4,"sec":"Virtue"},
{"n":34,"id":"TK-0034","ta":"மனத்துக்கண் மாசிலன் ஆதல் அனைத்தறன் ஆகுல நீர பிற.","en":"In spotless mind virtue is found And not in show and swelling sound","ch":"அறன் வலியுறுத்தல்","chEn":"Assertion of the Strength of Virtue","chNo":4,"sec":"Virtue"},
{"n":35,"id":"TK-0035","ta":"அழுக்காறு அவாவெகுளி இன்னாச்சொல் நான்கும் இழுக்கா இயன்றது அறம்.","en":"Four ills eschew and virtue reach, Lust, anger, envy, evil-speech","ch":"அறன் வலியுறுத்தல்","chEn":"Assertion of the Strength of Virtue","chNo":4,"sec":"Virtue"},
{"n":36,"id":"TK-0036","ta":"அன்றறிவாம் என்னாது அறஞ்செய்க மற்றது பொன்றுங்கால் பொன்றாத் துணை.","en":"Do good enow; defer it not A deathless aid in death if sought","ch":"அறன் வலியுறுத்தல்","chEn":"Assertion of the Strength of Virtue","chNo":4,"sec":"Virtue"},
{"n":37,"id":"TK-0037","ta":"அறத்தாறு இதுவென வேண்டா சிவிகை பொறுத்தானோடு ஊர்ந்தான் இடை.","en":"Litter-bearer and rider say  Without a word, the fortune's way","ch":"அறன் வலியுறுத்தல்","chEn":"Assertion of the Strength of Virtue","chNo":4,"sec":"Virtue"},
{"n":38,"id":"TK-0038","ta":"வீழ்நாள் படாஅமை நன்றாற்றின் அஃதொருவன் வாழ்நாள் வழியடைக்கும் கல்.","en":"Like stones that block rebirth and pain Are doing good and good again","ch":"அறன் வலியுறுத்தல்","chEn":"Assertion of the Strength of Virtue","chNo":4,"sec":"Virtue"},
{"n":39,"id":"TK-0039","ta":"அறத்தான் வருவதே இன்பம் மற்றெல்லாம் புறத்த புகழும் இல.","en":"Weal flows only from virtue done The rest is rue and renown gone","ch":"அறன் வலியுறுத்தல்","chEn":"Assertion of the Strength of Virtue","chNo":4,"sec":"Virtue"},
{"n":40,"id":"TK-0040","ta":"செயற்பால தோரும் அறனே ஒருவற்கு உயற்பால தோரும் பழி.","en":"Worthy act is virtue done Vice is what we ought to shun","ch":"அறன் வலியுறுத்தல்","chEn":"Assertion of the Strength of Virtue","chNo":4,"sec":"Virtue"},
{"n":41,"id":"TK-0041","ta":"இல்வாழ்வான் என்பான் இயல்புடைய மூவர்க்கும் நல்லாற்றின் நின்ற துணை.","en":"The ideal householder is he Who aids the natural orders there","ch":"இல்வாழ்க்கை","chEn":"Domestic Life","chNo":5,"sec":"Virtue"},
{"n":42,"id":"TK-0042","ta":"துறந்தார்க்கும் துவ்வாதவர்க்கும் இறந்தார்க்கும் இல்வாழ்வான் என்பான் துணை.","en":"His help the monk and retired share, And celibate students are his care","ch":"இல்வாழ்க்கை","chEn":"Domestic Life","chNo":5,"sec":"Virtue"},
{"n":43,"id":"TK-0043","ta":"தென்புலத்தார் தெய்வம் விருந்தொக்கல் தானென்றாங்கு ஐம்புலத்தாறு ஓம்பல் தலை.","en":"By dutiful householder's aid God, manes, kin, self and guests are served","ch":"இல்வாழ்க்கை","chEn":"Domestic Life","chNo":5,"sec":"Virtue"},
{"n":44,"id":"TK-0044","ta":"பழியஞ்சிப் பாத்தூண் உடைத்தாயின் வாழ்க்கை வழியெஞ்சல் எஞ்ஞான்றும் இல்.","en":"Sin he shuns and food he shares His home is bright and brighter fares","ch":"இல்வாழ்க்கை","chEn":"Domestic Life","chNo":5,"sec":"Virtue"},
{"n":45,"id":"TK-0045","ta":"அன்பும் அறனும் உடைத்தாயின் இல்வாழ்க்கை பண்பும் பயனும் அது.","en":"In grace and gain the home excels, Where love with virtue sweetly dwells","ch":"இல்வாழ்க்கை","chEn":"Domestic Life","chNo":5,"sec":"Virtue"},
{"n":46,"id":"TK-0046","ta":"அறத்தாற்றின் இல்வாழ்க்கை ஆற்றின் புறத்தாற்றில் போஒய்ப் பெறுவ தெவன்?","en":"Who turns from righteous family To be a monk, what profits he?","ch":"இல்வாழ்க்கை","chEn":"Domestic Life","chNo":5,"sec":"Virtue"},
{"n":47,"id":"TK-0047","ta":"இயல்பினான் இல்வாழ்க்கை வாழ்பவன் என்பான் முயல்வாருள் எல்லாம் தலை.","en":"Of all who strive for bliss, the great Is he who leads the married state","ch":"இல்வாழ்க்கை","chEn":"Domestic Life","chNo":5,"sec":"Virtue"},
{"n":48,"id":"TK-0048","ta":"ஆற்றின் ஒழுக்கி அறனிழுக்கா இல்வாழ்க்கை நோற்பாரின் நோன்மை உடைத்து.","en":"Straight in virtue, right in living Make men brighter than monks praying","ch":"இல்வாழ்க்கை","chEn":"Domestic Life","chNo":5,"sec":"Virtue"},
{"n":49,"id":"TK-0049","ta":"அறனெனப் பட்டதே இல்வாழ்க்கை அஃதும் பிறன்பழிப்ப தில்லாயின் நன்று.","en":"Home-life and virtue, are the same; Which spotless monkhood too can claim","ch":"இல்வாழ்க்கை","chEn":"Domestic Life","chNo":5,"sec":"Virtue"},
{"n":50,"id":"TK-0050","ta":"வையத்துள் வாழ்வாங்கு வாழ்பவன் வான்உறையும் தெய்வத்துள் வைக்கப் படும்.","en":"He is a man of divine worth Who lives in ideal home on earth","ch":"இல்வாழ்க்கை","chEn":"Domestic Life","chNo":5,"sec":"Virtue"},
{"n":51,"id":"TK-0051","ta":"மனைக்தக்க மாண்புடையள் ஆகித்தற் கொண்டான் வளத்தக்காள் வாழ்க்கைத் துணை.","en":"A good housewife befits the house, Spending with thrift the mate's resource","ch":"வாழ்க்கைத் துணைநலம்","chEn":"The Worth of a Wife","chNo":6,"sec":"Virtue"},
{"n":52,"id":"TK-0052","ta":"மனைமாட்சி இல்லாள்கண் இல்லாயின் வாழ்க்கை எனைமாட்சித் தாயினும் இல்.","en":"Bright is home when wife is chaste If not all greatness is but waste","ch":"வாழ்க்கைத் துணைநலம்","chEn":"The Worth of a Wife","chNo":6,"sec":"Virtue"},
{"n":53,"id":"TK-0053","ta":"இல்லதென் இல்லவள் மாண்பானால் உள்ளதென் இல்லவள் மாணாக் கடை?","en":"What is rare when wife is good What can be there when she is bad?","ch":"வாழ்க்கைத் துணைநலம்","chEn":"The Worth of a Wife","chNo":6,"sec":"Virtue"},
{"n":54,"id":"TK-0054","ta":"பெண்ணின் பெருந்தக்க யாவுள கற்பென்னும் திண்மைஉண் டாகப் பெறின்.","en":"What greater fortune is for men Than a constant chaste woman?","ch":"வாழ்க்கைத் துணைநலம்","chEn":"The Worth of a Wife","chNo":6,"sec":"Virtue"},
{"n":55,"id":"TK-0055","ta":"தெய்வம் தொழாஅள் கொழுநன் தொழுதெழுவாள் பெய்யெனப் பெய்யும் மழை.","en":"Her spouse before God who adores, Is like rain that at request pours","ch":"வாழ்க்கைத் துணைநலம்","chEn":"The Worth of a Wife","chNo":6,"sec":"Virtue"},
{"n":56,"id":"TK-0056","ta":"தற்காத்துத் தற்கொண்டாற் பேணித் தகைசான்ற சொற்காத்துச் சோர்விலாள் பெண்.","en":"The good wife guards herself from blame, She tends her spouse and brings him fame","ch":"வாழ்க்கைத் துணைநலம்","chEn":"The Worth of a Wife","chNo":6,"sec":"Virtue"},
{"n":57,"id":"TK-0057","ta":"சிறைகாக்கும் காப்பெவன் செய்யும் மகளிர் நிறைகாக்கும் காப்பே தலை.","en":"Of what avail are watch and ward? Their purity is women's guard","ch":"வாழ்க்கைத் துணைநலம்","chEn":"The Worth of a Wife","chNo":6,"sec":"Virtue"},
{"n":58,"id":"TK-0058","ta":"பெற்றாற் பெறின்பெறுவர் பெண்டிர் பெருஞ்சிறப்புப் புத்தேளிர் வாழும் உலகு.","en":"Women who win their husbands' heart Shall flourish where the gods resort","ch":"வாழ்க்கைத் துணைநலம்","chEn":"The Worth of a Wife","chNo":6,"sec":"Virtue"},
{"n":59,"id":"TK-0059","ta":"புகழ்புரிந்த இல்லிலோர்க்கு இல்லை இகழ்வார்முன் ஏறுபோல் பீடு நடை.","en":"A cuckold has not the lion-like gait Before his detractors aright","ch":"வாழ்க்கைத் துணைநலம்","chEn":"The Worth of a Wife","chNo":6,"sec":"Virtue"},
{"n":60,"id":"TK-0060","ta":"மங்கலம் என்ப மனைமாட்சி மற்று அதன் நன்கலம் நன்மக்கட் பேறு.","en":"An honest wife is home's delight And children good are jewels abright","ch":"வாழ்க்கைத் துணைநலம்","chEn":"The Worth of a Wife","chNo":6,"sec":"Virtue"},
{"n":61,"id":"TK-0061","ta":"பெறுமவற்றுள் யாமறிவது இல்லை அறிவறிந்த மக்கட்பேறு அல்ல பிற.","en":"The world no higher bliss bestows Than children virtuous and wise","ch":"மக்கட்பேறு","chEn":"The Wealth of Children","chNo":7,"sec":"Virtue"},
{"n":62,"id":"TK-0062","ta":"எழுபிறப்பும் தீயவை தீண்டா பழிபிறங்காப் பண்புடை மக்கட் பெறின்.","en":"No evil comes and no blemish; Noble sons bring all we wish","ch":"மக்கட்பேறு","chEn":"The Wealth of Children","chNo":7,"sec":"Virtue"},
{"n":63,"id":"TK-0063","ta":"தம்பொருள் என்பதம் மக்கள் அவர்பொருள் தம்தம் வினையான் வரும்.","en":"Children are one's wealth indeed Their wealth is measured by their deed","ch":"மக்கட்பேறு","chEn":"The Wealth of Children","chNo":7,"sec":"Virtue"},
{"n":64,"id":"TK-0064","ta":"அமிழ்தினும் ஆற்ற இனிதேதம் மக்கள் சிறுகை அளாவிய கூழ்.","en":"The food is more than nectar sweet In which one's children hands insert","ch":"மக்கட்பேறு","chEn":"The Wealth of Children","chNo":7,"sec":"Virtue"},
{"n":65,"id":"TK-0065","ta":"மக்கள்மெய் தீண்டல் உடற்கின்பம் மற்றுஅவர் சொற்கேட்டல் இன்பம் செவிக்கு.","en":"Children's touch delights the body Sweet to ears are their words lovely","ch":"மக்கட்பேறு","chEn":"The Wealth of Children","chNo":7,"sec":"Virtue"},
{"n":66,"id":"TK-0066","ta":"குழல்இனிது யாழ்இனிது என்பதம் மக்கள் மழலைச்சொல் கேளா தவர்.","en":"The flute and lute are sweet they say Deaf to baby's babble's lay!","ch":"மக்கட்பேறு","chEn":"The Wealth of Children","chNo":7,"sec":"Virtue"},
{"n":67,"id":"TK-0067","ta":"தந்தை மகற்காற்றும் நன்றி அவையத்து முந்தி இருப்பச் செயல்.","en":"A father's duty to his son is  To seat him in front of the wise","ch":"மக்கட்பேறு","chEn":"The Wealth of Children","chNo":7,"sec":"Virtue"},
{"n":68,"id":"TK-0068","ta":"தம்மின்தம் மக்கள் அறிவுடைமை மாநிலத்து மன்னுயிர்க் கெல்லாம் இனிது.","en":"With joy the hearts of parents swell  To see their children themselves excel","ch":"மக்கட்பேறு","chEn":"The Wealth of Children","chNo":7,"sec":"Virtue"},
{"n":69,"id":"TK-0069","ta":"ஈன்ற பொழுதின் பெரிதுவக்கும் தன்மகனைச் சான்றோன் எனக்கேட்ட தாய்.","en":"The mother, hearing her son's merit  Delights more than when she begot","ch":"மக்கட்பேறு","chEn":"The Wealth of Children","chNo":7,"sec":"Virtue"},
{"n":70,"id":"TK-0070","ta":"மகன்தந்தைக்கு ஆற்றும் உதவி இவன்தந்தை என்நோற்றான் கொல் எனும் சொல்.","en":"The son to sire this word is debt  \\\"What penance such a son begot!\\\"","ch":"மக்கட்பேறு","chEn":"The Wealth of Children","chNo":7,"sec":"Virtue"},
{"n":71,"id":"TK-0071","ta":"அன்பிற்கும் உண்டோ அடைக்குந்தாழ் ஆர்வலர் புன்கணீர் பூசல் தரும்.","en":"What bolt can bar true love in fact  The tricking tears reveal the heart","ch":"அன்புடைமை","chEn":"The Possession of Love","chNo":8,"sec":"Virtue"},
{"n":72,"id":"TK-0072","ta":"அன்பிலார் எல்லாம் தமக்குரியர் அன்புடையார் என்பும் உரியர் பிறர்க்கு.","en":"To selves belong the loveless ones;  To oth'rs the loving e'en to bones","ch":"அன்புடைமை","chEn":"The Possession of Love","chNo":8,"sec":"Virtue"},
{"n":73,"id":"TK-0073","ta":"அன்போடு இயைந்த வழக்கென்ப ஆருயிர்க்கு என்போடு இயைந்த தொடர்பு.","en":"Soul is encased in frame of bone  To taste the life of love alone","ch":"அன்புடைமை","chEn":"The Possession of Love","chNo":8,"sec":"Virtue"},
{"n":74,"id":"TK-0074","ta":"அன்புஈனும் ஆர்வம் உடைமை அதுஈனும் நண்பு என்னும் நாடாச் சிறப்பு.","en":"Love yields aspiration and thence  Friendship springs up in excellence","ch":"அன்புடைமை","chEn":"The Possession of Love","chNo":8,"sec":"Virtue"},
{"n":75,"id":"TK-0075","ta":"அன்புற்று அமர்ந்த வழக்கென்ப வையகத்து இன்புற்றார் எய்தும் சிறப்பு.","en":"The crowning joy of home life flows  From peaceful psychic love always","ch":"அன்புடைமை","chEn":"The Possession of Love","chNo":8,"sec":"Virtue"},
{"n":76,"id":"TK-0076","ta":"அறத்திற்கே அன்புசார் பென்ப அறியார் மறத்திற்கும் அஃதே துணை.","en":"\\\"Love is virtue's friend\\\" say know-nots  It helps us against evil plots","ch":"அன்புடைமை","chEn":"The Possession of Love","chNo":8,"sec":"Virtue"},
{"n":77,"id":"TK-0077","ta":"என்பி லதனை வெயில்போலக் காயுமே அன்பி லதனை அறம்.","en":"Justice burns the loveless form  Like solar blaze the boneless worm","ch":"அன்புடைமை","chEn":"The Possession of Love","chNo":8,"sec":"Virtue"},
{"n":78,"id":"TK-0078","ta":"அன்பகத் தில்லா உயிர்வாழ்க்கை வன்பாற்கண் வற்றல் மரந்தளிர்த் தற்று.","en":"Life bereft of love is gloom  Can sapless tree in desert bloom?","ch":"அன்புடைமை","chEn":"The Possession of Love","chNo":8,"sec":"Virtue"},
{"n":79,"id":"TK-0079","ta":"புறத்துறுப் பெல்லாம் எவன்செய்யும் யாக்கை அகத்துறுப்பு அன்பி லவர்க்கு.","en":"Love is the heart which limbs must move,  Or vain the outer parts will prove","ch":"அன்புடைமை","chEn":"The Possession of Love","chNo":8,"sec":"Virtue"},
{"n":80,"id":"TK-0080","ta":"அன்பின் வழியது உயிர்நிலை அஃதிலார்க்கு என்புதோல் போர்த்த உடம்பு.","en":"The seat of life is love alone;  Or beings are but skin and bone!","ch":"அன்புடைமை","chEn":"The Possession of Love","chNo":8,"sec":"Virtue"},
{"n":81,"id":"TK-0081","ta":"இருந்தோம்பி இல்வாழ்வ தெல்லாம் விருந்தோம்பி வேளாண்மை செய்தற் பொருட்டு.","en":"Men set up home, toil and earn  To tend the guests and do good turn","ch":"விருந்தோம்பல்","chEn":"Hospitality","chNo":9,"sec":"Virtue"},
{"n":82,"id":"TK-0082","ta":"விருந்து புறத்ததாத் தானுண்டல் சாவா மருந்தெனினும் வேண் டற்பாற் றன்று.","en":"To keep out guests cannot be good  Albeit you eat nector-like food","ch":"விருந்தோம்பல்","chEn":"Hospitality","chNo":9,"sec":"Virtue"},
{"n":83,"id":"TK-0083","ta":"வருவிருந்து வைகலும் ஓம்புவான் வாழ்க்கை பருவந்து பாழ்படுதல் இன்று.","en":"Who tends his guests day in and out  His life in want never wears out","ch":"விருந்தோம்பல்","chEn":"Hospitality","chNo":9,"sec":"Virtue"},
{"n":84,"id":"TK-0084","ta":"அகனமர்ந்து செய்யாள் உறையும் முகனமர்ந்து நல்விருந்து ஓம்புவான் இல்.","en":"The goddess of wealth will gladly rest  Where smiles welcome the worthy guest","ch":"விருந்தோம்பல்","chEn":"Hospitality","chNo":9,"sec":"Virtue"},
{"n":85,"id":"TK-0085","ta":"வித்தும் இடல்வேண்டும் கொல்லோ விருந்தோம்பி மிச்சில் மிசைவான் புலம்.","en":"Should his field be sown who first  Feeds the guests and eats the rest?","ch":"விருந்தோம்பல்","chEn":"Hospitality","chNo":9,"sec":"Virtue"},
{"n":86,"id":"TK-0086","ta":"செல்விருந்து ஓம்பி வருவிருந்து பார்த்திருப்பான் நல்வருந்து வானத் தவர்க்கு.","en":"Who tends a guest and looks for next  Is a welcome guest in heaven's feast","ch":"விருந்தோம்பல்","chEn":"Hospitality","chNo":9,"sec":"Virtue"},
{"n":87,"id":"TK-0087","ta":"இனைத்துணைத் தென்பதொன் றில்லை விருந்தின் துணைத்துணை வேள்விப் பயன்.","en":"Worth of the guest of quality  Is worth of hospitality","ch":"விருந்தோம்பல்","chEn":"Hospitality","chNo":9,"sec":"Virtue"},
{"n":88,"id":"TK-0088","ta":"பரிந்தோம்பிப் பற்றற்றேம் என்பர் விருந்தோம்பி வேள்வி தலைப்படா தார்.","en":"Who loathe guest-service one day cry:  \\\"We toil and store; but life is dry\\\"","ch":"விருந்தோம்பல்","chEn":"Hospitality","chNo":9,"sec":"Virtue"},
{"n":89,"id":"TK-0089","ta":"உடைமையுள் இன்மை விருந்தோம்பல் ஓம்பா மடமை மடவார்கண் உண்டு.","en":"The man of wealth is poor indeed  Whose folly fails the guest to feed","ch":"விருந்தோம்பல்","chEn":"Hospitality","chNo":9,"sec":"Virtue"},
{"n":90,"id":"TK-0090","ta":"மோப்பக் குழையும் அனிச்சம் முகந்திரிந்து நோக்கக் குநழ்யும் விருந்து.","en":"Anicham smelt withers: like that  A wry-faced look withers the guest","ch":"விருந்தோம்பல்","chEn":"Hospitality","chNo":9,"sec":"Virtue"},
{"n":91,"id":"TK-0091","ta":"இன்சொலால் ஈரம் அளைஇப் படிறுஇலவாம் செம்பொருள் கண்டார்வாய்ச் சொல்.","en":"The words of Seers are lovely sweet  Merciful and free from deceit","ch":"இனியவை கூறல்","chEn":"The Utterance of Pleasant Words","chNo":10,"sec":"Virtue"},
{"n":92,"id":"TK-0092","ta":"அகன்அமர்ந்து ஈதலின் நன்றே முகனமர்ந்து இன்சொலன் ஆகப் பெறின்.","en":"Sweet words from smiling lips dispense  More joys than heart's beneficence","ch":"இனியவை கூறல்","chEn":"The Utterance of Pleasant Words","chNo":10,"sec":"Virtue"},
{"n":93,"id":"TK-0093","ta":"முகத்தான் அமர்ந்து இனிதுநோக்கி அகத்தானாம் இன்சொ லினதே அறம்.","en":"Calm face, sweet look, kind words from heart  Such is the gracious virtue's part","ch":"இனியவை கூறல்","chEn":"The Utterance of Pleasant Words","chNo":10,"sec":"Virtue"},
{"n":94,"id":"TK-0094","ta":"துன்புறூஉம் துவ்வாமை இல்லாகும் யார்மாட்டும் இன்புறூஉம் இன்சொ லவர்க்கு.","en":"Whose loving words delight each one  The woe of want from them is gone","ch":"இனியவை கூறல்","chEn":"The Utterance of Pleasant Words","chNo":10,"sec":"Virtue"},
{"n":95,"id":"TK-0095","ta":"பணிவுடையன் இன்சொலன் ஆதல் ஒருவற்கு அணியல்ல மற்றுப் பிற.","en":"To be humble and sweet words speak  No other jewel do wise men seek","ch":"இனியவை கூறல்","chEn":"The Utterance of Pleasant Words","chNo":10,"sec":"Virtue"},
{"n":96,"id":"TK-0096","ta":"அல்லவை தேய அறம்பெருகும் நல்லவை நாடி இனிய சொலின்","en":"His sins vanish, his virtues grow  Whose fruitful words with sweetness flow","ch":"இனியவை கூறல்","chEn":"The Utterance of Pleasant Words","chNo":10,"sec":"Virtue"},
{"n":97,"id":"TK-0097","ta":"நயன்ஈன்று நன்றி பயக்கும் பயன்ஈன்று பண்பின் தலைப்பிரியாச் சொல்.","en":"The fruitful courteous kindly words  Lead to goodness and graceful deeds","ch":"இனியவை கூறல்","chEn":"The Utterance of Pleasant Words","chNo":10,"sec":"Virtue"},
{"n":98,"id":"TK-0098","ta":"சிறுமையுவு நீங்கிய இன்சொல் மறுமையும் இம்மையும் இன்பம் தரும்.","en":"Kind words free from meanness delight  This life on earth and life the next","ch":"இனியவை கூறல்","chEn":"The Utterance of Pleasant Words","chNo":10,"sec":"Virtue"},
{"n":99,"id":"TK-0099","ta":"இன்சொல் இனிதீன்றல் காண்பான் எவன்கொலோ வன்சொல் வழங்கு வது?","en":"Who sees the sweets of sweetness here  To use harsh words how can he dare?","ch":"இனியவை கூறல்","chEn":"The Utterance of Pleasant Words","chNo":10,"sec":"Virtue"},
{"n":100,"id":"TK-0100","ta":"இனிய உளவாக இன்னாத கூறல் கனிஇருப்பக் காய்கவர்ந் தற்று.","en":"Leaving ripe fruits the raw he eats  Who speaks harsh words when sweet word suits","ch":"இனியவை கூறல்","chEn":"The Utterance of Pleasant Words","chNo":10,"sec":"Virtue"},
{"n":101,"id":"TK-0101","ta":"செய்யாமல் செய்த உதவிக்கு வையகமும் வானகமும் ஆற்றல் அரிது.","en":"Unhelped in turn good help given  Exceeds in worth earth and heaven","ch":"செய்ந்நன்றியறிதல்","chEn":"Gratitude","chNo":11,"sec":"Virtue"},
{"n":102,"id":"TK-0102","ta":"காலத்தி னாற்செய்த நன்றி சிறிதெனினும் ஞாலத்தின் மாணப் பெரிது.","en":"A help rendered in hour of need  Though small is greater than the world","ch":"செய்ந்நன்றியறிதல்","chEn":"Gratitude","chNo":11,"sec":"Virtue"},
{"n":103,"id":"TK-0103","ta":"பயன்தூக்கார் செய்த உதவி நயன்தூக்கின் நன்மை கடலின் பெரிது.","en":"Help rendered without weighing fruits  Outweighs the sea in grand effects","ch":"செய்ந்நன்றியறிதல்","chEn":"Gratitude","chNo":11,"sec":"Virtue"},
{"n":104,"id":"TK-0104","ta":"தினைத்துணை நன்றி செயினும் பனைத்துணையாக் கொள்வர் பயன்தெரி வார்.","en":"Help given though millet-small  Knowers count its good palm-tree tall","ch":"செய்ந்நன்றியறிதல்","chEn":"Gratitude","chNo":11,"sec":"Virtue"},
{"n":105,"id":"TK-0105","ta":"உதவி வரைத்தன்று உதவி உதவி செயப்பட்டார் சால்பின் வரைத்து.","en":"A help is not the help's measure  It is gainer's worth and pleasure","ch":"செய்ந்நன்றியறிதல்","chEn":"Gratitude","chNo":11,"sec":"Virtue"},
{"n":106,"id":"TK-0106","ta":"மறவற்க மாசற்றார் கேண்மை துறவற்க துன்பத்துள் துப்பாயார் நட்பு.","en":"Forget not friendship of the pure  Forsake not timely helpers sure","ch":"செய்ந்நன்றியறிதல்","chEn":"Gratitude","chNo":11,"sec":"Virtue"},
{"n":107,"id":"TK-0107","ta":"எழுமை எழுபிறப்பும் உள்ளுவர் தங்கண் விழுமந் துடைத்தவர் நட்பு.","en":"Through sevenfold births, in memory fares  The willing friend who wiped one's tears","ch":"செய்ந்நன்றியறிதல்","chEn":"Gratitude","chNo":11,"sec":"Virtue"},
{"n":108,"id":"TK-0108","ta":"நன்றி மறப்பது நன்றன்று நன்றல்லது அன்றே மறப்பது நன்று.","en":"To forget good turns is not good  Good it is over wrong not to brood","ch":"செய்ந்நன்றியறிதல்","chEn":"Gratitude","chNo":11,"sec":"Virtue"},
{"n":109,"id":"TK-0109","ta":"கொன்றன்ன இன்னா செயினும் அவர்செய்த ஒன்றுநன்று உள்ளக் கெடும்.","en":"Let deadly harms be forgotten  While remembering one good-turn","ch":"செய்ந்நன்றியறிதல்","chEn":"Gratitude","chNo":11,"sec":"Virtue"},
{"n":110,"id":"TK-0110","ta":"எந்நன்றி கொன்றார்க்கும் உய்வுண்டாம் உய்வில்லை செய்ந்நன்றி கொன்ற மகற்கு.","en":"The virtue-killer may be saved  Not benefit-killer who is damned","ch":"செய்ந்நன்றியறிதல்","chEn":"Gratitude","chNo":11,"sec":"Virtue"},
{"n":111,"id":"TK-0111","ta":"தகுதி எனவொன்று நன்றே பகுதியால் பாற்பட்டு ஒழுகப் பெறின்.","en":"Equity is supreme virtue  It is to give each man his due","ch":"நடுவு நிலைமை","chEn":"Impartiality","chNo":12,"sec":"Virtue"},
{"n":112,"id":"TK-0112","ta":"செப்பம் உடையவன் ஆக்கஞ் சிதைவின்றி எச்சத்திற் கேமாப்பு உடைத்து.","en":"Wealth of the man of equity  Grows and lasts to posterity","ch":"நடுவு நிலைமை","chEn":"Impartiality","chNo":12,"sec":"Virtue"},
{"n":113,"id":"TK-0113","ta":"நன்றே தரினும் நடுவிகந்தாம் ஆக்கத்தை அன்றே யொழிய விடல்.","en":"Though profitable, turn away  From unjust gains without delay","ch":"நடுவு நிலைமை","chEn":"Impartiality","chNo":12,"sec":"Virtue"},
{"n":114,"id":"TK-0114","ta":"தக்கார் தகவிலர் என்பது அவரவர் எச்சத்தாற் காணப்ப படும்.","en":"The worthy and the unworthy  Are seen in their posterity","ch":"நடுவு நிலைமை","chEn":"Impartiality","chNo":12,"sec":"Virtue"},
{"n":115,"id":"TK-0115","ta":"கேடும் பெருக்கமும் இல்லல்ல நெஞ்சத்துக் கோடாமை சான்றோர்க் கணி.","en":"Loss and gain by cause arise;  Equal mind adorns the wise","ch":"நடுவு நிலைமை","chEn":"Impartiality","chNo":12,"sec":"Virtue"},
{"n":116,"id":"TK-0116","ta":"கெடுவல்யான் என்பது அறிகதன் நெஞ்சம் நடுவொரீஇ அல்ல செயின்.","en":"Of perdition let him be sure  Who leaves justice to sinful lure","ch":"நடுவு நிலைமை","chEn":"Impartiality","chNo":12,"sec":"Virtue"},
{"n":117,"id":"TK-0117","ta":"கெடுவாக வையாது உலகம் நடுவாக நன்றிக்கண் தங்கியான் தாழ்வு.","en":"The just reduced to poverty  Is not held down by equity","ch":"நடுவு நிலைமை","chEn":"Impartiality","chNo":12,"sec":"Virtue"},
{"n":118,"id":"TK-0118","ta":"சமன்செய்து சீர்தூக்குங் கோல்போல் அமைந்தொருபால் கோடாமை சான்றோர்க் கணி.","en":"Like balance holding equal scales  A well poised mind is jewel of the wise","ch":"நடுவு நிலைமை","chEn":"Impartiality","chNo":12,"sec":"Virtue"},
{"n":119,"id":"TK-0119","ta":"சொற்கோட்டம் இல்லது செப்பம் ஒருதலையா உட்கோட்டம் இன்மை பெறின்.","en":"Justice is upright, unbending  And free from crooked word-twisting","ch":"நடுவு நிலைமை","chEn":"Impartiality","chNo":12,"sec":"Virtue"},
{"n":120,"id":"TK-0120","ta":"வாணிகம் செய்வார்க்கு வாணிகம் பேணிப் பிறவும் தமபோல் செயின்.","en":"A trader's trade prospers fairly  When his dealings are neighbourly","ch":"நடுவு நிலைமை","chEn":"Impartiality","chNo":12,"sec":"Virtue"},
{"n":121,"id":"TK-0121","ta":"அடக்கம் அமரருள் உய்க்கும் அடங்காமை ஆரிருள் உய்த்து விடும்.","en":"Self-rule leads to realms of gods  Indulgence leads to gloomy hades","ch":"அடக்கம் உடைமை","chEn":"The Possession of Self-restraint","chNo":13,"sec":"Virtue"},
{"n":122,"id":"TK-0122","ta":"காக்க பொருளா அடக்கத்தை ஆக்கம் அதனினூஉங் கில்லை உயிர்க்கு.","en":"No gains with self-control measure  Guard with care this great treasure","ch":"அடக்கம் உடைமை","chEn":"The Possession of Self-restraint","chNo":13,"sec":"Virtue"},
{"n":123,"id":"TK-0123","ta":"செறிவறிந்து சீர்மை பயக்கும் அறிவறிந்து ஆற்றின் அடங்கப் பெறின்.","en":"Knowing wisdom who lives controlled  Name and fame seek him untold","ch":"அடக்கம் உடைமை","chEn":"The Possession of Self-restraint","chNo":13,"sec":"Virtue"},
{"n":124,"id":"TK-0124","ta":"நிலையின் திரியாது அடங்கியான் தோற்றம் மலையினும் மாணப் பெரிது.","en":"Firmly fixed in self serene  The sage looks grander than mountain","ch":"அடக்கம் உடைமை","chEn":"The Possession of Self-restraint","chNo":13,"sec":"Virtue"},
{"n":125,"id":"TK-0125","ta":"எல்லார்க்கும் நன்றாம் பணிதல் அவருள்ளும் செல்வர்க்கே செல்வம் தகைத்து.","en":"Humility is good for all  To the rich it adds a wealth special","ch":"அடக்கம் உடைமை","chEn":"The Possession of Self-restraint","chNo":13,"sec":"Virtue"},
{"n":126,"id":"TK-0126","ta":"ஒருமையுள் ஆமைபோல் ஐந்தடக்கல் ஆற்றின் எழுமையும் ஏமாப் புடைத்து.","en":"Who senses five like tortoise hold  Their joy prolongs to births sevenfold","ch":"அடக்கம் உடைமை","chEn":"The Possession of Self-restraint","chNo":13,"sec":"Virtue"},
{"n":127,"id":"TK-0127","ta":"யாகாவா ராயினும் நாகாக்க காவாக்கால் சோகாப்பர் சொல்லிழுக்குப் பட்டு.","en":"Rein the tongue if nothing else  Or slips of tongue bring all the woes","ch":"அடக்கம் உடைமை","chEn":"The Possession of Self-restraint","chNo":13,"sec":"Virtue"},
{"n":128,"id":"TK-0128","ta":"ஒன்றானுந் தீச்சொல் பொருட்பயன் உண்டாயின் நன்றாகா தாகி விடும்.","en":"Even a single evil word  Will turn all good results to bad","ch":"அடக்கம் உடைமை","chEn":"The Possession of Self-restraint","chNo":13,"sec":"Virtue"},
{"n":129,"id":"TK-0129","ta":"தீயினாற் சுட்டபுண் உள்ளாறும் ஆறாதே நாவினாற் சுட்ட வடு.","en":"The fire-burnt wounds do find a cure  Tongue-burnt wound rests a running sore","ch":"அடக்கம் உடைமை","chEn":"The Possession of Self-restraint","chNo":13,"sec":"Virtue"},
{"n":130,"id":"TK-0130","ta":"கதங்காத்துக் கற்றடங்கல் ஆற்றுவான் செவ்வி அறம்பார்க்கும் ஆற்றின் நுழைந்து.","en":"Virtue seeks and peeps to see  Self-controlled savant anger free","ch":"அடக்கம் உடைமை","chEn":"The Possession of Self-restraint","chNo":13,"sec":"Virtue"},
{"n":131,"id":"TK-0131","ta":"ஒழுக்கம் விழுப்பந் தரலான் ஒழுக்கம் உயிரினும் ஓம்பப் படும்.","en":"Decorum does one dignity  More than life guard its purity","ch":"ஒழுக்கம் உடைமை","chEn":"The Possession of Decorum","chNo":14,"sec":"Virtue"},
{"n":132,"id":"TK-0132","ta":"பரிந்தோம்பிக் காக்க ஒழுக்கம் தெரிந்தோம்பித் தேரினும் அஃதே துணை.","en":"Virtues of conduct all excel;  The soul aid should be guarded well","ch":"ஒழுக்கம் உடைமை","chEn":"The Possession of Decorum","chNo":14,"sec":"Virtue"},
{"n":133,"id":"TK-0133","ta":"ஒழுக்கம் உடைமை குடிமை இழுக்கம் இழிந்த பிறப்பாய் விடும்.","en":"Good conduct shows good family  Low manners mark anomaly","ch":"ஒழுக்கம் உடைமை","chEn":"The Possession of Decorum","chNo":14,"sec":"Virtue"},
{"n":134,"id":"TK-0134","ta":"மறப்பினும் ஓத்துக் கொளலாகும் பார்ப்பான் பிறப்பொழுக்கங் குன்றக் கெடும்.","en":"Readers recall forgotten lore,  But conduct lost returns no more","ch":"ஒழுக்கம் உடைமை","chEn":"The Possession of Decorum","chNo":14,"sec":"Virtue"},
{"n":135,"id":"TK-0135","ta":"அழுக்கா றுடையான்கண் ஆக்கம்போன்று இல்லை ஒழுக்க மிலான்கண் உயர்வு.","en":"The envious prosper but ill  The ill-behaved sinks lower still","ch":"ஒழுக்கம் உடைமை","chEn":"The Possession of Decorum","chNo":14,"sec":"Virtue"},
{"n":136,"id":"TK-0136","ta":"ஒழுக்கத்தின் ஒல்கார் உரவோர் இழுக்கத்தின் ஏதம் படுபாக் கறிந்து.","en":"The firm from virtue falter not  They know the ills of evil thought","ch":"ஒழுக்கம் உடைமை","chEn":"The Possession of Decorum","chNo":14,"sec":"Virtue"},
{"n":137,"id":"TK-0137","ta":"ஒழுக்கத்தின் எய்துவர் மேன்மை இழுக்கத்தின் எய்துவர் எய்தாப் பழி.","en":"Conduct good ennobles man,  Bad conduct entails disgrace mean","ch":"ஒழுக்கம் உடைமை","chEn":"The Possession of Decorum","chNo":14,"sec":"Virtue"},
{"n":138,"id":"TK-0138","ta":"நன்றிக்கு வித்தாகும் நல்லொழுக்கம் தீயொழுக்கம் என்றும் இடும்பை தரும்.","en":"Good conduct sows seeds of blessings  Bad conduct endless evil brings","ch":"ஒழுக்கம் உடைமை","chEn":"The Possession of Decorum","chNo":14,"sec":"Virtue"},
{"n":139,"id":"TK-0139","ta":"ஒழுக்க முடையவர்க்கு ஒல்லாவே தீய வழுக்கியும் வாயாற் சொலல்.","en":"Foul words will never fall from lips  Of righteous men even by slips","ch":"ஒழுக்கம் உடைமை","chEn":"The Possession of Decorum","chNo":14,"sec":"Virtue"},
{"n":140,"id":"TK-0140","ta":"உலகத்தோடு ஒட்ட ஒழுகல் பலகற்றும் கல்லார் அறிவிலா தார்","en":"Though read much they are ignorant  Whose life is not world-accordant","ch":"ஒழுக்கம் உடைமை","chEn":"The Possession of Decorum","chNo":14,"sec":"Virtue"},
{"n":141,"id":"TK-0141","ta":"பிறன்பொருளாள் பெட்டொழுகும் பேதைமை ஞாலத்து அறம்பொருள் கண்டார்கண் இல்.","en":"Who know the wealth and virtue's way  After other's wife do not stray","ch":"பிறனில் விழையாமை","chEn":"Not coveting another\"s Wife","chNo":15,"sec":"Virtue"},
{"n":142,"id":"TK-0142","ta":"அறன்கடை நின்றாருள் எல்லாம் பிறன்கடை நின்றாரின் பேதையார் இல்.","en":"He is the worst law breaking boor  Who haunts around his neighbour's door","ch":"பிறனில் விழையாமை","chEn":"Not coveting another\"s Wife","chNo":15,"sec":"Virtue"},
{"n":143,"id":"TK-0143","ta":"விளிந்தாரின் வேறல்லர் மன்ற தெளிந்தாரில் தீமை புரிந்து ஒழுகு வார்.","en":"The vile are dead who evil aim  And put faithful friends' wives to shame","ch":"பிறனில் விழையாமை","chEn":"Not coveting another\"s Wife","chNo":15,"sec":"Virtue"},
{"n":144,"id":"TK-0144","ta":"எனைத்துணையர் ஆயினும் என்னாம் தினைத்துணையும் தேரான் பிறனில் புகல்.","en":"Their boasted greatness means nothing  When to another's wife they cling","ch":"பிறனில் விழையாமை","chEn":"Not coveting another\"s Wife","chNo":15,"sec":"Virtue"},
{"n":145,"id":"TK-0145","ta":"எளிதென இல்லிறப்பான் எய்துமெஞ் ஞான்றும் விளியாது நிற்கும் பழி.","en":"Who trifles with another's wife  His guilty stain will last for life","ch":"பிறனில் விழையாமை","chEn":"Not coveting another\"s Wife","chNo":15,"sec":"Virtue"},
{"n":146,"id":"TK-0146","ta":"பகைபாவம் அச்சம் பழியென நான்கும் இகவாவாம் இல்லிறப்பான் கண்.","en":"Hatred, sin, fear, and shame-these four  Stain adulterers ever more","ch":"பிறனில் விழையாமை","chEn":"Not coveting another\"s Wife","chNo":15,"sec":"Virtue"},
{"n":147,"id":"TK-0147","ta":"அறனியலான் இல்வாழ்வான் என்பான் பிறனியலாள் பெண்மை நயவா தவன்.","en":"He is the righteous householder  His neighbour's wife who covets never","ch":"பிறனில் விழையாமை","chEn":"Not coveting another\"s Wife","chNo":15,"sec":"Virtue"},
{"n":148,"id":"TK-0148","ta":"பிறன்மனை நோக்காத பேராண்மை சான்றோர்க்கு அறனொன்றோ ஆன்ற வொழுக்கு.","en":"They lead a high-souled manly life  The pure who eye not another's wife","ch":"பிறனில் விழையாமை","chEn":"Not coveting another\"s Wife","chNo":15,"sec":"Virtue"},
{"n":149,"id":"TK-0149","ta":"நலக்குரியார் யாரெனின் நாமநீர் வைப்பின் பிறர்க்குரியாள் தோள்தோயா தார்.","en":"Good in storm bound earth is with those  Who clasp not arms of another's spouse","ch":"பிறனில் விழையாமை","chEn":"Not coveting another\"s Wife","chNo":15,"sec":"Virtue"},
{"n":150,"id":"TK-0150","ta":"அறன்வரையான் அல்ல செயினும் பிறன்வரையாள் பெண்மை நயவாமை நன்று.","en":"Sinners breaking virtue's behest  Lust not for another's wife at least","ch":"பிறனில் விழையாமை","chEn":"Not coveting another\"s Wife","chNo":15,"sec":"Virtue"},
{"n":151,"id":"TK-0151","ta":"அகழ்வாரைத் தாங்கும் நிலம்போலத் தம்மை இகழ்வார்ப் பொறுத்தல் தலை.","en":"As earth bears up with diggers too  To bear revilers is prime virtue","ch":"பொறையுடைமை","chEn":"The Possession of Patience, Forbearance","chNo":16,"sec":"Virtue"},
{"n":152,"id":"TK-0152","ta":"பொறுத்தல் இறப்பினை என்றும் அதனை மறத்தல் அதனினும் நன்று.","en":"Forgive insults is a good habit  Better it is to forget it","ch":"பொறையுடைமை","chEn":"The Possession of Patience, Forbearance","chNo":16,"sec":"Virtue"},
{"n":153,"id":"TK-0153","ta":"இன்மையுள் இன்மை விருந்தொரால் வன்மையுள் வன்மை மடவார்ப் பொறை.","en":"Neglect the guest is dearth of dearth  To bear with fools is strength of strength","ch":"பொறையுடைமை","chEn":"The Possession of Patience, Forbearance","chNo":16,"sec":"Virtue"},
{"n":154,"id":"TK-0154","ta":"நிறையுடைமை நீங்காமை வேண்டின் பொற்யுடைமை போற்றி யொழுகப் படும்.","en":"Practice of patient quality  Retains intact itegrity","ch":"பொறையுடைமை","chEn":"The Possession of Patience, Forbearance","chNo":16,"sec":"Virtue"},
{"n":155,"id":"TK-0155","ta":"ஒறுத்தாரை ஒன்றாக வையாரே வைப்பர் பொறுத்தாரைப் பொன்போற் பொதிந்து.","en":"Vengeance is not in esteem held  Patience is praised as hidden gold","ch":"பொறையுடைமை","chEn":"The Possession of Patience, Forbearance","chNo":16,"sec":"Virtue"},
{"n":156,"id":"TK-0156","ta":"ஒறுத்தார்க்கு ஒருநாளை இன்பம் பொறுத்தார்க்குப் பொன்றுந் துணையும் புகழ்.","en":"Revenge accords but one day's joy  Patience carries its praise for aye","ch":"பொறையுடைமை","chEn":"The Possession of Patience, Forbearance","chNo":16,"sec":"Virtue"},
{"n":157,"id":"TK-0157","ta":"திறனல்ல தற்பிறர் செய்யினும் நோநொந்து அறனல்ல செய்யாமை நன்று.","en":"Though others cause you wanton pain  Grieve not; from unjust harm refrain","ch":"பொறையுடைமை","chEn":"The Possession of Patience, Forbearance","chNo":16,"sec":"Virtue"},
{"n":158,"id":"TK-0158","ta":"மிகுதியான் மிக்கவை செய்தாரைத் தாந்தம் தகுதியான் வென்று விடல்.","en":"By noble forbearance vanquish  The proud that have caused you anguish","ch":"பொறையுடைமை","chEn":"The Possession of Patience, Forbearance","chNo":16,"sec":"Virtue"},
{"n":159,"id":"TK-0159","ta":"துறந்தாரின் தூய்மை உடையர் இறந்தார்வாய் இன்னாச்சொல் நோற்கிற் பவர்.","en":"More than ascetics they are pure  Who bitter tongues meekly endure","ch":"பொறையுடைமை","chEn":"The Possession of Patience, Forbearance","chNo":16,"sec":"Virtue"},
{"n":160,"id":"TK-0160","ta":"உண்ணாது நோற்பார் பெரியர் பிறர்சொல்லும் இன்னாச்சொல் நோற்பாரின் பின்.","en":"Who fast are great to do penance  Greater are they who bear offence","ch":"பொறையுடைமை","chEn":"The Possession of Patience, Forbearance","chNo":16,"sec":"Virtue"},
{"n":161,"id":"TK-0161","ta":"ஒழுக்காறாக் கொள்க ஒருவன்தன் நெஞ்சத்து அழுக்காறு இலாத இயல்பு.","en":"Deem your heart as virtuous  When your nature is not jealous","ch":"அழுக்காறாமை","chEn":"Not Envying","chNo":17,"sec":"Virtue"},
{"n":162,"id":"TK-0162","ta":"விழுப்பேற்றின் அஃதொப்பது இல்லையார் மாட்டும் அழுக்காற்றின் அன்மை பெறின்.","en":"No excellence excels the one  That by nature envies none","ch":"அழுக்காறாமை","chEn":"Not Envying","chNo":17,"sec":"Virtue"},
{"n":163,"id":"TK-0163","ta":"அறன்ஆக்கம் வேண்டாதான் என்பான் பிறனாக்கம் பேணாது அழுக்கறுப் பான்.","en":"Who envies others' good fortune  Can't prosper in virtue of his own","ch":"அழுக்காறாமை","chEn":"Not Envying","chNo":17,"sec":"Virtue"},
{"n":164,"id":"TK-0164","ta":"அழுக்காற்றின் அல்லவை செய்யார் இழுக்காற்றின் ஏதம் படுபாக்கு அறிந்து.","en":"The wise through envy don't others wrong  Knowing that woes from evils throng","ch":"அழுக்காறாமை","chEn":"Not Envying","chNo":17,"sec":"Virtue"},
{"n":165,"id":"TK-0165","ta":"அழுக்காறு உடையார்க்கு அதுசாலும் ஒன்னார் வழுக்காயும் கேடீன் பது.","en":"Man shall be wrecked by envy's whim  Even if enemies spare him","ch":"அழுக்காறாமை","chEn":"Not Envying","chNo":17,"sec":"Virtue"},
{"n":166,"id":"TK-0166","ta":"கொடுப்பது அழுக்கறுப்பான் சுற்றம் உடுப்பதூஉம் உண்பதூஉம் இன்றிக் கெடும்.","en":"Who envies gifts shall suffer ruin  Without food and clothes with his kin","ch":"அழுக்காறாமை","chEn":"Not Envying","chNo":17,"sec":"Virtue"},
{"n":167,"id":"TK-0167","ta":"அவ்வித்து அழுக்காறு உடையானைச் செய்யவள் தவ்வையைக் காட்டி விடும்.","en":"Fortune deserts the envious  Leaving misfortune omnious","ch":"அழுக்காறாமை","chEn":"Not Envying","chNo":17,"sec":"Virtue"},
{"n":168,"id":"TK-0168","ta":"அழுக்காறு எனஒரு பாவி திருச்செற்றுத் தீயுழி உய்த்து விடும்.","en":"Caitiff envy despoils wealth  And drags one into evil path","ch":"அழுக்காறாமை","chEn":"Not Envying","chNo":17,"sec":"Virtue"},
{"n":169,"id":"TK-0169","ta":"அவ்விய நெஞ்சத்தான் ஆக்கமும் செவ்வியான் கேடும் நினைக்கப் படும்.","en":"Why is envy rich, goodmen poor  People with surprise think over","ch":"அழுக்காறாமை","chEn":"Not Envying","chNo":17,"sec":"Virtue"},
{"n":170,"id":"TK-0170","ta":"அழுக்கற்று அகன்றாரும் இல்லை அஃதுஇல்லார் பெருக்கத்தில் தீர்ந்தாரும் இல்.","en":"The envious prosper never  The envyless prosper ever","ch":"அழுக்காறாமை","chEn":"Not Envying","chNo":17,"sec":"Virtue"},
{"n":171,"id":"TK-0171","ta":"நடுவின்றி நன்பொருள் வெஃகின் குடிபொன்றிக் குற்றமும் ஆங்கே தரும்.","en":"Who covets others' honest wealth  That greed ruins his house forthwith","ch":"வெஃகாமை","chEn":"Not Coveting","chNo":18,"sec":"Virtue"},
{"n":172,"id":"TK-0172","ta":"படுபயன் வெஃகிப் பழிப்படுவ செய்யார் நடுவன்மை நாணு பவர்.","en":"Who shrink with shame from sin, refrain  From coveting which brings ruin","ch":"வெஃகாமை","chEn":"Not Coveting","chNo":18,"sec":"Virtue"},
{"n":173,"id":"TK-0173","ta":"சிற்றின்பம் வெஃகி அறனல்ல செய்யாரே மற்றின்பம் வேண்டு பவர்.","en":"For spiritual bliss who long  For fleeting joy commit no wrong","ch":"வெஃகாமை","chEn":"Not Coveting","chNo":18,"sec":"Virtue"},
{"n":174,"id":"TK-0174","ta":"இலமென்று வெஃகுதல் செய்யார் புலம்வென்ற புன்மையில் காட்சி யவர்.","en":"The truth-knowers of sense-control  Though in want covet not at all","ch":"வெஃகாமை","chEn":"Not Coveting","chNo":18,"sec":"Virtue"},
{"n":175,"id":"TK-0175","ta":"அஃகி அகன்ற அறிவென்னாம் யார்மாட்டும் வெஃகி வெறிய செயின்.","en":"What is one's subtle wisdom worth  If it deals ill with all on earth","ch":"வெஃகாமை","chEn":"Not Coveting","chNo":18,"sec":"Virtue"},
{"n":176,"id":"TK-0176","ta":"அருள்வெஃகி ஆற்றின்கண் நின்றான் பொருள்வெஃகிப் பொல்லாத சூழக் கெடும்.","en":"Who seeks for grace on righteous path  Suffers by evil covetous wealth","ch":"வெஃகாமை","chEn":"Not Coveting","chNo":18,"sec":"Virtue"},
{"n":177,"id":"TK-0177","ta":"வேண்டற்க வெஃகியாம் ஆக்கம் விளைவயின் மாண்டற் கரிதாம் பயன்.","en":"Shun the fruit of covetousness  All its yield is inglorious","ch":"வெஃகாமை","chEn":"Not Coveting","chNo":18,"sec":"Virtue"},
{"n":178,"id":"TK-0178","ta":"அஃகாமை செல்வத்திற்கு யாதெனின் வெஃகாமை வேண்டும் பிறன்கைப் பொருள்.","en":"The mark of lasting wealth is shown  By not coveting others' own","ch":"வெஃகாமை","chEn":"Not Coveting","chNo":18,"sec":"Virtue"},
{"n":179,"id":"TK-0179","ta":"அறனறிந்து வெஃகா அறிவுடையார்ச் சேரும் திறன்அறிந் தாங்கே திரு.","en":"Fortune seeks the just and wise  Who are free from coveting vice","ch":"வெஃகாமை","chEn":"Not Coveting","chNo":18,"sec":"Virtue"},
{"n":180,"id":"TK-0180","ta":"இறலீனும் எண்ணாது வெஃகின் விறல்ஈனும் வேண்டாமை என்னுஞ் செருக்கு.","en":"Desireless, greatness conquers all;  Coveting misers ruined fall","ch":"வெஃகாமை","chEn":"Not Coveting","chNo":18,"sec":"Virtue"},
{"n":181,"id":"TK-0181","ta":"அறங்கூறான் அல்ல செயினும் ஒருவன் புறங்கூறான் என்றல் இனிது.","en":"Though a man from virtue strays,  To keep from slander brings him praise","ch":"புறங்கூறாமை","chEn":"Not Backbiting","chNo":19,"sec":"Virtue"},
{"n":182,"id":"TK-0182","ta":"அறனழீஇ அல்லவை செய்தலின் தீதே புறனழீஇப் பொய்த்து நகை.","en":"Who bite behind, and before smile  Are worse than open traitors vile","ch":"புறங்கூறாமை","chEn":"Not Backbiting","chNo":19,"sec":"Virtue"},
{"n":183,"id":"TK-0183","ta":"புறங்கூறிப் பொய்த்துயிர் வாழ்தலின் சாதல் அறங்கூற்றும் ஆக்கத் தரும்.","en":"Virtue thinks it better to die,  Than live to backbite and to lie","ch":"புறங்கூறாமை","chEn":"Not Backbiting","chNo":19,"sec":"Virtue"},
{"n":184,"id":"TK-0184","ta":"கண்ணின்று கண்ணறச் சொல்லினும் சொல்லற்க முன்னின்று பின்நோக்காச் சொல்.","en":"Though harsh you speak in one's presence  Abuse is worse in his absence","ch":"புறங்கூறாமை","chEn":"Not Backbiting","chNo":19,"sec":"Virtue"},
{"n":185,"id":"TK-0185","ta":"அறஞ்சொல்லும் நெஞ்சத்தான் அன்மை புறஞ்சொல்லும் புன்மையாற் காணப் படும்.","en":"Who turns to slander makes it plain  His praise of virtue is in vain","ch":"புறங்கூறாமை","chEn":"Not Backbiting","chNo":19,"sec":"Virtue"},
{"n":186,"id":"TK-0186","ta":"பிறன்பழி கூறுவான் தன்பழி யுள்ளும் திறன்தெரிந்து கூறப் படும்.","en":"His failings will be found and shown,  Who makes another's failings known","ch":"புறங்கூறாமை","chEn":"Not Backbiting","chNo":19,"sec":"Virtue"},
{"n":187,"id":"TK-0187","ta":"பகச்சொல்லிக் கேளிர்ப் பிரிப்பர் நகச்சொல்லி நட்பாடல் தேற்றா தவர்.","en":"By pleasing words who make not friends  Sever their hearts by hostile trends","ch":"புறங்கூறாமை","chEn":"Not Backbiting","chNo":19,"sec":"Virtue"},
{"n":188,"id":"TK-0188","ta":"துன்னியார் குற்றமும் தூற்றும் மரபினார் என்னைகொல் ஏதிலார் மாட்டு.","en":"What will they not to strangers do  Who bring their friends' defects to view?","ch":"புறங்கூறாமை","chEn":"Not Backbiting","chNo":19,"sec":"Virtue"},
{"n":189,"id":"TK-0189","ta":"அறன்நோக்கி ஆற்றுங்கொல் வையம் புறன்நோக்கிப் புன்சொல் உரைப்பான் பொறை.","en":"The world in mercy bears his load  Who rants behind words untoward","ch":"புறங்கூறாமை","chEn":"Not Backbiting","chNo":19,"sec":"Virtue"},
{"n":190,"id":"TK-0190","ta":"ஏதிலார் குற்றம்போல் தங்குற்றங் காண்கிற்பின் தீதுண்டோ மன்னும் உயிர்க்கு.","en":"No harm would fall to any man  If each his own defect could scan","ch":"புறங்கூறாமை","chEn":"Not Backbiting","chNo":19,"sec":"Virtue"},
{"n":191,"id":"TK-0191","ta":"பல்லார் முனியப் பயனில சொல்லுவான் எல்லாரும் எள்ளப் படும்.","en":"With silly words who insults all  Is held in contempt as banal","ch":"பயனில சொல்லாமை","chEn":"Against Vain Speaking","chNo":20,"sec":"Virtue"},
{"n":192,"id":"TK-0192","ta":"பயனில பல்லார்முன் சொல்லல் நயனில நட்டார்கண் செய்தலிற் றீது.","en":"Vain talk before many is worse  Than doing to friends deeds adverse","ch":"பயனில சொல்லாமை","chEn":"Against Vain Speaking","chNo":20,"sec":"Virtue"},
{"n":193,"id":"TK-0193","ta":"நயனிலன் என்பது சொல்லும் பயனில பாரித் துரைக்கும் உரை.","en":"The babbler's hasty lips proclaim  That \\\"good-for-nothing\\\" is his name","ch":"பயனில சொல்லாமை","chEn":"Against Vain Speaking","chNo":20,"sec":"Virtue"},
{"n":194,"id":"TK-0194","ta":"நயன்சாரா நன்மையின் நீக்கும் பயன்சாராப் பண்பில்சொல் பல்லா ரகத்து.","en":"Vain words before an assembly  Will make all gains and goodness flee","ch":"பயனில சொல்லாமை","chEn":"Against Vain Speaking","chNo":20,"sec":"Virtue"},
{"n":195,"id":"TK-0195","ta":"சீர்மை சிறப்பொடு நீங்கும் பயனில நீர்மை யுடையார் சொலின்.","en":"Glory and grace will go away  When savants silly nonsense say","ch":"பயனில சொல்லாமை","chEn":"Against Vain Speaking","chNo":20,"sec":"Virtue"},
{"n":196,"id":"TK-0196","ta":"பயனில்சொல் பாராட்டு வானை மகன்எனல் மக்கட் பதடி யெனல்.","en":"Call him a human chaff who prides  Himself in weightless idle words","ch":"பயனில சொல்லாமை","chEn":"Against Vain Speaking","chNo":20,"sec":"Virtue"},
{"n":197,"id":"TK-0197","ta":"நயனில சொல்லினுஞ் சொல்லுக சான்றோர் பயனில சொல்லாமை நன்று.","en":"Let not men of worth vainly quack  Even if they would roughly speak","ch":"பயனில சொல்லாமை","chEn":"Against Vain Speaking","chNo":20,"sec":"Virtue"},
{"n":198,"id":"TK-0198","ta":"அரும்பயன் ஆயும் அறிவினார் சொல்லார் பெரும்பயன் இல்லாத சொல்.","en":"The wise who weigh the worth refrain  From words that have no grain and brain","ch":"பயனில சொல்லாமை","chEn":"Against Vain Speaking","chNo":20,"sec":"Virtue"},
{"n":199,"id":"TK-0199","ta":"பொருள்தீர்ந்த பொச்சாந்துஞ் சொல்லார் மருள்தீர்ந்த மாசறு காட்சி யவர்.","en":"The wise of spotless self-vision  Slip not to silly words-mention","ch":"பயனில சொல்லாமை","chEn":"Against Vain Speaking","chNo":20,"sec":"Virtue"},
{"n":200,"id":"TK-0200","ta":"சொல்லுக சொல்லிற் பயனுடைய சொல்லற்க சொல்லிற் பயனிலாச் சொல்.","en":"To purpose speak the fruitful word  And never indulge in useless load","ch":"பயனில சொல்லாமை","chEn":"Against Vain Speaking","chNo":20,"sec":"Virtue"},
{"n":201,"id":"TK-0201","ta":"தீவினையார் அஞ்சார் விழுமியார் அஞ்சுவர் தீவினை என்னும் செருக்கு.","en":"Sinners fear not the pride of sin  The worthy dread the ill within","ch":"தீவினையச்சம்","chEn":"Dread of Evil Deeds","chNo":21,"sec":"Virtue"},
{"n":202,"id":"TK-0202","ta":"தீயவை தீய பயத்தலால் தீயவை தீயினும் அஞ்சப் படும்.","en":"Since evil begets evil dire  Fear ye evil more than fire","ch":"தீவினையச்சம்","chEn":"Dread of Evil Deeds","chNo":21,"sec":"Virtue"},
{"n":203,"id":"TK-0203","ta":"அறிவினுள் எல்லாந் தலையென்ப தீய செறுவார்க்கும் செய்யா விடல்.","en":"The wisest of the wise are those  Who injure not even their foes","ch":"தீவினையச்சம்","chEn":"Dread of Evil Deeds","chNo":21,"sec":"Virtue"},
{"n":204,"id":"TK-0204","ta":"மறந்தும் பிறன்கேடு சூழற்க சூழின் அறஞ்சூழம் சூழ்ந்தவன் கேடு.","en":"His ruin virtue plots who plans  The ruin of another man's","ch":"தீவினையச்சம்","chEn":"Dread of Evil Deeds","chNo":21,"sec":"Virtue"},
{"n":205,"id":"TK-0205","ta":"இலன்என்று தீயவை செய்யற்க செய்யின் இலனாகும் மற்றும் பெயர்த்து.","en":"Who makes poverty plea for ill  Shall reduce himself poorer still","ch":"தீவினையச்சம்","chEn":"Dread of Evil Deeds","chNo":21,"sec":"Virtue"},
{"n":206,"id":"TK-0206","ta":"தீப்பால தான்பிறர்கண் செய்யற்க நோய்ப்பால தன்னை அடல்வேண்டா தான்.","en":"From wounding others let him refrain  Who would from harm himself remain","ch":"தீவினையச்சம்","chEn":"Dread of Evil Deeds","chNo":21,"sec":"Virtue"},
{"n":207,"id":"TK-0207","ta":"எனைப்பகை யுற்றாரும் உய்வர் வினைப்பகை வீயாது பின்சென்று அடும்.","en":"Men may escape other foes and live  But sin its deadly blow will give","ch":"தீவினையச்சம்","chEn":"Dread of Evil Deeds","chNo":21,"sec":"Virtue"},
{"n":208,"id":"TK-0208","ta":"தீயவை செய்தார் கெடுதல் நிழல்தன்னை வீயாது அஇஉறைந் தற்று.","en":"Ruin follows who evil do  As shadow follows as they go","ch":"தீவினையச்சம்","chEn":"Dread of Evil Deeds","chNo":21,"sec":"Virtue"},
{"n":209,"id":"TK-0209","ta":"தன்னைத்தான் காதல னாயின் எனைத்தொன்றும் துன்னற்க தீவினைப் பால்.","en":"Let none who loves himself at all  Think of evil however small","ch":"தீவினையச்சம்","chEn":"Dread of Evil Deeds","chNo":21,"sec":"Virtue"},
{"n":210,"id":"TK-0210","ta":"அருங்கேடன் என்பது அறிக மருங்கோடித் தீவினை செய்யான் எனின்.","en":"He is secure, know ye, from ills  Who slips not right path to do evils","ch":"தீவினையச்சம்","chEn":"Dread of Evil Deeds","chNo":21,"sec":"Virtue"},
{"n":211,"id":"TK-0211","ta":"கைம்மாறு வேண்டா கடப்பாடு மாரிமாட்டு என் ஆற்றுங் கொல்லோ உலகு.","en":"Duty demands nothing in turn;  How can the world recompense rain?","ch":"ஒப்புரவறிதல்","chEn":"Duty to Society","chNo":22,"sec":"Virtue"},
{"n":212,"id":"TK-0212","ta":"தாளாற்றித் தந்த பொருளெல்லாம் தக்கார்க்கு வேளாண்மை செய்தற் பொருட்டு.","en":"All the wealth that toils give  Is meant to serve those who deserve","ch":"ஒப்புரவறிதல்","chEn":"Duty to Society","chNo":22,"sec":"Virtue"},
{"n":213,"id":"TK-0213","ta":"புத்தே ளுலகத்தும் ஈண்டும் பெறலரிதே ஒப்புரவின் நல்ல பிற.","en":"In heav'n and earth 'tis hard to find  A greater good than being kind","ch":"ஒப்புரவறிதல்","chEn":"Duty to Society","chNo":22,"sec":"Virtue"},
{"n":214,"id":"TK-0214","ta":"ஒத்த தறவோன் உயிர்வாழ்வான் மற்றையான் செத்தாருள் வைக்கப் படும்.","en":"He lives who knows befitting act  Others are deemed as dead in fact","ch":"ஒப்புரவறிதல்","chEn":"Duty to Society","chNo":22,"sec":"Virtue"},
{"n":215,"id":"TK-0215","ta":"ஊருணி நீர்நிறைந் தற்றே உலகவாம் பேரறி வாளன் திரு.","en":"The wealth that wise and kind do make  Is like water that fills a lake","ch":"ஒப்புரவறிதல்","chEn":"Duty to Society","chNo":22,"sec":"Virtue"},
{"n":216,"id":"TK-0216","ta":"பயன்மரம் உள்ளூர்ப் பழுத்தற்றால் செல்வம் நயனுடை யான்கண் படின்.","en":"Who plenty gets and plenty gives  Is like town-tree teeming with fruits","ch":"ஒப்புரவறிதல்","chEn":"Duty to Society","chNo":22,"sec":"Virtue"},
{"n":217,"id":"TK-0217","ta":"மருந்தாகித் தப்பா மரத்தற்றால் செல்வம் பெருந்தகை யான்கண் படின்.","en":"The wealth of a wide-hearted soul  Is a herbal tree that healeth all","ch":"ஒப்புரவறிதல்","chEn":"Duty to Society","chNo":22,"sec":"Virtue"},
{"n":218,"id":"TK-0218","ta":"இடனில் பருவத்தும் ஒப்புரவிற்கு ஒல்கார் கடனறி காட்சி யவர்.","en":"Though seers may fall on evil days  Their sense of duty never strays","ch":"ஒப்புரவறிதல்","chEn":"Duty to Society","chNo":22,"sec":"Virtue"},
{"n":219,"id":"TK-0219","ta":"நயனுடையான் நல்கூர்ந்தா னாதல் செயும்நீர செய்யாது அமைகலா வாறு.","en":"The good man's poverty and grief  Is want of means to give relief","ch":"ஒப்புரவறிதல்","chEn":"Duty to Society","chNo":22,"sec":"Virtue"},
{"n":220,"id":"TK-0220","ta":"ஒப்புரவி னால்வரும் கேடெனின் அஃதொருவன் விற்றுக்கோள் தக்க துடைத்து.","en":"By good if ruin comes across  Sell yourself to save that loss","ch":"ஒப்புரவறிதல்","chEn":"Duty to Society","chNo":22,"sec":"Virtue"},
{"n":221,"id":"TK-0221","ta":"வறியார்க்கொன்று ஈவதே ஈகைமற் றெல்லாம் குறியெதிர்ப்பை நீர துடைத்து.","en":"To give the poor is charity  The rest is loan and vanity","ch":"ஈகை","chEn":"Giving","chNo":23,"sec":"Virtue"},
{"n":222,"id":"TK-0222","ta":"நல்லாறு எனினும் கொளல்தீது மேலுலகம் இல்லெனினும் ஈதலே நன்று.","en":"To beg is bad e'en from the good  To give is good, were heaven forbid","ch":"ஈகை","chEn":"Giving","chNo":23,"sec":"Virtue"},
{"n":223,"id":"TK-0223","ta":"இலனென்னும் எவ்வம் உரையாமை ஈதல் குலனுடையான் கண்ணே யுள.","en":"No pleading, \\\"I am nothing worth,\\\"  But giving marks a noble birth","ch":"ஈகை","chEn":"Giving","chNo":23,"sec":"Virtue"},
{"n":224,"id":"TK-0224","ta":"இன்னாது இரக்கப் படுதல் இரந்தவர் இன்முகங் காணும் அளவு.","en":"The cry for alms is painful sight  Until the giver sees him bright","ch":"ஈகை","chEn":"Giving","chNo":23,"sec":"Virtue"},
{"n":225,"id":"TK-0225","ta":"ஆற்றுவார் ஆற்றல் பசிஆற்றல் அப்பசியை மாற்றுவார் ஆற்றலின் பின்.","en":"Higher's power which hunger cures  Than that of penance which endures","ch":"ஈகை","chEn":"Giving","chNo":23,"sec":"Virtue"},
{"n":226,"id":"TK-0226","ta":"அற்றார் அழிபசி தீர்த்தல் அஃதொருவன் பெற்றான் பொருள்வைப் புழி.","en":"Drive from the poor their gnawing pains  If room you seek to store your gains","ch":"ஈகை","chEn":"Giving","chNo":23,"sec":"Virtue"},
{"n":227,"id":"TK-0227","ta":"பாத்தூண் மரீஇ யவனைப் பசியென்னும் தீப்பிணி தீண்டல் அரிது.","en":"Who shares his food with those who need  Hunger shall not harm his creed","ch":"ஈகை","chEn":"Giving","chNo":23,"sec":"Virtue"},
{"n":228,"id":"TK-0228","ta":"ஈத்துவக்கும் இன்பம் அறியார்கொல் தாமுடைமை வைத்திழக்கும் வன்க ணவர்.","en":"The joy of give and take they lose  Hard-hearted rich whose hoarding fails","ch":"ஈகை","chEn":"Giving","chNo":23,"sec":"Virtue"},
{"n":229,"id":"TK-0229","ta":"இரத்தலின் இன்னாது மன்ற நிரப்பிய தாமே தமியர் உணல்.","en":"Worse than begging is that boarding  Alone what one's greed is hoarding","ch":"ஈகை","chEn":"Giving","chNo":23,"sec":"Virtue"},
{"n":230,"id":"TK-0230","ta":"சாதலின் இன்னாத தில்லை இனிததூஉம் ஈதல் இயையாக் கடை.","en":"Nothing is more painful than death  Yet more is pain of giftless dearth","ch":"ஈகை","chEn":"Giving","chNo":23,"sec":"Virtue"},
{"n":231,"id":"TK-0231","ta":"ஈதல் இசைபட வாழ்தல் அதுவல்லது ஊதியம் இல்லை உயிர்க்கு.","en":"They gather fame who freely give  The greatest gain for all that live","ch":"புகழ்","chEn":"Renown","chNo":24,"sec":"Virtue"},
{"n":232,"id":"TK-0232","ta":"உரைப்பார் உரைப்பவை எல்லாம் இரப்பார்க்கொன்று ஈவார்மேல் நிற்கும் புகழ்.","en":"The glory of the alms-giver  Is praised aloud as popular","ch":"புகழ்","chEn":"Renown","chNo":24,"sec":"Virtue"},
{"n":233,"id":"TK-0233","ta":"ஒன்றா உலகத்து உயர்ந்த புகழல்லால் பொன்றாது நிற்பதொன் றில்.","en":"Nothing else lasts on earth for e'er  Saving high fame of the giver!","ch":"புகழ்","chEn":"Renown","chNo":24,"sec":"Virtue"},
{"n":234,"id":"TK-0234","ta":"நிலவரை நீள்புகழ் ஆற்றின் புலவரைப் போற்றாது புத்தேள் உலகு.","en":"From hailing gods heavens will cease  To hail the men of lasting praise","ch":"புகழ்","chEn":"Renown","chNo":24,"sec":"Virtue"},
{"n":235,"id":"TK-0235","ta":"நத்தம்போல் கேடும் உளதாகும் சாக்காடும் வித்தகர்க் கல்லால் அரிது.","en":"Fame in fall and life in death  Are rare but for the soulful worth","ch":"புகழ்","chEn":"Renown","chNo":24,"sec":"Virtue"},
{"n":236,"id":"TK-0236","ta":"தோன்றின் புகழொடு தோன்றுக அஃதிலார் தோன்றலின் தோன்றாமை நன்று.","en":"Be born with fame if birth you want  If not of birth you must not vaunt","ch":"புகழ்","chEn":"Renown","chNo":24,"sec":"Virtue"},
{"n":237,"id":"TK-0237","ta":"புகழ்பட வாழாதார் தந்நோவார் தம்மை இகழ்வாரை நோவது எவன்?","en":"Why grieve at those who blame the shame  Of those who cannot live in fame?","ch":"புகழ்","chEn":"Renown","chNo":24,"sec":"Virtue"},
{"n":238,"id":"TK-0238","ta":"வசையென்ப வையத்தார்க் கெல்லாம் இசையென்னும் எச்சம் பெறாஅ விடின்.","en":"To men on earth it is a shame  Not to beget the child of fame","ch":"புகழ்","chEn":"Renown","chNo":24,"sec":"Virtue"},
{"n":239,"id":"TK-0239","ta":"வசையிலா வண்பயன் குன்றும் இசையிலா யாக்கை பொறுத்த நிலம்.","en":"The land will shrink in yield if men  O'erburden it without renown","ch":"புகழ்","chEn":"Renown","chNo":24,"sec":"Virtue"},
{"n":240,"id":"TK-0240","ta":"வசையொழிய வாழ்வாரே வாழ்வார் இசையொழிய வாழ்வாரே வாழா தவர்.","en":"They live who live without blemish  The blameful ones do not flurish","ch":"புகழ்","chEn":"Renown","chNo":24,"sec":"Virtue"},
{"n":241,"id":"TK-0241","ta":"அருட்செல்வம் செல்வத்துள் செல்வம் பொருட்செல்வம் பூரியார் கண்ணும் உள.","en":"The wealth of wealth is wealth of grace  Earthly wealth e'en the basest has","ch":"அருளுடைமை","chEn":"Compassion","chNo":25,"sec":"Virtue"},
{"n":242,"id":"TK-0242","ta":"நல்லாற்றாள் நாடி அருளாள்க பல்லாற்றால் தேரினும் அஃதே துணை.","en":"Seek by sound ways good compassion;  All faiths mark that for-salvation","ch":"அருளுடைமை","chEn":"Compassion","chNo":25,"sec":"Virtue"},
{"n":243,"id":"TK-0243","ta":"அருள்சேர்ந்த நெஞ்சினார்க் கில்லை இருள்சேர்ந்த இன்னா உலகம் புகல்.","en":"The hearts of mercy shall not go  Into dark worlds of gruesome woe","ch":"அருளுடைமை","chEn":"Compassion","chNo":25,"sec":"Virtue"},
{"n":244,"id":"TK-0244","ta":"மன்னுயிர் ஓம்பி அருளாள்வார்க்கு இல்லென்ப தன்னுயிர் அஞ்சும் வினை.","en":"His soul is free from dread of sins  Whose mercy serveth all beings","ch":"அருளுடைமை","chEn":"Compassion","chNo":25,"sec":"Virtue"},
{"n":245,"id":"TK-0245","ta":"அல்லல் அருளாள்வார்க்கு இல்லை வளிவழங்கும் மல்லன்மா ஞாலங் கரி.","en":"The wide wind-fed world witness bears:  Men of mercy meet not sorrows","ch":"அருளுடைமை","chEn":"Compassion","chNo":25,"sec":"Virtue"},
{"n":246,"id":"TK-0246","ta":"பொருள்நீங்கிப் பொச்சாந்தார் என்பர் அருள்நீங்கி அல்லவை செய்தொழுகு வார்.","en":"Who grace forsake and graceless act  The former loss and woes forget","ch":"அருளுடைமை","chEn":"Compassion","chNo":25,"sec":"Virtue"},
{"n":247,"id":"TK-0247","ta":"அருளில்லார்க்கு அவ்வுலகம் இல்லை பொருளில்லார்க்கு இவ்வுலகம் இல்லாகி யாங்கு.","en":"This world is not for weathless ones  That world is not for graceless swines","ch":"அருளுடைமை","chEn":"Compassion","chNo":25,"sec":"Virtue"},
{"n":248,"id":"TK-0248","ta":"பொருளற்றார் பூப்பர் ஒருகால் அருளற்றார் அற்றார்மற் றாதல் அரிது.","en":"The wealthless may prosper one day;  The graceless never bloom agay","ch":"அருளுடைமை","chEn":"Compassion","chNo":25,"sec":"Virtue"},
{"n":249,"id":"TK-0249","ta":"தெருளாதான் மெய்ப்பொருள் கண்டற்றால் தேரின் அருளாதான் செய்யும் அறம்.","en":"Like Truth twisted by confused mind  Wisdom is vain in hearts unkind","ch":"அருளுடைமை","chEn":"Compassion","chNo":25,"sec":"Virtue"},
{"n":250,"id":"TK-0250","ta":"வலியார்முன் தன்னை நினைக்கதான் தன்னின் மெலியார்மேல் செல்லு மிடத்து.","en":"Think how you feel before the strong  When to the feeble you do wrong","ch":"அருளுடைமை","chEn":"Compassion","chNo":25,"sec":"Virtue"},
{"n":251,"id":"TK-0251","ta":"தன்னூன் பெருக்கற்குத் தான்பிறிது ஊனுண்பான் எங்ஙனம் ஆளும் அருள்?","en":"What graciousness can one command  who feeds his flesh by flesh gourmand","ch":"புலால் மறுத்தல்","chEn":"Abstinence from Flesh","chNo":26,"sec":"Virtue"},
{"n":252,"id":"TK-0252","ta":"பொருளாட்சி போற்றாதார்க்கு இல்லை அருளாட்சி ஆங்கில்லை ஊன்தின் பவர்க்கு.","en":"The thriftless have no property  And flesh-eaters have no pity","ch":"புலால் மறுத்தல்","chEn":"Abstinence from Flesh","chNo":26,"sec":"Virtue"},
{"n":253,"id":"TK-0253","ta":"படைகொண்டார் நெஞ்சம்போல் நன்னூக்காது ஒன்றன் உடல்சுவை உண்டார் மனம்.","en":"Who wields a steel is steel-hearted  Who tastes body is hard-hearted","ch":"புலால் மறுத்தல்","chEn":"Abstinence from Flesh","chNo":26,"sec":"Virtue"},
{"n":254,"id":"TK-0254","ta":"அருளல்ல தியாதெனிற் கொல்லாமை கோறல் பொருளல்லது அவ்வூன் தினல்.","en":"If merciless it is to kill,  To kill and eat is disgraceful","ch":"புலால் மறுத்தல்","chEn":"Abstinence from Flesh","chNo":26,"sec":"Virtue"},
{"n":255,"id":"TK-0255","ta":"உண்ணாமை உள்ளது உயிர்நிலை ஊனுண்ண அண்ணாத்தல் செய்யாது அளறு.","en":"Off with flesh; a life you save  The eater hell's mouth shall not waive!","ch":"புலால் மறுத்தல்","chEn":"Abstinence from Flesh","chNo":26,"sec":"Virtue"},
{"n":256,"id":"TK-0256","ta":"தினற்பொருட்டால் கொல்லாது உலகெனின் யாரும் விலைப்பொருட்டால் ஊன்றருவா ரில்.","en":"None would kill and sell the flesh  For eating it if they don't wish","ch":"புலால் மறுத்தல்","chEn":"Abstinence from Flesh","chNo":26,"sec":"Virtue"},
{"n":257,"id":"TK-0257","ta":"உண்ணாமை வேண்டும் புலாஅல் பிறிதொன்றன் புண்ணது உணர்வார்ப் பெறின்.","en":"From eating flesh men must abstain  If they but feel the being's pain","ch":"புலால் மறுத்தல்","chEn":"Abstinence from Flesh","chNo":26,"sec":"Virtue"},
{"n":258,"id":"TK-0258","ta":"செயிரின் தலைப்பிரிந்த காட்சியார் உண்ணார் உயிரின் தலைப்பிரிந்த ஊன்.","en":"Whose mind from illusion is freed  Refuse on lifeless flesh to feed","ch":"புலால் மறுத்தல்","chEn":"Abstinence from Flesh","chNo":26,"sec":"Virtue"},
{"n":259,"id":"TK-0259","ta":"அவிசொரிந் தாயிரம் வேட்டலின் ஒன்றன் உயிர்செகுத் துண்ணாமை நன்று.","en":"Not to-kill-and-eat, truly  Excels thousand pourings of ghee!","ch":"புலால் மறுத்தல்","chEn":"Abstinence from Flesh","chNo":26,"sec":"Virtue"},
{"n":260,"id":"TK-0260","ta":"கொல்லான் புலாலை மறுத்தானைக் கைகூப்பி எல்லா உயிருந் தொழும்.","en":"All lives shall lift their palms to him  Who eats not flesh nor kills with whim","ch":"புலால் மறுத்தல்","chEn":"Abstinence from Flesh","chNo":26,"sec":"Virtue"},
{"n":261,"id":"TK-0261","ta":"உற்றநோய் நோன்றல் உயிர்க்குறுகண் செய்யாமை அற்றே தவத்திற் குரு.","en":"Pains endure; pain not beings  This is the type of true penance","ch":"தவம்","chEn":"Penance","chNo":27,"sec":"Virtue"},
{"n":262,"id":"TK-0262","ta":"தவமும் தவமுடையார்க்கு ஆகும் அதனை அஃதிலார் மேற்கொள் வது.","en":"Penance is fit for penitents  Not for him who in vain pretends","ch":"தவம்","chEn":"Penance","chNo":27,"sec":"Virtue"},
{"n":263,"id":"TK-0263","ta":"துறந்தார்க்குத் துப்புரவு வேண்டி மறந்தார்கொல் மற்றை யவர்கள் தவம்.","en":"Is it to true penitent's aid,  That others austere path avoid?","ch":"தவம்","chEn":"Penance","chNo":27,"sec":"Virtue"},
{"n":264,"id":"TK-0264","ta":"ஒன்னார்த் தெறலும் உவந்தாரை ஆக்கலும் எண்ணின் தவத்தான் வரும்.","en":"In penance lies the power to save  The friends and foil the foe and knave","ch":"தவம்","chEn":"Penance","chNo":27,"sec":"Virtue"},
{"n":265,"id":"TK-0265","ta":"வேண்டிய வேண்டியாங் கெய்தலால் செய்தவம் ஈண்டு முயலப் படும்.","en":"What they wish as they wish is won  Here hence by men penance is done","ch":"தவம்","chEn":"Penance","chNo":27,"sec":"Virtue"},
{"n":266,"id":"TK-0266","ta":"தவஞ்செய்வார் தங்கருமஞ் செய்வார்மற் றல்லார் அவஞ்செய்வார் ஆசையுட் பட்டு.","en":"Who do penance achieve their aim  Others desire-rid themselves harm","ch":"தவம்","chEn":"Penance","chNo":27,"sec":"Virtue"},
{"n":267,"id":"TK-0267","ta":"சுடச்சுடரும் பொன்போல் ஒளிவிடும் துன்பஞ் சுடச்சுட நோற்கிற் பவர்க்கு.","en":"Pure and bright gets the gold in fire;  and so the life by pain austere","ch":"தவம்","chEn":"Penance","chNo":27,"sec":"Virtue"},
{"n":268,"id":"TK-0268","ta":"தன்னுயிர் தான்அறப் பெற்றானை ஏனைய மன்னுயி ரெல்லாந் தொழும்.","en":"He worship wins from every soul  Who Master is by soul control","ch":"தவம்","chEn":"Penance","chNo":27,"sec":"Virtue"},
{"n":269,"id":"TK-0269","ta":"கூற்றம் குதித்தலும் கைகூடும் நோற்றலின் ஆற்றல் தலைப்பட் டவர்க்குல்.","en":"They can even defy death  Who get by penance godly strenth","ch":"தவம்","chEn":"Penance","chNo":27,"sec":"Virtue"},
{"n":270,"id":"TK-0270","ta":"இலர்பல ராகிய காரணம் நோற்பார் சிலர்பலர் நோலா தவர்.","en":"Many are poor and few are rich  For they care not for penance much","ch":"தவம்","chEn":"Penance","chNo":27,"sec":"Virtue"},
{"n":271,"id":"TK-0271","ta":"வஞ்ச மனத்தான் படிற்றொழுக்கம் பூதங்கள் ஐந்தும் அகத்தே நகும்.","en":"Elements five of feigned life  Of a sly hypocrite within laugh","ch":"கூடா ஒழுக்கம்","chEn":"Imposture","chNo":28,"sec":"Virtue"},
{"n":272,"id":"TK-0272","ta":"வானுயர் தோற்றம் எவன்செய்யும் தன்னெஞ்சம் தான்அறி குற்றப் படின்.","en":"Of what avail are sky-high shows  When guild the conscience gnaws and knows","ch":"கூடா ஒழுக்கம்","chEn":"Imposture","chNo":28,"sec":"Virtue"},
{"n":273,"id":"TK-0273","ta":"வலியில் நிலைமையான் வல்லுருவம் பெற்றம் புலியின்தோல் போர்த்துமேய்ந் தற்று.","en":"Vaunting sainthood while week within  Seems a grazer with tiger skin","ch":"கூடா ஒழுக்கம்","chEn":"Imposture","chNo":28,"sec":"Virtue"},
{"n":274,"id":"TK-0274","ta":"தவமறைந்து அல்லவை செய்தல் புதல்மறைந்து வேட்டுவன் புள்சிமிழ்த் தற்று.","en":"Sinning in saintly show is like  Fowlers in ambush birds to strike","ch":"கூடா ஒழுக்கம்","chEn":"Imposture","chNo":28,"sec":"Virtue"},
{"n":275,"id":"TK-0275","ta":"பற்றற்றேம் என்பார் படிற்றொழுக்கம் எற்றெற்றென்று ஏதம் பலவுந் தரும்.","en":"Who false within but freedom feign  Shall moan \\\"What have we done\\\" with pain","ch":"கூடா ஒழுக்கம்","chEn":"Imposture","chNo":28,"sec":"Virtue"},
{"n":276,"id":"TK-0276","ta":"நெஞ்சின் துறவார் துறந்தார்போல் வஞ்சித்து வாழ்வாரின் வன்கணார் இல்.","en":"Vilest is he who seems a saint  Cheating the world without restraint","ch":"கூடா ஒழுக்கம்","chEn":"Imposture","chNo":28,"sec":"Virtue"},
{"n":277,"id":"TK-0277","ta":"புறங்குன்றி கண்டனைய ரேனும் அகங்குன்றி முக்கிற் கரியார் உடைத்து.","en":"Berry-red is his outward view,  Black like its nose his inward hue","ch":"கூடா ஒழுக்கம்","chEn":"Imposture","chNo":28,"sec":"Virtue"},
{"n":278,"id":"TK-0278","ta":"மனத்தது மாசாக மாண்டார் நீராடி மறைந்தொழுகு மாந்தர் பலர்.","en":"Filthy in mind some bathe in streams  Hiding sins in showy extremes","ch":"கூடா ஒழுக்கம்","chEn":"Imposture","chNo":28,"sec":"Virtue"},
{"n":279,"id":"TK-0279","ta":"கணைகொடிது யாழ்கோடு செவ்விதுஆங் கன்ன வினைபடு பாலால் கொளல்.","en":"Know men by acts and not by forms  Strait arrow kills, bent lute but charms","ch":"கூடா ஒழுக்கம்","chEn":"Imposture","chNo":28,"sec":"Virtue"},
{"n":280,"id":"TK-0280","ta":"மழித்தலும் நீட்டலும் வேண்டா உலகம் பழித்தது ஒழித்து விடின்.","en":"No balding nor tangling the hair!  Abstain from condemned acts with care","ch":"கூடா ஒழுக்கம்","chEn":"Imposture","chNo":28,"sec":"Virtue"},
{"n":281,"id":"TK-0281","ta":"எள்ளாமை வேண்டுவான் என்பான் எனைத்தொன்றும் கள்ளாமை காக்கதன் நெஞ்சு.","en":"Let him who would reproachless be  From all frauds guard his conscience free","ch":"கள்ளாமை","chEn":"The Absence of Fraud","chNo":29,"sec":"Virtue"},
{"n":282,"id":"TK-0282","ta":"உள்ளத்தால் உள்ளலும் தீதே பிறன்பொருளைக் கள்ளத்தால் கள்வேம் எனல்.","en":"\\\"We will by fraud win other's wealth\\\"  Even this thought is sin and stealth","ch":"கள்ளாமை","chEn":"The Absence of Fraud","chNo":29,"sec":"Virtue"},
{"n":283,"id":"TK-0283","ta":"களவினால் ஆகிய ஆக்கம் அளவிறந்து ஆவது போலக் கெடும்.","en":"The gain by fraud may overflow  But swift to ruin it shall go","ch":"கள்ளாமை","chEn":"The Absence of Fraud","chNo":29,"sec":"Virtue"},
{"n":284,"id":"TK-0284","ta":"களவின்கண் கன்றிய காதல் விளைவின்கண் வீயா விழுமம் தரும்.","en":"The fruit that fraud and greed obtain  Shall end in endless grief and pain","ch":"கள்ளாமை","chEn":"The Absence of Fraud","chNo":29,"sec":"Virtue"},
{"n":285,"id":"TK-0285","ta":"அருள்கருதி அன்புடைய ராதல் பொருள்கருதிப் பொச்சாப்புப் பார்ப்பார்கண் இல்.","en":"Love and Grace are not their worth  Who watch to waylay dozer's wealth","ch":"கள்ளாமை","chEn":"The Absence of Fraud","chNo":29,"sec":"Virtue"},
{"n":286,"id":"TK-0286","ta":"அளவின்கண் நின்றொழுகல் ஆற்றார் களவின்கண் கன்றிய காத லவர்.","en":"They cannot walk in measured bounds  who crave and have covetous ends","ch":"கள்ளாமை","chEn":"The Absence of Fraud","chNo":29,"sec":"Virtue"},
{"n":287,"id":"TK-0287","ta":"களவென்னும் காரறி வாண்மை அளவென்னும் ஆற்றல் புரிந்தார்கண்ட இல்.","en":"Men of measured wisdom shun  Black art of fraud and what it won","ch":"கள்ளாமை","chEn":"The Absence of Fraud","chNo":29,"sec":"Virtue"},
{"n":288,"id":"TK-0288","ta":"அளவறிந்தார் நெஞ்சத் தறம்போல நிற்கும் களவறிந்தார் நெஞ்சில் கரவு.","en":"Virtue abides in righteous hearts  Into minds of frauds deceit darts","ch":"கள்ளாமை","chEn":"The Absence of Fraud","chNo":29,"sec":"Virtue"},
{"n":289,"id":"TK-0289","ta":"அளவல்ல செய்தாங்கே வீவர் களவல்ல மற்றைய தேற்றா தவர்.","en":"They perish in their perfidy  Who know nothing but pilfery","ch":"கள்ளாமை","chEn":"The Absence of Fraud","chNo":29,"sec":"Virtue"},
{"n":290,"id":"TK-0290","ta":"கள்வார்க்குத் தள்ளும் உயிர்நிலை கள்வார்க்குத் தள்ளாது புத்தே ளுளகு.","en":"Even the body rejects thieves;  The honest men, heaven receives","ch":"கள்ளாமை","chEn":"The Absence of Fraud","chNo":29,"sec":"Virtue"},
{"n":291,"id":"TK-0291","ta":"வாய்மை எனப்படுவது யாதெனின் யாதொன்றும் தீமை இலாத சொலல்.","en":"If \\\"What is truth\\\"? the question be,  It is to speak out evil-free","ch":"வாய்மை","chEn":"Veracity","chNo":30,"sec":"Virtue"},
{"n":292,"id":"TK-0292","ta":"பொய்மையும் வாய்மை யிடத்த புரைதீர்ந்த நன்மை பயக்கும் எனின்.","en":"E'en falsehood may for truth suffice,  When good it brings removing vice","ch":"வாய்மை","chEn":"Veracity","chNo":30,"sec":"Virtue"},
{"n":293,"id":"TK-0293","ta":"தன்நெஞ் சறிவது பொய்யற்க பொய்த்தபின் தன்நெஞ்சே தன்னைச் சுடும்.","en":"Let not a man knowingly lie;  Conscience will scorch and make him sigh","ch":"வாய்மை","chEn":"Veracity","chNo":30,"sec":"Virtue"},
{"n":294,"id":"TK-0294","ta":"உள்ளத்தாற் பொய்யா தொழுகின் உலகத்தார் உள்ளத்து ளெல்லாம் உளன்.","en":"He lives in loving hearts of all  Who serves the Truth serene in soul","ch":"வாய்மை","chEn":"Veracity","chNo":30,"sec":"Virtue"},
{"n":295,"id":"TK-0295","ta":"மனத்தொடு வாய்மை மொழியின் தவத்தொடு தானஞ்செய் வாரின் தலை.","en":"To speak the truth from heart sincere  Is more than giving and living austere","ch":"வாய்மை","chEn":"Veracity","chNo":30,"sec":"Virtue"},
{"n":296,"id":"TK-0296","ta":"பொய்யாமை அன்ன புகழில்லை எய்யாமை எல்லா அறமுந் தரும்.","en":"Not to lie brings all the praise  All virtues from Truth arise","ch":"வாய்மை","chEn":"Veracity","chNo":30,"sec":"Virtue"},
{"n":297,"id":"TK-0297","ta":"பொய்யாமை பொய்யாமை ஆற்றின் அறம்பிற செய்யாமை செய்யாமை நன்று.","en":"Lie not lie not Naught else you need  All virtues are in Truth indeed","ch":"வாய்மை","chEn":"Veracity","chNo":30,"sec":"Virtue"},
{"n":298,"id":"TK-0298","ta":"புறள்தூய்மை நீரான் அமையும் அகந்தூய்மை வாய்மையால் காணப் படும்.","en":"Water makes you pure outward  Truth renders you pure inward","ch":"வாய்மை","chEn":"Veracity","chNo":30,"sec":"Virtue"},
{"n":299,"id":"TK-0299","ta":"எல்லா விளக்கும் விளக்கல்ல சான்றோர்க்குப் பொய்யா விளக்கே விளக்கு.","en":"All lights are not lights for the wise;  Truth light is light bright like Sun-light","ch":"வாய்மை","chEn":"Veracity","chNo":30,"sec":"Virtue"},
{"n":300,"id":"TK-0300","ta":"யாமெய்யாக் கண்டவற்றுள் இல்லை எனைத்தொன்றும் வாய்மையின் நல்ல பிற.","en":"Of all the things we here have seen  Nothing surpasses Truth serene!","ch":"வாய்மை","chEn":"Veracity","chNo":30,"sec":"Virtue"},
{"n":301,"id":"TK-0301","ta":"செல்லிடத்துக் காப்பான் சினங்காப்பான் அல்லிடத்துக் காக்கின்என் காவாக்கால் என்?","en":"Anger against the weak is wrong  It is futile against the strong","ch":"வெகுளாமை","chEn":"Restraining Anger","chNo":31,"sec":"Virtue"},
{"n":302,"id":"TK-0302","ta":"செல்லா இடத்துச் சினந்தீது செல்லிடத்தும் இல்அதனின் தீய பிற.","en":"Vain is wrath against men of force  Against the meek it is still worse","ch":"வெகுளாமை","chEn":"Restraining Anger","chNo":31,"sec":"Virtue"},
{"n":303,"id":"TK-0303","ta":"மறத்தல் வெகுளியை யார்மாட்டும் தீய பிறத்தல் அதனான் வரும்.","en":"Off with wrath with any one  It is the source of sin and pain","ch":"வெகுளாமை","chEn":"Restraining Anger","chNo":31,"sec":"Virtue"},
{"n":304,"id":"TK-0304","ta":"நகையும் உவகையும் கொல்லும் சினத்தின் பகையும் உளவோ பிற.","en":"Is there a foe like harmful ire  Which kills the smile and joyful cheer?","ch":"வெகுளாமை","chEn":"Restraining Anger","chNo":31,"sec":"Virtue"},
{"n":305,"id":"TK-0305","ta":"தன்னைத்தான் காக்கின் சினங்காக்க காவாக்கால் தன்னையே கொல்லுஞ் சினம்.","en":"Thyself to save, from wrath away!  If not thyself the wrath will slay","ch":"வெகுளாமை","chEn":"Restraining Anger","chNo":31,"sec":"Virtue"},
{"n":306,"id":"TK-0306","ta":"சினமென்னும் சேர்ந்தாரைக் கொல்லி இனமென்னும் ஏமப் புணையைச் சுடும்.","en":"Friend-killer is the fatal rage  It burns the helpful kinship-barge","ch":"வெகுளாமை","chEn":"Restraining Anger","chNo":31,"sec":"Virtue"},
{"n":307,"id":"TK-0307","ta":"சினத்தைப் பொருளென்று கொண்டவன் கேடு நிலத்தறைந்தான் கைபிழையா தற்று.","en":"The wrath-lover to doom is bound  Like failless-hand that strikes the ground","ch":"வெகுளாமை","chEn":"Restraining Anger","chNo":31,"sec":"Virtue"},
{"n":308,"id":"TK-0308","ta":"இணர்எரி தோய்வன்ன இன்னா செயினும் புணரின் வெகுளாமை நன்று.","en":"Save thy soul from burning ire  Though tortured like the touch of fire","ch":"வெகுளாமை","chEn":"Restraining Anger","chNo":31,"sec":"Virtue"},
{"n":309,"id":"TK-0309","ta":"உள்ளிய தெல்லாம் உடனெய்தும் உள்ளத்தால் உள்ளான் வெகுளி எனின்.","en":"Wishes he gains as he wishes  If man refrains from rage vicious!","ch":"வெகுளாமை","chEn":"Restraining Anger","chNo":31,"sec":"Virtue"},
{"n":310,"id":"TK-0310","ta":"இறந்தார் இறந்தார் அனையர் சினத்தைத் துறந்தார் துறந்தார் துணை.","en":"Dead are they who are anger-fed  Saints are they from whom wrath has fled","ch":"வெகுளாமை","chEn":"Restraining Anger","chNo":31,"sec":"Virtue"},
{"n":311,"id":"TK-0311","ta":"சிறப்பீனும் செல்வம் பெறினும் பிறர்க்குஇன்னா செய்யாமை மாசற்றார் கோள்.","en":"The pure by faith mean pain to none  Though princely wealth by that is won","ch":"இன்னா செய்யாமை","chEn":"Not doing Evil","chNo":32,"sec":"Virtue"},
{"n":312,"id":"TK-0312","ta":"கறுத்துஇன்னா செய்தவக் கண்ணும் மறுத்தின்னா செய்யாமை மாசற்றார் கோள்.","en":"The spotless hearts seek not revenge  Though Malice does the worst in rage","ch":"இன்னா செய்யாமை","chEn":"Not doing Evil","chNo":32,"sec":"Virtue"},
{"n":313,"id":"TK-0313","ta":"செய்யாமல் செற்றார்க்கும் இன்னாத செய்தபின் உய்யா விழுமந் தரும்.","en":"Revenging even causeless hate  Bad-blood breeds and baneful heat","ch":"இன்னா செய்யாமை","chEn":"Not doing Evil","chNo":32,"sec":"Virtue"},
{"n":314,"id":"TK-0314","ta":"இன்னாசெய் தாரை ஒறுத்தல் அவர்நாண நன்னயஞ் செய்து விடல்.","en":"Doing good-turns, put them to shame  Thus chide the evil who do harm","ch":"இன்னா செய்யாமை","chEn":"Not doing Evil","chNo":32,"sec":"Virtue"},
{"n":315,"id":"TK-0315","ta":"அறிவினான் ஆகுவ துண்டோ பிறிதின்நோய் தந்நோய்போல் போற்றாக் கடை.","en":"What does a man from wisdom gain  If he pines not at other's pain?","ch":"இன்னா செய்யாமை","chEn":"Not doing Evil","chNo":32,"sec":"Virtue"},
{"n":316,"id":"TK-0316","ta":"இன்னா எனத்தான் உணர்ந்தவை துன்னாமை வேண்டும் பிறன்கண் செயல்.","en":"What you feel as pain to yourself  Do it not to the other-self","ch":"இன்னா செய்யாமை","chEn":"Not doing Evil","chNo":32,"sec":"Virtue"},
{"n":317,"id":"TK-0317","ta":"எனைத்தானும் எஞ்ஞான்றும் யார்க்கும் மனத்தானாம் மாணாசெய் யாமை தலை.","en":"Any, anywhere injure not  At any time even in thought","ch":"இன்னா செய்யாமை","chEn":"Not doing Evil","chNo":32,"sec":"Virtue"},
{"n":318,"id":"TK-0318","ta":"தன்னுயிர்ககு ஏன்னாமை தானறிவான் என்கொலோ மன்னுயிர்க்கு இன்னா செயல்.","en":"How can he injure other souls  Who in his life injury feels","ch":"இன்னா செய்யாமை","chEn":"Not doing Evil","chNo":32,"sec":"Virtue"},
{"n":319,"id":"TK-0319","ta":"பிறர்க்கின்னா முற்பகல் செய்யின் தமக்குஇன்னா பிற்பகல் தாமே வரும்.","en":"Harm others in the forenoon  Harm seeks thee in afternoon","ch":"இன்னா செய்யாமை","chEn":"Not doing Evil","chNo":32,"sec":"Virtue"},
{"n":320,"id":"TK-0320","ta":"நோயெல்லாம் நோய்செய்தார் மேலவாம் நோய்செய்யார் நோயின்மை வேண்டு பவர்.","en":"No harm is done by peace-lovers  For pains rebound on pain-givers","ch":"இன்னா செய்யாமை","chEn":"Not doing Evil","chNo":32,"sec":"Virtue"},
{"n":321,"id":"TK-0321","ta":"அறவினை யாதெனின் கொல்லாமை கோறல் பிறவினை எல்லாந் தரும்.","en":"What is Virtue? 'Tis not to kill  For killing causes every ill","ch":"கொல்லாமை","chEn":"Not killing","chNo":33,"sec":"Virtue"},
{"n":322,"id":"TK-0322","ta":"பகுத்துண்டு பல்லுயிர் ஓம்புதல் நூலோர் தொகுத்தவற்றுள் எல்லாந் தலை.","en":"Share the food and serve all lives  This is the law of all the laws","ch":"கொல்லாமை","chEn":"Not killing","chNo":33,"sec":"Virtue"},
{"n":323,"id":"TK-0323","ta":"ஒன்றாக நல்லது கொல்லாமை மற்றதன் பின்சாரப் பொய்யாமை நன்று.","en":"Not to kill is unique good  The next, not to utter falsehood","ch":"கொல்லாமை","chEn":"Not killing","chNo":33,"sec":"Virtue"},
{"n":324,"id":"TK-0324","ta":"நல்லாறு எனப்படுவது யாதெனின் யாதொன்றும் கொல்லாமை சூழும் நெறி.","en":"What way is good? That we can say  The way away from heat to slay","ch":"கொல்லாமை","chEn":"Not killing","chNo":33,"sec":"Virtue"},
{"n":325,"id":"TK-0325","ta":"நிலைஅஞ்சி நீத்தாருள் எல்லாம் கொலைஅஞ்சிக் கொல்லாமை சூழ்வான் தலை.","en":"Of saints who renounce birth-fearing  The head is he who dreads killing","ch":"கொல்லாமை","chEn":"Not killing","chNo":33,"sec":"Virtue"},
{"n":326,"id":"TK-0326","ta":"கொல்லாமை மேற்கொண் டொழுகுவான் வாழ்நாள்மேல் செல்லாது உயிருண்ணுங் கூற்று.","en":"Life-eating-Death shall spare the breath  Of him who no life puts to death","ch":"கொல்லாமை","chEn":"Not killing","chNo":33,"sec":"Virtue"},
{"n":327,"id":"TK-0327","ta":"தன்னுயிர் நீப்பினும் செய்யற்க தான்பிறிது இன்னுயிர் நீக்கும் வினை.","en":"Kill not life that others cherish  Even when your life must perish","ch":"கொல்லாமை","chEn":"Not killing","chNo":33,"sec":"Virtue"},
{"n":328,"id":"TK-0328","ta":"நன்றாகும் ஆக்கம் பெரிதெனினும் சான்றோர்க்குக் கொன்றாகும் ஆக்கங் கடை.","en":"The gain of slaughter is a vice  Though deemed good in sacrifice","ch":"கொல்லாமை","chEn":"Not killing","chNo":33,"sec":"Virtue"},
{"n":329,"id":"TK-0329","ta":"கொலைவினைய ராகிய மாக்கள் புலைவினையர் புன்மை தெரிவா ரகத்து.","en":"Those who live by slaying are  Eaters of carrion bizarre!","ch":"கொல்லாமை","chEn":"Not killing","chNo":33,"sec":"Virtue"},
{"n":330,"id":"TK-0330","ta":"உயிருடம்பின் நீக்கியா ரென்ப செயிருடம்பின் செல்லாத்தீ வாழ்க்கை யவர்.","en":"The loathsome poor sickly and sore  Are killers stained by blood before","ch":"கொல்லாமை","chEn":"Not killing","chNo":33,"sec":"Virtue"},
{"n":331,"id":"TK-0331","ta":"நில்லாத வற்றை நிலையின என்றுணரும் புல்லறி வாண்மை கடை.","en":"The worst of follies it is told  The fleeting as lasting to hold","ch":"நிலையாமை","chEn":"Instability","chNo":34,"sec":"Virtue"},
{"n":332,"id":"TK-0332","ta":"கூத்தாட்டு அவைக்குழாத் தற்றே பெருஞ்செல்வம் போக்கும் அதுவிளிந் தற்று.","en":"Like a drama-crowd wealth gathers  Like passing show its pride too goes","ch":"நிலையாமை","chEn":"Instability","chNo":34,"sec":"Virtue"},
{"n":333,"id":"TK-0333","ta":"அற்கா இயல்பிற்றுச் செல்வம் அதுபெற்றால் அற்குப ஆங்கே செயல்.","en":"Wealth wanes away; but when it comes  Take care to do enduring things","ch":"நிலையாமை","chEn":"Instability","chNo":34,"sec":"Virtue"},
{"n":334,"id":"TK-0334","ta":"நாளென ஒன்றுபோற் காட்டி உயிர்ஈரும் வாளது உணர்வார்ப் பெறின்.","en":"The showy day is but a saw  Your life, know that, to file and gnaw","ch":"நிலையாமை","chEn":"Instability","chNo":34,"sec":"Virtue"},
{"n":335,"id":"TK-0335","ta":"நாச்செற்று விக்குள்மேல் வாராமுன் நல்வினை மேற்சென்று செய்யப் படும்","en":"Ere tongue benumbs and hiccough comes  Rise up to do good deeds betimes","ch":"நிலையாமை","chEn":"Instability","chNo":34,"sec":"Virtue"},
{"n":336,"id":"TK-0336","ta":"நெருநல் உளனொருவன் இன்றில்லை என்னும் பெருமை உடைத்துஇவ் வுலகு.","en":"One was yesterday; not today!","ch":"நிலையாமை","chEn":"Instability","chNo":34,"sec":"Virtue"},
{"n":337,"id":"TK-0337","ta":"ஒருபொழுதும் வாழ்வது அறியார் கருதுப கோடியும் அல்ல பல.","en":"Man knows not his next moment  On crores of things he is intent","ch":"நிலையாமை","chEn":"Instability","chNo":34,"sec":"Virtue"},
{"n":338,"id":"TK-0338","ta":"குடம்பை தனித்துஒழியப் புள்பறந் தற்றே உடம்பொடு உயிரிடை நட்பு.","en":"The soul from body any day  Like bird from egg-shell flies away","ch":"நிலையாமை","chEn":"Instability","chNo":34,"sec":"Virtue"},
{"n":339,"id":"TK-0339","ta":"உறங்கு வதுபோலுஞ் சாக்காடு உறங்கி விழிப்பது போலும் பிறப்பு.","en":"Death is like a slumber deep  And birth like waking from that sleep","ch":"நிலையாமை","chEn":"Instability","chNo":34,"sec":"Virtue"},
{"n":340,"id":"TK-0340","ta":"புக்கில் அமைந்தின்று கொல்லோ உடம்பினுள் துச்சில் இருந்த உயிர்க்கு.","en":"The life berthed in this body shows  A fixed home it never knows","ch":"நிலையாமை","chEn":"Instability","chNo":34,"sec":"Virtue"},
{"n":341,"id":"TK-0341","ta":"யாதனின் யாதனின் நீங்கியான் நோதல் அதனின் அதனின் இலன்.","en":"From what from what a man is free  From that, from that his torments flee","ch":"துறவு","chEn":"Renunciation","chNo":35,"sec":"Virtue"},
{"n":342,"id":"TK-0342","ta":"வேண்டின்உண் டாகத் துறக்க துறந்தபின் ஈண்டுஇயற் பால பல.","en":"Give up all to gain the True  And endless joys shall hence seek you","ch":"துறவு","chEn":"Renunciation","chNo":35,"sec":"Virtue"},
{"n":343,"id":"TK-0343","ta":"அடல்வேண்டும் ஐந்தன் புலத்தை விடல்வேண்டும் வேண்டிய வெல்லாம் ஒருங்கு.","en":"Curb the senses five and renounce  The carving desires all at once","ch":"துறவு","chEn":"Renunciation","chNo":35,"sec":"Virtue"},
{"n":344,"id":"TK-0344","ta":"இயல்பாகும் நோன்பிற்கொன்று இன்மை உடைமை மயலாகும் மற்றும் பெயர்த்து.","en":"To have nothing is law of vows  Having the least deludes and snares","ch":"துறவு","chEn":"Renunciation","chNo":35,"sec":"Virtue"},
{"n":345,"id":"TK-0345","ta":"மற்றும் தொடர்ப்பாடு எவன்கொல் பிறப்பறுக்கல் உற்றார்க்கு உடம்பும் மிகை.","en":"Why add to bonds while this body  Is too much for saints to be birth-free","ch":"துறவு","chEn":"Renunciation","chNo":35,"sec":"Virtue"},
{"n":346,"id":"TK-0346","ta":"யான்எனது என்னும் செருக்குஅறுப்பான் வானோர்க்கு உயர்ந்த உலகம் புகும்.","en":"Who curbs the pride of I and mine  Gets a world rare for gods to gain","ch":"துறவு","chEn":"Renunciation","chNo":35,"sec":"Virtue"},
{"n":347,"id":"TK-0347","ta":"பற்றி விடாஅ இடும்பைகள் பற்றினைப் பற்றி விடாஅ தவர் க்கு.","en":"Grief clings on and on to those  Who cling to bonds without release","ch":"துறவு","chEn":"Renunciation","chNo":35,"sec":"Virtue"},
{"n":348,"id":"TK-0348","ta":"தலைப்பட்டார் தீரத் துறந்தார் மயங்கி வலைப்பட்டார் மற்றை யவர்.","en":"Who renounce all are free from care  Others suffer delusive snare","ch":"துறவு","chEn":"Renunciation","chNo":35,"sec":"Virtue"},
{"n":349,"id":"TK-0349","ta":"பற்றற்ற கண்ணே பிறப்பறுக்கும் மற்று நிலையாமை காணப் படும்.","en":"Bondage cut off, rebirth is off  The world then seems instable stuff","ch":"துறவு","chEn":"Renunciation","chNo":35,"sec":"Virtue"},
{"n":350,"id":"TK-0350","ta":"பற்றுக பற்றற்றான் பற்றினை அப்பற்றைப் பற்றுக பற்று விடற்கு.","en":"Bind Thyself to the unbound one  That binding breaks all bonds anon","ch":"துறவு","chEn":"Renunciation","chNo":35,"sec":"Virtue"},
{"n":351,"id":"TK-0351","ta":"பொருளல்ல வற்றைப் பொருளென்று உணரும் மருளானாம் மாணாப் பிறப்பு.","en":"That error entails ignoble birth  Which deems vain things as things of worth","ch":"மெய்யுணர்தல்","chEn":"Truth-Conciousness","chNo":36,"sec":"Virtue"},
{"n":352,"id":"TK-0352","ta":"இருள்நீங்கி இன்பம் பயக்கும் மருள்நீங்கி மாசறு காட்சி யவர்க்கு.","en":"Men of spotless pure insight  Enjoy delight devoid of night","ch":"மெய்யுணர்தல்","chEn":"Truth-Conciousness","chNo":36,"sec":"Virtue"},
{"n":353,"id":"TK-0353","ta":"ஐயத்தின் நீங்கித் தெளிந்தார்க்கு வையத்தின் வானம் நணிய துடைத்து.","en":"To doubtless minds whose heart is clear  More than earth heaven is near","ch":"மெய்யுணர்தல்","chEn":"Truth-Conciousness","chNo":36,"sec":"Virtue"},
{"n":354,"id":"TK-0354","ta":"ஐயுணர்வு எய்தியக் கண்ணும் பயமின்றே மெய்யுணர்வு இல்லா தவர்க்கு.","en":"Knowledge of five senses is vain  Without knowing the Truth within","ch":"மெய்யுணர்தல்","chEn":"Truth-Conciousness","chNo":36,"sec":"Virtue"},
{"n":355,"id":"TK-0355","ta":"எப்பொருள் எத்தன்மைத் தாயினும் அப்பொருள் மெய்ப்பொருள் காண்பது அறிவு.","en":"Knowledge is truth of things to find  In every case of every kind","ch":"மெய்யுணர்தல்","chEn":"Truth-Conciousness","chNo":36,"sec":"Virtue"},
{"n":356,"id":"TK-0356","ta":"கற்றீண்டு மெய்ப்பொருள் கண்டார் தலைப்படுவர் மற்றீண்டு வாரா நெறி.","en":"Who learn and here the Truth discern  Enter the path of non-return","ch":"மெய்யுணர்தல்","chEn":"Truth-Conciousness","chNo":36,"sec":"Virtue"},
{"n":357,"id":"TK-0357","ta":"ஓர்த்துள்ளம் உள்ளது உணரின் ஒருதலையாப் பேர்த்துள்ள வேண்டா பிறப்பு.","en":"One-minded sage sees inner-truth  He is free from thoughts of rebirth","ch":"மெய்யுணர்தல்","chEn":"Truth-Conciousness","chNo":36,"sec":"Virtue"},
{"n":358,"id":"TK-0358","ta":"பிறப்பென்னும் பேதைமை நீங்கச் சிறப்பென்னும் செம்பொருள் காண்பது அறிவு.","en":"It is knowledge to know Self-Truth  And remove the folly of birth","ch":"மெய்யுணர்தல்","chEn":"Truth-Conciousness","chNo":36,"sec":"Virtue"},
{"n":359,"id":"TK-0359","ta":"சார்புணர்ந்து சார்பு கெடஒழுகின் மற்றழித்துச் சார்தரா சார்தரு நோய்.","en":"Know the Refuge; off with bondage  Be free from ills of thraldom, O sage","ch":"மெய்யுணர்தல்","chEn":"Truth-Conciousness","chNo":36,"sec":"Virtue"},
{"n":360,"id":"TK-0360","ta":"காமம் வெகுளி மயக்கம் இவ்மூன்றன் நாமம் கெடக்கெடும் நோய்.","en":"Woes expire when lust, wrath, folly  Expire even to name, fully","ch":"மெய்யுணர்தல்","chEn":"Truth-Conciousness","chNo":36,"sec":"Virtue"},
{"n":361,"id":"TK-0361","ta":"அவாஎன்ப எல்லா உயிர்க்கும் எஞ்ஞான்றும் தவாஅப் பிறப்பீனும் வித்து.","en":"Desire to all, always is seed  From which ceaseless births proceed","ch":"அவா அறுத்தல்","chEn":"Curbing of Desire","chNo":37,"sec":"Virtue"},
{"n":362,"id":"TK-0362","ta":"வேண்டுங்கால் வேண்டும் பிறவாமை மற்றது வேண்டாமை வேண்ட வரும்.","en":"If long thou must, long for non-birth  It comes by longing no more for earth","ch":"அவா அறுத்தல்","chEn":"Curbing of Desire","chNo":37,"sec":"Virtue"},
{"n":363,"id":"TK-0363","ta":"வேண்டாமை அன்ன விழுச்செல்வம் ஈண்டில்லை ஆண்டும் அஃதொப்பது இல்.","en":"No such wealth is here and there  As peerless wealth of non-desire","ch":"அவா அறுத்தல்","chEn":"Curbing of Desire","chNo":37,"sec":"Virtue"},
{"n":364,"id":"TK-0364","ta":"தூஉய்மை என்பது அவாவின்மை மற்றது வாஅய்மை வேண்ட வரும்.","en":"To nothing crave is purity  That is the fruit of verity","ch":"அவா அறுத்தல்","chEn":"Curbing of Desire","chNo":37,"sec":"Virtue"},
{"n":365,"id":"TK-0365","ta":"அற்றவர் என்பார் அவாஅற்றார் மற்றையார் அற்றாக அற்றது இலர்.","en":"The free are those who desire not  The rest not free in bonds are caught","ch":"அவா அறுத்தல்","chEn":"Curbing of Desire","chNo":37,"sec":"Virtue"},
{"n":366,"id":"TK-0366","ta":"அஞ்சுவ தோரும் அறனே ஒருவனை வஞ்சிப்ப தோரும் அவா.","en":"Dread desire; Virtue is there  To every soul desire is snare!","ch":"அவா அறுத்தல்","chEn":"Curbing of Desire","chNo":37,"sec":"Virtue"},
{"n":367,"id":"TK-0367","ta":"அவாவினை ஆற்ற அறுப்பின் தவாவினை தான்வேண்டு மாற்றான் வரும்.","en":"Destroy desire; deliverance  Comes as much as you aspire hence","ch":"அவா அறுத்தல்","chEn":"Curbing of Desire","chNo":37,"sec":"Virtue"},
{"n":368,"id":"TK-0368","ta":"அவாஇல்லார்க் கில்லாகுந் துன்பம் அஃதுண்டேல் தவாஅது மேன்மேல் வரும்.","en":"Desire extinct no sorrow-taints  Grief comes on grief where it pretends","ch":"அவா அறுத்தல்","chEn":"Curbing of Desire","chNo":37,"sec":"Virtue"},
{"n":369,"id":"TK-0369","ta":"இன்பம் இடையறா தீண்டும் அவாவென்னும் துன்பத்துள் துன்பங் கெடின்.","en":"Desire, the woe of woes destroy  Joy of joys here you enjoy","ch":"அவா அறுத்தல்","chEn":"Curbing of Desire","chNo":37,"sec":"Virtue"},
{"n":370,"id":"TK-0370","ta":"ஆரா இயற்கை அவாநீப்பின் அந்நிலையே பேரா இயற்கை தரும்.","en":"Off with desire insatiate  You gain the native blissful state","ch":"அவா அறுத்தல்","chEn":"Curbing of Desire","chNo":37,"sec":"Virtue"},
{"n":371,"id":"TK-0371","ta":"ஆகூழால் தோன்றும் அசைவின்மை கைப்பொருள் போகூழால் தோன்றும் மடி.","en":"Efforts succeed by waxing star  Wealth-losing brings waning star","ch":"ஊழ்","chEn":"Fate","chNo":38,"sec":"Virtue"},
{"n":372,"id":"TK-0372","ta":"பேதைப் படுக்கும் இழவூழ் அறிவகற்றும் ஆகலூழ் உற்றக் கடை.","en":"Loss-fate makes a dull fool of us  Gain-fate makes us prosperous, wise!","ch":"ஊழ்","chEn":"Fate","chNo":38,"sec":"Virtue"},
{"n":373,"id":"TK-0373","ta":"நுண்ணிய நூல்பல கற்பினும் மற்றுந்தன் உண்மை யறிவே மிகும்.","en":"What matters subtle study deep?  Levels of innate wisdom-keep","ch":"ஊழ்","chEn":"Fate","chNo":38,"sec":"Virtue"},
{"n":374,"id":"TK-0374","ta":"இருவேறு உலகத்து இயற்கை திருவேறு தெள்ளிய ராதலும் வேறு.","en":"Two natures in the world obtain  Some wealth and others wisdom gain","ch":"ஊழ்","chEn":"Fate","chNo":38,"sec":"Virtue"},
{"n":375,"id":"TK-0375","ta":"நல்லவை எல்லாஅந் தீயவாம் தீயவும் நல்லவாம் செல்வம் செயற்கு.","en":"In making wealth fate changes mood;  The good as bad and bad as good","ch":"ஊழ்","chEn":"Fate","chNo":38,"sec":"Virtue"},
{"n":376,"id":"TK-0376","ta":"பரியினும் ஆகாவாம் பாலல்ல உய்த்துச் சொரியினும் போகா தம.","en":"Things not thine never remain  Things destined are surely thine","ch":"ஊழ்","chEn":"Fate","chNo":38,"sec":"Virtue"},
{"n":377,"id":"TK-0377","ta":"வகுத்தான் வகுத்த வகையல்லால் கோடி தொகுத்தார்க்கு துய்த்தல் அரிது.","en":"Who crores amass enjoy but what  The Dispenser's decrees allot","ch":"ஊழ்","chEn":"Fate","chNo":38,"sec":"Virtue"},
{"n":378,"id":"TK-0378","ta":"துறப்பார்மன் துப்புர வில்லார் உறற்பால ஊட்டா கழியு மெனின்.","en":"The destitute desire will quit  If fate with ills visit them not","ch":"ஊழ்","chEn":"Fate","chNo":38,"sec":"Virtue"},
{"n":379,"id":"TK-0379","ta":"நன்றாங்கால் நல்லவாக் காண்பவர் அன்றாங்கால் அல்லற் படுவ தெவன்?","en":"Who good in time of good perceive  In evil time why should they grieve?","ch":"ஊழ்","chEn":"Fate","chNo":38,"sec":"Virtue"},
{"n":380,"id":"TK-0380","ta":"ஊழிற் பெருவலி யாவுள மற்றொன்று சூழினுந் தான்முந் துறும்.","en":"What power surpasses fate? Its will  Persists against the human skill","ch":"ஊழ்","chEn":"Fate","chNo":38,"sec":"Virtue"},
{"n":381,"id":"TK-0381","ta":"படைகுடி கூழ்அமைச்சு நட்பரண் ஆறும் உடையான் அரசருள் ஏறு.","en":"People, troops, wealth, forts, council, friends  Who owns these six is lion of kings","ch":"இறைமாட்சி","chEn":"The Greatness of a King","chNo":39,"sec":"Wealth"},
{"n":382,"id":"TK-0382","ta":"அஞ்சாமை ஈகை அறிவூக்கம் இந்நான்கும் எஞ்சாமை வேந்தர்க் கியல்பு.","en":"Courage, giving, knowledge and zeal  Are four failless features royal","ch":"இறைமாட்சி","chEn":"The Greatness of a King","chNo":39,"sec":"Wealth"},
{"n":383,"id":"TK-0383","ta":"தூங்காமை கல்வி துணிவுடைமை இம்மூன்றும் நீங்கா நிலனான் பவர்க்கு.","en":"Alertness, learning bravery  Are adjuncts three of monarchy","ch":"இறைமாட்சி","chEn":"The Greatness of a King","chNo":39,"sec":"Wealth"},
{"n":384,"id":"TK-0384","ta":"அறனிழுக்கா தல்லவை நீக்கி மறனிழுக்கா மானம் உடைய தரசு.","en":"A brave noble king refrains from vice  Full of virtue and enterprise","ch":"இறைமாட்சி","chEn":"The Greatness of a King","chNo":39,"sec":"Wealth"},
{"n":385,"id":"TK-0385","ta":"இயற்றலும் ஈட்டலுங் காத்தலும் காத்த வகுத்தலும் வல்ல தரசு.","en":"The able king gets, stores and guards  And spends them for people's safeguards","ch":"இறைமாட்சி","chEn":"The Greatness of a King","chNo":39,"sec":"Wealth"},
{"n":386,"id":"TK-0386","ta":"காட்சிக் கெளியன் கடுஞ்சொல்லன் அல்லனேல் மீக்கூறும் மன்னன் நிலம்","en":"That land prospers where the king is  Easy to see, not harsh of words","ch":"இறைமாட்சி","chEn":"The Greatness of a King","chNo":39,"sec":"Wealth"},
{"n":387,"id":"TK-0387","ta":"இன்சொலால் ஈத்தளிக்க வல்லார்க்குத் தன்சொலால் தான்கண் டனைத்திவ் வுலகு.","en":"The world commends and acts his phrase  Who sweetly speaks and gives with grace","ch":"இறைமாட்சி","chEn":"The Greatness of a King","chNo":39,"sec":"Wealth"},
{"n":388,"id":"TK-0388","ta":"முறைசெய்து காப்பாற்றும் மன்னவன் மக்கட்கு இறையென்று வைக்கப் படும்.","en":"He is the Lord of men who does  Sound justice and saves his race","ch":"இறைமாட்சி","chEn":"The Greatness of a King","chNo":39,"sec":"Wealth"},
{"n":389,"id":"TK-0389","ta":"செவிகைப்பச் சொற்பொறுக்கும் பண்புடை வேந்தன் கவிகைக்கீழ்த் தங்கும் உலகு.","en":"Under his shelter thrives the world  Who bears remarks bitter and bold","ch":"இறைமாட்சி","chEn":"The Greatness of a King","chNo":39,"sec":"Wealth"},
{"n":390,"id":"TK-0390","ta":"கொடையளி செங்கோல் குடியோம்பல் நான்கும் உடையானாம் வேந்தர்க் கொளி.","en":"He is the Light of Kings who has  Bounty, justice, care and grace","ch":"இறைமாட்சி","chEn":"The Greatness of a King","chNo":39,"sec":"Wealth"},
{"n":391,"id":"TK-0391","ta":"கற்க கசடறக் கற்பவை கற்றபின் நிற்க அதற்குத் தக.","en":"Lore worth learning, learn flawlessly  Live by that learning thoroughly","ch":"கல்வி","chEn":"Learning","chNo":40,"sec":"Wealth"},
{"n":392,"id":"TK-0392","ta":"எண்ணென்ப ஏனை எழுத்தென்ப இவ்விரண்டும் கண்ணென்ப வாழும் உயிர்க்கு.","en":"Letter, number, art and science  Of living kind both are the eyes","ch":"கல்வி","chEn":"Learning","chNo":40,"sec":"Wealth"},
{"n":393,"id":"TK-0393","ta":"கண்ணுடையர் என்பவர் கற்றோர் முகத்திரண்டு புண்ணுடையர் கல்லா தவர்.","en":"The learned alone have eyes on face  The ignorant two sores of disgrace","ch":"கல்வி","chEn":"Learning","chNo":40,"sec":"Wealth"},
{"n":394,"id":"TK-0394","ta":"உவப்பத் தலைக்கூடி உள்ளப் பிரிதல் அனைத்தே புலவர் தொழில்.","en":"To meet with joy and part with thought  Of learned men this is the art","ch":"கல்வி","chEn":"Learning","chNo":40,"sec":"Wealth"},
{"n":395,"id":"TK-0395","ta":"உடையார்முன் இல்லார்போல் ஏக்கற்றுங் கற்றார் கடையரே கல்லா தவர்.","en":"Like poor before rich they yearn:  For knowledge: the low never learn","ch":"கல்வி","chEn":"Learning","chNo":40,"sec":"Wealth"},
{"n":396,"id":"TK-0396","ta":"தொட்டனைத் தூறும் மணற்கேணி மாந்தர்க்குக் கற்றனைத் தூறும் அறிவு.","en":"As deep you dig the sand spring flows  As deep you learn the knowledge grows","ch":"கல்வி","chEn":"Learning","chNo":40,"sec":"Wealth"},
{"n":397,"id":"TK-0397","ta":"யாதானும் நாடாமால் ஊராமால் என்னொருவன் சாந்துணையுங் கல்லாத வாறு.","en":"All lands and towns are learner's own  Why not till death learning go on!","ch":"கல்வி","chEn":"Learning","chNo":40,"sec":"Wealth"},
{"n":398,"id":"TK-0398","ta":"ஒருமைக்கண் தான்கற்ற கல்வி ஒருவற்கு எழுமையும் ஏமாப் புடைத்து.","en":"The joy of learning in one birth  Exalts man upto his seventh","ch":"கல்வி","chEn":"Learning","chNo":40,"sec":"Wealth"},
{"n":399,"id":"TK-0399","ta":"தாமின் புறுவது உலகின் புறக்கண்டு காமுறுவர் கற்றறிந் தார்.","en":"The learned foster learning more  On seeing the world enjoy their lore","ch":"கல்வி","chEn":"Learning","chNo":40,"sec":"Wealth"},
{"n":400,"id":"TK-0400","ta":"கேடில் விழுச்செல்வம் கல்வி யொருவற்கு மாடல்ல மற்றை யவை.","en":"Learning is wealth none could destroy  Nothing else gives genuine joy","ch":"கல்வி","chEn":"Learning","chNo":40,"sec":"Wealth"},
{"n":401,"id":"TK-0401","ta":"அரங்கின்றி வட்டாடி யற்றே நிரம்பிய நூலின்றிக் கோட்டி கொளல்.","en":"Like play of chess on squareless board  Vain is imperfect loreless word","ch":"கல்லாமை","chEn":"Ignorance","chNo":41,"sec":"Wealth"},
{"n":402,"id":"TK-0402","ta":"கல்லாதான் சொற்கா முறுதல் முலையிரண்டும் இல்லாதாள் பெண்காமுற் றற்று.","en":"Unlearned man aspiring speech  Is breastless lady's love-approach","ch":"கல்லாமை","chEn":"Ignorance","chNo":41,"sec":"Wealth"},
{"n":403,"id":"TK-0403","ta":"கல்லா தவரும் நனிநல்லர் கற்றார்முன் சொல்லா திருக்கப் பெறின்.","en":"Ev'n unread men are good and wise  If before the wise, they hold their peace","ch":"கல்லாமை","chEn":"Ignorance","chNo":41,"sec":"Wealth"},
{"n":404,"id":"TK-0404","ta":"கல்லாதான் ஒட்பம் கழியநன் றாயினும் கொள்ளார் அறிவுடை யார்.","en":"The unread's wit though excellent  Is not valued by the savant","ch":"கல்லாமை","chEn":"Ignorance","chNo":41,"sec":"Wealth"},
{"n":405,"id":"TK-0405","ta":"கல்லா ஒருவன் தகைமை தலைப்பெய்து சொல்லாடச் சோர்வு படும்.","en":"A man untaught when speech he vaunts  Sadly fails before savants","ch":"கல்லாமை","chEn":"Ignorance","chNo":41,"sec":"Wealth"},
{"n":406,"id":"TK-0406","ta":"உளரென்னும் மாத்திரையர் அல்லால் பயவாக் களரனையர் கல்லா தவர்.","en":"People speak of untaught minds  \\\"They just exist like barren lands\\\"","ch":"கல்லாமை","chEn":"Ignorance","chNo":41,"sec":"Wealth"},
{"n":407,"id":"TK-0407","ta":"நுண்மாண் நுழைபுலம் இல்லான் எழில்நலம் மண்மாண் புனைபாவை யற்று.","en":"Like painted clay-doll is his show  Grand subtle lore who fails to know","ch":"கல்லாமை","chEn":"Ignorance","chNo":41,"sec":"Wealth"},
{"n":408,"id":"TK-0408","ta":"நல்லார்கண் பட்ட வறுமையின் இன்னாதே கல்லார்கண் பட் ட திரு.","en":"Wealth in the hand of fools is worse  Than a learned man's empty purse","ch":"கல்லாமை","chEn":"Ignorance","chNo":41,"sec":"Wealth"},
{"n":409,"id":"TK-0409","ta":"மேற்பிறந்தா ராயினும் கல்லாதார் கீழ்ப்பிறந்தும் கற்றார் அனைத்திலர் பாடு.","en":"Lower are fools of higher birth  Than low-born men of learning's worth","ch":"கல்லாமை","chEn":"Ignorance","chNo":41,"sec":"Wealth"},
{"n":410,"id":"TK-0410","ta":"விலங்கொடு மக்கள் அனையர் இலங்குநூல் கற்றாரோடு ஏனை யவர்.","en":"Like beasts before men, dunces are  Before scholars of shining lore","ch":"கல்லாமை","chEn":"Ignorance","chNo":41,"sec":"Wealth"},
{"n":411,"id":"TK-0411","ta":"செல்வத்துட் செல்வஞ் செவிச்செல்வம் அச்செல்வம் செல்வத்து ளெல்லாந் தலை.","en":"Wealth of wealths is listening's wealth  It is the best of wealths on earth","ch":"கேள்வி","chEn":"Hearing","chNo":42,"sec":"Wealth"},
{"n":412,"id":"TK-0412","ta":"செவுக்குண வில்லாத போழ்து சிறிது வயிற்றுக்கும் ஈயப் படும்.","en":"Some food for the stomach is brought  When the ear gets no food for thought","ch":"கேள்வி","chEn":"Hearing","chNo":42,"sec":"Wealth"},
{"n":413,"id":"TK-0413","ta":"செவியுணவிற் கேள்வி யுடையார் அவியுணவின் ஆன்றாரோ டொப்பர் நிலத்து.","en":"Whose ears get lots of wisdom-food  Equal gods on oblations fed","ch":"கேள்வி","chEn":"Hearing","chNo":42,"sec":"Wealth"},
{"n":414,"id":"TK-0414","ta":"கற்றில னாயினுங் கேட்க அஃதொருவற்கு ஒற்கத்தின் ஊற்றாந் துணை.","en":"Though not learned, hear and heed  That serves a staff and stay in need","ch":"கேள்வி","chEn":"Hearing","chNo":42,"sec":"Wealth"},
{"n":415,"id":"TK-0415","ta":"இழுக்கல் உடையுழி ஊற்றுக்கோல் அற்றே ஒழுக்க முடையார்வாய்ச் சொல்.","en":"Virtuous men's wisdom is found  A strong staff on slippery ground","ch":"கேள்வி","chEn":"Hearing","chNo":42,"sec":"Wealth"},
{"n":416,"id":"TK-0416","ta":"எனைத்தானும் நல்லவை கேட்க அனைத்தானும் ஆன்ற பெருமை தரும்.","en":"Lend ear to good words however few  That much will highly exalt you","ch":"கேள்வி","chEn":"Hearing","chNo":42,"sec":"Wealth"},
{"n":417,"id":"TK-0417","ta":"பிழைத்துணர்ந்தும் பேதைமை சொல்லா ரிழைத்துணர்ந் தீண்டிய கேள்வி யவர்.","en":"Who listen well and learn sharply  Not ev'n by slip speak foolishly","ch":"கேள்வி","chEn":"Hearing","chNo":42,"sec":"Wealth"},
{"n":418,"id":"TK-0418","ta":"கேட்பினுங் கேளாத் தகையவே கேள்வியால் தோட்கப் படாத செவி.","en":"That ear though hearing is dulled  Which is not by wisdom drilled","ch":"கேள்வி","chEn":"Hearing","chNo":42,"sec":"Wealth"},
{"n":419,"id":"TK-0419","ta":"நுணங்கிய கேள்விய ரல்லார் வணங்கிய வாயின ராதல் அரிது.","en":"A modest mouth is hard for those  Who care little to counsels wise","ch":"கேள்வி","chEn":"Hearing","chNo":42,"sec":"Wealth"},
{"n":420,"id":"TK-0420","ta":"செவியிற் சுவையுணரா வாயுணர்வின் மாக்கள் அவியினும் வாழினும் என்?","en":"Who taste by mouth and not by ear  What if they fare ill or well here?","ch":"கேள்வி","chEn":"Hearing","chNo":42,"sec":"Wealth"},
{"n":421,"id":"TK-0421","ta":"அறிவற்றங் காக்குங் கருவி செறுவார்க்கும் உள்ளழிக்க லாகா அரண்.","en":"Wisdom's weapon wards off all woes  It is a fort defying foes","ch":"அறிவுடைமை","chEn":"The Possession of Knowledge","chNo":43,"sec":"Wealth"},
{"n":422,"id":"TK-0422","ta":"சென்ற இடத்தால் செலவிடா தீதொரீஇ நன்றின்பால் உய்ப்ப தறிவு.","en":"Wisdom checks the straying senses  Expels evils, impels goodness","ch":"அறிவுடைமை","chEn":"The Possession of Knowledge","chNo":43,"sec":"Wealth"},
{"n":423,"id":"TK-0423","ta":"எப்பொருள் யார்யார்வாய்க் கேட்பினும் அப்பொருள் மெய்ப்பொருள் காண்ப தறிவு.","en":"To grasp the Truth from everywhere  From everyone is wisdom fair","ch":"அறிவுடைமை","chEn":"The Possession of Knowledge","chNo":43,"sec":"Wealth"},
{"n":424,"id":"TK-0424","ta":"எண்பொருள வாகச் செலச்சொல்லித் தான்பிறர்வாய் நுண்பொருள் காண்ப தறிவு.","en":"Speaking out thoughts in clear trends  Wisdom subtle sense comprehends","ch":"அறிவுடைமை","chEn":"The Possession of Knowledge","chNo":43,"sec":"Wealth"},
{"n":425,"id":"TK-0425","ta":"உலகம் தழீஇய தொட்பம் மலர்தலும் கூம்பலும் இல்ல தறிவு.","en":"The wise-world the wise befriend  They bloom nor gloom, equal in mind","ch":"அறிவுடைமை","chEn":"The Possession of Knowledge","chNo":43,"sec":"Wealth"},
{"n":426,"id":"TK-0426","ta":"எவ்வ துறைவது உலகம் உலகத்தோடு அவ்வ துறைவ தறிவு.","en":"As moves the world so move the wise  In tune with changing times and ways","ch":"அறிவுடைமை","chEn":"The Possession of Knowledge","chNo":43,"sec":"Wealth"},
{"n":427,"id":"TK-0427","ta":"அறிவுடையார் ஆவ தறிவார் அறிவிலார் அஃதறி கல்லா தவர்.","en":"The wise foresee what is to come  The unwise lack in that wisdom","ch":"அறிவுடைமை","chEn":"The Possession of Knowledge","chNo":43,"sec":"Wealth"},
{"n":428,"id":"TK-0428","ta":"அஞ்சுவ தஞ்சாமை பேதைமை அஞ்சுவது அஞ்சல் அறிவார் தொழில்.","en":"Fear the frightful and act wisely  Not to fear the frightful's folly","ch":"அறிவுடைமை","chEn":"The Possession of Knowledge","chNo":43,"sec":"Wealth"},
{"n":429,"id":"TK-0429","ta":"எதிரதாக் காக்கும் அறிவினார்க் கில்லை அதிர வருவதோர் நோய்.","en":"No frightful evil shocks the wise  Who guard themselves against surprise","ch":"அறிவுடைமை","chEn":"The Possession of Knowledge","chNo":43,"sec":"Wealth"},
{"n":430,"id":"TK-0430","ta":"அறிவுடையார் எல்லா முடையார் அறிவிலார் என்னுடைய ரேனும் இலர்.","en":"Who have wisdom they are all full  Whatev'r they own, misfits are nil","ch":"அறிவுடைமை","chEn":"The Possession of Knowledge","chNo":43,"sec":"Wealth"},
{"n":431,"id":"TK-0431","ta":"செருக்குஞ் சினமும் சிறுமையும் இல்லார் பெருக்கம் பெருமித நீர்த்து.","en":"Plenty is their prosperity  Who're free from wrath pride lust petty","ch":"குற்றங்கடிதல்","chEn":"The Correction of Faults","chNo":44,"sec":"Wealth"},
{"n":432,"id":"TK-0432","ta":"இவறலும் மாண்பிறந்த மானமும் மாணா உவகையும் ஏதம் இறைக்கு.","en":"Mean pride, low pleasure, avarice  These add blemishes to a prince","ch":"குற்றங்கடிதல்","chEn":"The Correction of Faults","chNo":44,"sec":"Wealth"},
{"n":433,"id":"TK-0433","ta":"தினைத்துணையாங் குற்றம் வரினும் பனைத்துணையாக் கொள்வர் பழிநாணு வார்.","en":"Though millet-small their faults might seem  Men fearing disgrace, Palm-tall deem","ch":"குற்றங்கடிதல்","chEn":"The Correction of Faults","chNo":44,"sec":"Wealth"},
{"n":434,"id":"TK-0434","ta":"குற்றமே காக்க பொருளாகக் குற்றமே அற்றந் த்ரூஉம் பகை.","en":"Watch like treasure freedom from fault  Our fatal foe is that default","ch":"குற்றங்கடிதல்","chEn":"The Correction of Faults","chNo":44,"sec":"Wealth"},
{"n":435,"id":"TK-0435","ta":"வருமுன்னர்க் காவாதான் வாழ்க்கை எரிமுன்னர் வைத்தூறு போலக் கெடும்.","en":"Who fails to guard himself from flaw  Loses his life like flame-lit straw","ch":"குற்றங்கடிதல்","chEn":"The Correction of Faults","chNo":44,"sec":"Wealth"},
{"n":436,"id":"TK-0436","ta":"தன்குற்றம் நீக்கிப் பிறர்குற்றங் காண்கிற்பின் என்குற்ற மாகும் இறைக்கு?","en":"What fault can be the king's who cures  First his faults, then scans others","ch":"குற்றங்கடிதல்","chEn":"The Correction of Faults","chNo":44,"sec":"Wealth"},
{"n":437,"id":"TK-0437","ta":"செயற்பால செய்யா திவறியான் செல்வம் உயற்பால தன்றிக் கெடும்.","en":"That miser's wealth shall waste and end  Who would not for a good cause spend","ch":"குற்றங்கடிதல்","chEn":"The Correction of Faults","chNo":44,"sec":"Wealth"},
{"n":438,"id":"TK-0438","ta":"பற்றுள்ளம் என்னும் இவறன்மை எற்றுள்ளும் எண்ணப் படுவதொன் றன்று.","en":"The gripping greed of miser's heart  Is more than fault the worst apart","ch":"குற்றங்கடிதல்","chEn":"The Correction of Faults","chNo":44,"sec":"Wealth"},
{"n":439,"id":"TK-0439","ta":"வியவற்க எஞ்ஞான்றும் தன்னை நயவற்க நன்றி பயவா வினை.","en":"Never boast yourself in any mood  Nor do a deed that does no good","ch":"குற்றங்கடிதல்","chEn":"The Correction of Faults","chNo":44,"sec":"Wealth"},
{"n":440,"id":"TK-0440","ta":"காதல காதல் அறியாமை உய்க்கிற்பின் ஏதில ஏதிலார் நூல்.","en":"All designs of the foes shall fail  If one his wishes guards in veil","ch":"குற்றங்கடிதல்","chEn":"The Correction of Faults","chNo":44,"sec":"Wealth"},
{"n":441,"id":"TK-0441","ta":"அறனறிந்து மூத்த அறிவுடையார் கேண்மை திறனறிந்து தேர்ந்து கொளல்.","en":"Weigh their worth and friendship gain  Of men of virtue and mature brain","ch":"பெரியாரைத் துணைக்கோடல்","chEn":"Seeking the Aid of Great Men","chNo":45,"sec":"Wealth"},
{"n":442,"id":"TK-0442","ta":"உற்றநோய் நீக்கி உறாஅமை முற்காக்கும் பெற்றியார்ப் பேணிக் கொளல்.","en":"Cherish the help of men of skill  Who ward and safe-guard you from ill","ch":"பெரியாரைத் துணைக்கோடல்","chEn":"Seeking the Aid of Great Men","chNo":45,"sec":"Wealth"},
{"n":443,"id":"TK-0443","ta":"அரியவற்று ளெல்லாம் அரிதே பெரியாரைப் பேணித் தமராக் கொளல்.","en":"Honour and have the great your own  Is rarest of the rare things known","ch":"பெரியாரைத் துணைக்கோடல்","chEn":"Seeking the Aid of Great Men","chNo":45,"sec":"Wealth"},
{"n":444,"id":"TK-0444","ta":"தம்மிற் பெரியார் தமரா ஒழுகுதல் வன்மையு ளெல்லாந் தலை.","en":"To have betters as intimates  Power of all powers promotes","ch":"பெரியாரைத் துணைக்கோடல்","chEn":"Seeking the Aid of Great Men","chNo":45,"sec":"Wealth"},
{"n":445,"id":"TK-0445","ta":"சூழ்வார்கண் ணாக ஒழுகலான் மன்னவன் சூழ்வாரைக் சூழ்ந்து கொளல்.","en":"Ministers are the monarch's eyes  Round him should be the right and wise","ch":"பெரியாரைத் துணைக்கோடல்","chEn":"Seeking the Aid of Great Men","chNo":45,"sec":"Wealth"},
{"n":446,"id":"TK-0446","ta":"தக்கா ரினத்தனாய்த் தானொழுக வல்லானைச் செற்றார் செயக்கிடந்த தில்.","en":"To move with worthy friends who knows  Has none to fear from frightful foes","ch":"பெரியாரைத் துணைக்கோடல்","chEn":"Seeking the Aid of Great Men","chNo":45,"sec":"Wealth"},
{"n":447,"id":"TK-0447","ta":"இடிக்குந் துணையாரை யாள்வரை யாரே கெடுக்குந் தகைமை யவர்.","en":"No foe can foil his powers  whose friends reprove him when he errs","ch":"பெரியாரைத் துணைக்கோடல்","chEn":"Seeking the Aid of Great Men","chNo":45,"sec":"Wealth"},
{"n":448,"id":"TK-0448","ta":"இடிப்பாரை இல்லாத ஏமரா மன்னன் கெடுப்பா ரிலானுங் கெடும்.","en":"The careless king whom none reproves  Ruins himself sans harmful foes","ch":"பெரியாரைத் துணைக்கோடல்","chEn":"Seeking the Aid of Great Men","chNo":45,"sec":"Wealth"},
{"n":449,"id":"TK-0449","ta":"முதலிலார்க ஊதிய மில்லை மதலையாஞ் சார்பிலார்க் கில்லை நிலை.","en":"No capital, no gain in trade  No prop secure sans good comrade","ch":"பெரியாரைத் துணைக்கோடல்","chEn":"Seeking the Aid of Great Men","chNo":45,"sec":"Wealth"},
{"n":450,"id":"TK-0450","ta":"பல்லார் பகைகொளலிற் பத்தடுத்த தீமைத்தே நல்லார் தொடர்கை விடல்.","en":"To give up good friends is ten times worse  Than being hated by countless foes","ch":"பெரியாரைத் துணைக்கோடல்","chEn":"Seeking the Aid of Great Men","chNo":45,"sec":"Wealth"},
{"n":451,"id":"TK-0451","ta":"சிற்றினம் அஞ்சும் பெருமை சிறுமைதான் சுற்றமாச் சூழ்ந்து விடும்.","en":"The ignoble the noble fear  The mean hold them as kinsmen dear","ch":"சிற்றினம் சேராமை","chEn":"Avoiding mean Associations","chNo":46,"sec":"Wealth"},
{"n":452,"id":"TK-0452","ta":"நிலத்தியல்பால் நீர்திரிந் தற்றாகும் மாந்தர்க்கு இனத்தியல்ப தாகும் அறிவு.","en":"With soil changes water's taste  With mates changes the mental state","ch":"சிற்றினம் சேராமை","chEn":"Avoiding mean Associations","chNo":46,"sec":"Wealth"},
{"n":453,"id":"TK-0453","ta":"மனத்தானாம் மாந்தர்க் குணர்ச்சி இனத்தானாம் இன்னான் எனப்படுஞ் சொல்.","en":"Wisdom depends upon the mind  The worth of man upon his friend","ch":"சிற்றினம் சேராமை","chEn":"Avoiding mean Associations","chNo":46,"sec":"Wealth"},
{"n":454,"id":"TK-0454","ta":"மனத்து ளதுபோலக் காட்டி ஒருவற்கு இனத்துள தாகும் அறிவு.","en":"Wisdom seems to come from mind  But it truly flows from the kind","ch":"சிற்றினம் சேராமை","chEn":"Avoiding mean Associations","chNo":46,"sec":"Wealth"},
{"n":455,"id":"TK-0455","ta":"மனந்தூய்மை செய்வினை தூய்மை இரண்டும் இனந்தூய்மை தூவா வரும்.","en":"Purity of the thought and deed  Comes from good company indeed","ch":"சிற்றினம் சேராமை","chEn":"Avoiding mean Associations","chNo":46,"sec":"Wealth"},
{"n":456,"id":"TK-0456","ta":"மனந்தூயார்க் கெச்சம்நன் றாகும் இனந்தூயார்க்கு இல்லைநன் றாகா வினை.","en":"Pure-hearted get good progeny  Pure friendship acts with victory","ch":"சிற்றினம் சேராமை","chEn":"Avoiding mean Associations","chNo":46,"sec":"Wealth"},
{"n":457,"id":"TK-0457","ta":"மனநலம் மன்னுயிர்க் காக்கம் இனநலம் எல்லாப் புகழும் தரும்.","en":"Goodness of mind increases gain  Good friendship fosters fame again","ch":"சிற்றினம் சேராமை","chEn":"Avoiding mean Associations","chNo":46,"sec":"Wealth"},
{"n":458,"id":"TK-0458","ta":"மனநலம் நன்குடைய ராயினும் சான்றோர்க்கு இனநலம் ஏமாப் புடைத்து.","en":"Men of wisdom, though good in mind  In friends of worth a new strength find","ch":"சிற்றினம் சேராமை","chEn":"Avoiding mean Associations","chNo":46,"sec":"Wealth"},
{"n":459,"id":"TK-0459","ta":"மனநலத்தின் ஆகும் மறுமைமற் றஃதும் இனநலத்தின் ஏமாப் புடைத்து.","en":"Good mind decides the future bliss  Good company gains strength to this","ch":"சிற்றினம் சேராமை","chEn":"Avoiding mean Associations","chNo":46,"sec":"Wealth"},
{"n":460,"id":"TK-0460","ta":"நல்லினத்தி னூங்குந் துணையில்லை தீயினத்தின் அல்லற் படுப்பதூஉம் இல்.","en":"No help good company exeeds;  The bad to untold anguish leads","ch":"சிற்றினம் சேராமை","chEn":"Avoiding mean Associations","chNo":46,"sec":"Wealth"},
{"n":461,"id":"TK-0461","ta":"அழிவதூஉம் ஆவதூஉம் ஆகி வழிபயக்கும் ஊதியமும் சூழ்ந்து செயல்.","en":"Weigh well output the loss and gain  And proper action ascertain","ch":"தெரிந்து செயல்வகை","chEn":"Acting after due Consideration","chNo":47,"sec":"Wealth"},
{"n":462,"id":"TK-0462","ta":"தெரிந்த இனத்தொடு தேர்ந்தெண்ணிச் செய்வார்க்கு அரும்பொருள் யாதொன்றும் இல்","en":"Nothing is hard for him who acts  With worthy counsels weighing facts","ch":"தெரிந்து செயல்வகை","chEn":"Acting after due Consideration","chNo":47,"sec":"Wealth"},
{"n":463,"id":"TK-0463","ta":"ஆக்கம் கருதி முதலிழக்கும் செய்வினை ஊக்கார் அறிவுடை யார்.","en":"The wise risk not their capital  In doubtful gains and lose their all","ch":"தெரிந்து செயல்வகை","chEn":"Acting after due Consideration","chNo":47,"sec":"Wealth"},
{"n":464,"id":"TK-0464","ta":"தெளிவி லதனைத் தொடங்கார் இளிவென்னும் ஏதப்பாடு அஞ்சு பவர்.","en":"They who scornful reproach fear  Commence no work not made clear","ch":"தெரிந்து செயல்வகை","chEn":"Acting after due Consideration","chNo":47,"sec":"Wealth"},
{"n":465,"id":"TK-0465","ta":"வகையறச் சூழா தெழுதல் பகைவரைப் பாத்திப் படுப்பதோ ராறு.","en":"Who marches without plans and ways  His field is sure to foster foes","ch":"தெரிந்து செயல்வகை","chEn":"Acting after due Consideration","chNo":47,"sec":"Wealth"},
{"n":466,"id":"TK-0466","ta":"செய்தக்க அல்ல செயக்கெடும் செய்தக்க செய்யாமை யானுங் கெடும்.","en":"Doing unfit action ruins Failing fit-act also ruins","ch":"தெரிந்து செயல்வகை","chEn":"Acting after due Consideration","chNo":47,"sec":"Wealth"},
{"n":467,"id":"TK-0467","ta":"எண்ணித் துணிக கருமம் துணிந்தபின் எண்ணுவம் என்பது இழுக்கு.","en":"Think and dare a proper deed  Dare and think is bad in need","ch":"தெரிந்து செயல்வகை","chEn":"Acting after due Consideration","chNo":47,"sec":"Wealth"},
{"n":468,"id":"TK-0468","ta":"ஆற்றின் வருந்தா வருத்தம் பலர்நின்று போற்றினும் பொத்துப் படும்.","en":"Toil without a plan ahead Is doomed to fall though supported","ch":"தெரிந்து செயல்வகை","chEn":"Acting after due Consideration","chNo":47,"sec":"Wealth"},
{"n":469,"id":"TK-0469","ta":"நன்றாற்ற லுள்ளுந் தவுறுண்டு அவரவர் பண்பறிந் தாற்றாக் கடை.","en":"Attune the deeds to habitude Or ev'n good leads to evil feud","ch":"தெரிந்து செயல்வகை","chEn":"Acting after due Consideration","chNo":47,"sec":"Wealth"},
{"n":470,"id":"TK-0470","ta":"எள்ளாத எண்ணிச் செயல்வேண்டும் தம்மோடு கொள்ளாத கொள்ளாது உலகு.","en":"Do deeds above reproachfulness The world refutes uncomely mess","ch":"தெரிந்து செயல்வகை","chEn":"Acting after due Consideration","chNo":47,"sec":"Wealth"},
{"n":471,"id":"TK-0471","ta":"வினைவலியும் தன்வலியும் மாற்றான் வலியும் துணைவலியும் தூக்கிச் செயல்.","en":"Judge act and might and foeman's strength The allies' strength and go at length","ch":"வலியறிதல்","chEn":"The Knowledge of Power","chNo":48,"sec":"Wealth"},
{"n":472,"id":"TK-0472","ta":"ஒல்வ தறிவது அறிந்ததன் கண்தங்கிச் செல்வார்க்குச் செல்லாதது இல்.","en":"Nothing hampers the firm who know What they can and how to go","ch":"வலியறிதல்","chEn":"The Knowledge of Power","chNo":48,"sec":"Wealth"},
{"n":473,"id":"TK-0473","ta":"உடைத்தம் வலியறியார் ஊக்கத்தின் ஊக்கி இடைக்கண் முரிந்தார் பலர்.","en":"Many know not their meagre might Their pride breaks up in boastful fight","ch":"வலியறிதல்","chEn":"The Knowledge of Power","chNo":48,"sec":"Wealth"},
{"n":474,"id":"TK-0474","ta":"அமைந்தாங் கொழுகான் அளவறியான் தன்னை வியந்தான் விரைந்து கெடும்.","en":"Who adapts not, outsteps measure And brags himself-his fall is sure","ch":"வலியறிதல்","chEn":"The Knowledge of Power","chNo":48,"sec":"Wealth"},
{"n":475,"id":"TK-0475","ta":"பீலிபெய் சாகாடும் அச்சிறும் அப்பண்டஞ் சால மிகுத்துப் பெயின்.","en":"Even the gentle peacock's plume Cart's axle breaks by gross volume","ch":"வலியறிதல்","chEn":"The Knowledge of Power","chNo":48,"sec":"Wealth"},
{"n":476,"id":"TK-0476","ta":"நுனிக்கொம்பர் ஏறினார் அஃதிறந் தூக்கின் உயிர்க்கிறுதி ஆகி விடும்.","en":"Beyond the branches' tip who skips Ends the life as his body rips","ch":"வலியறிதல்","chEn":"The Knowledge of Power","chNo":48,"sec":"Wealth"},
{"n":477,"id":"TK-0477","ta":"ஆற்றின் அறவறிந்து ஈக அதுபொருள் போற்றி வழங்கு நெறி.","en":"Know the limit; grant with measure This way give and guard your treasure","ch":"வலியறிதல்","chEn":"The Knowledge of Power","chNo":48,"sec":"Wealth"},
{"n":478,"id":"TK-0478","ta":"ஆகாறு அளவிட்டி தாயினுங் கேடில்லை போகாறு அகலாக் கடை.","en":"The outflow must not be excess No matter how small income is","ch":"வலியறிதல்","chEn":"The Knowledge of Power","chNo":48,"sec":"Wealth"},
{"n":479,"id":"TK-0479","ta":"அளவறிந்து வாழாதான் வாழ்க்கை உளபோல இல்லாகித் தோன்றாக் கெடும்.","en":"Who does not know to live in bounds His life seems rich but thins and ends","ch":"வலியறிதல்","chEn":"The Knowledge of Power","chNo":48,"sec":"Wealth"},
{"n":480,"id":"TK-0480","ta":"உளவரை தூக்காத ஒப்புர வாண்மை வளவரை வல்லைக் கெடும்.","en":"Wealth amassed quickly vanishes Sans level if one lavishes","ch":"வலியறிதல்","chEn":"The Knowledge of Power","chNo":48,"sec":"Wealth"},
{"n":481,"id":"TK-0481","ta":"பகல்வெல்லும் கூகையைக் காக்கை இகல்வெல்லும் வேந்தர்க்கு வேண்டும் பொழுது.","en":"By day the crow defeats the owl Kings need right time their foes to quell","ch":"காலமறிதல்","chEn":"Knowing the fitting Time","chNo":49,"sec":"Wealth"},
{"n":482,"id":"TK-0482","ta":"பருவத்தோடு ஒட்ட ஒழுகல் திருவினைத் தீராமை ஆர்க்குங் கயிறு.","en":"Well-ordered seasoned act is cord That fortune binds in bon accord","ch":"காலமறிதல்","chEn":"Knowing the fitting Time","chNo":49,"sec":"Wealth"},
{"n":483,"id":"TK-0483","ta":"அருவினை யென்ப உளவோ கருவியான் காலம் அற஧ந்து செயின்.","en":"What is hard for him who acts With proper means and time and tacts?","ch":"காலமறிதல்","chEn":"Knowing the fitting Time","chNo":49,"sec":"Wealth"},
{"n":484,"id":"TK-0484","ta":"ஞாலம் கருதினுங் கைகூடுங் காலம் கருதி இடத்தாற் செயின்.","en":"Choose proper time and act and place Even the world you win with ease","ch":"காலமறிதல்","chEn":"Knowing the fitting Time","chNo":49,"sec":"Wealth"},
{"n":485,"id":"TK-0485","ta":"காலம் கருதி இருப்பர் கலங்காது ஞாலம் கருது பவர்.","en":"Who want to win the world sublime Wait unruffled biding their time","ch":"காலமறிதல்","chEn":"Knowing the fitting Time","chNo":49,"sec":"Wealth"},
{"n":486,"id":"TK-0486","ta":"ஊக்க முடையான் ஒடுக்கம் பொருதகர் தாக்கற்குப் பேருந் தகைத்து.","en":"By self-restraint stalwarts keep fit Like rams retreating but to butt","ch":"காலமறிதல்","chEn":"Knowing the fitting Time","chNo":49,"sec":"Wealth"},
{"n":487,"id":"TK-0487","ta":"பொள்ளென ஆங்கே புறம்வேரார் காலம்பார்த்து உள்வேர்ப்பர் ஒள்ளி யவர்.","en":"The wise jut not their vital fire They watch their time with hidden ire","ch":"காலமறிதல்","chEn":"Knowing the fitting Time","chNo":49,"sec":"Wealth"},
{"n":488,"id":"TK-0488","ta":"செறுநரைக் காணின் சுமக்க இறுவரை காணின் கிழக்காம் தலை.","en":"Bear with hostiles when you meet them Fell down their head in fateful time","ch":"காலமறிதல்","chEn":"Knowing the fitting Time","chNo":49,"sec":"Wealth"},
{"n":489,"id":"TK-0489","ta":"எய்தற் கரியது இயைந்தக்கால் அந்நிலையே செய்தற் கரிய செயல்.","en":"When comes the season ripe and rare Dare and do hard things then and there","ch":"காலமறிதல்","chEn":"Knowing the fitting Time","chNo":49,"sec":"Wealth"},
{"n":490,"id":"TK-0490","ta":"கொக்கொக்க கூம்பும் பருவத்து மற்றதன் குத்தொக்க சீர்த்த இடத்து.","en":"In waiting time feign peace like stork In fighting time strike like its peck","ch":"காலமறிதல்","chEn":"Knowing the fitting Time","chNo":49,"sec":"Wealth"},
{"n":491,"id":"TK-0491","ta":"தொடங்கற்க எவ்வினையும் எள்ளற்க முற்றும் இடங்கண்ட பின்அல் லது.","en":"No action take, no foe despise Until you have surveyed the place","ch":"இடனறிதல்","chEn":"Knowing the Place","chNo":50,"sec":"Wealth"},
{"n":492,"id":"TK-0492","ta":"முரண்சேர்ந்த மொய்ம்பி னவர்க்கும் அரண்சேர்ந்தாம் ஆக்கம் பலவுந் தரும்.","en":"Many are gains of fortresses Ev'n to kings of power and prowess","ch":"இடனறிதல்","chEn":"Knowing the Place","chNo":50,"sec":"Wealth"},
{"n":493,"id":"TK-0493","ta":"ஆற்றாரும் ஆற்றி அடுப இடனறிந்து போற்றார்கண் போற்றிச் செயின்.","en":"Weaklings too withstand foe's offence In proper fields of strong defence","ch":"இடனறிதல்","chEn":"Knowing the Place","chNo":50,"sec":"Wealth"},
{"n":494,"id":"TK-0494","ta":"எண்ணியார் எண்ணம் இழப்பர் இடனறிந்து துன்னியார் துன்னிச் செயின்.","en":"If fighters fight in vantage field The plans of foes shall be baffled","ch":"இடனறிதல்","chEn":"Knowing the Place","chNo":50,"sec":"Wealth"},
{"n":495,"id":"TK-0495","ta":"நெடும்புனலுள் வெல்லும் முதலை அடும்புனலின் நீங்கின் அதனைப் பிற.","en":"In water crocodile prevails In land before others it fails","ch":"இடனறிதல்","chEn":"Knowing the Place","chNo":50,"sec":"Wealth"},
{"n":496,"id":"TK-0496","ta":"கடலோடா கால்வல் நெடுந்தேர் கடலோடும் நாவாயும் ஓடா நிலத்து.","en":"Sea-going ship goes not on shore Nor on sea the strong-wheeled car","ch":"இடனறிதல்","chEn":"Knowing the Place","chNo":50,"sec":"Wealth"},
{"n":497,"id":"TK-0497","ta":"அஞ்சாமை அல்லால் துணைவேண்டா எஞ்சாமை எண்ணி இடத்தால் செயின்.","en":"No aid but daring dash they need When field is chosen right for deed","ch":"இடனறிதல்","chEn":"Knowing the Place","chNo":50,"sec":"Wealth"},
{"n":498,"id":"TK-0498","ta":"சிறுபடையான் செல்லிடம் சேரின் உறுபடையான் ஊக்கம் அழிந்து விடும்.","en":"Though force is small, if place is right One quells a foe of well-armed might","ch":"இடனறிதல்","chEn":"Knowing the Place","chNo":50,"sec":"Wealth"},
{"n":499,"id":"TK-0499","ta":"சிறைநலனும் சீரும் இலரெனினும் மாந்தர் உறைநிலத்தோடு ஒட்டல் அரிது.","en":"To face a foe at home is vain Though fort and status are not fine","ch":"இடனறிதல்","chEn":"Knowing the Place","chNo":50,"sec":"Wealth"},
{"n":500,"id":"TK-0500","ta":"காலாழ் களரில் நரியடும் கண்ணஞ்சா வேலாள் முகத்த களிறு.","en":"A fox can kill a war tusker Fearless with feet in deep quagmire","ch":"இடனறிதல்","chEn":"Knowing the Place","chNo":50,"sec":"Wealth"},
{"n":501,"id":"TK-0501","ta":"அறம்பொருள் இன்பம் உயிரச்சம் நான்கின் திறந்தெரிந்து தேறப் படும்.","en":"Pleasure, gold, fear of life Virtue- Test by these four and trust the true","ch":"தெரிந்து தெளிதல்","chEn":"Selection and Confidence","chNo":51,"sec":"Wealth"},
{"n":502,"id":"TK-0502","ta":"குடிப்பிறந்து குற்றத்தின் நீங்கி வடுப்பரியும் நாணுடையான் சுட்டே தெளிவு.","en":"Spotless name of noble birth Shamed of stain-that choice is worth","ch":"தெரிந்து தெளிதல்","chEn":"Selection and Confidence","chNo":51,"sec":"Wealth"},
{"n":503,"id":"TK-0503","ta":"அரியகற்று ஆசற்றார் கண்ணும் தெரியுங்கால் இன்மை அரிதே வெளிறு.","en":"Though deep scholars of stainless sense Rare is freedom from ignorance","ch":"தெரிந்து தெளிதல்","chEn":"Selection and Confidence","chNo":51,"sec":"Wealth"},
{"n":504,"id":"TK-0504","ta":"குணம்நாடிக் குற்றமும் நாடி அவற்றுள் மிகைநாடி மிக்க கொளல்.","en":"Good and evil in man weigh well Judge him by virtues which prevail","ch":"தெரிந்து தெளிதல்","chEn":"Selection and Confidence","chNo":51,"sec":"Wealth"},
{"n":505,"id":"TK-0505","ta":"பெருமைக்கும் ஏனைச் சிறுமைக்கும் தத்தம் கருமமே கட்டளைக் கல்.","en":"By the touchstone of deeds is seen If any one is great or mean","ch":"தெரிந்து தெளிதல்","chEn":"Selection and Confidence","chNo":51,"sec":"Wealth"},
{"n":506,"id":"TK-0506","ta":"அற்றாரைத் தேறுதல் ஓம்புக மற்றவர் பற்றிலர் நாணார் பழி.","en":"Choose not those men without kinsmen Without affine or shame of sin","ch":"தெரிந்து தெளிதல்","chEn":"Selection and Confidence","chNo":51,"sec":"Wealth"},
{"n":507,"id":"TK-0507","ta":"காதன்மை கந்தா அறிவறியார்த் தேறுதல் பேதைமை எல்லாந் தரும்.","en":"On favour leaning fools you choose; Folly in all its forms ensues","ch":"தெரிந்து தெளிதல்","chEn":"Selection and Confidence","chNo":51,"sec":"Wealth"},
{"n":508,"id":"TK-0508","ta":"தேரான் பிறனைத் தெளிந்தான் வழிமுறை தீரா இடும்பை தரும்.","en":"To trust an untried stranger brings Endless troubles on all our kins","ch":"தெரிந்து தெளிதல்","chEn":"Selection and Confidence","chNo":51,"sec":"Wealth"},
{"n":509,"id":"TK-0509","ta":"தேறற்க யாரையும் தேராது தேர்ந்தபின் தேறுக தேறும் பொருள்.","en":"Trust not without testing and then Find proper work for trusted men","ch":"தெரிந்து தெளிதல்","chEn":"Selection and Confidence","chNo":51,"sec":"Wealth"},
{"n":510,"id":"TK-0510","ta":"தேரான் தெளிவும் தெளிந்தான்கண் ஐயுறவும் தீரா இடும்பை தரும்.","en":"Trust without test; The trusted doubt; Both entail troubles in and out","ch":"தெரிந்து தெளிதல்","chEn":"Selection and Confidence","chNo":51,"sec":"Wealth"},
{"n":511,"id":"TK-0511","ta":"நன்மையும் தீமையும் நாடி நலம்புரிந்த தன்மையான் ஆளப் படும்.","en":"Employ the wise who will discern The good and bad and do good turn","ch":"தெரிந்து வினையாடல்","chEn":"Selection and Employment","chNo":52,"sec":"Wealth"},
{"n":512,"id":"TK-0512","ta":"வாரி பெருக்கி வளம்படுத்து உற்றவை ஆராய்வான் செய்க வினை.","en":"Let him act who resource swells; Fosters wealth and prevents ills","ch":"தெரிந்து வினையாடல்","chEn":"Selection and Employment","chNo":52,"sec":"Wealth"},
{"n":513,"id":"TK-0513","ta":"அன்பறிவு தேற்றம் அவாவின்மை இந்நான்கும் நன்குடையான் கட்டே தெளிவு.","en":"Trust him in whom these four you see: Love, wit, non-craving, clarity","ch":"தெரிந்து வினையாடல்","chEn":"Selection and Employment","chNo":52,"sec":"Wealth"},
{"n":514,"id":"TK-0514","ta":"எனைவகையான் தேறியக் கண்ணும் வினைவகையான் வேறாகும் மாந்தர் பலர்.","en":"Though tried and found fit, yet we see Many differ before duty","ch":"தெரிந்து வினையாடல்","chEn":"Selection and Employment","chNo":52,"sec":"Wealth"},
{"n":515,"id":"TK-0515","ta":"அறிந்தாற்றிச் செய்கிற்பாற்கு அல்லால் வினைதான் சிறந்தானென்று ஏவற்பாற் றன்று.","en":"Wise able men with power invest Not by fondness but by hard test","ch":"தெரிந்து வினையாடல்","chEn":"Selection and Employment","chNo":52,"sec":"Wealth"},
{"n":516,"id":"TK-0516","ta":"செய்வானை நாடி வினைநாடிக் காலத்தோடு எய்த உணர்ந்து செயல்.","en":"Discern the agent and the deed And just in proper time proceed","ch":"தெரிந்து வினையாடல்","chEn":"Selection and Employment","chNo":52,"sec":"Wealth"},
{"n":517,"id":"TK-0517","ta":"இதனை இதனால் இவன்முடிக்கும் என்றாய்ந்து அதனை அவன்கண் விடல்.","en":"This work, by this, this man can do Like this entrust the duty due","ch":"தெரிந்து வினையாடல்","chEn":"Selection and Employment","chNo":52,"sec":"Wealth"},
{"n":518,"id":"TK-0518","ta":"வினைக்குரிமை நாடிய பின்றை அவனை அதற்குரிய னாகச் செயல்.","en":"His fitness for the duty scan Leave him to do the best he can","ch":"தெரிந்து வினையாடல்","chEn":"Selection and Employment","chNo":52,"sec":"Wealth"},
{"n":519,"id":"TK-0519","ta":"வினைக்கண் வினையுடையான் கேண்மைவே றாக நினைப்பானை நீங்கும் திரு.","en":"Who do duty for duty's sake Doubt them; and fortune departs quick","ch":"தெரிந்து வினையாடல்","chEn":"Selection and Employment","chNo":52,"sec":"Wealth"},
{"n":520,"id":"TK-0520","ta":"நாடோறும் நாடுக மன்னன் வினைசெய்வான் கோடாமை கோடா துலகு.","en":"Worker straight the world is straight The king must look to this aright","ch":"தெரிந்து வினையாடல்","chEn":"Selection and Employment","chNo":52,"sec":"Wealth"},
{"n":521,"id":"TK-0521","ta":"பற்றற்ற கண்ணும் பழைமைபா ராட்டுதல் சுற்றத்தார் கண்ணே உள.","en":"Let fortunes go; yet kinsmen know The old accustomed love to show","ch":"சுற்றந் தழால்","chEn":"Cherishing Kinsmen","chNo":53,"sec":"Wealth"},
{"n":522,"id":"TK-0522","ta":"விருப்பறாச் சுற்றம் இயையின் அருப்பறா ஆக்கம் பலவும் தரும்.","en":"The gift of loving Kins bestows  Fadeless fortune's fresh flowers","ch":"சுற்றந் தழால்","chEn":"Cherishing Kinsmen","chNo":53,"sec":"Wealth"},
{"n":523,"id":"TK-0523","ta":"அளவளா வில்லாதான் வாழ்க்கை குளவளாக் கோடின்றி நீர்நிறைந் தற்று.","en":"A kinless wealth is like a tank Which overflows without a bank","ch":"சுற்றந் தழால்","chEn":"Cherishing Kinsmen","chNo":53,"sec":"Wealth"},
{"n":524,"id":"TK-0524","ta":"சுற்றத்தால் சுற்றப் படஒழுகல் செல்வந்தான் பெற்றத்தால் பெற்ற பயன்.","en":"The fruit of growing wealth is gained When kith and kin are happy found","ch":"சுற்றந் தழால்","chEn":"Cherishing Kinsmen","chNo":53,"sec":"Wealth"},
{"n":525,"id":"TK-0525","ta":"கொடுத்தலும் இன்சொலும் ஆற்றின் அடுக்கிய சுற்றத்தால் சுற்றப் படும்.","en":"Loving words and liberal hand Encircle kith and kin around","ch":"சுற்றந் தழால்","chEn":"Cherishing Kinsmen","chNo":53,"sec":"Wealth"},
{"n":526,"id":"TK-0526","ta":"பெருங்கொடையான் பேணான் வெகுளி அவனின் மருங்குடையார் மாநிலத்து இல்.","en":"Large giver and wrathless man Commands on earth countless kinsmen","ch":"சுற்றந் தழால்","chEn":"Cherishing Kinsmen","chNo":53,"sec":"Wealth"},
{"n":527,"id":"TK-0527","ta":"காக்கை கரவா கரைந்துண்ணும் ஆக்கமும் அன்னநீ ரார்க்கே உள.","en":"The crows hide not; thy call and eat Welfare abides a man of heart","ch":"சுற்றந் தழால்","chEn":"Cherishing Kinsmen","chNo":53,"sec":"Wealth"},
{"n":528,"id":"TK-0528","ta":"பொதுநோக்கான் வேந்தன் வரிசையா நோக்கின் அதுநோக்கி வாழ்வார் பலர்.","en":"From public gaze when kings perceive Each one's merits so many thrive","ch":"சுற்றந் தழால்","chEn":"Cherishing Kinsmen","chNo":53,"sec":"Wealth"},
{"n":529,"id":"TK-0529","ta":"தமராகிக் தற்றுறந்தார் சுற்றம் அமராமைக் காரணம் இன்றி வரும்.","en":"Forsaken friends will come and stay When cause for discord goes away","ch":"சுற்றந் தழால்","chEn":"Cherishing Kinsmen","chNo":53,"sec":"Wealth"},
{"n":530,"id":"TK-0530","ta":"உழைப்பிரிந்து காரணத்தின் வந்தானை வேந்தன் இழைத் திருந்து எண்ணிக் கொளல்.","en":"Who leaves and returns with motive The king should test him and receive","ch":"சுற்றந் தழால்","chEn":"Cherishing Kinsmen","chNo":53,"sec":"Wealth"},
{"n":531,"id":"TK-0531","ta":"இறந்த வெகுளியின் தீதே சிறந்த உவகை மகிழ்ச்சியிற் சோர்வு.","en":"Worse than wrath in excess is Forgetfulness in joy-excess","ch":"பொச்சாவாமை","chEn":"Unforgetfulness","chNo":54,"sec":"Wealth"},
{"n":532,"id":"TK-0532","ta":"பொச்சாப்புக் கொல்லும் புகழை அறிவினை நிச்ச நிரப்புக் கொன் றாங்கு.","en":"Negligence kills renown just as Ceaseless want wisdom destroys","ch":"பொச்சாவாமை","chEn":"Unforgetfulness","chNo":54,"sec":"Wealth"},
{"n":533,"id":"TK-0533","ta":"பொச்சாப்பார்க் கில்லை புகழ்மை அதுஉலகத்து எப்பால்நூ லோர்க்கும் துணிவு.","en":"Forgetful nature fails of fame All schools of thinkers say the same","ch":"பொச்சாவாமை","chEn":"Unforgetfulness","chNo":54,"sec":"Wealth"},
{"n":534,"id":"TK-0534","ta":"அச்ச முடையார்க்கு அரணில்லை ஆங்கில்லை பொச்சாப் புடையார்க்கு நன்கு.","en":"The fearful find no fortress here The forgetful find good never","ch":"பொச்சாவாமை","chEn":"Unforgetfulness","chNo":54,"sec":"Wealth"},
{"n":535,"id":"TK-0535","ta":"முன்னுறக் காவாது இழுக்கியான் தன்பிழை பின்னூறு இரங்கி விடும்.","en":"Failing foresight the guardless man Shall rue his folly later on","ch":"பொச்சாவாமை","chEn":"Unforgetfulness","chNo":54,"sec":"Wealth"},
{"n":536,"id":"TK-0536","ta":"இழுக்காமை யார்மாட்டும் என்றும் வழுக்காமை வாயின் அதுவொப்பது இல்.","en":"Forget none; watch with wakeful care Miss none; the gain is sans compare","ch":"பொச்சாவாமை","chEn":"Unforgetfulness","chNo":54,"sec":"Wealth"},
{"n":537,"id":"TK-0537","ta":"அரியஎன்று ஆகாத இல்லைபொச் சாவாக் கருவியால் போற்றிச் செயின்.","en":"With cautious care pursue a thing Impossible there is nothing","ch":"பொச்சாவாமை","chEn":"Unforgetfulness","chNo":54,"sec":"Wealth"},
{"n":538,"id":"TK-0538","ta":"புகழ்ந்தவை போற்றிச் செயல்வேண்டும் செய்யாது இகழ்ந்தார்க்கு எழுமையும் இல்.","en":"Do what the wise commend as worth If not, for seven births no mirth","ch":"பொச்சாவாமை","chEn":"Unforgetfulness","chNo":54,"sec":"Wealth"},
{"n":539,"id":"TK-0539","ta":"இகழ்ச்சியின் கெட்டாரை உள்ளுக தாந்தம் மகிழ்ச்சியின் மைந்துறும் போழ்து.","en":"When joy deludes, their fate recall Whom negligence has made to fall","ch":"பொச்சாவாமை","chEn":"Unforgetfulness","chNo":54,"sec":"Wealth"},
{"n":540,"id":"TK-0540","ta":"உள்ளியது எய்தல் எளிதுமன் மற்றுந்தான் உள்ளியது உள்ளப் பெறின்.","en":"Easy it is a thing to get When the mind on it is set","ch":"பொச்சாவாமை","chEn":"Unforgetfulness","chNo":54,"sec":"Wealth"},
{"n":541,"id":"TK-0541","ta":"ஓர்ந்துகண் ணோடாது இறைபுரிந்து யார்மாட்டும் தேர்ந்துசெய் வஃதே முறை.","en":"Test and attest impartially Consult and act the laws justly","ch":"செங்கோன்மை","chEn":"The Right Sceptre","chNo":55,"sec":"Wealth"},
{"n":542,"id":"TK-0542","ta":"வானோக்கி வாழும் உலகெல்லாம் மன்னவன் கோல் நோக்கி வாழுங் குடி.","en":"The earth looks up to sky and thrives And mankind to king's rod of justice","ch":"செங்கோன்மை","chEn":"The Right Sceptre","chNo":55,"sec":"Wealth"},
{"n":543,"id":"TK-0543","ta":"அந்தணர் நூற்கும் அறத்திற்கும் ஆதியாய் நின்றது மன்னவன் கோல்.","en":"The Sage's scripture and virtue spring From the sceptre of a stately king","ch":"செங்கோன்மை","chEn":"The Right Sceptre","chNo":55,"sec":"Wealth"},
{"n":544,"id":"TK-0544","ta":"குடிதழீஇக் கோலோச்சும் மாநில மன்னன் அடிதழீஇ நிற்கும் உலகு.","en":"The world clings to the ruler's feet Whose sceptre clasps the people's heart","ch":"செங்கோன்மை","chEn":"The Right Sceptre","chNo":55,"sec":"Wealth"},
{"n":545,"id":"TK-0545","ta":"இயல்புளிக் கோலோச்சும் மன்னவன் நாட்ட பெயலும் விளையுளும் தொக்கு.","en":"Full rains and yields enrich the land Which is ruled by a righteous hand","ch":"செங்கோன்மை","chEn":"The Right Sceptre","chNo":55,"sec":"Wealth"},
{"n":546,"id":"TK-0546","ta":"வேலன்று வென்றி தருவது மன்னவன் கோலதூஉங் கோடா தெனின்.","en":"Not the spear but the sceptre straight That brings success to monarch's might","ch":"செங்கோன்மை","chEn":"The Right Sceptre","chNo":55,"sec":"Wealth"},
{"n":547,"id":"TK-0547","ta":"இறைகாக்கும் வையகம் எல்லாம் அவனை முறைகாக்கும் முட்டாச் செயின்.","en":"The king protects the entire earth And justice protects his royal worth","ch":"செங்கோன்மை","chEn":"The Right Sceptre","chNo":55,"sec":"Wealth"},
{"n":548,"id":"TK-0548","ta":"எண்பதத்தான் ஓரா முறைசெய்யா மன்னவன் தண்பதத்தான் தானே கெடும்.","en":"Hard of access, the unjust king He shall himself his ruin bring","ch":"செங்கோன்மை","chEn":"The Right Sceptre","chNo":55,"sec":"Wealth"},
{"n":549,"id":"TK-0549","ta":"குடிபுறங் காத்தோம்பிக் குற்றம் கடிதல் வடுவன்று வேந்தன் தொழில்.","en":"Save his subjects and chide the wrong Is flawless duty of a king","ch":"செங்கோன்மை","chEn":"The Right Sceptre","chNo":55,"sec":"Wealth"},
{"n":550,"id":"TK-0550","ta":"கொலையிற் கொடியாரை வேந்தொறுத்தல் பைங்கூழ் களைகட் டதனொடு நேர்.","en":"Killing killers, the king, behold Weeds removes from cropful field","ch":"செங்கோன்மை","chEn":"The Right Sceptre","chNo":55,"sec":"Wealth"},
{"n":551,"id":"TK-0551","ta":"கொலைமேற்கொண் டாரிற் கொடிதே அலைமேற்கொண்டு அல்லவை செய்தொழுகும் வேந்து.","en":"The unjust tyrant oppressor  Is worse than cruel murderer","ch":"கொடுங்கோன்மை","chEn":"The Cruel Sceptre","chNo":56,"sec":"Wealth"},
{"n":552,"id":"TK-0552","ta":"வேலொடு நின்றான் இடுவென் றதுபோலும் கோலொடு நின்றான் இரவு.","en":"Sceptered tyrant exacting gold Is \\\"give\\\" of lanced robber bold","ch":"கொடுங்கோன்மை","chEn":"The Cruel Sceptre","chNo":56,"sec":"Wealth"},
{"n":553,"id":"TK-0553","ta":"நாடொறும் நாடி முறைசெய்யா மன்னவன் நாடொறும் நாடு கெடும்.","en":"Spy wrongs daily and do justice Or day by day the realm decays","ch":"கொடுங்கோன்மை","chEn":"The Cruel Sceptre","chNo":56,"sec":"Wealth"},
{"n":554,"id":"TK-0554","ta":"கூழுங் குடியும் ஒருங்கிழக்கும் கோல்கோடிச் சூழாது செய்யும் அரசு.","en":"The king shall wealth and subjects lose If his sceptre he dares abuse","ch":"கொடுங்கோன்மை","chEn":"The Cruel Sceptre","chNo":56,"sec":"Wealth"},
{"n":555,"id":"TK-0555","ta":"அல்லற்பட்டு ஆற்றாது அழுதகண் ணீரன்றே செல்வத்தைத் தேய்க்கும் படை","en":"Groaning tears caused by tyrant's sway  File the royal wealth away","ch":"கொடுங்கோன்மை","chEn":"The Cruel Sceptre","chNo":56,"sec":"Wealth"},
{"n":556,"id":"TK-0556","ta":"மன்னர்க்கு மன்னுதல் செங்கோன்மை அஃதின்றேல் மன்னாவாம் மன்னர்க் கொளி.","en":"Glory endures by sceptre right Without it wanes the royal light","ch":"கொடுங்கோன்மை","chEn":"The Cruel Sceptre","chNo":56,"sec":"Wealth"},
{"n":557,"id":"TK-0557","ta":"துளியின்மை ஞாலத்திற்கு எற்றற்றே வேந்தன் அளியின்மை வாழும் உயிர்க்கு.","en":"Dry like the earth without rainfall Is graceless king to creatures all","ch":"கொடுங்கோன்மை","chEn":"The Cruel Sceptre","chNo":56,"sec":"Wealth"},
{"n":558,"id":"TK-0558","ta":"இன்மையின் இன்னாது உடைமை முறைசெய்யா மன்னவன் கோற்கீழ்ப் படின்.","en":"To have is worse than having not If ruler is unjust despot","ch":"கொடுங்கோன்மை","chEn":"The Cruel Sceptre","chNo":56,"sec":"Wealth"},
{"n":559,"id":"TK-0559","ta":"முறைகோடி மன்னவன் செய்யின் உறைகோடி ஒல்லாது வானம் பெயல்.","en":"The sky withdraws season's shower If the king misuses his power","ch":"கொடுங்கோன்மை","chEn":"The Cruel Sceptre","chNo":56,"sec":"Wealth"},
{"n":560,"id":"TK-0560","ta":"ஆபயன் குன்றும் அறுதொழிலோர் நூல்மறப்பர் காவலன் காவான் எனின்.","en":"The *six-functioned forget their lore Cows give less if kings guard no more * the six functions are: learning, teaching,  giving,  getting, sacrificing, kindling sacrifice These are duties of Vedic savants","ch":"கொடுங்கோன்மை","chEn":"The Cruel Sceptre","chNo":56,"sec":"Wealth"},
{"n":561,"id":"TK-0561","ta":"தக்காங்கு நாடித் தலைச்செல்லா வண்ணத்தால் ஒத்தாங்கு ஒறுப்பது வேந்து.","en":"A king enquires and gives sentence  Just to prevent future offence","ch":"வெருவந்த செய்யாமை","chEn":"Absence of Terrorism","chNo":57,"sec":"Wealth"},
{"n":562,"id":"TK-0562","ta":"கடிதோச்சி மெல்ல எறிக நெடிதாக்கம் நீங்காமை வேண்டு பவர்.","en":"Wield fast the rod but gently lay This strict mildness prolongs the sway","ch":"வெருவந்த செய்யாமை","chEn":"Absence of Terrorism","chNo":57,"sec":"Wealth"},
{"n":563,"id":"TK-0563","ta":"வெருவந்த செய்தொழுகும் வெங்கோல னாயின் ஒருவந்தம் ஒல்லைக் கெடும்.","en":"His cruel rod of dreadful deed Brings king's ruin quick indeed","ch":"வெருவந்த செய்யாமை","chEn":"Absence of Terrorism","chNo":57,"sec":"Wealth"},
{"n":564,"id":"TK-0564","ta":"இறைகடியன் என்றுரைக்கும் இன்னாச்சொல் வேந்தன் உறைகடுகி ஒல்லைக் கெடும்.","en":"As men the king a tyrant call  His days dwindled, hasten his fall","ch":"வெருவந்த செய்யாமை","chEn":"Absence of Terrorism","chNo":57,"sec":"Wealth"},
{"n":565,"id":"TK-0565","ta":"அருஞ்செவ்வி இன்னா முகத்தான் பெருஞ்செல்வம் பேஎய்கண் டன்னது உடைத்து.","en":"Whose sight is scarce, whose face is foul His wealth seems watched by a ghoul","ch":"வெருவந்த செய்யாமை","chEn":"Absence of Terrorism","chNo":57,"sec":"Wealth"},
{"n":566,"id":"TK-0566","ta":"கடுஞ்சொல்லன் கண்ணிலன் ஆயின் நெடுஞ்செல்வம் நீடின்றி ஆங்கே கெடும்.","en":"Whose word is harsh, whose sight is rude His wealth and power quickly fade","ch":"வெருவந்த செய்யாமை","chEn":"Absence of Terrorism","chNo":57,"sec":"Wealth"},
{"n":567,"id":"TK-0567","ta":"கடுமொழியும் கையிகந்த தண்டமும் வேந்தன் அடுமுரண் தேய்க்கும் அரம்.","en":"Reproofs rough and punishments rude Like files conquering power corrode","ch":"வெருவந்த செய்யாமை","chEn":"Absence of Terrorism","chNo":57,"sec":"Wealth"},
{"n":568,"id":"TK-0568","ta":"இனத்தாற்றி எண்ணாத வேந்தன் சினத்தாற்றிச் சீறிற் சிறுகும் திரு.","en":"The king who would not take counsels Rages with wrath-his fortune fails","ch":"வெருவந்த செய்யாமை","chEn":"Absence of Terrorism","chNo":57,"sec":"Wealth"},
{"n":569,"id":"TK-0569","ta":"செருவந்த போழ்திற் சிறைசெய்யா வேந்தன் வெருவந்து வெய்து கெடும்.","en":"The king who builds not fort betimes Fears his foes in wars and dies","ch":"வெருவந்த செய்யாமை","chEn":"Absence of Terrorism","chNo":57,"sec":"Wealth"},
{"n":570,"id":"TK-0570","ta":"கல்லார்ப் பிணிக்கும் கடுங்கோல் அதுவல்லது இல்லை நிலக்குப் பொறை.","en":"The crushing burden borne by earth Is tyrants bound to fools uncouth","ch":"வெருவந்த செய்யாமை","chEn":"Absence of Terrorism","chNo":57,"sec":"Wealth"},
{"n":571,"id":"TK-0571","ta":"கண்ணோட்டம் என்னும் கழிபெருங் காரிகை உண்மையான் உண்டிவ் வுலகு.","en":"Living in the world implies The bounteous dame of benign eyes","ch":"கண்ணோட்டம்","chEn":"Benignity","chNo":58,"sec":"Wealth"},
{"n":572,"id":"TK-0572","ta":"கண்ணோட்டத் துள்ளது உலகியல் அஃதிலார் உண்மை நிலக்குப் பொறை.","en":"World lives by looks of lovely worth Who lack them are burdens of earth","ch":"கண்ணோட்டம்","chEn":"Benignity","chNo":58,"sec":"Wealth"},
{"n":573,"id":"TK-0573","ta":"பண்என்னாம் பாடற்கு இயைபின்றேல் கண்என்னாம் கண்ணோட்டம் இல்லாத கண்.","en":"Of tuneless song what is the use? Without gracious looks what are eyes?","ch":"கண்ணோட்டம்","chEn":"Benignity","chNo":58,"sec":"Wealth"},
{"n":574,"id":"TK-0574","ta":"உளபோல் முகத்தெவன் செய்யும் அளவினால் கண்ணோட்டம் இல்லாத கண்.","en":"Except that they are on the face  What for are eyes sans measured grace","ch":"கண்ணோட்டம்","chEn":"Benignity","chNo":58,"sec":"Wealth"},
{"n":575,"id":"TK-0575","ta":"கண்ணிற்கு அணிகலம் கண்ணோட்டம் அஃதின்றேல் புண்ணென்று உணரப் படும்","en":"Kind looks are jewels for eyes to wear Without them they are felt as sore","ch":"கண்ணோட்டம்","chEn":"Benignity","chNo":58,"sec":"Wealth"},
{"n":576,"id":"TK-0576","ta":"மண்ணோ டியைந்த மரத்தனையர் கண்ணோ டியைந்துகண் ணோடா தவர்.","en":"Like trees on inert earth they grow Who don't eye to eye kindness show","ch":"கண்ணோட்டம்","chEn":"Benignity","chNo":58,"sec":"Wealth"},
{"n":577,"id":"TK-0577","ta":"கண்ணோட்டம் இல்லவர் கண்ணிலர் கண்ணுடையார் கண்ணோட்டம் இன்மையும் இல்.","en":"Ungracious men lack real eyes Men of real eyes show benign grace","ch":"கண்ணோட்டம்","chEn":"Benignity","chNo":58,"sec":"Wealth"},
{"n":578,"id":"TK-0578","ta":"கருமம் சிதையாமல் கண்ணோட வல்லார்க்கு உரிமை உடைத்திவ் வுலகு.","en":"Who gracious are but dutiful Have right for this earth beautiful","ch":"கண்ணோட்டம்","chEn":"Benignity","chNo":58,"sec":"Wealth"},
{"n":579,"id":"TK-0579","ta":"ஒறுத்தாற்றும் பண்பினார் கண்ணும்கண் ணோடிப் பொறுத்தாற்றும் பண்பே தலை.","en":"To be benign and bear with foes Who vex us is true virtue's phase","ch":"கண்ணோட்டம்","chEn":"Benignity","chNo":58,"sec":"Wealth"},
{"n":580,"id":"TK-0580","ta":"பெயக்கண்டும் நஞ்சுண் டமைவர் நயத்தக்க நாகரிகம் வேண்டு பவர்.","en":"Men of graceful courtesy Take hemlock and look cheerfully","ch":"கண்ணோட்டம்","chEn":"Benignity","chNo":58,"sec":"Wealth"},
{"n":581,"id":"TK-0581","ta":"ஒற்றும் உரைசான்ற நூலும் இவையிரண்டும் தெற்றென்க மன்னவன் கண்.","en":"A king should treat these two as eyes  The code of laws and careful spies","ch":"ஒற்றாடல்","chEn":"Detectives","chNo":59,"sec":"Wealth"},
{"n":582,"id":"TK-0582","ta":"எல்லார்க்கும் எல்லாம் நிகழ்பவை எஞ்ஞான்றும் வல்லறிதல் வேந்தன் தொழில்.","en":"All that happens, always, to all  The king should know in full detail","ch":"ஒற்றாடல்","chEn":"Detectives","chNo":59,"sec":"Wealth"},
{"n":583,"id":"TK-0583","ta":"ஒற்றினான் ஒற்றிப் பொருள்தெரியா மன்னவன் கொற்றங் கொளக்கிடந்தது இல்.","en":"Conquests are not for the monarch Who cares not for the Spy's remark","ch":"ஒற்றாடல்","chEn":"Detectives","chNo":59,"sec":"Wealth"},
{"n":584,"id":"TK-0584","ta":"வினைசெய்வார் தம்சுற்றம் வேண்டாதார் என்றாங்கு அனைவரையும் ஆராய்வது ஒற்று.","en":"His officers, kinsmen and foes  Who watch keenly are worthy spies","ch":"ஒற்றாடல்","chEn":"Detectives","chNo":59,"sec":"Wealth"},
{"n":585,"id":"TK-0585","ta":"கடாஅ உருவொடு கண்ணஞ்சாது யாண்டும் உகாஅமை வல்லதே ஒற்று.","en":"Fearless gaze, suspectless guise  Guarding secrets mark the spies","ch":"ஒற்றாடல்","chEn":"Detectives","chNo":59,"sec":"Wealth"},
{"n":586,"id":"TK-0586","ta":"துறந்தார் படிவத்த ராகி இறந்தாராய்ந்து என்செயினும் சோர்விலது ஒற்று.","en":"Guised as monks they gather secrets They betray them not under threats","ch":"ஒற்றாடல்","chEn":"Detectives","chNo":59,"sec":"Wealth"},
{"n":587,"id":"TK-0587","ta":"மறைந்தவை கேட்கவற் றாகி அறிந்தவை ஐயப்பாடு இல்லதே ஒற்று.","en":"A spy draws out other's secrets Beyond a doubt he clears his facts","ch":"ஒற்றாடல்","chEn":"Detectives","chNo":59,"sec":"Wealth"},
{"n":588,"id":"TK-0588","ta":"ஒற்றொற்றித் தந்த பொருளையும் மற்றுமோர் ஒற்றினால் ஒற்றிக் கொளல்.","en":"The reports given by one spy By another spy verify","ch":"ஒற்றாடல்","chEn":"Detectives","chNo":59,"sec":"Wealth"},
{"n":589,"id":"TK-0589","ta":"ஒற்றெற் றுணராமை ஆள்க உடன்மூவர் சொற்றொக்க தேறப் படும்.","en":"Engage the spies alone, apart When three agree confirm report","ch":"ஒற்றாடல்","chEn":"Detectives","chNo":59,"sec":"Wealth"},
{"n":590,"id":"TK-0590","ta":"சிறப்பறிய ஒற்றின்கண் செய்யற்க செய்யின் புறப்படுத்தான் ஆகும் மறை.","en":"Give not the spy open reward It would divulge the secret heard!","ch":"ஒற்றாடல்","chEn":"Detectives","chNo":59,"sec":"Wealth"},
{"n":591,"id":"TK-0591","ta":"உடையர் எனப்படுவது ஊக்கம் அஃதில்லார் உடையது உடையரோ மற்று.","en":"To own is to own energy All others own but lethargy","ch":"ஊக்கம் உடைமை","chEn":"Energy","chNo":60,"sec":"Wealth"},
{"n":592,"id":"TK-0592","ta":"உள்ளம் உடைமை உடைமை பொருளுடைமை நில்லாது நீங்கி விடும்.","en":"Psychic heart is wealth indeed Worldly wealth departs in speed","ch":"ஊக்கம் உடைமை","chEn":"Energy","chNo":60,"sec":"Wealth"},
{"n":593,"id":"TK-0593","ta":"ஆக்கம் இழந்தேமென்று அல்லாவார் ஊக்கம் ஒருவந்தம் கைத்துடை யார்.","en":"The strong in will do not complain  The loss of worldly wealth and gain","ch":"ஊக்கம் உடைமை","chEn":"Energy","chNo":60,"sec":"Wealth"},
{"n":594,"id":"TK-0594","ta":"ஆக்கம் அதர்வினாய்ச் செல்லும் அசைவிலா ஊக்க முடையா னுழை.","en":"Fortune enquires, enters with boom Where tireless strivers have their home","ch":"ஊக்கம் உடைமை","chEn":"Energy","chNo":60,"sec":"Wealth"},
{"n":595,"id":"TK-0595","ta":"வெள்ளத் தனைய மலர்நீட்டம் மாந்தர்தம் உள்ளத் தனையது உயர்வு.","en":"Water depth is lotus height  Mental strength is men's merit","ch":"ஊக்கம் உடைமை","chEn":"Energy","chNo":60,"sec":"Wealth"},
{"n":596,"id":"TK-0596","ta":"உள்ளுவ தெல்லாம் உயர்வுள்ளல் மற்றது தள்ளினுந் தள்ளாமை நீர்த்து.","en":"Let thoughts be always great and grand  Though they fail their virtues stand","ch":"ஊக்கம் உடைமை","chEn":"Energy","chNo":60,"sec":"Wealth"},
{"n":597,"id":"TK-0597","ta":"சிதைவிடத்து ஒல்கார் உரவோர் புதையம்பிற் பட்டுப்பா டூன்றுங் களிறு.","en":"Elephants are firm when arrows hit Great minds keep fit ev'n in defeat","ch":"ஊக்கம் உடைமை","chEn":"Energy","chNo":60,"sec":"Wealth"},
{"n":598,"id":"TK-0598","ta":"உள்ளம் இலாதவர் எய்தார் உலகத்து வள்ளியம் என்னுஞ் செருக்கு.","en":"Heartless persons cannot boast \\\"We are liberal to our best\\\"","ch":"ஊக்கம் உடைமை","chEn":"Energy","chNo":60,"sec":"Wealth"},
{"n":599,"id":"TK-0599","ta":"பரியது கூர்ங்கோட்டது ஆயினும் யானை ஦வ்ருஉம் புலிதாக் குறின்.","en":"Huge elephant sharp in tusk quails  When tiger, less in form, assails","ch":"ஊக்கம் உடைமை","chEn":"Energy","chNo":60,"sec":"Wealth"},
{"n":600,"id":"TK-0600","ta":"உரமொருவற்கு உள்ள வெறுக்கைஅஃ தில்லார் மரம்மக்க ளாதலே வேறு.","en":"Mental courage is true manhood Lacking that man is like a wood","ch":"ஊக்கம் உடைமை","chEn":"Energy","chNo":60,"sec":"Wealth"},
{"n":601,"id":"TK-0601","ta":"குடியென்னும் குன்றா விளக்கம் மடியென்னும் மாசூர மாய்ந்து கெடும்.","en":"Quenchless lamp of ancestry goes When foul idleness encloses","ch":"மடி இன்மை","chEn":"Unsluggishness","chNo":61,"sec":"Wealth"},
{"n":602,"id":"TK-0602","ta":"மடியை மடியா ஒழுகல் குடியைக் குடியாக வேண்டு பவர்.","en":"To make your home an ideal home Loath sloth as sloth; refuse it room","ch":"மடி இன்மை","chEn":"Unsluggishness","chNo":61,"sec":"Wealth"},
{"n":603,"id":"TK-0603","ta":"மடிமடிக் கொண்டொழுகும் பேதை பிறந்த குடிமடியும் தன்னினும் முந்து.","en":"The fool who fosters sluggishness Before he dies ruins his house","ch":"மடி இன்மை","chEn":"Unsluggishness","chNo":61,"sec":"Wealth"},
{"n":604,"id":"TK-0604","ta":"குடிமடிந்து குற்றம் பெருகும் மடிமடிந்து மாண்ட உஞற்றி லவர்க்கு.","en":"Who strive not high, sunk deep in sloth Ruin their house by evil growth","ch":"மடி இன்மை","chEn":"Unsluggishness","chNo":61,"sec":"Wealth"},
{"n":605,"id":"TK-0605","ta":"நெடுநீர் மறவி மடிதுயில் நான்கும் கெடுநீரார் காமக் கலன்.","en":"To lag, forget, idle and doze These four are pleasure boats of loss","ch":"மடி இன்மை","chEn":"Unsluggishness","chNo":61,"sec":"Wealth"},
{"n":606,"id":"TK-0606","ta":"படியுடையார் பற்றமைந்தக் கண்ணும் மடியுடையார் மாண்பயன் எய்தல் அரிது.","en":"With all the wealth of lords of earth The slothful gain nothing of worth","ch":"மடி இன்மை","chEn":"Unsluggishness","chNo":61,"sec":"Wealth"},
{"n":607,"id":"TK-0607","ta":"இடிபுரிந்து எள்ளுஞ்சொல் கேட்பர் மடிபுரிந்து மாண்ட உஞற்றி லவர்.","en":"The slothful lacking noble deeds Subject themselves to scornful words","ch":"மடி இன்மை","chEn":"Unsluggishness","chNo":61,"sec":"Wealth"},
{"n":608,"id":"TK-0608","ta":"மடிமை குடிமைக்கண் தங்கின்தன் ஒன்னார்க்கு அடிமை புகுத்தி விடும்.","en":"If sloth invades a noble house It will become a slave of foes","ch":"மடி இன்மை","chEn":"Unsluggishness","chNo":61,"sec":"Wealth"},
{"n":609,"id":"TK-0609","ta":"குடியாண்மை யுள்வந்த குற்றம் ஒருவன் மடியாண்மை மாற்றக் கெடும்.","en":"The blots on race and rule shall cease When one from sloth gets his release","ch":"மடி இன்மை","chEn":"Unsluggishness","chNo":61,"sec":"Wealth"},
{"n":610,"id":"TK-0610","ta":"மடியிலா மன்னவன் எய்தும் அடியளந்தான் தாஅய தெல்லாம் ஒருங்கு.","en":"The slothless king shall gain en masse *All regions trod by Lord apace * Hindu mythology holds that Lord Vishnu measured with his feet the three worlds","ch":"மடி இன்மை","chEn":"Unsluggishness","chNo":61,"sec":"Wealth"},
{"n":611,"id":"TK-0611","ta":"அருமை உடைத்தென்று அசாவாமை வேண்டும் பெருமை முயற்சி தரும்.","en":"Feel not frustrate saying This hard Who tries attains striving's reward","ch":"ஆள்வினை உடைமை","chEn":"Manly Effort","chNo":62,"sec":"Wealth"},
{"n":612,"id":"TK-0612","ta":"வினைக்கண் வினைகெடல் ஓம்பல் வினைக்குறை தீர்ந்தாரின் தீர்ந்தன்று உலகு.","en":"In doing work don't break and shirk The world will quit who quits his work","ch":"ஆள்வினை உடைமை","chEn":"Manly Effort","chNo":62,"sec":"Wealth"},
{"n":613,"id":"TK-0613","ta":"தாளாண்மை என்னும் தகைமைக்கண் தங்கிற்றே வேளாண்மை என்னுஞ் செருக்கு.","en":"On excellence of industry Depends magnanimous bounty","ch":"ஆள்வினை உடைமை","chEn":"Manly Effort","chNo":62,"sec":"Wealth"},
{"n":614,"id":"TK-0614","ta":"தாளாண்மை இல்லாதான் வேளாண்மை பேடிகை வாளாண்மை போலக் கெடும்.","en":"Bounty of man who never strives Like sword in eunuch's hand it fails","ch":"ஆள்வினை உடைமை","chEn":"Manly Effort","chNo":62,"sec":"Wealth"},
{"n":615,"id":"TK-0615","ta":"இன்பம் விழையான் வினைவிழைவான் தன்கேளிர் துன்பம் துடைத்தூன்றும் தூண்.","en":"Work who likes and not pleasure  Wipes grief of friends, pillar secure","ch":"ஆள்வினை உடைமை","chEn":"Manly Effort","chNo":62,"sec":"Wealth"},
{"n":616,"id":"TK-0616","ta":"முயற்சி திருவினை ஆக்கும் முயற்றின்மை இன்மை புகுத்தி விடும்.","en":"Industry adds prosperity Indolence brings but poverty","ch":"ஆள்வினை உடைமை","chEn":"Manly Effort","chNo":62,"sec":"Wealth"},
{"n":617,"id":"TK-0617","ta":"மடியுளாள் மாமுகடி என்ப மடியிலான் தாளுளான் தாமரையி னாள்.","en":"Illuck abides with sloth they say *Laxmi's gifts with labourers stay *Laxmi the Goddes of wealth and prosperity","ch":"ஆள்வினை உடைமை","chEn":"Manly Effort","chNo":62,"sec":"Wealth"},
{"n":618,"id":"TK-0618","ta":"பொறியின்மை யார்க்கும் பழியன்று அறிவறிந்து ஆள்வினை இன்மை பழி.","en":"Misfortune is disgrace to none The shame is nothing learnt or done","ch":"ஆள்வினை உடைமை","chEn":"Manly Effort","chNo":62,"sec":"Wealth"},
{"n":619,"id":"TK-0619","ta":"தெய்வத்தான் ஆகா தெனினும் முயற்சிதன் மெய்வருத்தக் கூலி தரும்.","en":"Though fate is against fulfilment Hard labour has ready payment","ch":"ஆள்வினை உடைமை","chEn":"Manly Effort","chNo":62,"sec":"Wealth"},
{"n":620,"id":"TK-0620","ta":"ஊழையும் உப்பக்கம் காண்பர் உலைவின்றித் தாழாது உஞற்று பவர்.","en":"Tireless Toiler's striving hand Shall leave even the fate behind","ch":"ஆள்வினை உடைமை","chEn":"Manly Effort","chNo":62,"sec":"Wealth"},
{"n":621,"id":"TK-0621","ta":"இடுக்கண் வருங்கால் நகுக அதனை அடுத்தூர்வது அஃதொப்ப தில்.","en":"Laugh away troubles; there is No other way to conquer woes","ch":"இடுக்கண் அழியாமை","chEn":"Hopefulness in Trouble","chNo":63,"sec":"Wealth"},
{"n":622,"id":"TK-0622","ta":"வெள்ளத் தனைய இடும்பை அறிவுடையான் உள்ளத்தின் உள்ளக் கெடும்.","en":"Deluging sorrows come to nought When wise men face them with firm thought","ch":"இடுக்கண் அழியாமை","chEn":"Hopefulness in Trouble","chNo":63,"sec":"Wealth"},
{"n":623,"id":"TK-0623","ta":"இடும்பைக்கு இடும்பை படுப்பர் இடும்பைக்கு இடும்பை படாஅ தவர்.","en":"Grief they face and put to grief Who grieve not grief by mind's relief","ch":"இடுக்கண் அழியாமை","chEn":"Hopefulness in Trouble","chNo":63,"sec":"Wealth"},
{"n":624,"id":"TK-0624","ta":"மடுத்தவா யெல்லாம் பகடன்னான் உற்ற இடுக்கண் இடர்ப்பாடு உடைத்து.","en":"Who pulls like bulls patiently on Causes grief to grieve anon","ch":"இடுக்கண் அழியாமை","chEn":"Hopefulness in Trouble","chNo":63,"sec":"Wealth"},
{"n":625,"id":"TK-0625","ta":"அடுக்கி வரினும் அழிவிலான் உற்ற இடுக்கண் இடுக்கட் படும்.","en":"Before the brave grief grieves and goes Who dare a host of pressing woes","ch":"இடுக்கண் அழியாமை","chEn":"Hopefulness in Trouble","chNo":63,"sec":"Wealth"},
{"n":626,"id":"TK-0626","ta":"அற்றேமென்று அல்லற் படுபவோ பெற்றேமென்று ஓம்புதல் தேற்றா தவர்.","en":"The wise that never gloat in gain Do not fret in fateful ruin","ch":"இடுக்கண் அழியாமை","chEn":"Hopefulness in Trouble","chNo":63,"sec":"Wealth"},
{"n":627,"id":"TK-0627","ta":"இலக்கம் உடம்பிடும்பைக் கென்று கலக்கத்தைக் கையாறாக் கொள்ளாதாம் மேல்.","en":"The wise worry no more of woes Knowing body's butt of sorrows","ch":"இடுக்கண் அழியாமை","chEn":"Hopefulness in Trouble","chNo":63,"sec":"Wealth"},
{"n":628,"id":"TK-0628","ta":"இன்பம் விழையான் இடும்பை இயல்பென்பான் துன்பம் உறுதல் இலன்.","en":"Who seek not joy, deem grief norm By sorrows do not come to harm","ch":"இடுக்கண் அழியாமை","chEn":"Hopefulness in Trouble","chNo":63,"sec":"Wealth"},
{"n":629,"id":"TK-0629","ta":"இன்பத்துள் இன்பம் விழையாதான் துன்பத்துள் துன்பம் உறுதல் இலன்.","en":"In joy to joy who is not bound In grief he grieves not dual round!","ch":"இடுக்கண் அழியாமை","chEn":"Hopefulness in Trouble","chNo":63,"sec":"Wealth"},
{"n":630,"id":"TK-0630","ta":"இன்னாமை இன்பம் எனக்கொளின் ஆகுந்தன் ஒன்னார் விழையுஞ் சிறப்பு.","en":"His glory is esteemed by foes Who sees weal in wanton woes!","ch":"இடுக்கண் அழியாமை","chEn":"Hopefulness in Trouble","chNo":63,"sec":"Wealth"},
{"n":631,"id":"TK-0631","ta":"கருவியும் காலமும் செய்கையும் செய்யும் அருவினையும் மாண்டது அமைச்சு.","en":"He is minister who chooses Right means, time, mode and rare ventures","ch":"அமைச்சு","chEn":"The Office of Minister of state","chNo":64,"sec":"Wealth"},
{"n":632,"id":"TK-0632","ta":"வன்கண் குடிகாத்தல் கற்றறிதல் ஆள்வினையோடு ஐந்துடன் மாண்டது அமைச்சு.","en":"With these he guards people, -by his Knowledge, firmness and manliness","ch":"அமைச்சு","chEn":"The Office of Minister of state","chNo":64,"sec":"Wealth"},
{"n":633,"id":"TK-0633","ta":"பிரித்தலும் பேணிக் கொளலும் பிரிந்தார்ப் பொருத்தலும் வல்ல தமைச்சு.","en":"A minister cherishes friends Divides foes and the parted blends","ch":"அமைச்சு","chEn":"The Office of Minister of state","chNo":64,"sec":"Wealth"},
{"n":634,"id":"TK-0634","ta":"தெரிதலும் தேர்ந்து செயலும் ஒருதலையாச் சொல்லலும் வல்லது அமைச்சு.","en":"A minister must sift reflect Select and say surely one fact","ch":"அமைச்சு","chEn":"The Office of Minister of state","chNo":64,"sec":"Wealth"},
{"n":635,"id":"TK-0635","ta":"அறனறிந்து ஆன்றமைந்த சொல்லான்எஞ் ஞான்றுந் திறனறிந்தான் தேர்ச்சித் துணை.","en":"Have him for help who virtue knows Right wisdom speaks, ever apt in acts","ch":"அமைச்சு","chEn":"The Office of Minister of state","chNo":64,"sec":"Wealth"},
{"n":636,"id":"TK-0636","ta":"மதிநுட்பம் நூலோடு உடையார்க்கு அதிநுட்பம் யாவுள முன்நிற் பவை.","en":"Which subtler brain can stand before The keen in brain with learned love?","ch":"அமைச்சு","chEn":"The Office of Minister of state","chNo":64,"sec":"Wealth"},
{"n":637,"id":"TK-0637","ta":"செயற்கை அறிந்தக் கடைத்தும் உலகத்து இயற்கை அறிந்து செயல்.","en":"Albeit you know to act from books Act after knowing world's outlooks","ch":"அமைச்சு","chEn":"The Office of Minister of state","chNo":64,"sec":"Wealth"},
{"n":638,"id":"TK-0638","ta":"அறிகொன்று அறியான் எனினும் உறுதி உழையிருந்தான் கூறல் கடன்.","en":"The man in place must tell the facts Though the ignorant king refutes","ch":"அமைச்சு","chEn":"The Office of Minister of state","chNo":64,"sec":"Wealth"},
{"n":639,"id":"TK-0639","ta":"பழுதெண்ணும் மந்திரியின் பக்கததுள் தெவ்வோர் எழுபது கோடி உறும்.","en":"Seventy crores of foes are better Than a minister with mind bitter","ch":"அமைச்சு","chEn":"The Office of Minister of state","chNo":64,"sec":"Wealth"},
{"n":640,"id":"TK-0640","ta":"முறைப்படச் சூழ்ந்தும் முடிவிலவே செய்வர் திறப்பாடு இலாஅ தவர்.","en":"The unresolved, though well designed To fulfil an act they have no mind","ch":"அமைச்சு","chEn":"The Office of Minister of state","chNo":64,"sec":"Wealth"},
{"n":641,"id":"TK-0641","ta":"நாநலம் என்னும் நலனுடைமை அந்நலம் யாநலத்து உள்ளதூஉம் அன்று.","en":"The goodness called goodness of speech Is goodness which nothing can reach","ch":"சொல்வன்மை","chEn":"Power of Speech","chNo":65,"sec":"Wealth"},
{"n":642,"id":"TK-0642","ta":"ஆக்கமுங் கேடும் அதனால் வருதலால் காத்தோம்பல் சொல்லின்கட் சோர்வு.","en":"Since gain or ruin speeches bring Guard against the slips of tongue","ch":"சொல்வன்மை","chEn":"Power of Speech","chNo":65,"sec":"Wealth"},
{"n":643,"id":"TK-0643","ta":"கேட்டார்ப் பிணிக்கும் தகையவாய்க் கேளாரும் வேட்ப மொழிவதாம் சொல்.","en":"A speech is speech that holds ears And attracts ev'n those that are averse","ch":"சொல்வன்மை","chEn":"Power of Speech","chNo":65,"sec":"Wealth"},
{"n":644,"id":"TK-0644","ta":"திறனறிந்து சொல்லுக சொல்லை அறனும் பொருளும் அதனினூஉங்கு இல்.","en":"Weigh thy words and speak; because  No wealth or virtue words surpass","ch":"சொல்வன்மை","chEn":"Power of Speech","chNo":65,"sec":"Wealth"},
{"n":645,"id":"TK-0645","ta":"சொல்லுக சொல்லைப் பிறிதோர்சொல் அச்சொல்லை வெல்லுஞ்சொல் இன்மை அறிந்து.","en":"Speak out thy world so that no word Can win it and say untoward","ch":"சொல்வன்மை","chEn":"Power of Speech","chNo":65,"sec":"Wealth"},
{"n":646,"id":"TK-0646","ta":"வேட்பத்தாஞ் சொல்லிப் பிறர்சொல் பயன்கோடல் மாட்சியின் மாசற்றார் கோள்.","en":"Spotless men speak what is sweet And grasp in others what is meet","ch":"சொல்வன்மை","chEn":"Power of Speech","chNo":65,"sec":"Wealth"},
{"n":647,"id":"TK-0647","ta":"சொலல்வல்லன் சோர்விலன் அஞ்சான் அவனை இகல்வெல்லல் யார்க்கும் அரிது.","en":"No foe defies the speaker clear Flawless, puissant, and free from fear","ch":"சொல்வன்மை","chEn":"Power of Speech","chNo":65,"sec":"Wealth"},
{"n":648,"id":"TK-0648","ta":"விரைந்து தொழில்கேட்கும் ஞாலம் நிரந்தினிது சொல்லுதல் வல்லார்ப் பெறின்.","en":"The world will quickly carry out The words of counsellors astute","ch":"சொல்வன்மை","chEn":"Power of Speech","chNo":65,"sec":"Wealth"},
{"n":649,"id":"TK-0649","ta":"பலசொல்லக் காமுறுவர் மன்றமா சற்ற சிலசொல்லல் தேற்றா தவர்.","en":"They overspeak who do not seek A few and flawless words to speak","ch":"சொல்வன்மை","chEn":"Power of Speech","chNo":65,"sec":"Wealth"},
{"n":650,"id":"TK-0650","ta":"இணருழ்த்தும் நாறா மலரனையர் கற்றது உணர விரித்துரையா தார்.","en":"Who can't express what they have learnt Are bunch of flowers not fragrant","ch":"சொல்வன்மை","chEn":"Power of Speech","chNo":65,"sec":"Wealth"},
{"n":651,"id":"TK-0651","ta":"துணைநலம் ஆக்கம் த்ருஉம் வினைநலம் வேண்டிய எல்லாந் தரும்.","en":"Friendship brings gain; but action pure Does every good thing we desire","ch":"வினைத் தூய்மை","chEn":"Purity in Action","chNo":66,"sec":"Wealth"},
{"n":652,"id":"TK-0652","ta":"என்றும் ஒருவுதல் வேண்டும் புகழொடு நன்றி பயவா வினை.","en":"Eschew always acts that do not  Bring good nor glory on their part","ch":"வினைத் தூய்மை","chEn":"Purity in Action","chNo":66,"sec":"Wealth"},
{"n":653,"id":"TK-0653","ta":"ஒஓதல் வேண்டும் ஒளிமாழ்கும் செய்வினை ஆஅதும் என்னு மவர்.","en":"Those in the world desire for fame Should shun the deed that dims their name","ch":"வினைத் தூய்மை","chEn":"Purity in Action","chNo":66,"sec":"Wealth"},
{"n":654,"id":"TK-0654","ta":"இடுக்கண் படினும் இளிவந்த செய்யார் நடுக்கற்ற காட்சி யவர்.","en":"Though perils press the faultless wise Shun deeds of mean, shameful device","ch":"வினைத் தூய்மை","chEn":"Purity in Action","chNo":66,"sec":"Wealth"},
{"n":655,"id":"TK-0655","ta":"எற்றென்று இரங்குவ செய்யற்க செய்வானேல் மற்றன்ன செய்யாமை நன்று.","en":"Do not wrong act and grieve, \\\"Alas\\\"  If done, do not repeat it twice","ch":"வினைத் தூய்மை","chEn":"Purity in Action","chNo":66,"sec":"Wealth"},
{"n":656,"id":"TK-0656","ta":"ஈன்றாள் பசிகாண்பான் ஆயினுஞ் செய்யற்க சான்றோர் பழிக்கும் வினை.","en":"Though she who begot thee hungers Shun acts denounced by ancient seers","ch":"வினைத் தூய்மை","chEn":"Purity in Action","chNo":66,"sec":"Wealth"},
{"n":657,"id":"TK-0657","ta":"பழிமலைந்து எய்திய ஆக்கத்தின் சான்றோர் கழிநல் குரவே தலை.","en":"Pinching poverty of the wise Is more than wealth hoarded by Vice","ch":"வினைத் தூய்மை","chEn":"Purity in Action","chNo":66,"sec":"Wealth"},
{"n":658,"id":"TK-0658","ta":"கடிந்த கடிந்தொரார் செய்தார்க்கு அவைதாம் முடிந்தாலும் பீழை தரும்.","en":"Those who dare a forbidden deed Suffer troubles though they succeed","ch":"வினைத் தூய்மை","chEn":"Purity in Action","chNo":66,"sec":"Wealth"},
{"n":659,"id":"TK-0659","ta":"அழக்கொண்ட எல்லாம் அழப்போம் இழப்பினும் பிற்பயக்கும் நற்பா லவை.","en":"Gains from weeping, weeping go Though lost, from good deeds blessings flow","ch":"வினைத் தூய்மை","chEn":"Purity in Action","chNo":66,"sec":"Wealth"},
{"n":660,"id":"TK-0660","ta":"சலத்தால் பொருள்செய்தே மார்த்தல் பசுமண் கலத்துள்நீர் பெய்திரீஇ யற்று.","en":"The wealth gathered in guilty ways Is water poured in wet clay vase","ch":"வினைத் தூய்மை","chEn":"Purity in Action","chNo":66,"sec":"Wealth"},
{"n":661,"id":"TK-0661","ta":"வினைத்திட்பம் என்பது ஒருவன் மனத்திட்பம் மற்றைய எல்லாம் பிற.","en":"A powerful mind does powerful act And all the rest are imperfect","ch":"வினைத்திட்பம்","chEn":"Power in Action","chNo":67,"sec":"Wealth"},
{"n":662,"id":"TK-0662","ta":"ஊறொரால் உற்றபின் ஒல்காமை இவ்விரண்டின் ஆறென்பர் ஆய்ந்தவர் கோள்.","en":"Shun failing fuss; fail not purpose These two are maxims of the wise","ch":"வினைத்திட்பம்","chEn":"Power in Action","chNo":67,"sec":"Wealth"},
{"n":663,"id":"TK-0663","ta":"கடைக்கொட்கச் செய்தக்க தாண்மை இடைக்கொட்கின் எற்றா விழுமந் தரும்.","en":"The strong achieve and then display Woe unto work displayed midway","ch":"வினைத்திட்பம்","chEn":"Power in Action","chNo":67,"sec":"Wealth"},
{"n":664,"id":"TK-0664","ta":"சொல்லுதல் யார்க்கும் எளிய அரியவாம் சொல்லிய வண்ணம் செயல்.","en":"Easy it is to tell a fact But hard it is to know and act","ch":"வினைத்திட்பம்","chEn":"Power in Action","chNo":67,"sec":"Wealth"},
{"n":665,"id":"TK-0665","ta":"வீறெய்தி மாண்டார் வினைத்திட்பம் வேந்தன்கண் ஊறெய்தி உள்ளப் படும்.","en":"Dynamic deeds of a doughty soul Shall win the praise of king and all","ch":"வினைத்திட்பம்","chEn":"Power in Action","chNo":67,"sec":"Wealth"},
{"n":666,"id":"TK-0666","ta":"எண்ணிய எண்ணியாங்கு எய்துவர் எண்ணியார் திண்ணியர் ஆகப் பெறின்.","en":"The will-to-do achieves the deed When mind that wills is strong indeed","ch":"வினைத்திட்பம்","chEn":"Power in Action","chNo":67,"sec":"Wealth"},
{"n":667,"id":"TK-0667","ta":"உருவுகண்டு எள்ளாமை வேண்டும் உருள்பெருந்தேர்க்கு அச்சாணி அன்னார் உடைத்து.","en":"Scorn not the form: for men there are Like linchpin of big rolling car","ch":"வினைத்திட்பம்","chEn":"Power in Action","chNo":67,"sec":"Wealth"},
{"n":668,"id":"TK-0668","ta":"கலங்காது கண்ட வினைக்கண் துளங்காது தூக்கங் கடிந்து செயல்.","en":"Waver not; do wakefully  The deed resolved purposefully","ch":"வினைத்திட்பம்","chEn":"Power in Action","chNo":67,"sec":"Wealth"},
{"n":669,"id":"TK-0669","ta":"துன்பம் உறவரினும் செய்க துணிவாற்றி இன்பம் பயக்கும் வினை.","en":"Do with firm will though pains beset  The deed that brings delight at last","ch":"வினைத்திட்பம்","chEn":"Power in Action","chNo":67,"sec":"Wealth"},
{"n":670,"id":"TK-0670","ta":"எனைத்திட்பம் எய்தியக் கண்ணும் வினைத்திட்பம் வேண்டாரை வேண்டாது உலகு.","en":"The world merits no other strength But strength of will-to-do at length","ch":"வினைத்திட்பம்","chEn":"Power in Action","chNo":67,"sec":"Wealth"},
{"n":671,"id":"TK-0671","ta":"சூழ்ச்சி முடிவு துணிவெய்தல் அத்துணிவு தாழ்ச்சியுள் தங்குதல் தீது.","en":"When counsel takes a resolve strong Weak delay of action is wrong","ch":"வினை செயல்வகை","chEn":"Modes of Action","chNo":68,"sec":"Wealth"},
{"n":672,"id":"TK-0672","ta":"தூங்குக தூங்கிச் செயற்பால தூங்கற்க தூங்காது செய்யும் வினை.","en":"Delay such acts as need delay Delay not acts that need display","ch":"வினை செயல்வகை","chEn":"Modes of Action","chNo":68,"sec":"Wealth"},
{"n":673,"id":"TK-0673","ta":"ஒல்லும்வா யெல்லாம் வினைநன்றே ஒல்லாக்கால் செல்லும்வாய் நோக்கிச் செயல்.","en":"It's best to act when feasible If not see what is possible","ch":"வினை செயல்வகை","chEn":"Modes of Action","chNo":68,"sec":"Wealth"},
{"n":674,"id":"TK-0674","ta":"வினைபகை என்றிரண்டின் எச்சம் நினையுங்கால் தீயெச்சம் போலத் தெறும்.","en":"Work or foe left unfinished Flare up like fire unextinguished","ch":"வினை செயல்வகை","chEn":"Modes of Action","chNo":68,"sec":"Wealth"},
{"n":675,"id":"TK-0675","ta":"பொருள்கருவி காலம் வினையிடனொடு ஐந்தும் இருள்தீர எண்ணிச் செயல்.","en":"Money and means, time, place and deed Decide these five and then proceed","ch":"வினை செயல்வகை","chEn":"Modes of Action","chNo":68,"sec":"Wealth"},
{"n":676,"id":"TK-0676","ta":"முடிவும் இடையூறும் முற்றியாங்கு எய்தும் படுபயனும் பார்த்துச் செயல்.","en":"Weigh well the end, hindrance, profit  And then pursue a fitting act","ch":"வினை செயல்வகை","chEn":"Modes of Action","chNo":68,"sec":"Wealth"},
{"n":677,"id":"TK-0677","ta":"செய்வினை செய்வான் செயன்முறை அவ்வினை உள்ளறிவான் உள்ளம் கொளல்.","en":"Know first the secret from experts That is the way of fruitful acts","ch":"வினை செயல்வகை","chEn":"Modes of Action","chNo":68,"sec":"Wealth"},
{"n":678,"id":"TK-0678","ta":"வினையான் வினையாக்கிக் கோடல் நனைகவுள் யானையால் யானையாத் தற்று.","en":"Lure a tusker by a tusker Achieve a deed by deed better","ch":"வினை செயல்வகை","chEn":"Modes of Action","chNo":68,"sec":"Wealth"},
{"n":679,"id":"TK-0679","ta":"நட்டார்க்கு நல்ல செயலின் விரைந்ததே ஒட்டாரை ஒட்டிக் கொளல்.","en":"Than doing good to friends it is More urgent to befriend the foes","ch":"வினை செயல்வகை","chEn":"Modes of Action","chNo":68,"sec":"Wealth"},
{"n":680,"id":"TK-0680","ta":"உறைசிறியார் உள்நடுங்கல் அஞ்சிக் குறைபெறின் கொள்வர் பெரியார்ப் பணிந்து.","en":"Small statesmen fearing people's fear Submit to foes superior","ch":"வினை செயல்வகை","chEn":"Modes of Action","chNo":68,"sec":"Wealth"},
{"n":681,"id":"TK-0681","ta":"அன்புடைமை ஆன்ற குடிப்பிறத்தல் வேந்தவாம் பண்புடைமை தூதுரைப்பான் பண்பு.","en":"Love, noble birth, good courtesy Pleasing kings mark true embassy","ch":"தூது","chEn":"The Envoy","chNo":69,"sec":"Wealth"},
{"n":682,"id":"TK-0682","ta":"அன்பறிவு ஆராய்ந்த சொல்வன்மை தூதுரைப்பார்க்கு இன்றி யமையாத மூன்று.","en":"Envoys must bear love for their prince Knowledge and learned eloquence","ch":"தூது","chEn":"The Envoy","chNo":69,"sec":"Wealth"},
{"n":683,"id":"TK-0683","ta":"நூலாருள் நூல்வல்லன் ஆகுதல் வேலாருள் வென்றி வினையுரைப்பான் பண்பு.","en":"Savant among savants, he pleads  Before lanced king, triumphant words","ch":"தூது","chEn":"The Envoy","chNo":69,"sec":"Wealth"},
{"n":684,"id":"TK-0684","ta":"அறிவுரு வாராய்ந்த கல்விஇம் மூன்றன் செறிவுடையான் செல்க வினைக்கு.","en":"Who has these three: good form, sense, lore Can act as bold ambassador","ch":"தூது","chEn":"The Envoy","chNo":69,"sec":"Wealth"},
{"n":685,"id":"TK-0685","ta":"தொகச்சொல்லித் தூவாத நீக்கி நகச்சொல்லி நன்றி பயப்பதாந் தூது.","en":"Not harsh, the envoy's winsome ways Does good by pleasant words concise","ch":"தூது","chEn":"The Envoy","chNo":69,"sec":"Wealth"},
{"n":686,"id":"TK-0686","ta":"கற்றுக்கண் அஞ்சான் செலச்சொல்லிக் காலத்தால் தக்கது அறிவதாம் தூது.","en":"Learned; fearless, the envoy tends Convincing words which time demands","ch":"தூது","chEn":"The Envoy","chNo":69,"sec":"Wealth"},
{"n":687,"id":"TK-0687","ta":"கடனறிந்து காலங் கருதி இடனறிந்து எண்ணி உரைப்பான் தலை.","en":"Knowing duty time and place The envoy employs mature phrase","ch":"தூது","chEn":"The Envoy","chNo":69,"sec":"Wealth"},
{"n":688,"id":"TK-0688","ta":"தூய்மை துணைமை துணிவுடைமை இம்மூன்றின் வாய்மை வழியுரைப்பான் பண்பு.","en":"The true envoy of three virtues Is pure helpful and bold in views","ch":"தூது","chEn":"The Envoy","chNo":69,"sec":"Wealth"},
{"n":689,"id":"TK-0689","ta":"விடுமாற்றம் வேந்தர்க்கு உரைப்பான் வடுமாற்றம் வாய்சேரா வன்கணவன்.","en":"The envoy who ports the king's message Has flawless words and heart's courage","ch":"தூது","chEn":"The Envoy","chNo":69,"sec":"Wealth"},
{"n":690,"id":"TK-0690","ta":"இறுதி பயப்பினும் எஞ்சாது இறைவற்கு உறுதி பயப்பதாம் தூது.","en":"Braving death the bold envoy Assures his king's safety and joy","ch":"தூது","chEn":"The Envoy","chNo":69,"sec":"Wealth"},
{"n":691,"id":"TK-0691","ta":"அகலாது அணுகாது தீக்காய்வார் போல்க இகல்வேந்தர்ச் சேர்ந்தொழுகு வார்.","en":"Move with hostile kings as with fire  Not coming close nor going far","ch":"மன்னரைச் சேர்ந்து ஒழுகல்","chEn":"Conduct in the Presence of the King","chNo":70,"sec":"Wealth"},
{"n":692,"id":"TK-0692","ta":"மன்னர் விழைப விழையாமை மன்னரால் மன்னிய ஆக்கந் தரும்.","en":"Crave not for things which kings desire  This brings thee their fruitful favour","ch":"மன்னரைச் சேர்ந்து ஒழுகல்","chEn":"Conduct in the Presence of the King","chNo":70,"sec":"Wealth"},
{"n":693,"id":"TK-0693","ta":"போற்றின் அரியவை போற்றல் கடுத்தபின் தேற்றுதல் யார்க்கும் அரிது.","en":"Guard thyself from petty excess Suspected least, there's no redress","ch":"மன்னரைச் சேர்ந்து ஒழுகல்","chEn":"Conduct in the Presence of the King","chNo":70,"sec":"Wealth"},
{"n":694,"id":"TK-0694","ta":"செவிச்சொல்லும் சேர்ந்த நகையும் அவித்தொழுகல் ஆன்ற பெரியா ரகத்து.","en":"Whisper not; nor smile exchange Amidst august men's assemblage","ch":"மன்னரைச் சேர்ந்து ஒழுகல்","chEn":"Conduct in the Presence of the King","chNo":70,"sec":"Wealth"},
{"n":695,"id":"TK-0695","ta":"எப்பொருளும் ஓரார் தொடரார்மற் றப்பொருளை விட்டக்கால் கேட்க மறை.","en":"Hear not, ask not the king's secret Hear only when he lets it out","ch":"மன்னரைச் சேர்ந்து ஒழுகல்","chEn":"Conduct in the Presence of the King","chNo":70,"sec":"Wealth"},
{"n":696,"id":"TK-0696","ta":"குறிப்பறிந்து காலங் கருதி வெறுப்பில வேண்டுப வேட்பச் சொலல்.","en":"Discern his mood and time and tell No dislikes but what king likes well","ch":"மன்னரைச் சேர்ந்து ஒழுகல்","chEn":"Conduct in the Presence of the King","chNo":70,"sec":"Wealth"},
{"n":697,"id":"TK-0697","ta":"வேட்பன சொல்லி வினையில எஞ்ஞான்றும் கேட்பினும் சொல்லா விடல்.","en":"Tell pleasing things; and never tell Even if pressed what is futile","ch":"மன்னரைச் சேர்ந்து ஒழுகல்","chEn":"Conduct in the Presence of the King","chNo":70,"sec":"Wealth"},
{"n":698,"id":"TK-0698","ta":"இளையர் இனமுறையர் என்றிகழார் நின்ற ஒளியோடு ஒழுகப் படும்.","en":"As young and kinsman do not slight; Look with awe king's light and might","ch":"மன்னரைச் சேர்ந்து ஒழுகல்","chEn":"Conduct in the Presence of the King","chNo":70,"sec":"Wealth"},
{"n":699,"id":"TK-0699","ta":"கொளப்பட்டேம் என்றெண்ணிக் கொள்ளாத செய்யார் துளக்கற்ற காட்சி யவர்.","en":"The clear-visioned do nothing base Deeming they have the monarch's grace","ch":"மன்னரைச் சேர்ந்து ஒழுகல்","chEn":"Conduct in the Presence of the King","chNo":70,"sec":"Wealth"},
{"n":700,"id":"TK-0700","ta":"பழையம் எனக்கருதிப் பண்பல்ல செய்யும் கெழுதகைமை கேடு தரும்.","en":"Worthless acts based on friendship old  Shall spell ruin and woe untold","ch":"மன்னரைச் சேர்ந்து ஒழுகல்","chEn":"Conduct in the Presence of the King","chNo":70,"sec":"Wealth"},
{"n":701,"id":"TK-0701","ta":"கூறாமை நோக்கக் குறிப்பறிவான் எஞ்ஞான்றும் மாறாநீர் வையக் கணி.","en":"Who reads the mind by look, untold Adorns the changeless sea-girt world","ch":"குறிப்பறிதல்","chEn":"The Knowledge of Indications","chNo":71,"sec":"Wealth"},
{"n":702,"id":"TK-0702","ta":"ஐயப் படாஅது அகத்தது உணர்வானைத் தெய்வத்தோ டொப்பக் கொளல்.","en":"Take him as God who reads the thought Of another man with without a doubt","ch":"குறிப்பறிதல்","chEn":"The Knowledge of Indications","chNo":71,"sec":"Wealth"},
{"n":703,"id":"TK-0703","ta":"குறிப்பிற் குறிப்புணர் வாரை உறுப்பினுள் யாது கொடுத்தும் கொளல்.","en":"By sign who scans the sign admit At any cost in cabinet","ch":"குறிப்பறிதல்","chEn":"The Knowledge of Indications","chNo":71,"sec":"Wealth"},
{"n":704,"id":"TK-0704","ta":"குறித்தது கூறாமைக் கொள்வாரோ டேனை உறுப்போ ரனையரால் வேறு.","en":"Untold, he who divines the thought Though same in form is quite apart","ch":"குறிப்பறிதல்","chEn":"The Knowledge of Indications","chNo":71,"sec":"Wealth"},
{"n":705,"id":"TK-0705","ta":"குறிப்பிற் குறிப்புணரா வாயின் உறுப்பினுள் என்ன பயத்தவோ கண்?","en":"Among senses what for is eye If thought by thought one can't descry?","ch":"குறிப்பறிதல்","chEn":"The Knowledge of Indications","chNo":71,"sec":"Wealth"},
{"n":706,"id":"TK-0706","ta":"அடுத்தது காட்டும் பளிங்குபோல் நெஞ்சம் கடுத்தது காட்டும் முகம்.","en":"What throbs in mind the face reflects Just as mirror nearby objects","ch":"குறிப்பறிதல்","chEn":"The Knowledge of Indications","chNo":71,"sec":"Wealth"},
{"n":707,"id":"TK-0707","ta":"முகத்தின் முதுக்குறைந்தது உண்டோ உவப்பினும் காயினும் தான்முந் துறும்.","en":"Than face what is subtler to tell First if the mind feels well or ill","ch":"குறிப்பறிதல்","chEn":"The Knowledge of Indications","chNo":71,"sec":"Wealth"},
{"n":708,"id":"TK-0708","ta":"முகம்நோக்கி நிற்க அமையும் அகம்நோக்கி உற்ற துணர்வார்ப் பெறின்.","en":"Just standing in front would suffice For those who read the mind on face","ch":"குறிப்பறிதல்","chEn":"The Knowledge of Indications","chNo":71,"sec":"Wealth"},
{"n":709,"id":"TK-0709","ta":"பகைமையும் கேண்மையும் கண்ணுரைக்கும் கண்ணின் வகைமை உணர்வார்ப் பெறின்.","en":"Friend or foe the eyes will show To those who changing outlooks know","ch":"குறிப்பறிதல்","chEn":"The Knowledge of Indications","chNo":71,"sec":"Wealth"},
{"n":710,"id":"TK-0710","ta":"நுண்ணியம் என்பார் அளக்குங்கோல் காணுங்கால் கண்ணல்லது இல்லை பிற.","en":"The scale of keen discerning minds  Is eye and eye that secrets finds","ch":"குறிப்பறிதல்","chEn":"The Knowledge of Indications","chNo":71,"sec":"Wealth"},
{"n":711,"id":"TK-0711","ta":"அவையறிநது ஆராய்ந்து சொல்லுக சொல்லின் தொகையறிந்த தூய்மை யவர்.","en":"The pure in thought and eloquence  Adapt their words to audience","ch":"அவை அறிதல்","chEn":"The Knowledge of the Council Chamber","chNo":72,"sec":"Wealth"},
{"n":712,"id":"TK-0712","ta":"இடைதெரிந்து நன்குணர்ந்து சொல்லுக சொல்லின் நடைதெரிந்த நன்மை யவர்.","en":"Who know the art of speech shall suit Their chosen words to time in fact","ch":"அவை அறிதல்","chEn":"The Knowledge of the Council Chamber","chNo":72,"sec":"Wealth"},
{"n":713,"id":"TK-0713","ta":"அவையறியார் சொல்லல்மேற் கொள்பவர் சொல்லின் வகையறியார் வல்லதூஉம் இல்.","en":"They speak in vain at length who talk Words unversed which ears don't take","ch":"அவை அறிதல்","chEn":"The Knowledge of the Council Chamber","chNo":72,"sec":"Wealth"},
{"n":714,"id":"TK-0714","ta":"ஒளியார்முன் ஒள்ளிய ராதல் வெளியார்முன் வான்சுதை வண்ணம் கொளல்.","en":"Before the bright be brilliant light Before the muff be mortar white","ch":"அவை அறிதல்","chEn":"The Knowledge of the Council Chamber","chNo":72,"sec":"Wealth"},
{"n":715,"id":"TK-0715","ta":"நன்றென்ற வற்றுள்ளும் நன்றே முதுவருள் முந்து கிளவாச் செறிவு.","en":"Modest restraint all good excels Which argues not before elders","ch":"அவை அறிதல்","chEn":"The Knowledge of the Council Chamber","chNo":72,"sec":"Wealth"},
{"n":716,"id":"TK-0716","ta":"ஆற்றின் நிலைதளர்ந் தற்றே வியன்புலம் ஏற்றுணர்வார் முன்னர் இழுக்கு.","en":"Tongue-slip before the talented wise is like slipping from righteous ways","ch":"அவை அறிதல்","chEn":"The Knowledge of the Council Chamber","chNo":72,"sec":"Wealth"},
{"n":717,"id":"TK-0717","ta":"கற்றறிந்தார் கல்வி விளங்கும் கசடறச் சொல்தெரிதல் வல்லார் அகத்து.","en":"The learning of the learned shines Valued by flawless scholar-minds","ch":"அவை அறிதல்","chEn":"The Knowledge of the Council Chamber","chNo":72,"sec":"Wealth"},
{"n":718,"id":"TK-0718","ta":"உணர்வ துடையார்முன் சொல்லல் வளர்வதன் பாத்தியுள் நீர்சொரிந் தற்று.","en":"To address understanding ones Is to water beds of growing grains","ch":"அவை அறிதல்","chEn":"The Knowledge of the Council Chamber","chNo":72,"sec":"Wealth"},
{"n":719,"id":"TK-0719","ta":"புல்லவையுள் பொச்சாந்தும் சொல்லற்க நல்லவையுள் நன்குசலச் சொல்லு வார்.","en":"O ye who speak before the keen Forgetful, address not the mean","ch":"அவை அறிதல்","chEn":"The Knowledge of the Council Chamber","chNo":72,"sec":"Wealth"},
{"n":720,"id":"TK-0720","ta":"அங்கணத்துள் உக்க அமிழ்தற்றால் தங்கணத்தார் அல்லார்முன் கோட்டி கொளல்.","en":"To hostiles who wise words utters Pours ambrosia into gutters","ch":"அவை அறிதல்","chEn":"The Knowledge of the Council Chamber","chNo":72,"sec":"Wealth"},
{"n":721,"id":"TK-0721","ta":"வகையறிந்து வல்லவை வாய்சோரார் சொல்லின் தொகையறிந்த தூய்மை யவர்.","en":"The pure fail not in power of words Knowing grand council's moods and modes","ch":"அவை அஞ்சாமை","chEn":"Not to dread the Council","chNo":73,"sec":"Wealth"},
{"n":722,"id":"TK-0722","ta":"கற்றாருள் கற்றார் எனப்படுவர் கற்றார்முன் கற்ற செலச்சொல்லு வார்.","en":"Among scholars he is scholar Who holds scholars with learned lore","ch":"அவை அஞ்சாமை","chEn":"Not to dread the Council","chNo":73,"sec":"Wealth"},
{"n":723,"id":"TK-0723","ta":"பகையகத்துச் சாவார் எளியர் அரியர் அவையகத்து அஞ்சா தவர்.","en":"Many brave foes and die in fields The fearless few face wise councils","ch":"அவை அஞ்சாமை","chEn":"Not to dread the Council","chNo":73,"sec":"Wealth"},
{"n":724,"id":"TK-0724","ta":"கற்றார்முன் கற்ற செலச்சொல்லித் தாம்கற்ற மிக்காருள் மிக்க கொளல்.","en":"Impress the learned with your lore From greater savants learn still more","ch":"அவை அஞ்சாமை","chEn":"Not to dread the Council","chNo":73,"sec":"Wealth"},
{"n":725,"id":"TK-0725","ta":"ஆற்றின் அளவறிந்து கற்க அவையஞ்சா மாற்றங் கொடுத்தற் பொருட்டு.","en":"Grammar and logic learn so that Foes you can boldly retort","ch":"அவை அஞ்சாமை","chEn":"Not to dread the Council","chNo":73,"sec":"Wealth"},
{"n":726,"id":"TK-0726","ta":"வாளொடென் வன்கண்ணர் அல்லார்க்கு நூலொடென் நுண்ணவை அஞ்சு பவர்க்கு.","en":"To cowards what can sword avail And books to those who councils fail?","ch":"அவை அஞ்சாமை","chEn":"Not to dread the Council","chNo":73,"sec":"Wealth"},
{"n":727,"id":"TK-0727","ta":"பகையகத்துப் பேடிகை ஒள்வாள் அவையகத்து அஞ்சு மவன்கற்ற நூல்.","en":"Like eunuch's sword in field, is vain His lore who fears men of brain","ch":"அவை அஞ்சாமை","chEn":"Not to dread the Council","chNo":73,"sec":"Wealth"},
{"n":728,"id":"TK-0728","ta":"பல்லவை கற்றும் பயமிலரே நல்லவையுள் நன்கு செலச்சொல்லா தார்.","en":"Though learned much his lore is dead Who says no good before the good","ch":"அவை அஞ்சாமை","chEn":"Not to dread the Council","chNo":73,"sec":"Wealth"},
{"n":729,"id":"TK-0729","ta":"கல்லா தவரின் கடையென்ப கற்றறிந்தும் நல்லா ரவையஞ்சு வார்.","en":"Who fear to face good assembly Are learned idiots, certainly","ch":"அவை அஞ்சாமை","chEn":"Not to dread the Council","chNo":73,"sec":"Wealth"},
{"n":730,"id":"TK-0730","ta":"உளரெனினும் இல்லாரொடு ஒப்பர் களன்அஞ்சிக் கற்ற செலச்சொல்லா தார்.","en":"They are breathing dead who dare not Empress before the wise their art","ch":"அவை அஞ்சாமை","chEn":"Not to dread the Council","chNo":73,"sec":"Wealth"},
{"n":731,"id":"TK-0731","ta":"தள்ளா விளையுளும் தக்காரும் தாழ்விலாச் செல்வரும் சேர்வது நாடு.","en":"It's country which has souls of worth Unfailing yields and ample wealth","ch":"நாடு","chEn":"The Land","chNo":74,"sec":"Wealth"},
{"n":732,"id":"TK-0732","ta":"பெரும்பொருளால் பெட்டக்க தாகி அருங்கேட்டால் ஆற்ற விளைவது நாடு.","en":"The Land has large luring treasure Where pests are nil and yields are sure","ch":"நாடு","chEn":"The Land","chNo":74,"sec":"Wealth"},
{"n":733,"id":"TK-0733","ta":"பொறையொருங்கு மேல்வருங்கால் தாங்கி இறைவற்கு இறையொருங்கு நேர்வது நாடு.","en":"It's land that bears pressing burdens And pays its tax which king demands","ch":"நாடு","chEn":"The Land","chNo":74,"sec":"Wealth"},
{"n":734,"id":"TK-0734","ta":"உறுபசியும் ஓவாப் பிணியும் செறுபகையும் சேரா தியல்வது நாடு.","en":"It is country which is free from Fierce famine, plague and foemen's harm","ch":"நாடு","chEn":"The Land","chNo":74,"sec":"Wealth"},
{"n":735,"id":"TK-0735","ta":"பல்குழுவும் பாழ்செய்யும் உட்பகையும் வேந்தலைக்கும் கொல்குறும்பும் இல்லது நாடு.","en":"Sects and ruinous foes are nil No traitors in a land tranquil","ch":"நாடு","chEn":"The Land","chNo":74,"sec":"Wealth"},
{"n":736,"id":"TK-0736","ta":"கேடறியாக் கெட்ட இடத்தும் வளங்குன்றா நாடென்ப நாட்டின் தலை.","en":"The land of lands no ruin knows Even in grief its wealth yet grows","ch":"நாடு","chEn":"The Land","chNo":74,"sec":"Wealth"},
{"n":737,"id":"TK-0737","ta":"இருபுனலும் வாய்ந்த மலையும் வருபுனலும் வல்லரணும் நாட்டிற்கு உறுப்பு.","en":"Waters up and down, hills and streams With strong forts as limbs country beams","ch":"நாடு","chEn":"The Land","chNo":74,"sec":"Wealth"},
{"n":738,"id":"TK-0738","ta":"பிணியின்மை செல்வம் விளைவின்பம் ஏமம் அணியென்ப நாட்டிவ் வைந்து.","en":"Rich yield, delight, defence and wealth Are jewels of lands with blooming health","ch":"நாடு","chEn":"The Land","chNo":74,"sec":"Wealth"},
{"n":739,"id":"TK-0739","ta":"நாடென்ப நாடா வளத்தன நாடல்ல நாட வளந்தரு நாடு.","en":"A land is land which yields unsought Needing hard work the land is nought","ch":"நாடு","chEn":"The Land","chNo":74,"sec":"Wealth"},
{"n":740,"id":"TK-0740","ta":"ஆங்கமை வெய்தியக் கண்ணும் பயமின்றே வேந்தமை வில்லாத நாடு.","en":"Though a land has thus every thing It is worthless without a king","ch":"நாடு","chEn":"The Land","chNo":74,"sec":"Wealth"},
{"n":741,"id":"TK-0741","ta":"ஆற்று பவர்க்கும் அரண்பொருள் அஞ்சித்தற் போற்று பவர்க்கும் பொருள்.","en":"The fort is vital for offence Who fear the foes has its defence","ch":"அரண்","chEn":"The Fortification","chNo":75,"sec":"Wealth"},
{"n":742,"id":"TK-0742","ta":"மணிநீரும் மண்ணும் மலையும் அணிநிழற் காடும் உடைய தரண்.","en":"A crystal fount, a space a mount Thick woods form a fort paramount","ch":"அரண்","chEn":"The Fortification","chNo":75,"sec":"Wealth"},
{"n":743,"id":"TK-0743","ta":"உயர்வகலம் திண்மை அருமைஇந் நான்கின் அமைவரண் என்றுரைக்கும் நூல்.","en":"An ideal fort's so says science: High, broad, strong and hard for access","ch":"அரண்","chEn":"The Fortification","chNo":75,"sec":"Wealth"},
{"n":744,"id":"TK-0744","ta":"சிறுகாப்பிற் பேரிடத்த தாகி உறுபகை ஊக்கம் அழிப்ப தரண்.","en":"Ample in space, easy to hold The fort foils enemies bold","ch":"அரண்","chEn":"The Fortification","chNo":75,"sec":"Wealth"},
{"n":745,"id":"TK-0745","ta":"கொளற்கரிதாய்க் கொண்டகூழ்த் தாகி அகத்தார் நிலைக்கெளிதாம் நீரது அரண்.","en":"Impregnable with stores of food Cosy to live-That fort is good","ch":"அரண்","chEn":"The Fortification","chNo":75,"sec":"Wealth"},
{"n":746,"id":"TK-0746","ta":"எல்லாப் பொருளும் உடைத்தாய் இடத்துதவும் நல்லாள் உடையது அரண்.","en":"A fort is full of stores and arms And brave heroes to meet alarms","ch":"அரண்","chEn":"The Fortification","chNo":75,"sec":"Wealth"},
{"n":747,"id":"TK-0747","ta":"முற்றியும் முற்றா தெறிந்தும் அறைப்படுத்தும் பற்றற் கரியது அரண்.","en":"Besieging foes a fort withstands Darts and mines of treacherous hands","ch":"அரண்","chEn":"The Fortification","chNo":75,"sec":"Wealth"},
{"n":748,"id":"TK-0748","ta":"முற்றாற்றி முற்றி யவரையும் பற்றாற்றிப் பற்றியார் வெல்வது அரண்.","en":"A fort holds itself and defies The attacks of encircling foes","ch":"அரண்","chEn":"The Fortification","chNo":75,"sec":"Wealth"},
{"n":749,"id":"TK-0749","ta":"முனைமுகத்து மாற்றலர் சாய வினைமுகத்து வீறெய்தி மாண்ட தரண்.","en":"A fort it is that fells the foes And gains by deeds a name glorious","ch":"அரண்","chEn":"The Fortification","chNo":75,"sec":"Wealth"},
{"n":750,"id":"TK-0750","ta":"எனைமாட்சித் தாகியக் கண்ணும் வினைமாட்சி இல்லார்கண் இல்லது அரண்.","en":"But a fort however grand Is nil if heroes do not stand","ch":"அரண்","chEn":"The Fortification","chNo":75,"sec":"Wealth"},
{"n":751,"id":"TK-0751","ta":"பொருளல் லவரைப் பொருளாகச் செய்யும் பொருளல்லது இல்லை பொருள்.","en":"Naught exists that can, save wealth Make the worthless as men of worth","ch":"பொருள் செயல்வகை","chEn":"Way of Accumulating Wealth","chNo":76,"sec":"Wealth"},
{"n":752,"id":"TK-0752","ta":"இல்லாரை எல்லாரும் எள்ளுவர் செல்வரை எல்லாரும் செய்வர் சிறப்பு.","en":"The have-nothing poor all despise The men of wealth all raise and praise","ch":"பொருள் செயல்வகை","chEn":"Way of Accumulating Wealth","chNo":76,"sec":"Wealth"},
{"n":753,"id":"TK-0753","ta":"பொருளென்னும் பொய்யா விளக்கம் இருளறுக்கும் எண்ணிய தேயத்துச் சென்று.","en":"Waneless wealth is light that goes To every land and gloom removes","ch":"பொருள் செயல்வகை","chEn":"Way of Accumulating Wealth","chNo":76,"sec":"Wealth"},
{"n":754,"id":"TK-0754","ta":"அறன்ஈனும் இன்பமும் ஈனும் திறனறிந்து தீதின்றி வந்த பொருள்.","en":"The blameless wealth from fairest means Brings good virtue and also bliss","ch":"பொருள் செயல்வகை","chEn":"Way of Accumulating Wealth","chNo":76,"sec":"Wealth"},
{"n":755,"id":"TK-0755","ta":"அருளொடும் அன்பொடும் வாராப் பொருளாக்கம் புல்லார் புரள விடல்.","en":"Riches devoid of love and grace Off with it; it is disgrace!","ch":"பொருள் செயல்வகை","chEn":"Way of Accumulating Wealth","chNo":76,"sec":"Wealth"},
{"n":756,"id":"TK-0756","ta":"உறுபொருளும் உல்கு பொருளும்தன் ஒன்னார்த் தெறுபொருளும் வேந்தன் பொருள்.","en":"Escheats, derelicts; spoils of war Taxes duties are king's treasure","ch":"பொருள் செயல்வகை","chEn":"Way of Accumulating Wealth","chNo":76,"sec":"Wealth"},
{"n":757,"id":"TK-0757","ta":"அருளென்னும் அன்பீன் குழவி பொருளென்னும் செல்வச் செவிலியால் உண்டு.","en":"Grace the child of love is nourished By the wet-nurse of wealth cherished","ch":"பொருள் செயல்வகை","chEn":"Way of Accumulating Wealth","chNo":76,"sec":"Wealth"},
{"n":758,"id":"TK-0758","ta":"குன்றேறி யானைப்போர் கண்டற்றால் தன்கைத்தொன்று உண்டாகச் செய்வான் வினை.","en":"Treasures in hand fulfil all things Like hill-tuskers the wars of kings","ch":"பொருள் செயல்வகை","chEn":"Way of Accumulating Wealth","chNo":76,"sec":"Wealth"},
{"n":759,"id":"TK-0759","ta":"செய்க பொருளைச் செறுநர் செருக்கறுக்கும் எஃகதனிற் கூரிய தில்.","en":"Make wealth; there is no sharper steel The insolence of foes to quell","ch":"பொருள் செயல்வகை","chEn":"Way of Accumulating Wealth","chNo":76,"sec":"Wealth"},
{"n":760,"id":"TK-0760","ta":"ஒண்பொருள் காழ்ப்ப இயற்றியார்க்கு எண்பொருள் ஏனை இரண்டும் ஒருங்கு.","en":"They have joy and virtue at hand Who acquire treasures abundant","ch":"பொருள் செயல்வகை","chEn":"Way of Accumulating Wealth","chNo":76,"sec":"Wealth"},
{"n":761,"id":"TK-0761","ta":"உறுப்பமைந்து ஊறஞ்சா வெல்படை வேந்தன் வெறுக்கையுள் எல்லாம் தலை.","en":"The daring well-armed winning force Is king's treasure and main resource","ch":"படை மாட்சி","chEn":"The Excellence of an Army","chNo":77,"sec":"Wealth"},
{"n":762,"id":"TK-0762","ta":"உலைவிடத்து ஊறஞ்சா வன்கண் தொலைவிடத்துத் தொல்படைக் கல்லால் அரிது.","en":"Through shots and wounds brave heroes hold Quailing not in fall, the field","ch":"படை மாட்சி","chEn":"The Excellence of an Army","chNo":77,"sec":"Wealth"},
{"n":763,"id":"TK-0763","ta":"ஒலித்தக்கால் என்னாம் உவரி எலிப்பகை நாகம் உயிர்ப்பக் கெடும்.","en":"Sea-like ratfoes roar What if? They perish at a cobra's whiff","ch":"படை மாட்சி","chEn":"The Excellence of an Army","chNo":77,"sec":"Wealth"},
{"n":764,"id":"TK-0764","ta":"அழிவின்றி அறைபோகா தாகி வழிவந்த வன்க ணதுவே படை.","en":"The army guards its genial flame Not crushed, routed nor marred in name","ch":"படை மாட்சி","chEn":"The Excellence of an Army","chNo":77,"sec":"Wealth"},
{"n":765,"id":"TK-0765","ta":"கூற்றுடன்று மேல்வரினும் கூடி எதிர்நிற்கும் ஆற்ற லதுவே படை.","en":"The real army with rallied force Resists even Death-God fierce","ch":"படை மாட்சி","chEn":"The Excellence of an Army","chNo":77,"sec":"Wealth"},
{"n":766,"id":"TK-0766","ta":"மறமானம் மாண்ட வழிச்செலவு தேற்றம் எனநான்கே ஏமம் படைக்கு.","en":"Manly army has merits four:- Stately-march, faith, honour, valour","ch":"படை மாட்சி","chEn":"The Excellence of an Army","chNo":77,"sec":"Wealth"},
{"n":767,"id":"TK-0767","ta":"தார்தாங்கிச் செல்வது தானை தலைவந்த போர்தாங்கும் தன்மை அறிந்து.","en":"Army sets on to face to foes Knowing how the trend of war goes","ch":"படை மாட்சி","chEn":"The Excellence of an Army","chNo":77,"sec":"Wealth"},
{"n":768,"id":"TK-0768","ta":"அடல்தகையும் ஆற்றலும் இல்லெனினும் தானை படைத்தகையால் பாடு பெறும்.","en":"Army gains force by grand array Lacking in stay or dash in fray","ch":"படை மாட்சி","chEn":"The Excellence of an Army","chNo":77,"sec":"Wealth"},
{"n":769,"id":"TK-0769","ta":"சிறுமையும் செல்லாத் துனியும் வறுமையும் இல்லாயின் வெல்லும் படை.","en":"Army shall win if it is free From weakness, aversion, poverty","ch":"படை மாட்சி","chEn":"The Excellence of an Army","chNo":77,"sec":"Wealth"},
{"n":770,"id":"TK-0770","ta":"நிலைமக்கள் சால உடைத்தெனினும் தானை தலைமக்கள் இல்வழி இல்.","en":"With troops in large numbers on rolls Army can't march missing gen'rals","ch":"படை மாட்சி","chEn":"The Excellence of an Army","chNo":77,"sec":"Wealth"},
{"n":771,"id":"TK-0771","ta":"என்னைமுன் நில்லன்மின் தெவ்விர் பலரென்னை முன்நின்று கல்நின் றவர்.","en":"Stand not before my chief, O foes! Many who stood, in stones repose","ch":"படைச் செருக்கு","chEn":"Military Spirit","chNo":78,"sec":"Wealth"},
{"n":772,"id":"TK-0772","ta":"கான முயலெய்த அம்பினில் யானை பிழைத்தவேல் ஏந்தல் இனிது.","en":"To lift a lance that missed a tusker Is prouder than shaft that hit a hare","ch":"படைச் செருக்கு","chEn":"Military Spirit","chNo":78,"sec":"Wealth"},
{"n":773,"id":"TK-0773","ta":"பேராண்மை என்ப தறுகண்ஒன் றுற்றக்கால் ஊராண்மை மற்றதன் எஃகு.","en":"Valour is fight with fierce courage Mercy to the fallen is its edge","ch":"படைச் செருக்கு","chEn":"Military Spirit","chNo":78,"sec":"Wealth"},
{"n":774,"id":"TK-0774","ta":"கைவேல் களிற்றொடு போக்கி வருபவன் மெய்வேல் பறியா நகும்.","en":"At the tusker he flings his lance One in body smiles another chance","ch":"படைச் செருக்கு","chEn":"Military Spirit","chNo":78,"sec":"Wealth"},
{"n":775,"id":"TK-0775","ta":"விழித்தகண் வேல்கொண டெறிய அழித்திமைப்பின் ஒட்டன்றோ வன்க ணவர்க்கு.","en":"When lances dart if heroes wink \\\"It is a rout\\\" the world will think","ch":"படைச் செருக்கு","chEn":"Military Spirit","chNo":78,"sec":"Wealth"},
{"n":776,"id":"TK-0776","ta":"விழுப்புண் படாதநாள் எல்லாம் வழுக்கினுள் வைக்கும்தன் நாளை எடுத்து.","en":"The brave shall deem the days as vain Which did not battle-wounds sustain","ch":"படைச் செருக்கு","chEn":"Military Spirit","chNo":78,"sec":"Wealth"},
{"n":777,"id":"TK-0777","ta":"சுழலும் இசைவேண்டி வேண்டா உயிரார் கழல்யாப்புக் காரிகை நீர்த்து.","en":"Their anklets aloud jingle their name Who sacrifice their life for fame","ch":"படைச் செருக்கு","chEn":"Military Spirit","chNo":78,"sec":"Wealth"},
{"n":778,"id":"TK-0778","ta":"உறின்உயிர் அஞ்சா மறவர் இறைவன் செறினும் சீர்குன்றல் இலர்.","en":"The king may chide, they pursue strife; They fear loss of glory; not life","ch":"படைச் செருக்கு","chEn":"Military Spirit","chNo":78,"sec":"Wealth"},
{"n":779,"id":"TK-0779","ta":"இழைத்தது இகவாமைச் சாவாரை யாரே பிழைத்தது ஒறுக்கிற் பவர்.","en":"Who will blame the heroes that lose Their lives in war to keep their vows?","ch":"படைச் செருக்கு","chEn":"Military Spirit","chNo":78,"sec":"Wealth"},
{"n":780,"id":"TK-0780","ta":"புரந்தார்கண் நீர்மல்கச் சாகிற்பின் சாக்காடு இரந்துகோள் தக்கது உடைத்து.","en":"Such a death shall be prayed for Which draws the the tears of the ruler","ch":"படைச் செருக்கு","chEn":"Military Spirit","chNo":78,"sec":"Wealth"},
{"n":781,"id":"TK-0781","ta":"செயற்கரிய யாவுள நட்பின் அதுபோல் வினைக்கரிய யாவுள காப்பு.","en":"Like friendship what's so hard to gain? That guards one against acts villain?","ch":"நட்பு","chEn":"Friendship","chNo":79,"sec":"Wealth"},
{"n":782,"id":"TK-0782","ta":"நிறைநீர நீரவர் கேண்மை பிறைமதிப் பின்னீர பேதையார் நட்பு.","en":"Good friendship shines like waxing moon, The bad withers like waning moon","ch":"நட்பு","chEn":"Friendship","chNo":79,"sec":"Wealth"},
{"n":783,"id":"TK-0783","ta":"நவில்தொறும் நூல்நயம் போலும் பயில்தொறும் பண்புடை யாளர் தொடர்பு.","en":"Like taste in books good friendship grows The more one moves the more he knows","ch":"நட்பு","chEn":"Friendship","chNo":79,"sec":"Wealth"},
{"n":784,"id":"TK-0784","ta":"நகுதற் பொருட்டன்று நட்டல் மிகுதிக்கண் மேற்செனறு இடித்தற் பொருட்டு.","en":"Not to laugh is friendship made But to hit when faults exceed","ch":"நட்பு","chEn":"Friendship","chNo":79,"sec":"Wealth"},
{"n":785,"id":"TK-0785","ta":"புணர்ச்சி பழகுதல் வேண்டா உணர்ச்சிதான் நட்பாங் கிழமை தரும்.","en":"No close living nor clasping grip Friendship's feeling heart's fellowship","ch":"நட்பு","chEn":"Friendship","chNo":79,"sec":"Wealth"},
{"n":786,"id":"TK-0786","ta":"முகநக நட்பது நட்பன்று நெஞ்சத்து அகநக நட்பது நட்பு.","en":"Friendship is not more smile on face It is the smiling heart's embrace","ch":"நட்பு","chEn":"Friendship","chNo":79,"sec":"Wealth"},
{"n":787,"id":"TK-0787","ta":"அழிவி னவைநீக்கி ஆறுய்த்து அழிவின்கண் அல்லல் உழப்பதாம் நட்பு.","en":"From ruin friendship saves and shares The load of pain and right path shows","ch":"நட்பு","chEn":"Friendship","chNo":79,"sec":"Wealth"},
{"n":788,"id":"TK-0788","ta":"உடுக்கை இழந்தவன் கைபோல ஆங்கே இடுக்கண் களைவதாம் நட்பு.","en":"Friendship hastens help in mishaps Like hands picking up dress that slips","ch":"நட்பு","chEn":"Friendship","chNo":79,"sec":"Wealth"},
{"n":789,"id":"TK-0789","ta":"நட்பிற்கு வீற்றிருக்கை யாதெனின் கொட்பின்றி ஒல்லும்வாய் ஊன்றும் நிலை.","en":"Friendship is enthroned on the strength That always helps with utmost warmth","ch":"நட்பு","chEn":"Friendship","chNo":79,"sec":"Wealth"},
{"n":790,"id":"TK-0790","ta":"இனையர் இவரெமக்கு இன்னம்யாம் என்று புனையினும் புல்லென்னும் நட்பு.","en":"\\\"Such we are and such they are!\\\" Ev'n this boast will friendship mar","ch":"நட்பு","chEn":"Friendship","chNo":79,"sec":"Wealth"},
{"n":791,"id":"TK-0791","ta":"நாடாது நட்டலிற் கேடில்லை நட்டபின் வீடில்லை நட்பாள் பவர்க்கு.","en":"Than testless friendship nought is worse For contacts formed will scarcely cease","ch":"நட்பாராய்தல்","chEn":"Investigation in forming Friendships","chNo":80,"sec":"Wealth"},
{"n":792,"id":"TK-0792","ta":"ஆய்ந்தாய்ந்து கொள்ளாதான் கேண்மை கடைமுறை தான்சாம் துயரம் தரும்.","en":"Friendship made without frequent test Shall end in grief and death at last","ch":"நட்பாராய்தல்","chEn":"Investigation in forming Friendships","chNo":80,"sec":"Wealth"},
{"n":793,"id":"TK-0793","ta":"குணமும் குடிமையும் குற்றமும் குன்றா இனனும் அறிந்தியாக்க நட்பு.","en":"Temper, descent, defects and kins Trace well and take companions","ch":"நட்பாராய்தல்","chEn":"Investigation in forming Friendships","chNo":80,"sec":"Wealth"},
{"n":794,"id":"TK-0794","ta":"குடிப்பிறந்து தன்கண் பழிநாணு வானைக் கொடுத்தும் கொளல்வேண்டும் நட்பு.","en":"Take as good friend at any price The nobly born who shun disgrace","ch":"நட்பாராய்தல்","chEn":"Investigation in forming Friendships","chNo":80,"sec":"Wealth"},
{"n":795,"id":"TK-0795","ta":"அழச்சொல்லி அல்லது இடித்து வழக்கறிய வல்லார்நடபு ஆய்ந்து கொளல்.","en":"Who make you weep and chide wrong trends And lead you right are worthy friends","ch":"நட்பாராய்தல்","chEn":"Investigation in forming Friendships","chNo":80,"sec":"Wealth"},
{"n":796,"id":"TK-0796","ta":"கேட்டினும் உண்டோர் உறுதி கிளைஞரை நீட்டி அளப்பதோர் கோல்.","en":"Is there a test like misfortune A rod to measure out kinsmen?","ch":"நட்பாராய்தல்","chEn":"Investigation in forming Friendships","chNo":80,"sec":"Wealth"},
{"n":797,"id":"TK-0797","ta":"ஊதியம் என்பது ஒருவற்குப் பேதையார் கேண்மை ஒரீஇ விடல்.","en":"Keep off contacts with fools; that is The greatest gain so say the wise","ch":"நட்பாராய்தல்","chEn":"Investigation in forming Friendships","chNo":80,"sec":"Wealth"},
{"n":798,"id":"TK-0798","ta":"உள்ளற்க உள்ளம் சிறுகுவ கொள்ளற்க அல்லற்கண் ஆற்றறுப்பார் நட்பு.","en":"Off with thoughts that depress the heart Off with friends that in woe depart","ch":"நட்பாராய்தல்","chEn":"Investigation in forming Friendships","chNo":80,"sec":"Wealth"},
{"n":799,"id":"TK-0799","ta":"கெடுங்காலைக் கைவிடுவார் கேண்மை அடுங்காலை உள்ளினும் உள்ளஞ் சுடும்.","en":"Friends who betray at ruin's brink Burn our mind ev'n at death to think","ch":"நட்பாராய்தல்","chEn":"Investigation in forming Friendships","chNo":80,"sec":"Wealth"},
{"n":800,"id":"TK-0800","ta":"மருவுக மாசற்றார் கேண்மைஒன் றீத்தும் ஒருவுக ஒப்பிலார் நட்பு.","en":"The blameless ones as friends embarace; Give something and give up the base","ch":"நட்பாராய்தல்","chEn":"Investigation in forming Friendships","chNo":80,"sec":"Wealth"},
{"n":801,"id":"TK-0801","ta":"பழைமை எனப்படுவது யாதெனின் யாதும் கிழமையைக் கீழ்ந்திடா நட்பு.","en":"That friendship is good amity Which restrains not one's liberty","ch":"பழைமை","chEn":"Familiarity","chNo":81,"sec":"Wealth"},
{"n":802,"id":"TK-0802","ta":"நட்பிற் குறுப்புக் கெழுதகைமை மற்றதற்கு உப்பாதல் சான்றோர் கடன்.","en":"Friendship's heart is freedom close; Wise men's duty is such to please","ch":"பழைமை","chEn":"Familiarity","chNo":81,"sec":"Wealth"},
{"n":803,"id":"TK-0803","ta":"பழகிய நட்பெவன் செய்யுங் கெழுதகைமை செய்தாங்கு அமையாக் கடை.","en":"Of long friendship what is the use Righteous freedom if men refuse?","ch":"பழைமை","chEn":"Familiarity","chNo":81,"sec":"Wealth"},
{"n":804,"id":"TK-0804","ta":"விழைதகையான் வேண்டி இருப்பர் கெழுதகையாற் கேளாது நட்டார் செயின்.","en":"Things done unasked by loving friends Please the wise as familiar trends!","ch":"பழைமை","chEn":"Familiarity","chNo":81,"sec":"Wealth"},
{"n":805,"id":"TK-0805","ta":"பேதைமை ஒன்றோ பெருங்கிழமை என்றுணர்க நோதக்க நட்டார் செயின்.","en":"Offence of friends feel it easy As folloy or close intimacy","ch":"பழைமை","chEn":"Familiarity","chNo":81,"sec":"Wealth"},
{"n":806,"id":"TK-0806","ta":"எல்லைக்கண் நின்றார் துறவார் தொலைவிடத்தும் தொல்லைக்கண் நின்றார் தொடர்பு.","en":"They forsake not but continue In friendship's bounds though loss ensue","ch":"பழைமை","chEn":"Familiarity","chNo":81,"sec":"Wealth"},
{"n":807,"id":"TK-0807","ta":"அழிவந்த செய்யினும் அன்பறார் அன்பின் வழிவந்த கேண்மை யவர்.","en":"Comrades established in firm love Though ruin comes waive not their vow","ch":"பழைமை","chEn":"Familiarity","chNo":81,"sec":"Wealth"},
{"n":808,"id":"TK-0808","ta":"கேளிழுக்கம் கேளாக் கெழுதகைமை வல்லார்க்கு நாளிழுக்கம் நட்டார் செயின்.","en":"Fast friends who list not tales of ill Though wronged they say \\\"that day is well\\\"","ch":"பழைமை","chEn":"Familiarity","chNo":81,"sec":"Wealth"},
{"n":809,"id":"TK-0809","ta":"கெடாஅ வழிவந்த கேண்மையார் கேண்மை விடாஅர் விழையும் உலகு.","en":"To love such friends the world desires Whose friendship has unbroken ties","ch":"பழைமை","chEn":"Familiarity","chNo":81,"sec":"Wealth"},
{"n":810,"id":"TK-0810","ta":"விழையார் விழையப் படுப பழையார்கண் பண்பின் தலைப்பிரியா தார்.","en":"Even foes love for better ends Those who leave not long-standing friends","ch":"பழைமை","chEn":"Familiarity","chNo":81,"sec":"Wealth"},
{"n":811,"id":"TK-0811","ta":"பருகுவார் போலினும் பண்பிலார் கேண்மை பெருகலிற் குன்றல் இனிது.","en":"Swallowing love of soulless men Had better wane than wax anon","ch":"தீ நட்பு","chEn":"Evil Friendship","chNo":82,"sec":"Wealth"},
{"n":812,"id":"TK-0812","ta":"உறின்நட்டு அறினொருஉம் ஒப்பிலார் கேண்மை பெறினும் இழப்பினும் என்?","en":"Who fawn in wealth and fail in dearth Gain or lose; such friends have no worth","ch":"தீ நட்பு","chEn":"Evil Friendship","chNo":82,"sec":"Wealth"},
{"n":813,"id":"TK-0813","ta":"உறுவது சீர்தூக்கும் நட்பும் பெறுவது கொள்வாரும் கள்வரும் நேர்.","en":"Cunning friends who calculate  Are like thieves and whores wicked","ch":"தீ நட்பு","chEn":"Evil Friendship","chNo":82,"sec":"Wealth"},
{"n":814,"id":"TK-0814","ta":"அமரகத்து ஆற்றறுக்கும் கல்லாமா அன்னார் தமரின் தனிமை தலை.","en":"Better be alone than trust in those That throw in field like faithless horse","ch":"தீ நட்பு","chEn":"Evil Friendship","chNo":82,"sec":"Wealth"},
{"n":815,"id":"TK-0815","ta":"செய்தேமஞ் சாராச் சிறியவர் புன்கேண்மை எய்தலின் எய்தாமை நன்று.","en":"Friends low and mean that give no help- Leave them is better than to keep","ch":"தீ நட்பு","chEn":"Evil Friendship","chNo":82,"sec":"Wealth"},
{"n":816,"id":"TK-0816","ta":"பேதை பெருங்கெழீஇ நட்பின் அறிவுடையார் ஏதின்மை கோடி உறும்.","en":"Million times the wise man's hate Is better than a fool intimate","ch":"தீ நட்பு","chEn":"Evil Friendship","chNo":82,"sec":"Wealth"},
{"n":817,"id":"TK-0817","ta":"நகைவகைய ராகிய நட்பின் பகைவரால் பத்தடுத்த கோடி உறும்.","en":"Ten-fold crore you gain from foes Than from friends who are vain laughers","ch":"தீ நட்பு","chEn":"Evil Friendship","chNo":82,"sec":"Wealth"},
{"n":818,"id":"TK-0818","ta":"ஒல்லும் கருமம் உடற்று பவர்கேண்மை சொல்லாடார் சோர விடல்.","en":"Without a word those friends eschew Who spoil deeds which they can do","ch":"தீ நட்பு","chEn":"Evil Friendship","chNo":82,"sec":"Wealth"},
{"n":819,"id":"TK-0819","ta":"கனவினும் இன்னாது மன்னோ வினைவேறு சொல்வேறு பட்டார் தொடர்பு.","en":"Even in dreams the tie is bad With those whose deed is far from word","ch":"தீ நட்பு","chEn":"Evil Friendship","chNo":82,"sec":"Wealth"},
{"n":820,"id":"TK-0820","ta":"எனைத்தும் குறுகுதல் ஓம்பல் மனைக்கெழீஇ மன்றில் பழிப்பார் தொடர்பு.","en":"Keep aloof from those that smile At home and in public revile","ch":"தீ நட்பு","chEn":"Evil Friendship","chNo":82,"sec":"Wealth"},
{"n":821,"id":"TK-0821","ta":"சீரிடம் காணின் எறிதற்குப் பட்டடை நேரா நிரந்தவர் நட்பு.","en":"The friendship by an enemy shown Is anvil in time, to strike you down","ch":"கூடா நட்பு","chEn":"Unreal Friendship","chNo":83,"sec":"Wealth"},
{"n":822,"id":"TK-0822","ta":"இனம்போன்று இனமல்லார் கேண்மை மகளிர் மனம்போல வேறு படும்.","en":"Who pretend kinship but are not Their friendship's fickle like woman's heart","ch":"கூடா நட்பு","chEn":"Unreal Friendship","chNo":83,"sec":"Wealth"},
{"n":823,"id":"TK-0823","ta":"பலநல்ல கற்றக் கடைத்து மனநல்லர் ஆகுதல் மாணார்க் கரிது.","en":"They may be vast in good studies But heartfelt-love is hard for foes","ch":"கூடா நட்பு","chEn":"Unreal Friendship","chNo":83,"sec":"Wealth"},
{"n":824,"id":"TK-0824","ta":"முகத்தின் இனிய நகாஅ அகத்தின்னா வஞ்சரை அஞ்சப் படும்.","en":"Fear foes whose face has winning smiles Whose heart is full of cunning guiles","ch":"கூடா நட்பு","chEn":"Unreal Friendship","chNo":83,"sec":"Wealth"},
{"n":825,"id":"TK-0825","ta":"மனத்தின் அமையா தவரை எனைத்தொன்றும் சொல்லினால் தேறற்பாற்று அன்று.","en":"Do not trust in what they tell Whose mind with your mind goes ill","ch":"கூடா நட்பு","chEn":"Unreal Friendship","chNo":83,"sec":"Wealth"},
{"n":826,"id":"TK-0826","ta":"நட்டார்போல் நல்லவை சொல்லினும் ஒட்டார்சொல் ஒல்லை உணரப் படும்.","en":"The words of foes is quickly seen Though they speak like friends in fine","ch":"கூடா நட்பு","chEn":"Unreal Friendship","chNo":83,"sec":"Wealth"},
{"n":827,"id":"TK-0827","ta":"சொல்வணக்கம் ஒன்னார்கண் கொள்ளற்க வில்வணக்கம் தீங்கு குறித்தமை யான்.","en":"Trust not the humble words of foes Danger darts from bending bows","ch":"கூடா நட்பு","chEn":"Unreal Friendship","chNo":83,"sec":"Wealth"},
{"n":828,"id":"TK-0828","ta":"தொழுதகை யுள்ளும் படையொடுங்கும் ஒன்னார் அழுதகண் ணீரும் அனைத்து.","en":"Adoring hands of foes hide arms Their sobbing tears have lurking harms","ch":"கூடா நட்பு","chEn":"Unreal Friendship","chNo":83,"sec":"Wealth"},
{"n":829,"id":"TK-0829","ta":"மிகச்செய்து தம்மெள்ளு வாரை நகச்செய்து நட்பினுள் சாப்புல்லற் பாற்று.","en":"In open who praise, at heart despise Cajole and crush them in friendly guise","ch":"கூடா நட்பு","chEn":"Unreal Friendship","chNo":83,"sec":"Wealth"},
{"n":830,"id":"TK-0830","ta":"பகைநட்பாம் காலம் வருங்கால் முகநட்டு அகநட்பு ஒரீஇ விடல்.","en":"When foes, in time, play friendship's part Feign love on face but not in heart","ch":"கூடா நட்பு","chEn":"Unreal Friendship","chNo":83,"sec":"Wealth"},
{"n":831,"id":"TK-0831","ta":"பேதைமை என்பதொன்று யாதெனின் ஏதங்கொண்டு ஊதியம் போக விடல்.","en":"This is folly's prominent vein To favour loss and forego gain","ch":"பேதைமை","chEn":"Folly","chNo":84,"sec":"Wealth"},
{"n":832,"id":"TK-0832","ta":"பேதைமையுள் எல்லாம் பேதைமை காதன்மை கையல்ல தன்கட் செயல்.","en":"Folly of follies is to lead A lewd and lawless life so bad","ch":"பேதைமை","chEn":"Folly","chNo":84,"sec":"Wealth"},
{"n":833,"id":"TK-0833","ta":"நாணாமை நாடாமை நாரின்மை யாதொன்றும் பேணாமை பேதை தொழில்","en":"Shameless, aimless, callous, listless Such are the marks of foolishness","ch":"பேதைமை","chEn":"Folly","chNo":84,"sec":"Wealth"},
{"n":834,"id":"TK-0834","ta":"ஓதி உணர்ந்தும் பிறர்க்குரைத்தும் தானடங்காப் பேதையின் பேதையார் இல்.","en":"No fool equals the fool who learns Knows, teaches, but self-control spurns","ch":"பேதைமை","chEn":"Folly","chNo":84,"sec":"Wealth"},
{"n":835,"id":"TK-0835","ta":"ஒருமைச் செயலாற்றும் பேதை எழுமையும் தான்புக் கழுந்தும் அளறு.","en":"The fool suffers seven fold hells In single birth of hellish ills","ch":"பேதைமை","chEn":"Folly","chNo":84,"sec":"Wealth"},
{"n":836,"id":"TK-0836","ta":"பொய்படும் ஒன்றோ புனைபூணும் கையறியாப் பேதை வினைமேற் கொளின்.","en":"A know-nothing fool daring a deed Not only fails but feels fettered","ch":"பேதைமை","chEn":"Folly","chNo":84,"sec":"Wealth"},
{"n":837,"id":"TK-0837","ta":"ஏதிலார் ஆரத் தமர்பசிப்பர் பேதை பெருஞ்செல்வம் உற்றக் கடை.","en":"Strangers feast and kinsmen fast  When fools mishandle fortunes vast","ch":"பேதைமை","chEn":"Folly","chNo":84,"sec":"Wealth"},
{"n":838,"id":"TK-0838","ta":"மையல் ஒருவன் களித்தற்றால் பேதைதன் கையொன்று உடைமை பெறின்.","en":"Fools possessing something on hand Like dazed and drunken stupids stand","ch":"பேதைமை","chEn":"Folly","chNo":84,"sec":"Wealth"},
{"n":839,"id":"TK-0839","ta":"பெரிதினிது பேதையார் கேண்மை பிரிவின்கண் பீழை தருவதொன் றில்.","en":"Friendship with fools is highly sweet For without a groan we part","ch":"பேதைமை","chEn":"Folly","chNo":84,"sec":"Wealth"},
{"n":840,"id":"TK-0840","ta":"கழாஅக்கால் பள்ளியுள் வைத்தற்றால் சான்றோர் குழாஅத்துப் பேதை புகல்.","en":"Entrance of fools where Savants meet Looks like couch trod by unclean feet","ch":"பேதைமை","chEn":"Folly","chNo":84,"sec":"Wealth"},
{"n":841,"id":"TK-0841","ta":"அறிவின்மை இன்மையுள் இன்மை பிறிதின்மை இன்மையா வையா துலகு.","en":"Want of wisdom is want of wants Want of aught else the world nev'r counts","ch":"புல்லறிவாண்மை","chEn":"Ignorance","chNo":85,"sec":"Wealth"},
{"n":842,"id":"TK-0842","ta":"அறிவிலான் நெஞ்சுவந்து ஈதல் பிறிதியாதும் இல்லை பெறுவான் தவம்.","en":"When fool bestows with glee a gift It comes but by getter's merit","ch":"புல்லறிவாண்மை","chEn":"Ignorance","chNo":85,"sec":"Wealth"},
{"n":843,"id":"TK-0843","ta":"அறிவிலார் தாந்தம்மைப் பீழிக்கும் பீழை செறுவார்க்கும் செய்தல் அரிது.","en":"The self-torments of fools exceed Ev'n tortures of their foes indeed","ch":"புல்லறிவாண்மை","chEn":"Ignorance","chNo":85,"sec":"Wealth"},
{"n":844,"id":"TK-0844","ta":"வெண்மை எனப்படுவ தியாதெனின் ஒண்மை உடையம்யாம் என்னும் செருக்கு.","en":"Stupidity is vanity That cries \\\"We have sagacity\\\"","ch":"புல்லறிவாண்மை","chEn":"Ignorance","chNo":85,"sec":"Wealth"},
{"n":845,"id":"TK-0845","ta":"கல்லாத மேற்கொண் டொழுகல் கசடற வல்லதூஉம் ஐயம் தரும்.","en":"Feigning knowledge that one has not Leads to doubt ev'n that he has got","ch":"புல்லறிவாண்மை","chEn":"Ignorance","chNo":85,"sec":"Wealth"},
{"n":846,"id":"TK-0846","ta":"அற்றம் மறைத்தலோ புல்லறிவு தம்வயின் குற்றம் மறையா வழி.","en":"Fools their nakedness conceal And yet their glaring faults reveal","ch":"புல்லறிவாண்மை","chEn":"Ignorance","chNo":85,"sec":"Wealth"},
{"n":847,"id":"TK-0847","ta":"அருமறை சோரும் அறிவிலான் செய்யும் பெருமிறை தானே தனக்கு.","en":"The fool that slights sacred counsels Upon himself great harm entails","ch":"புல்லறிவாண்மை","chEn":"Ignorance","chNo":85,"sec":"Wealth"},
{"n":848,"id":"TK-0848","ta":"ஏவவும் செய்கலான் தான்தேறான் அவ்வுயிர் போஒம் அளவுமோர் நோய்.","en":"He listens not nor himself knows Plague is his life until it goes","ch":"புல்லறிவாண்மை","chEn":"Ignorance","chNo":85,"sec":"Wealth"},
{"n":849,"id":"TK-0849","ta":"காணாதான் காட்டுவான் தான்காணான் காணாதான் கண்டானாம் தான்கண்ட வாறு.","en":"Sans Self-sight in vain one opens Sight To the blind who bet their sight as right","ch":"புல்லறிவாண்மை","chEn":"Ignorance","chNo":85,"sec":"Wealth"},
{"n":850,"id":"TK-0850","ta":"உலகத்தார் உண்டென்பது இல்லென்பான் வையத்து அலகையா வைக்கப் படும்.","en":"To people's \\\"Yes\\\" who proffer \\\"No\\\" Deemed as ghouls on earth they go","ch":"புல்லறிவாண்மை","chEn":"Ignorance","chNo":85,"sec":"Wealth"},
{"n":851,"id":"TK-0851","ta":"இகலென்ப எல்லா உயிர்க்கும் பகலென்னும் பண்பின்மை பார஧க்கும் நோய்.","en":"Hatred is a plague that divides And rouses illwill on all sides","ch":"இகல்","chEn":"Hostility","chNo":86,"sec":"Wealth"},
{"n":852,"id":"TK-0852","ta":"பகல்கருதிப் பற்றா செயினும் இகல்கருதி இன்னாசெய் யாமை தலை.","en":"Rouse not hatred and confusion Though foes provoke disunion","ch":"இகல்","chEn":"Hostility","chNo":86,"sec":"Wealth"},
{"n":853,"id":"TK-0853","ta":"இகலென்னும் எவ்வநோய் நீக்கின் தவலில்லாத் தாவில் விளக்கம் தரும்.","en":"Shun the plague of enmity And win everlasting glory","ch":"இகல்","chEn":"Hostility","chNo":86,"sec":"Wealth"},
{"n":854,"id":"TK-0854","ta":"இன்பத்துள் இன்பம் பயக்கும் இகலென்னும் துன்பத்துள் துன்பங் கெடின்.","en":"Hate-the woe of woes destroy; Then joy of joys you can enjoy","ch":"இகல்","chEn":"Hostility","chNo":86,"sec":"Wealth"},
{"n":855,"id":"TK-0855","ta":"இகலெதிர் சாய்ந்தொழுக வல்லாரை யாரே மிக்லூக்கும் தன்மை யவர்.","en":"Who can overcome them in glory That are free from enmity?","ch":"இகல்","chEn":"Hostility","chNo":86,"sec":"Wealth"},
{"n":856,"id":"TK-0856","ta":"இகலின் மிகலினிது என்பவன் வாழ்க்கை தவலும் கெடலும் நணித்து.","en":"His fall and ruin are quite near Who holds enmity sweet and dear","ch":"இகல்","chEn":"Hostility","chNo":86,"sec":"Wealth"},
{"n":857,"id":"TK-0857","ta":"மிகல்மேவல் மெய்ப்பொருள் காணார் இகல்மேவல் இன்னா அறிவி னவர்.","en":"They cannot see the supreme Truth Who hate and injure without ruth","ch":"இகல்","chEn":"Hostility","chNo":86,"sec":"Wealth"},
{"n":858,"id":"TK-0858","ta":"இகலிற்கு எதிர்சாய்தல் ஆக்கம் அதனை மிக்லூக்கின் ஊக்குமாம் கேடு.","en":"To turn from enmity is gain Fomenting it brings fast ruin","ch":"இகல்","chEn":"Hostility","chNo":86,"sec":"Wealth"},
{"n":859,"id":"TK-0859","ta":"இகல்காணான் ஆக்கம் வருங்கால் அதனை மிகல்காணும் கேடு தரற்கு.","en":"Fortune favours when hate recedes Hatred exceeding ruin breeds","ch":"இகல்","chEn":"Hostility","chNo":86,"sec":"Wealth"},
{"n":860,"id":"TK-0860","ta":"இகலானாம் இன்னாத எல்லாம் நகலானாம் நன்னயம் என்னும் செருக்கு.","en":"All evils come from enmity All goodness flow from amity","ch":"இகல்","chEn":"Hostility","chNo":86,"sec":"Wealth"},
{"n":861,"id":"TK-0861","ta":"வலியார்க்கு மாறேற்றல் ஓம்புக ஓம்பா மெலியார்மேல் மேக பகை.","en":"Turn from strife with foes too strong With the feeble for battle long","ch":"பகை மாட்சி","chEn":"The Might of Hatred","chNo":87,"sec":"Wealth"},
{"n":862,"id":"TK-0862","ta":"அன்பிலன் ஆன்ற துணையிலன் தான்துவ்வான் என்பரியும் ஏதிலான் துப்பு.","en":"Loveless, aidless, powerless king Can he withstand an enemy strong?","ch":"பகை மாட்சி","chEn":"The Might of Hatred","chNo":87,"sec":"Wealth"},
{"n":863,"id":"TK-0863","ta":"அஞ்சும் அறியான் அமைவிலன் ஈகலான் தஞ்சம் எளியன் பகைக்கு.","en":"Unskilled, timid, miser, misfit He is easy for foes to hit","ch":"பகை மாட்சி","chEn":"The Might of Hatred","chNo":87,"sec":"Wealth"},
{"n":864,"id":"TK-0864","ta":"நீங்கான் வெகுளி நிறையிலன் எஞ்ஞான்றும் யாங்கணும் யார்க்கும் எளிது.","en":"The wrathful restive man is prey To any, anywhere any day","ch":"பகை மாட்சி","chEn":"The Might of Hatred","chNo":87,"sec":"Wealth"},
{"n":865,"id":"TK-0865","ta":"வழிநோக்கான் வாய்ப்பன செய்யான் பழிநோக்கான் பண்பிலன் பற்றார்க்கு இனிது.","en":"Crooked, cruel, tactless and base Any foe can fell him with ease","ch":"பகை மாட்சி","chEn":"The Might of Hatred","chNo":87,"sec":"Wealth"},
{"n":866,"id":"TK-0866","ta":"காணாச் சினத்தான் கழிபெருங் காமத்தான் பேணாமை பேணப் படும்.","en":"Blind in rage and mad in lust To have his hatred is but just","ch":"பகை மாட்சி","chEn":"The Might of Hatred","chNo":87,"sec":"Wealth"},
{"n":867,"id":"TK-0867","ta":"கொடுத்தும் கொளல்வேண்டும் மன்ற அடுத்திருந்து மாணாத செய்வான் பகை.","en":"Pay and buy his enmity Who muddles chance with oddity","ch":"பகை மாட்சி","chEn":"The Might of Hatred","chNo":87,"sec":"Wealth"},
{"n":868,"id":"TK-0868","ta":"குணனிலனாய்க் குற்றம் பலவாயின் மாற்றார்க்கு இனனிலனாம் ஏமாப் புடைத்து.","en":"With no virtue but full of vice He loses friends and delights foes","ch":"பகை மாட்சி","chEn":"The Might of Hatred","chNo":87,"sec":"Wealth"},
{"n":869,"id":"TK-0869","ta":"செறுவார்க்குச் சேணிகவா இன்பம் அறிவிலா அஞ்சும் பகைவர்ப் பெறின்.","en":"The joy of heroes knows no bounds When timid fools are opponents","ch":"பகை மாட்சி","chEn":"The Might of Hatred","chNo":87,"sec":"Wealth"},
{"n":870,"id":"TK-0870","ta":"கல்லான் வெகுளும் சிறுபொருள் எஞ்ஞான்றும் ஒல்லானை ஒல்லா தொளி.","en":"Glory's light he will not gain Who fails to fight a fool and win","ch":"பகை மாட்சி","chEn":"The Might of Hatred","chNo":87,"sec":"Wealth"},
{"n":871,"id":"TK-0871","ta":"பகைஎன்னும் பண்பி லதனை ஒருவன் நகையேயும் வேண்டற்பாற்று அன்று.","en":"Let not one even as a sport The ill-natured enmity court","ch":"பகைத்திறம் தெரிதல்","chEn":"Knowing the Quality of Hate","chNo":88,"sec":"Wealth"},
{"n":872,"id":"TK-0872","ta":"வில்லேர் உழவர் பகைகொளினும் கொள்ளற்க சொல்லேர் உழவர் பகை.","en":"Incur the hate of bow-ploughers But not the hate of word-ploughers","ch":"பகைத்திறம் தெரிதல்","chEn":"Knowing the Quality of Hate","chNo":88,"sec":"Wealth"},
{"n":873,"id":"TK-0873","ta":"ஏமுற் றவரினும் ஏழை தமியனாய்ப் பல்லார் பகைகொள் பவன்.","en":"Forlorn, who rouses many foes The worst insanity betrays","ch":"பகைத்திறம் தெரிதல்","chEn":"Knowing the Quality of Hate","chNo":88,"sec":"Wealth"},
{"n":874,"id":"TK-0874","ta":"பகைநட்பாக் கொண்டொழுகும் பண்புடை யாளன் தகைமைக்கண் தங்கிற்று உலகு.","en":"This world goes safely in his grace Whose heart makes friends even of foes","ch":"பகைத்திறம் தெரிதல்","chEn":"Knowing the Quality of Hate","chNo":88,"sec":"Wealth"},
{"n":875,"id":"TK-0875","ta":"தன்துணை இன்றால் பகையிரண்டால் தான்ஒருவன் இன்துணையாக் கொள்கவற்றின் ஒன்று.","en":"Alone, if two foes you oppose Make one of them your ally close","ch":"பகைத்திறம் தெரிதல்","chEn":"Knowing the Quality of Hate","chNo":88,"sec":"Wealth"},
{"n":876,"id":"TK-0876","ta":"தேறினும் தேறா விடினும் அழிவின்கண் தேறான் பகாஅன் விடல்.","en":"Trust or distrust; during distress Keep aloof; don't mix with foes","ch":"பகைத்திறம் தெரிதல்","chEn":"Knowing the Quality of Hate","chNo":88,"sec":"Wealth"},
{"n":877,"id":"TK-0877","ta":"நோவற்க நொந்தது அறியார்க்கு மேவற்க மென்மை பகைவர் அகத்து.","en":"To those who know not, tell not your pain Nor your weakness to foes explain","ch":"பகைத்திறம் தெரிதல்","chEn":"Knowing the Quality of Hate","chNo":88,"sec":"Wealth"},
{"n":878,"id":"TK-0878","ta":"வகையறிந்து தற்செய்து தற்காப்ப மாயும் பகைவர்கண் பட்ட செருக்கு.","en":"Know how and act and defend well The pride of enemies shall fall","ch":"பகைத்திறம் தெரிதல்","chEn":"Knowing the Quality of Hate","chNo":88,"sec":"Wealth"},
{"n":879,"id":"TK-0879","ta":"இளைதாக முள்மரம் கொல்க களையுநர் கைகொல்லும் காழ்த்த இடத்து.","en":"Cut off thorn-trees when young they are; Grown hard, they cut your hands beware","ch":"பகைத்திறம் தெரிதல்","chEn":"Knowing the Quality of Hate","chNo":88,"sec":"Wealth"},
{"n":880,"id":"TK-0880","ta":"உயிர்ப்ப உளரல்லர் மன்ற செயிர்ப்பவர் செம்மல் சிதைக்கலா தார்.","en":"To breathe on earth they are not fit Defying foes who don't defeat","ch":"பகைத்திறம் தெரிதல்","chEn":"Knowing the Quality of Hate","chNo":88,"sec":"Wealth"},
{"n":881,"id":"TK-0881","ta":"நிழல்நீரும் இன்னாத இன்னா தமர்நீரும் இன்னாவாம் இன்னா செயின்.","en":"Traitorous kinsmen will make you sad As water and shade do harm when bad","ch":"உட்பகை","chEn":"Enmity within","chNo":89,"sec":"Wealth"},
{"n":882,"id":"TK-0882","ta":"வாள்போல பகைவரை அஞ்சற்க அஞ்சுக கேள்போல் பகைவர் தொடர்பு.","en":"You need not sword-like kinsmen fear Fear foes who feign as kinsmen dear","ch":"உட்பகை","chEn":"Enmity within","chNo":89,"sec":"Wealth"},
{"n":883,"id":"TK-0883","ta":"உட்பகை அஞ்சித்தற் காக்க உலைவிடத்து மட்பகையின் மாணத் தெறும்.","en":"The secret foe in days evil Will cut you, beware, like potters' steel","ch":"உட்பகை","chEn":"Enmity within","chNo":89,"sec":"Wealth"},
{"n":884,"id":"TK-0884","ta":"மனமாணா உட்பகை தோன்றின் இனமாணா ஏதம் பலவும் தரும்.","en":"The evil-minded foe within Foments trouble, spoils kinsmen!","ch":"உட்பகை","chEn":"Enmity within","chNo":89,"sec":"Wealth"},
{"n":885,"id":"TK-0885","ta":"உறல்முறையான் உட்பகை தோன்றின் இறல்முறையான் ஏதம் பலவும் தரும்.","en":"A traitor among kinsmen will Bring life-endangering evil","ch":"உட்பகை","chEn":"Enmity within","chNo":89,"sec":"Wealth"},
{"n":886,"id":"TK-0886","ta":"ஒன்றாமை ஒன்றியார் கட்படின் எஞ்ஞான்றும் பொன்றாமை ஒன்றல் அரிது.","en":"Discord in kings' circle entails Life-destroying deadly evils","ch":"உட்பகை","chEn":"Enmity within","chNo":89,"sec":"Wealth"},
{"n":887,"id":"TK-0887","ta":"செப்பின் புணர்ச்சிபோல் கூடினும் கூடாதே உட்பகை உற்ற குடி.","en":"A house hiding hostiles in core Just seems on like the lid in jar","ch":"உட்பகை","chEn":"Enmity within","chNo":89,"sec":"Wealth"},
{"n":888,"id":"TK-0888","ta":"அரம்பொருத பொன்போலத் தேயும் உரம்பொருது உட்பகை உற்ற குடி.","en":"By secret spite the house wears out Like gold crumbling by file's contact","ch":"உட்பகை","chEn":"Enmity within","chNo":89,"sec":"Wealth"},
{"n":889,"id":"TK-0889","ta":"எட்பக வன்ன சிறுமைத்தே ஆயினும் உட்பகை உள்ளதாங் கேடு.","en":"Ruin lurks in enmity As slit in sesame though it be","ch":"உட்பகை","chEn":"Enmity within","chNo":89,"sec":"Wealth"},
{"n":890,"id":"TK-0890","ta":"உடம்பாடு இலாதவர் வாழ்க்கை குடங்கருள் பாம்போடு உடனுறைந் தற்று.","en":"Dwell with traitors that hate in heart Is dwelling with snake in selfsame hut","ch":"உட்பகை","chEn":"Enmity within","chNo":89,"sec":"Wealth"},
{"n":891,"id":"TK-0891","ta":"ஆற்றுவார் ஆற்றல் இகழாமை போற்றுவார் போற்றலுள் எல்லாம் தலை.","en":"Not to spite the mighty ones Safest safeguard to living brings","ch":"பெரியாரைப் பிழையாமை","chEn":"Not Offending the Great","chNo":90,"sec":"Wealth"},
{"n":892,"id":"TK-0892","ta":"பெரியாரைப் பேணாது ஒழுகிற் பெரியாரால் பேரா இடும்பை தரும்.","en":"To walk unmindful of the great Shall great troubles ceaseless create","ch":"பெரியாரைப் பிழையாமை","chEn":"Not Offending the Great","chNo":90,"sec":"Wealth"},
{"n":893,"id":"TK-0893","ta":"கெடல்வேண்டின் கேளாது செய்க அடல்வேண்டின் ஆற்று பவர்கண் இழுக்கு.","en":"Heed not and do, if ruin you want Offence against the mighty great","ch":"பெரியாரைப் பிழையாமை","chEn":"Not Offending the Great","chNo":90,"sec":"Wealth"},
{"n":894,"id":"TK-0894","ta":"கூற்றத்தைக் கையால் விளித்தற்றால் ஆற்றுவார்க்கு ஆற்றாதார் இன்னா செயல்.","en":"The weak who insult men of might Death with their own hands invite","ch":"பெரியாரைப் பிழையாமை","chEn":"Not Offending the Great","chNo":90,"sec":"Wealth"},
{"n":895,"id":"TK-0895","ta":"யாண்டுச்சென்று யாண்டும் உளராகார் வெந்துப்பின் வேந்து செறப்பட் டவர்.","en":"Where can they go and thrive where Pursued by powerful monarch's ire?","ch":"பெரியாரைப் பிழையாமை","chEn":"Not Offending the Great","chNo":90,"sec":"Wealth"},
{"n":896,"id":"TK-0896","ta":"எரியால் சுடப்படினும் உய்வுண்டாம் உய்யார் பெரியார்ப் பிழைத்தொழுகு வார்.","en":"One can escape in fire caught The great who offends escapes not","ch":"பெரியாரைப் பிழையாமை","chEn":"Not Offending the Great","chNo":90,"sec":"Wealth"},
{"n":897,"id":"TK-0897","ta":"வகைமாண்ட வாழ்க்கையும் வான்பொருளும் என்னாம் தகைமாண்ட தக்கார் செறின்.","en":"If holy mighty sages frown Stately gifts and stores who can own?","ch":"பெரியாரைப் பிழையாமை","chEn":"Not Offending the Great","chNo":90,"sec":"Wealth"},
{"n":898,"id":"TK-0898","ta":"குன்றன்னார் குன்ற மதிப்பின் குடியொடு நின்றன்னார் மாய்வர் நிலத்து.","en":"When hill-like sages are held small The firm on earth lose home and all","ch":"பெரியாரைப் பிழையாமை","chEn":"Not Offending the Great","chNo":90,"sec":"Wealth"},
{"n":899,"id":"TK-0899","ta":"ஏந்திய கொள்கையார் சீறின் இடைமுரிந்து வேந்தனும் வேந்து கெடும்.","en":"Before the holy sage's rage Ev'n Indra's empire meets damage","ch":"பெரியாரைப் பிழையாமை","chEn":"Not Offending the Great","chNo":90,"sec":"Wealth"},
{"n":900,"id":"TK-0900","ta":"இறந்தமைந்த சார்புடையர் ஆயினும் உய்யார் சிறந்தமைந்த சீரார் செறின்.","en":"Even mighty aided men shall quail If the enraged holy seers will","ch":"பெரியாரைப் பிழையாமை","chEn":"Not Offending the Great","chNo":90,"sec":"Wealth"},
{"n":901,"id":"TK-0901","ta":"மனைவிழைவார் மாண்பயன் எய்தார் வினைவிழையார் வேண்டாப் பொருளும் அது.","en":"Who dote on wives lose mighty gain That lust, dynamic men disdain","ch":"பெண்வழிச் சேறல்","chEn":"Being led by Women","chNo":91,"sec":"Wealth"},
{"n":902,"id":"TK-0902","ta":"பேணாது பெண்விழைவான் ஆக்கம் பெரியதோர் நாணாக நாணுத் தரும்.","en":"Who dotes, unmanly, on his dame His wealth to him and all is shame","ch":"பெண்வழிச் சேறல்","chEn":"Being led by Women","chNo":91,"sec":"Wealth"},
{"n":903,"id":"TK-0903","ta":"இல்லாள்கண் தாழ்ந்த இயல்பின்மை எஞ்ஞான்றும் நல்லாருள் நாணுத் தரும்.","en":"Who's servile to his wife always Shy he feels before the wise","ch":"பெண்வழிச் சேறல்","chEn":"Being led by Women","chNo":91,"sec":"Wealth"},
{"n":904,"id":"TK-0904","ta":"மனையாளை அஞ்சும் மறுமையி லாளன் வினையாண்மை வீறெய்த லின்று.","en":"Fearing his wife salvationless The weaklings' action has no grace","ch":"பெண்வழிச் சேறல்","chEn":"Being led by Women","chNo":91,"sec":"Wealth"},
{"n":905,"id":"TK-0905","ta":"இல்லாளை அஞ்சுவான் அஞ்சுமற் றெஞ்ஞான்றும் நல்லார்க்கு நல்ல செயல்.","en":"Who fears his wife fears always Good to do to the good and wise","ch":"பெண்வழிச் சேறல்","chEn":"Being led by Women","chNo":91,"sec":"Wealth"},
{"n":906,"id":"TK-0906","ta":"இமையாரின் வாழினும் பாடிலரே இல்லாள் அமையார்தோள் அஞ்சு பவர்.","en":"Who fear douce arms of their wives Look petty even with god-like lives","ch":"பெண்வழிச் சேறல்","chEn":"Being led by Women","chNo":91,"sec":"Wealth"},
{"n":907,"id":"TK-0907","ta":"பெண்ணேவல் செய்தொழுகும் ஆண்மையின் நாணுடைப் பெண்ணே பெருமை உடைத்து.","en":"Esteemed more is women bashful Than man servile unto her will","ch":"பெண்வழிச் சேறல்","chEn":"Being led by Women","chNo":91,"sec":"Wealth"},
{"n":908,"id":"TK-0908","ta":"நட்டார் குறைமுடியார் நன்றாற்றார் நன்னுதலாள் பெட் டாங்கு ஒழுகு பவர்.","en":"By fair-browed wives who are governed Help no friends nor goodness tend","ch":"பெண்வழிச் சேறல்","chEn":"Being led by Women","chNo":91,"sec":"Wealth"},
{"n":909,"id":"TK-0909","ta":"அறவினையும் ஆன்ற பொருளும் பிறவினையும் பெண்ஏவல் செய்வார்கண் இல்.","en":"No virtue riches nor joy is seen In those who submit to women","ch":"பெண்வழிச் சேறல்","chEn":"Being led by Women","chNo":91,"sec":"Wealth"},
{"n":910,"id":"TK-0910","ta":"எண்சேர்ந்த நெஞ்சத் திடனுடையார்க்கு எஞ்ஞான்றும் பெண்சேர்ந்தாம் பேதைமை இல்.","en":"Thinkers strong and broad of heart By folly on fair sex do not dote","ch":"பெண்வழிச் சேறல்","chEn":"Being led by Women","chNo":91,"sec":"Wealth"},
{"n":911,"id":"TK-0911","ta":"அன்பின் விழையார் பொருள்விழையும் ஆய்தொடியார் இன்சொல் இழுக்குத் தரும்.","en":"For gold, not love their tongue cajoles Men are ruined by bangled belles","ch":"வரைவின் மகளிர்","chEn":"Wanton Women","chNo":92,"sec":"Wealth"},
{"n":912,"id":"TK-0912","ta":"பயன்தூக்கிப் பண்புரைக்கும் பண்பின் மகளிர் நயன்தூக்கி நள்ளா விடல்.","en":"Avoid ill-natured whores who feign Love only for their selfish gain","ch":"வரைவின் மகளிர்","chEn":"Wanton Women","chNo":92,"sec":"Wealth"},
{"n":913,"id":"TK-0913","ta":"பொருட்பெண்டிர் பொய்ம்மை முயக்கம் இருட்டறையில் ஏத஧ல் பிணந்தழீஇ அற்று.","en":"The false embrace of whores is like That of a damned corpse in the dark","ch":"வரைவின் மகளிர்","chEn":"Wanton Women","chNo":92,"sec":"Wealth"},
{"n":914,"id":"TK-0914","ta":"பொருட்பொருளார் புன்னலந் தோயார் அருட்பொருள் ஆயும் அறிவி னவர்.","en":"The wise who seek the wealth of grace Look not for harlots' low embrace","ch":"வரைவின் மகளிர்","chEn":"Wanton Women","chNo":92,"sec":"Wealth"},
{"n":915,"id":"TK-0915","ta":"பொதுநலத்தார் புன்னலம் தோயார் மதிநலத்தின் மாண்ட அறிவி னவர்.","en":"The lofty wise will never covet The open charms of a vile harlot","ch":"வரைவின் மகளிர்","chEn":"Wanton Women","chNo":92,"sec":"Wealth"},
{"n":916,"id":"TK-0916","ta":"தந்நலம் பாரிப்பார் தோயார் தகைசெருக்கிப் புன்னலம் பாரிப்பார் தோள்.","en":"Those who guard their worthy fame Shun the wanton's vaunting charm","ch":"வரைவின் மகளிர்","chEn":"Wanton Women","chNo":92,"sec":"Wealth"},
{"n":917,"id":"TK-0917","ta":"நிறைநெஞ்சம் இல்லவர் தோய்வார் பிறநெஞ்சிற் பேணிப் புணர்பவர் தோள்.","en":"Hollow hearts alone desire The arms of whores with hearts elsewere","ch":"வரைவின் மகளிர்","chEn":"Wanton Women","chNo":92,"sec":"Wealth"},
{"n":918,"id":"TK-0918","ta":"ஆயும் அறிவினர் அல்லார்க்கு அணங்கென்ப மாய மகளிர் முயக்கு.","en":"Senseless fools are lured away By arms of sirens who lead astray","ch":"வரைவின் மகளிர்","chEn":"Wanton Women","chNo":92,"sec":"Wealth"},
{"n":919,"id":"TK-0919","ta":"வரைவிலா மாணிழையார் மென்தோள் புரையிலாப் பூரியர்கள் ஆழும் அளறு.","en":"The soft jewelled arms of whores are hell Into which the degraded fall","ch":"வரைவின் மகளிர்","chEn":"Wanton Women","chNo":92,"sec":"Wealth"},
{"n":920,"id":"TK-0920","ta":"இருமனப் பெண்டிரும் கள்ளும் கவறும் திருநீக்கப் பட்டார் தொடர்பு.","en":"Double-minded whores, wine and dice Are lures of those whom fortune flies","ch":"வரைவின் மகளிர்","chEn":"Wanton Women","chNo":92,"sec":"Wealth"},
{"n":921,"id":"TK-0921","ta":"உட்கப் படாஅர் ஒளியிழப்பர் எஞ்ஞான்றும் கட்காதல் கொண்டொழுகு வார்.","en":"Foes fear not who for toddy craze The addicts daily their glory lose","ch":"கள்ளுண்ணாமை","chEn":"Not Drinking Palm-Wine","chNo":93,"sec":"Wealth"},
{"n":922,"id":"TK-0922","ta":"உண்ணற்க கள்ளை உணில்உண்க சான்றோரான் எண்ணப் படவேண்டா தார்.","en":"Drink not liquor; but let them drink Whom with esteem the wise won't think","ch":"கள்ளுண்ணாமை","chEn":"Not Drinking Palm-Wine","chNo":93,"sec":"Wealth"},
{"n":923,"id":"TK-0923","ta":"ஈன்றாள் முகத்தேயும் இன்னாதால் என்மற்றுச் சான்றோர் முகத்துக் களி.","en":"The drunkard's joy pains ev'n mother's face How vile must it look for the wise?","ch":"கள்ளுண்ணாமை","chEn":"Not Drinking Palm-Wine","chNo":93,"sec":"Wealth"},
{"n":924,"id":"TK-0924","ta":"நாண்என்னும் நல்லாள் புறங்கொடுக்கும் கள்ளென்னும் பேணாப் பெருங்குற்றத் தார்க்கு.","en":"Good shame turns back from him ashamed Who is guilty of wine condemned","ch":"கள்ளுண்ணாமை","chEn":"Not Drinking Palm-Wine","chNo":93,"sec":"Wealth"},
{"n":925,"id":"TK-0925","ta":"கையறி யாமை உடைத்தே பொருள்கொடுத்து மெய்யறி யாமை கொளல்.","en":"To pay and drink and lose the sense Is nothing but rank ignorance","ch":"கள்ளுண்ணாமை","chEn":"Not Drinking Palm-Wine","chNo":93,"sec":"Wealth"},
{"n":926,"id":"TK-0926","ta":"துஞ்சினார் செத்தாரின் வேறல்லர் எஞ்ஞான்றும் நஞ்சுண்பார் கள்ளுண் பவர்.","en":"They take poison who take toddy And doze ev'n like a dead body","ch":"கள்ளுண்ணாமை","chEn":"Not Drinking Palm-Wine","chNo":93,"sec":"Wealth"},
{"n":927,"id":"TK-0927","ta":"உள்ளொற்றி உள்ளூர் நகப்படுவர் எஞ்ஞான்றும் கள்ளொற்றிக் கண்சாய் பவர்","en":"The secret drunkards' senses off Make the prying public laugh","ch":"கள்ளுண்ணாமை","chEn":"Not Drinking Palm-Wine","chNo":93,"sec":"Wealth"},
{"n":928,"id":"TK-0928","ta":"களித்தறியேன் என்பது கைவிடுக நெஞ்சத்து ஒளித்ததூஉம் ஆங்கே மிகும்.","en":"Don't say I'm not a drunkard hard The hidden fraud is known abroad","ch":"கள்ளுண்ணாமை","chEn":"Not Drinking Palm-Wine","chNo":93,"sec":"Wealth"},
{"n":929,"id":"TK-0929","ta":"களித்தானைக் காரணம் காட்டுதல் கீழ்நீர்க் குளித்தானைத் தீத்துரீஇ அற்று.","en":"Can torch search one in water sunk?  Can reason reach the raving drunk?","ch":"கள்ளுண்ணாமை","chEn":"Not Drinking Palm-Wine","chNo":93,"sec":"Wealth"},
{"n":930,"id":"TK-0930","ta":"கள்ளுண்ணாப் போழ்திற் களித்தானைக் காணுங்கால் உள்ளான்கொல் உண்டதன் சோர்வு.","en":"The sober seeing the drunkard's plight On selves can't they feel same effect?","ch":"கள்ளுண்ணாமை","chEn":"Not Drinking Palm-Wine","chNo":93,"sec":"Wealth"},
{"n":931,"id":"TK-0931","ta":"வேண்டற்க வென்றிடினும் சூதினை வென்றதூஉம் தூண்டிற்பொன் மீன்விழுங்கி அற்று.","en":"Avoid gambling, albeit you win Gulping bait-hook what does fish gain?","ch":"சூது","chEn":"Gambling","chNo":94,"sec":"Wealth"},
{"n":932,"id":"TK-0932","ta":"ஒன்றெய்தி நூறிழக்கும் சூதர்க்கும் உண்டாங்கொல் நன்றெய்தி வாழ்வதோர் ஆறு.","en":"Can gamblers in life good obtain Who lose a hundred one to gain?","ch":"சூது","chEn":"Gambling","chNo":94,"sec":"Wealth"},
{"n":933,"id":"TK-0933","ta":"உருளாயம் ஓவாது கூறின் பொருளாயம் போஒய்ப் புறமே படும்.","en":"If kings indulge in casting dice All their fortune will flow to foes","ch":"சூது","chEn":"Gambling","chNo":94,"sec":"Wealth"},
{"n":934,"id":"TK-0934","ta":"சிறுமை பலசெய்து சீரழக்கும் சூதின் வறுமை தருவதொன்று இல்.","en":"Nothing will make you poor like game Which adds to woes and ruins fame","ch":"சூது","chEn":"Gambling","chNo":94,"sec":"Wealth"},
{"n":935,"id":"TK-0935","ta":"கவறும் கழகமும் கையும் தருக்கி இவறியார் இல்லாகி யார்.","en":"The game, game-hall and gambler's art Who sought with glee have come to nought","ch":"சூது","chEn":"Gambling","chNo":94,"sec":"Wealth"},
{"n":936,"id":"TK-0936","ta":"அகடாரார் அல்லல் உழப்பர்சூ தென்னும் முகடியான் மூடப்பட் டார்.","en":"Men swallowed by the ogress, dice Suffer grief and want by that vice","ch":"சூது","chEn":"Gambling","chNo":94,"sec":"Wealth"},
{"n":937,"id":"TK-0937","ta":"பழகிய செல்வமும் பண்பும் கெடுக்கும் கழகத்துக் காலை புகின்.","en":"If men their time in game-den spend Ancestral wealth and virtues end","ch":"சூது","chEn":"Gambling","chNo":94,"sec":"Wealth"},
{"n":938,"id":"TK-0938","ta":"பொருள்கெடுத்துப் பொய்மேற் கொளீஇ அருள்கெடுத்து அல்லல் உழப்பிக்கும் சூது.","en":"Game ruins wealth and spoils grace Leads to lies and wretched woes","ch":"சூது","chEn":"Gambling","chNo":94,"sec":"Wealth"},
{"n":939,"id":"TK-0939","ta":"உடைசெல்வம் ஊண்ஒளி கல்விஎன்று ஐந்தும் அடையாவாம் ஆயங் கொளின்.","en":"Dress, wealth, food, fame, learning-these five In gambler's hand will never thrive","ch":"சூது","chEn":"Gambling","chNo":94,"sec":"Wealth"},
{"n":940,"id":"TK-0940","ta":"இழத்தொறூஉம் காதலிக்கும் சூதேபோல் துன்பம் உழத்தொறூஉம் காதற்று உயிர்.","en":"Love for game grows with every loss As love for life with sorrows grows","ch":"சூது","chEn":"Gambling","chNo":94,"sec":"Wealth"},
{"n":941,"id":"TK-0941","ta":"மிகினும் குறையினும் நோய்செய்யும் நூலோர் வளிமுதலா எண்ணிய மூன்று.","en":"Wind, bile and phlegm three cause disease So doctors deem it more or less","ch":"மருந்து","chEn":"Medicine","chNo":95,"sec":"Wealth"},
{"n":942,"id":"TK-0942","ta":"மருந்தென வேண்டாவாம் யாக்கைக்கு அருந்தியது அற்றது போற்றி உணின்.","en":"After digestion one who feeds His body no medicine needs","ch":"மருந்து","chEn":"Medicine","chNo":95,"sec":"Wealth"},
{"n":943,"id":"TK-0943","ta":"அற்றால் அறவறிந்து உண்க அஃதுடம்பு பெற்றான் நெடிதுய்க்கும் ஆறு.","en":"Eat food to digestive measure Life in body lasts with pleasure","ch":"மருந்து","chEn":"Medicine","chNo":95,"sec":"Wealth"},
{"n":944,"id":"TK-0944","ta":"அற்றது அறிந்து கடைப்பிடித்து மாறல்ல துய்க்க துவரப் பசித்து.","en":"Know digestion; with keen appetite Eat what is suitable and right","ch":"மருந்து","chEn":"Medicine","chNo":95,"sec":"Wealth"},
{"n":945,"id":"TK-0945","ta":"மாறுபாடு இல்லாத உண்டி மறுத்துண்ணின் ஊறுபாடு இல்லை உயிர்க்கு.","en":"With fasting adjusted food right Cures ills of life and makes you bright","ch":"மருந்து","chEn":"Medicine","chNo":95,"sec":"Wealth"},
{"n":946,"id":"TK-0946","ta":"இழிவறிந்து உண்பான்கண் இன்பம்போல் நிற்கும் கழிபேர் இரையான்கண் நோய்.","en":"Who eats with clean stomach gets health With greedy glutton abides ill-health","ch":"மருந்து","chEn":"Medicine","chNo":95,"sec":"Wealth"},
{"n":947,"id":"TK-0947","ta":"தீயள வன்றித் தெரியான் பெரிதுண்ணின் நோயள வின்றிப் படும்.","en":"who glut beyond the hunger's fire Suffer from untold diseases here","ch":"மருந்து","chEn":"Medicine","chNo":95,"sec":"Wealth"},
{"n":948,"id":"TK-0948","ta":"நோய்நாடி நோய்முதல் நாடி அதுதணிக்கும் வாய்நாடி வாய்ப்பச் செயல்.","en":"Test disease, its cause and cure And apply remedy that is sure","ch":"மருந்து","chEn":"Medicine","chNo":95,"sec":"Wealth"},
{"n":949,"id":"TK-0949","ta":"உற்றான் அளவும் பிணியளவும் காலமும் கற்றான் கருதிச் செயல்.","en":"Let the skilful doctor note The sickmen, sickness, season and treat","ch":"மருந்து","chEn":"Medicine","chNo":95,"sec":"Wealth"},
{"n":950,"id":"TK-0950","ta":"உற்றவன் தீர்ப்பான் மருந்துழைச் செல்வானென்று அப்பால் நாற் கூற்றே மருந்து.","en":"Patient, doctor, medicine and nurse Are four-fold codes of treating course","ch":"மருந்து","chEn":"Medicine","chNo":95,"sec":"Wealth"},
{"n":951,"id":"TK-0951","ta":"இற்பிறந்தார் கண்அல்லது இல்லை இயல்பாகச் செப்பமும் நாணும் ஒருங்கு.","en":"Right-sense and bashfulness adorn By nature only the noble-born","ch":"குடிமை","chEn":"Nobility","chNo":96,"sec":"Wealth"},
{"n":952,"id":"TK-0952","ta":"ஒழுக்கமும் வாய்மையும் நாணும்இம் மூன்றும் இழுக்கார் குடிப்பிறந் தார்.","en":"The noble-born lack not these three: Good conduct, truth and modesty","ch":"குடிமை","chEn":"Nobility","chNo":96,"sec":"Wealth"},
{"n":953,"id":"TK-0953","ta":"நகைஈகை இன்சொல் இகழாமை நான்கும் வகையென்ப வாய்மைக் குடிக்கு.","en":"Smile, gift, sweet words and courtesy These four mark true nobility","ch":"குடிமை","chEn":"Nobility","chNo":96,"sec":"Wealth"},
{"n":954,"id":"TK-0954","ta":"அடுக்கிய கோடி பெறினும் குடிப்பிறந்தார் குன்றுவ செய்தல் இலர்.","en":"Even for crores, the noble mood Cannot bend to degrading deed","ch":"குடிமை","chEn":"Nobility","chNo":96,"sec":"Wealth"},
{"n":955,"id":"TK-0955","ta":"வழங்குவ துள்வீழ்ந்தக் கண்ணும் பழங்குடி பண்பில் தலைப்பிரிதல் இன்று.","en":"The means of gift may dwindle; yet Ancient homes guard their noble trait","ch":"குடிமை","chEn":"Nobility","chNo":96,"sec":"Wealth"},
{"n":956,"id":"TK-0956","ta":"சலம்பற்றிச் சால்பில செய்யார்மா சற்ற குலம்பற்றி வாழ்தும் என் பார்.","en":"Who guard their family prestige pure Stoop not to acts of cunning lure","ch":"குடிமை","chEn":"Nobility","chNo":96,"sec":"Wealth"},
{"n":957,"id":"TK-0957","ta":"குடிப்பிறந்தார் கண்விளங்கும் குற்றம் விசும்பின் மத஧க்கண் மறுப்போல் உயர்ந்து.","en":"The faults of nobly-born are seen Like on the sky the spots of moon","ch":"குடிமை","chEn":"Nobility","chNo":96,"sec":"Wealth"},
{"n":958,"id":"TK-0958","ta":"நலத்தின்கண் நாரின்மை தோன்றின் அவனைக் குலத்தின்கண் ஐயப் படும்.","en":"If manners of the good are rude People deem their pedigree crude","ch":"குடிமை","chEn":"Nobility","chNo":96,"sec":"Wealth"},
{"n":959,"id":"TK-0959","ta":"நிலத்தில் கிடந்தமை கால்காட்டும் காட்டும் குலத்தில் பிறந்தார்வாய்ச் சொல்.","en":"Soil's nature is seen in sprout The worth of birth from words flow out","ch":"குடிமை","chEn":"Nobility","chNo":96,"sec":"Wealth"},
{"n":960,"id":"TK-0960","ta":"நலம்வேண்டின் நாணுடைமை வேண்டும் குலம்வேண்டின் வேண்டுக யார்க்கும் பணிவு.","en":"All gain good name by modesty Nobility by humility","ch":"குடிமை","chEn":"Nobility","chNo":96,"sec":"Wealth"},
{"n":961,"id":"TK-0961","ta":"இன்றி அமையாச் சிறப்பின ஆயினும் குன்ற வருப விடல்.","en":"Though needed for your life in main, From mean degrading acts refrain","ch":"மானம்","chEn":"Honour","chNo":97,"sec":"Wealth"},
{"n":962,"id":"TK-0962","ta":"சீரினும் சீரல்ல செய்யாரே சீரொடு பேராண்மை வேண்டு பவர்.","en":"Who seek honour and manly fame Don't do mean deeds even for name","ch":"மானம்","chEn":"Honour","chNo":97,"sec":"Wealth"},
{"n":963,"id":"TK-0963","ta":"பெருக்கத்து வேண்டும் பணிதல் சிறிய சுருக்கத்து வேண்டும் உயர்வு.","en":"Be humble in prosperity In decline uphold dignity","ch":"மானம்","chEn":"Honour","chNo":97,"sec":"Wealth"},
{"n":964,"id":"TK-0964","ta":"தலையின் இழிந்த மயிரனையர் மாந்தர் நிலையின் இழிந்தக் கடை.","en":"Like hair fallen from head are those Who fall down from their high status","ch":"மானம்","chEn":"Honour","chNo":97,"sec":"Wealth"},
{"n":965,"id":"TK-0965","ta":"குன்றின் அனையாரும் குன்றுவர் குன்றுவ குன்றி அனைய செயின்.","en":"Even hill-like men will sink to nought With abrus-grain-like small default","ch":"மானம்","chEn":"Honour","chNo":97,"sec":"Wealth"},
{"n":966,"id":"TK-0966","ta":"புகழ்இன்றால் புத்தேள்நாட்டு உய்யாதால் என்மற்று இகழ்வார்பின் சென்று நிலை.","en":"Why fawn on men that scorn you here It yields no fame, heaven's bliss neither","ch":"மானம்","chEn":"Honour","chNo":97,"sec":"Wealth"},
{"n":967,"id":"TK-0967","ta":"ஒட்டார்பின் சென்றொருவன் வாழ்தலின் அந்நிலையே கெட்டான் எனப்படுதல் நன்று.","en":"Better it is to die forlorn Than live as slaves of those who scorn","ch":"மானம்","chEn":"Honour","chNo":97,"sec":"Wealth"},
{"n":968,"id":"TK-0968","ta":"மருந்தோமற்று ஊன்ஓம்பும் வாழ்க்கை பெருந்தகைமை பீடழிய வந்த இடத்து.","en":"Is nursing body nectar sweet Even when one's honour is lost?","ch":"மானம்","chEn":"Honour","chNo":97,"sec":"Wealth"},
{"n":969,"id":"TK-0969","ta":"மயிர்நீப்பின் வாழாக் கவரிமா அன்னார் உயிர்நீப்பர் மானம் வரின்.","en":"Honour lost, the noble expire Like a yak that loses its hair","ch":"மானம்","chEn":"Honour","chNo":97,"sec":"Wealth"},
{"n":970,"id":"TK-0970","ta":"இளிவரின் வாழாத மானம் உடையார் ஒளிதொழுது ஏத்தும் உலகு.","en":"Their light the world adores and hails  Who will not live when honour fails","ch":"மானம்","chEn":"Honour","chNo":97,"sec":"Wealth"},
{"n":971,"id":"TK-0971","ta":"ஒளிஒருவற்கு உள்ள வெறுக்கை இளிஒருவற்கு அஃதிறந்து வாழ்தும் எனல்.","en":"A heart of courage lives in light  Devoid of that one's life is night","ch":"பெருமை","chEn":"Greatness","chNo":98,"sec":"Wealth"},
{"n":972,"id":"TK-0972","ta":"பிறப்பொக்கும் எல்லா உயிர்க்கும் சிறப்பொவ்வா செய்தொழில் வேற்றுமை யான்.","en":"All beings are the same in birth But work decides their varied worth","ch":"பெருமை","chEn":"Greatness","chNo":98,"sec":"Wealth"},
{"n":973,"id":"TK-0973","ta":"மேலிருந்தும் மேலல்லார் மேலல்லர் கீழிருந்தும் கீழல்லார் கீழல் லவர்.","en":"Ignoble high not high they are The noble low not low they fare","ch":"பெருமை","chEn":"Greatness","chNo":98,"sec":"Wealth"},
{"n":974,"id":"TK-0974","ta":"ஒருமை மகளிரே போலப் பெருமையும் தன்னைத்தான் கொண்டொழுகின் உண்டு.","en":"Greatness like woman's chastity Is guarded by self-varacity","ch":"பெருமை","chEn":"Greatness","chNo":98,"sec":"Wealth"},
{"n":975,"id":"TK-0975","ta":"பெருமை யுடையவர் ஆற்றுவார் ஆற்றின் அருமை உடைய செயல்.","en":"Great souls when their will is active Do mighty deeds rare to achieve","ch":"பெருமை","chEn":"Greatness","chNo":98,"sec":"Wealth"},
{"n":976,"id":"TK-0976","ta":"சிறியார் உணர்ச்சியுள் இல்லை பெரியாரைப் பேணிக் கொள் வேம் என்னும் நோக்கு.","en":"The petty-natured ones have not The mind to seek and befriend the great","ch":"பெருமை","chEn":"Greatness","chNo":98,"sec":"Wealth"},
{"n":977,"id":"TK-0977","ta":"இறப்பே புரிந்த தொழிற்றாம் சிறப்புந்தான் சீரல் லவர்கண் படின்.","en":"The base with power and opulence Wax with deeds of insolence","ch":"பெருமை","chEn":"Greatness","chNo":98,"sec":"Wealth"},
{"n":978,"id":"TK-0978","ta":"பணியுமாம் என்றும் பெருமை சிறுமை அணியுமாம் தன்னை வியந்து.","en":"Greatness bends with modesty Meanness vaunts with vanity","ch":"பெருமை","chEn":"Greatness","chNo":98,"sec":"Wealth"},
{"n":979,"id":"TK-0979","ta":"பெருமை பெருமிதம் இன்மை சிறுமை பெருமிதம் ஊர்ந்து விடல்.","en":"Greatness is free from insolence Littleness swells with that offence","ch":"பெருமை","chEn":"Greatness","chNo":98,"sec":"Wealth"},
{"n":980,"id":"TK-0980","ta":"அற்றம் மறைக்கும் பெருமை சிறுமைதான் குற்றமே கூறி விடும்.","en":"Weakness of others greatness screens Smallness defects alone proclaims","ch":"பெருமை","chEn":"Greatness","chNo":98,"sec":"Wealth"},
{"n":981,"id":"TK-0981","ta":"கடன்என்ப நல்லவை எல்லாம் கடன்அறிந்து சான்றாண்மை மேற்கொள் பவர்க்கு.","en":"All goodness is duty to them  Who are dutiful and sublime","ch":"சான்றாண்மை","chEn":"Perfectness","chNo":99,"sec":"Wealth"},
{"n":982,"id":"TK-0982","ta":"குணநலம் சான்றோர் நலனே பிறநலம் எந்நலத்து உள்ளதூஉம் அன்று.","en":"Good in the great is character Than that there is nothing better","ch":"சான்றாண்மை","chEn":"Perfectness","chNo":99,"sec":"Wealth"},
{"n":983,"id":"TK-0983","ta":"அன்புநாண் ஒப்புரவு கண்ணோட்டம் வாய்மையொடு ஐந்துசால் ஊன்றிய தூண்.","en":"Love, truth, regard, modesty, grace These five are virtue's resting place","ch":"சான்றாண்மை","chEn":"Perfectness","chNo":99,"sec":"Wealth"},
{"n":984,"id":"TK-0984","ta":"கொல்லா நலத்தது நோன்மை பிறர்தீமை சொல்லா நலத்தது சால்பு.","en":"Not to kill is penance pure Not to slander virtue sure","ch":"சான்றாண்மை","chEn":"Perfectness","chNo":99,"sec":"Wealth"},
{"n":985,"id":"TK-0985","ta":"ஆற்றுவார் ஆற்றல் பணிதல் அதுசான்றோர் மாற்றாரை மாற்றும் படை.","en":"Humility is valour's strength A force that averts foes at length","ch":"சான்றாண்மை","chEn":"Perfectness","chNo":99,"sec":"Wealth"},
{"n":986,"id":"TK-0986","ta":"சால்பிற்குக் கட்டளை யாதெனின் தோல்வி துலையல்லார் கண்ணும் கொளல்.","en":"To bear repulse e'en from the mean Is the touch-stone of worthy men","ch":"சான்றாண்மை","chEn":"Perfectness","chNo":99,"sec":"Wealth"},
{"n":987,"id":"TK-0987","ta":"இன்னாசெய் தார்க்கும் இனியவே செய்யாக்கால் என்ன பயத்ததோ சால்பு.","en":"Of perfection what is the gain If it returns not joy for pain?","ch":"சான்றாண்மை","chEn":"Perfectness","chNo":99,"sec":"Wealth"},
{"n":988,"id":"TK-0988","ta":"இன்மை ஒருவற்கு இளிவன்று சால்பென்னும் திண்மை உண் டாகப் பெறின்.","en":"No shame there is in poverty To one strong in good quality","ch":"சான்றாண்மை","chEn":"Perfectness","chNo":99,"sec":"Wealth"},
{"n":989,"id":"TK-0989","ta":"ஊழி பெயரினும் தாம்பெயரார் சான்றாண்மைக்கு ஆழி எனப்படு வார்.","en":"Aeons may change but not the seer Who is a sea of virtue pure","ch":"சான்றாண்மை","chEn":"Perfectness","chNo":99,"sec":"Wealth"},
{"n":990,"id":"TK-0990","ta":"சான்றவர் சான்றாண்மை குன்றின் இருநிலந்தான் தாங்காது மன்னோ பொறை.","en":"The world will not more bear its weight If from high virtue fall the great","ch":"சான்றாண்மை","chEn":"Perfectness","chNo":99,"sec":"Wealth"},
{"n":991,"id":"TK-0991","ta":"எண்பதத்தால் எய்தல் எளிதென்ப யார்மாட்டும் பண்புடைமை என்னும் வழக்கு.","en":"To the polite free of access Easily comes courteousness","ch":"பண்புடைமை","chEn":"Courtesy","chNo":100,"sec":"Wealth"},
{"n":992,"id":"TK-0992","ta":"அன்புடைமை ஆன்ற குடிப்பிறத்தல் இவ்விரண்டும் பண்புடைமை என்னும் வழக்கு.","en":"Humanity and noble birth Develop courtesy and moral worth","ch":"பண்புடைமை","chEn":"Courtesy","chNo":100,"sec":"Wealth"},
{"n":993,"id":"TK-0993","ta":"உறுப்பொத்தல் மக்களொப்பு அன்றால் வெறுத்தக்க பண்பொத்தல் ஒப்பதாம் ஒப்பு.","en":"Likeness in limbs is not likeness It's likeness in kind courteousness","ch":"பண்புடைமை","chEn":"Courtesy","chNo":100,"sec":"Wealth"},
{"n":994,"id":"TK-0994","ta":"நயனொடு நன்றி புரிந்த பயனுடையார் பண்புபா ராட்டும் உலகு.","en":"The world applauds those helpful men Whose actions are just and benign","ch":"பண்புடைமை","chEn":"Courtesy","chNo":100,"sec":"Wealth"},
{"n":995,"id":"TK-0995","ta":"நகையுள்ளும் இன்னா திகழ்ச்சி பகையுள்ளும் பண்புள பாடறிவார் மாட்டு.","en":"The courteous don't even foes detest For contempt offends even in jest","ch":"பண்புடைமை","chEn":"Courtesy","chNo":100,"sec":"Wealth"},
{"n":996,"id":"TK-0996","ta":"பண்புடையார்ப் பட்டுண்டு உலகம் அதுஇன்றேல் மண்புக்கு மாய்வது மன்.","en":"The world rests with the mannered best Or it crumbles and falls to dust","ch":"பண்புடைமை","chEn":"Courtesy","chNo":100,"sec":"Wealth"},
{"n":997,"id":"TK-0997","ta":"அரம்போலும் கூர்மைய ரேனும் மரம்போல்வர் மக்கட்பண்பு இல்லா தவர்.","en":"The mannerless though sharp like file Are like wooden blocks indocile","ch":"பண்புடைமை","chEn":"Courtesy","chNo":100,"sec":"Wealth"},
{"n":998,"id":"TK-0998","ta":"நண்பாற்றார் ஆகி நயமில செய்வார்க்கும் பண்பாற்றார் ஆதல் கடை.","en":"Discourtesy is mean indeed E'en to a base unfriendly breed","ch":"பண்புடைமை","chEn":"Courtesy","chNo":100,"sec":"Wealth"},
{"n":999,"id":"TK-0999","ta":"நகல்வல்லர் அல்லார்க்கு மாயிரு ஞாலம் பகலும்பாற் பட்டன்று இருள்.","en":"To those bereft of smiling light Even in day the earth is night","ch":"பண்புடைமை","chEn":"Courtesy","chNo":100,"sec":"Wealth"},
{"n":1000,"id":"TK-1000","ta":"பண்பிலான் பெற்ற பெருஞ்செல்வம் நன்பால் கலந்தீமை யால்திரிந் தற்று.","en":"The wealth heaped by the churlish base Is pure milk soured by impure vase","ch":"பண்புடைமை","chEn":"Courtesy","chNo":100,"sec":"Wealth"},
{"n":1001,"id":"TK-1001","ta":"வைத்தான்வாய் சான்ற பெரும்பொருள் அஃதுண்ணான் செத்தான் செயக்கிடந்தது இல்.","en":"Dead is he with wealth in pile Unenjoyed, it is futile","ch":"நன்றியில் செல்வம்","chEn":"Wealth without Benefaction","chNo":101,"sec":"Wealth"},
{"n":1002,"id":"TK-1002","ta":"பொருளானாம் எல்லாமென்று ஈயாது இவறும் மருளானாம் மாணாப் பிறப்பு","en":"The niggard miser thinks wealth is all He hoards, gives not is born devil","ch":"நன்றியில் செல்வம்","chEn":"Wealth without Benefaction","chNo":101,"sec":"Wealth"},
{"n":1003,"id":"TK-1003","ta":"ஈட்டம் இவறி இசைவேண்டா ஆடவர் தோற்றம் நிலக்குப் பொறை.","en":"A burden he is to earth indeed Who hoards without a worthy deed","ch":"நன்றியில் செல்வம்","chEn":"Wealth without Benefaction","chNo":101,"sec":"Wealth"},
{"n":1004,"id":"TK-1004","ta":"எச்சமென்று என்எண்ணுங் கொல்லோ ஒருவரால் நச்சப் படாஅ தவன்.","en":"What legacy can he leave behind Who is for approach too unkind","ch":"நன்றியில் செல்வம்","chEn":"Wealth without Benefaction","chNo":101,"sec":"Wealth"},
{"n":1005,"id":"TK-1005","ta":"கொடுப்பதூஉம் துய்ப்பதூஉம் இல்லார்க்கு அடுக்கிய கோடியுண் டாயினும் இல்.","en":"What is the good of crores they hoard To give and enjoy whose heart is hard","ch":"நன்றியில் செல்வம்","chEn":"Wealth without Benefaction","chNo":101,"sec":"Wealth"},
{"n":1006,"id":"TK-1006","ta":"ஏதம் பெருஞ்செல்வம் தான்துவ்வான் தக்கார்க்கொன்று ஈதல் இயல்பிலா தான்.","en":"Great wealth unused for oneself nor To worthy men is but a slur","ch":"நன்றியில் செல்வம்","chEn":"Wealth without Benefaction","chNo":101,"sec":"Wealth"},
{"n":1007,"id":"TK-1007","ta":"அற்றார்க்கொன்று ஆற்றாதான் செல்வம் மிகநலம் பெற்றாள் தமியள்மூத் தற்று.","en":"Who loaths to help have-nots, his gold Is like a spinster-belle grown old","ch":"நன்றியில் செல்வம்","chEn":"Wealth without Benefaction","chNo":101,"sec":"Wealth"},
{"n":1008,"id":"TK-1008","ta":"நச்சப் படாதவன் செல்வம் நடுவூருள் நச்சு மரம்பழுத் தற்று.","en":"The idle wealth of unsought men Is poison-fruit-tree amidst a town","ch":"நன்றியில் செல்வம்","chEn":"Wealth without Benefaction","chNo":101,"sec":"Wealth"},
{"n":1009,"id":"TK-1009","ta":"அன்பொரீஇத் தற்செற்று அறநோக்காது ஈட்டிய ஒண்பொருள் கொள்வார் பிறர்.","en":"Others usurp the shining gold In loveless, stingy, vicious hold","ch":"நன்றியில் செல்வம்","chEn":"Wealth without Benefaction","chNo":101,"sec":"Wealth"},
{"n":1010,"id":"TK-1010","ta":"சீருடைச் செல்வர் சிறுதுனி மாரி வறங்கூர்ந் தனையது உடைத்து.","en":"The brief want of the rich benign Is like rainclouds growing thin","ch":"நன்றியில் செல்வம்","chEn":"Wealth without Benefaction","chNo":101,"sec":"Wealth"},
{"n":1011,"id":"TK-1011","ta":"கருமத்தால் நாணுதல் நாணுந் திருநுதல் நல்லவர் நாணுப் பிற.","en":"To shrink from evil deed is shame The rest is blush of fair-faced dame","ch":"நாணுடைமை","chEn":"Shame","chNo":102,"sec":"Wealth"},
{"n":1012,"id":"TK-1012","ta":"ஊணுடை எச்சம் உயிர்க்கெல்லாம் வேறல்ல நாணுடைமை மாந்தர் சிறப்பு.","en":"Food, dress and such are one for all Modesty marks the higher soul","ch":"நாணுடைமை","chEn":"Shame","chNo":102,"sec":"Wealth"},
{"n":1013,"id":"TK-1013","ta":"ஊனைக் குறித்த உயிரெல்லாம் நாண்என்னும் நன்மை குறித்தது சால்பு.","en":"All lives have their lodge in flesh Perfection has its home in blush","ch":"நாணுடைமை","chEn":"Shame","chNo":102,"sec":"Wealth"},
{"n":1014,"id":"TK-1014","ta":"அணிஅன்றோ நாணுடைமை சான்றோர்க்கு அஃதின்றேல் பிணிஅன்றோ பீடு நடை.","en":"Shame is the jewel of dignity Shameless swagger is vanity","ch":"நாணுடைமை","chEn":"Shame","chNo":102,"sec":"Wealth"},
{"n":1015,"id":"TK-1015","ta":"பிறர்பழியும் தம்பழியும் நாணுவார் நாணுக்கு உறைபதி என்னும் உலகு.","en":"In them resides the sense of shame Who blush for their and other's blame","ch":"நாணுடைமை","chEn":"Shame","chNo":102,"sec":"Wealth"},
{"n":1016,"id":"TK-1016","ta":"நாண்வேலி கொள்ளாது மன்னோ வியன்ஞாலம் பேணலர் மேலா யவர்.","en":"The great refuse the wonder-world Without modesty's hedge and shield","ch":"நாணுடைமை","chEn":"Shame","chNo":102,"sec":"Wealth"},
{"n":1017,"id":"TK-1017","ta":"நாணால் உயிரைத் துறப்பர் உயிர்ப்பொருட்டால் நாண்துறவார் நாணாள் பவர்.","en":"For shame their life the shame-sensed give Loss of shame they won't outlive","ch":"நாணுடைமை","chEn":"Shame","chNo":102,"sec":"Wealth"},
{"n":1018,"id":"TK-1018","ta":"பிறர்நாணத் தக்கது தான்நாணா னாயின் அறம்நாணத் தக்கது உடைத்து.","en":"Virtue is much ashamed of him Who shameless does what others shame","ch":"நாணுடைமை","chEn":"Shame","chNo":102,"sec":"Wealth"},
{"n":1019,"id":"TK-1019","ta":"குலஞ்சுடும் கொள்கை பிழைப்பின் நலஞ்சுடும் நாணின்மை நின்றக் கடை.","en":"Lapse in manners injures the race Want of shame harms every good grace","ch":"நாணுடைமை","chEn":"Shame","chNo":102,"sec":"Wealth"},
{"n":1020,"id":"TK-1020","ta":"நாண்அகத் தில்லார் இயக்கம் மரப்பாவை நாணால் உயிர்மருட்டி அற்று.","en":"Movements of the shameless in heart Are string-led puppet show in fact","ch":"நாணுடைமை","chEn":"Shame","chNo":102,"sec":"Wealth"},
{"n":1021,"id":"TK-1021","ta":"கருமம் செயஒருவன் கைதூவேன் என்னும் பெருமையின் பீடுடையது இல்.","en":"No greatness is grander like Saying \\\"I shall work without slack\\\"","ch":"குடிசெயல் வகை","chEn":"The Way of Maintaining the Family","chNo":103,"sec":"Wealth"},
{"n":1022,"id":"TK-1022","ta":"ஆள்வினையும் ஆன்ற அறிவும் எனஇரண்டின் நீள்வினையால் நீளும் குடி.","en":"These two exalt a noble home Ardent effort and ripe wisdom","ch":"குடிசெயல் வகை","chEn":"The Way of Maintaining the Family","chNo":103,"sec":"Wealth"},
{"n":1023,"id":"TK-1023","ta":"குடிசெய்வல் என்னும் ஒருவற்குத் தெய்வம் மடிதற்றுத் தான்முந் துறும்.","en":"When one resolves to raise his race Loin girt up God leads his ways","ch":"குடிசெயல் வகை","chEn":"The Way of Maintaining the Family","chNo":103,"sec":"Wealth"},
{"n":1024,"id":"TK-1024","ta":"சூழாமல் தானே முடிவெய்தும் தம்குடியைத் தாழாது உஞற்று பவர்க்கு.","en":"Who raise their races with ceaseless pain No need for plan; their ends will gain","ch":"குடிசெயல் வகை","chEn":"The Way of Maintaining the Family","chNo":103,"sec":"Wealth"},
{"n":1025,"id":"TK-1025","ta":"குற்றம் இலனாய்க் குடிசெய்து வாழ்வானைச் சுற்றமாச் சுற்றும் உலகு.","en":"Who keeps his house without a blame People around, his kinship claim","ch":"குடிசெயல் வகை","chEn":"The Way of Maintaining the Family","chNo":103,"sec":"Wealth"},
{"n":1026,"id":"TK-1026","ta":"நல்லாண்மை என்பது ஒருவற்குத் தான்பிறந்த இல்லாண்மை ஆக்கிக் கொளல்.","en":"Who raise their race which gave them birth Are deemed as men of manly worth","ch":"குடிசெயல் வகை","chEn":"The Way of Maintaining the Family","chNo":103,"sec":"Wealth"},
{"n":1027,"id":"TK-1027","ta":"அமரகத்து வன்கண்ணர் போலத் தமரகத்தும் ஆற்றுவார் மேற்றே பொறை.","en":"Like dauntless heroes in battle field The home-burden rests on the bold","ch":"குடிசெயல் வகை","chEn":"The Way of Maintaining the Family","chNo":103,"sec":"Wealth"},
{"n":1028,"id":"TK-1028","ta":"குடிசெய்வார்க் கில்லை பருவம் மடிசெய்து மானங் கருதக் கெடும்.","en":"No season have they who raise their race Sloth and pride will honour efface","ch":"குடிசெயல் வகை","chEn":"The Way of Maintaining the Family","chNo":103,"sec":"Wealth"},
{"n":1029,"id":"TK-1029","ta":"இடும்பைக்கே கொள்கலம் கொல்லோ குடும்பத்தைக் குற்ற மறைப்பான் உடம்பு.","en":"Is not his frame a vase for woes Who from mishaps shields his house?","ch":"குடிசெயல் வகை","chEn":"The Way of Maintaining the Family","chNo":103,"sec":"Wealth"},
{"n":1030,"id":"TK-1030","ta":"இடுக்கண்கால் கொன்றிட வீழும் அடுத்தூன்றும் நல்லாள் இலாத குடி.","en":"A house will fall by a mishap With no good man to prop it up","ch":"குடிசெயல் வகை","chEn":"The Way of Maintaining the Family","chNo":103,"sec":"Wealth"},
{"n":1031,"id":"TK-1031","ta":"சுழன்றும்ஏர்ப் பின்னது உலகம் அதனால் உழந்தும் உழவே தலை.","en":"Farming though hard is foremost trade Men ply at will but ploughmen lead","ch":"உழவு","chEn":"Farming","chNo":104,"sec":"Wealth"},
{"n":1032,"id":"TK-1032","ta":"உழுவார் உலகத்தார்க்கு ஆணிஅஃ தாற்றாது எழுவாரை எல்லாம் பொறுத்து.","en":"Tillers are linch-pin of mankind Bearing the rest who cannot tend","ch":"உழவு","chEn":"Farming","chNo":104,"sec":"Wealth"},
{"n":1033,"id":"TK-1033","ta":"உழுதுண்டு வாழ்வாரே வாழ்வார்மற் றெல்லாம் தொழுதுண்டு பின்செல் பவர்.","en":"They live who live to plough and eat The rest behind them bow and eat","ch":"உழவு","chEn":"Farming","chNo":104,"sec":"Wealth"},
{"n":1034,"id":"TK-1034","ta":"பலகுடை நீழலும் தங்குடைக்கீழ்க் காண்பர் அலகுடை நீழ லவர்.","en":"Who have the shade of cornful crest Under their umbra umbrellas rest","ch":"உழவு","chEn":"Farming","chNo":104,"sec":"Wealth"},
{"n":1035,"id":"TK-1035","ta":"இரவார் இரப்பார்க்கொன்று ஈவர் கரவாது கைசெய்தூண் மாலை யவர்.","en":"Who till and eat, beg not; nought hide But give to those who are in need","ch":"உழவு","chEn":"Farming","chNo":104,"sec":"Wealth"},
{"n":1036,"id":"TK-1036","ta":"உழவினார் கைம்மடங்கின் இல்லை விழைவதூஉம் விட்டேம்என் பார்க்கும் நிலை.","en":"Should ploughmen sit folding their hands Desire-free monks too suffer wants","ch":"உழவு","chEn":"Farming","chNo":104,"sec":"Wealth"},
{"n":1037,"id":"TK-1037","ta":"தொடிப்புழுதி கஃசா உணக்கின் பிடித்தெருவும் வேண்டாது சாலப் படும்.","en":"Moulds dried to quarter-dust ensure Rich crops without handful manure","ch":"உழவு","chEn":"Farming","chNo":104,"sec":"Wealth"},
{"n":1038,"id":"TK-1038","ta":"ஏரினும் நன்றால் எருவிடுதல் கட்டபின் நீரினும் நன்றதன் காப்பு.","en":"Better manure than plough; then weed; Than irrigating, better guard","ch":"உழவு","chEn":"Farming","chNo":104,"sec":"Wealth"},
{"n":1039,"id":"TK-1039","ta":"செல்லான் கிழவன் இருப்பின் நிலம்புலந்து இல்லாளின் ஊடி விடும்.","en":"If landsmen sit sans moving about The field like wife will sulk and pout","ch":"உழவு","chEn":"Farming","chNo":104,"sec":"Wealth"},
{"n":1040,"id":"TK-1040","ta":"இலமென்று அசைஇ இருப்பாரைக் காணின் நிலமென்னும் நல்லாள் நகும்.","en":"Fair good earth will laugh to see Idlers pleading poverty","ch":"உழவு","chEn":"Farming","chNo":104,"sec":"Wealth"},
{"n":1041,"id":"TK-1041","ta":"இன்மையின் இன்னாதது யாதெனின் இன்மையின் இன்மையே இன்னா தது.","en":"What gives more pain than scarcity? No pain pinches like poverty","ch":"நல்குரவு","chEn":"Poverty","chNo":105,"sec":"Wealth"},
{"n":1042,"id":"TK-1042","ta":"இன்மை எனவொரு பாவி மறுமையும் இம்மையும் இன்றி வரும்.","en":"The sinner Want is enemy dire Of joys of earth and heaven there","ch":"நல்குரவு","chEn":"Poverty","chNo":105,"sec":"Wealth"},
{"n":1043,"id":"TK-1043","ta":"தொல்வரவும் தோலும் கெடுக்கும் தொகையாக நல்குரவு என்னும் நசை.","en":"The craving itch of poverty Kills graceful words and ancestry","ch":"நல்குரவு","chEn":"Poverty","chNo":105,"sec":"Wealth"},
{"n":1044,"id":"TK-1044","ta":"இற்பிறந்தார் கண்ணேயும் இன்மை இளிவந்த சொற்பிறக்கும் சோர்வு தரும்.","en":"Want makes even good familymen Utter words that are low and mean","ch":"நல்குரவு","chEn":"Poverty","chNo":105,"sec":"Wealth"},
{"n":1045,"id":"TK-1045","ta":"நல்குரவு என்னும் இடும்பையுள் பல்குரைத் துன்பங்கள் சென்று படும்.","en":"The pest of wanton poverty Brings a train of misery","ch":"நல்குரவு","chEn":"Poverty","chNo":105,"sec":"Wealth"},
{"n":1046,"id":"TK-1046","ta":"நற்பொருள் நன்குணர்ந்து சொல்லினும் நல்கூர்ந்தார் சொற்பொருள் சோர்வு படும்.","en":"The poor men's words are thrown away Though from heart good things they say","ch":"நல்குரவு","chEn":"Poverty","chNo":105,"sec":"Wealth"},
{"n":1047,"id":"TK-1047","ta":"அறஞ்சாரா நல்குரவு ஈன்றதா யானும் பிறன்போல நோக்கப் படும்.","en":"Even the mother looks as stranger The poor devoid of character","ch":"நல்குரவு","chEn":"Poverty","chNo":105,"sec":"Wealth"},
{"n":1048,"id":"TK-1048","ta":"இன்றும் வருவது கொல்லோ நெருநலும் கொன்றது போலும் நிரப்பு.","en":"The killing Want of yesterday Will it pester me even to-day?","ch":"நல்குரவு","chEn":"Poverty","chNo":105,"sec":"Wealth"},
{"n":1049,"id":"TK-1049","ta":"நெருப்பினுள் துஞ்சலும் ஆகும் நிரப்பினுள் யாதொன்றும் கண்பாடு அரிது.","en":"One may sleep in the midst of fire In want a wink of sleep is rare","ch":"நல்குரவு","chEn":"Poverty","chNo":105,"sec":"Wealth"},
{"n":1050,"id":"TK-1050","ta":"துப்புர வில்லார் துவரத் துறவாமை உப்பிற்கும் காடிக்கும் கூற்று.","en":"Renounce their lives the poor must Or salt and gruel go to waste","ch":"நல்குரவு","chEn":"Poverty","chNo":105,"sec":"Wealth"},
{"n":1051,"id":"TK-1051","ta":"இரக்க இரத்தக்கார்க் காணின் கரப்பின் அவர்பழி தம்பழி அன்று.","en":"Demand from those who can supply Default is theirs when they deny","ch":"இரவு","chEn":"Mendicancy","chNo":106,"sec":"Wealth"},
{"n":1052,"id":"TK-1052","ta":"இன்பம் ஒருவற்கு இரத்தல் இரந்தவை துன்பம் உறாஅ வரின்.","en":"Even demand becomes a joy When the things comes without annoy","ch":"இரவு","chEn":"Mendicancy","chNo":106,"sec":"Wealth"},
{"n":1053,"id":"TK-1053","ta":"கரப்பிலா நெஞ்சின் கடனறிவார் முன்நின்று இரப்புமோ ரேஎர் உடைத்து.","en":"Request has charm form open hearts Who know the duty on their part","ch":"இரவு","chEn":"Mendicancy","chNo":106,"sec":"Wealth"},
{"n":1054,"id":"TK-1054","ta":"இரத்தலும் ஈதலே போலும் கரத்தல் கனவிலும் தேற்றாதார் மாட்டு.","en":"Like giving even asking seems From those who hide not even in dreams","ch":"இரவு","chEn":"Mendicancy","chNo":106,"sec":"Wealth"},
{"n":1055,"id":"TK-1055","ta":"கரப்பிலார் வையகத்து உண்மையால் கண்ணின்று இரப்பவர் மேற்கொள் வது.","en":"The needy demand for help because The world has men who don't refuse","ch":"இரவு","chEn":"Mendicancy","chNo":106,"sec":"Wealth"},
{"n":1056,"id":"TK-1056","ta":"கரப்பிடும்பை யில்லாரைக் காணின் நிரப்பிடும்பை எல்லாம் ஒருங்கு கெடும்.","en":"The pain of poverty shall die Before the free who don't deny","ch":"இரவு","chEn":"Mendicancy","chNo":106,"sec":"Wealth"},
{"n":1057,"id":"TK-1057","ta":"இகழ்ந்தெள்ளாது ஈவாரைக் காணின் மகிழ்ந்துள்ளம் உள்ளுள் உவப்பது உடைத்து.","en":"When givers without scorn impart A thrill of delight fills the heart","ch":"இரவு","chEn":"Mendicancy","chNo":106,"sec":"Wealth"},
{"n":1058,"id":"TK-1058","ta":"இரப்பாரை இல்லாயின் ஈர்ங்கண்மா ஞாலம் மரப்பாவை சென்றுவந் தற்று.","en":"This grand cool world shall move to and fro Sans Askers like a puppet show","ch":"இரவு","chEn":"Mendicancy","chNo":106,"sec":"Wealth"},
{"n":1059,"id":"TK-1059","ta":"ஈவார்கண் என்னுண்டாம் தோற்றம் இரந்துகோள் மேவார் இலாஅக் கடை.","en":"Where stands the glory of givers Without obligation seekers?","ch":"இரவு","chEn":"Mendicancy","chNo":106,"sec":"Wealth"},
{"n":1060,"id":"TK-1060","ta":"இரப்பான் வெகுளாமை வேண்டும் நிரப்பிடும்பை தானேயும் சாலும் கரி.","en":"The needy should not scowl at \\\"No\\\" His need another's need must show * Saint valluvar talks of two kinds of Asking:() Asking help for public causes or enterprises () Begging when one is able to work and this is condemned","ch":"இரவு","chEn":"Mendicancy","chNo":106,"sec":"Wealth"},
{"n":1061,"id":"TK-1061","ta":"கரவாது உவந்தீயும் கண்ணன்னார் கண்ணும் இரவாமை கோடி உறும்.","en":"Not to beg is billions worth E'en from eye-like friends who give with mirth","ch":"இரவச்சம்","chEn":"The Dread of Mendicancy","chNo":107,"sec":"Wealth"},
{"n":1062,"id":"TK-1062","ta":"இரந்தும் உயிர்வாழ்தல் வேண்டின் பரந்து கெடுக உலகியற்றி யான்.","en":"Let World-Maker loiter and rot If \\\"beg and live\\\" be human fate","ch":"இரவச்சம்","chEn":"The Dread of Mendicancy","chNo":107,"sec":"Wealth"},
{"n":1063,"id":"TK-1063","ta":"இன்மை இடும்பை இரந்துதீர் வாமென்னும் வன்மையின் வன்பாட்ட தில்.","en":"Nothing is hard like hard saying \\\"We end poverty by begging\\\"","ch":"இரவச்சம்","chEn":"The Dread of Mendicancy","chNo":107,"sec":"Wealth"},
{"n":1064,"id":"TK-1064","ta":"இடமெல்லாம் கொள்ளாத் தகைத்தே இடமில்லாக் காலும் இரவொல்லாச் சால்பு.","en":"All space is small before the great Who beg not e'en in want acute","ch":"இரவச்சம்","chEn":"The Dread of Mendicancy","chNo":107,"sec":"Wealth"},
{"n":1065,"id":"TK-1065","ta":"தெண்ணீர் அடுபுற்கை ஆயினும் தாள்தந்தது உண்ணலின் ஊங்கினிய தில்.","en":"Though gruel thin, nothing is sweet Like the food earned by labour's sweat","ch":"இரவச்சம்","chEn":"The Dread of Mendicancy","chNo":107,"sec":"Wealth"},
{"n":1066,"id":"TK-1066","ta":"ஆவிற்கு நீரென்று இரப்பினும் நாவிற்கு இரவின் இளிவந்த தில்.","en":"It may be water for the cow Begging tongue is mean anyhow","ch":"இரவச்சம்","chEn":"The Dread of Mendicancy","chNo":107,"sec":"Wealth"},
{"n":1067,"id":"TK-1067","ta":"இரப்பன் இரப்பாரை எல்லாம் இரப்பின் கரப்பார் இரவன்மின் என்று.","en":"If beg they must I beg beggers Not to beg from shrinking misers","ch":"இரவச்சம்","chEn":"The Dread of Mendicancy","chNo":107,"sec":"Wealth"},
{"n":1068,"id":"TK-1068","ta":"இரவென்னும் ஏமாப்பில் தோணி கரவென்னும் பார்தாக்கப் பக்கு விடும்.","en":"The hapless bark of beggary splits On the rock of refusing hits","ch":"இரவச்சம்","chEn":"The Dread of Mendicancy","chNo":107,"sec":"Wealth"},
{"n":1069,"id":"TK-1069","ta":"இரவுள்ள உள்ளம் உருகும் கரவுள்ள உள்ளதூஉம் இன்றிக் கெடும்.","en":"The heart at thought of beggars melts; It dies at repulsing insults","ch":"இரவச்சம்","chEn":"The Dread of Mendicancy","chNo":107,"sec":"Wealth"},
{"n":1070,"id":"TK-1070","ta":"கரப்பவர்க்கு யாங்கொளிக்கும் கொல்லோ இரப்பவர் சொல்லாடப் போஒம் உயிர்.","en":"The word \\\"No\\\" kills the begger's life Where can the niggard's life be safe?","ch":"இரவச்சம்","chEn":"The Dread of Mendicancy","chNo":107,"sec":"Wealth"},
{"n":1071,"id":"TK-1071","ta":"மக்களே போல்வர் கயவர் அவரன்ன ஒப்பாரி யாங்கண்ட தில்.","en":"The mean seem men only in form We have never seen such a sham","ch":"கயமை","chEn":"Baseness","chNo":108,"sec":"Wealth"},
{"n":1072,"id":"TK-1072","ta":"நன்றறி வாரிற் கயவர் திருவுடையர் நெஞ்சத்து அவலம் இலர்.","en":"The base seem richer than the good For no care enters their heart or head","ch":"கயமை","chEn":"Baseness","chNo":108,"sec":"Wealth"},
{"n":1073,"id":"TK-1073","ta":"தேவர் அனையர் கயவர் அவருந்தாம் மேவன செய்தொழுக லான்.","en":"The base are like gods; for they too As prompted by their desire do","ch":"கயமை","chEn":"Baseness","chNo":108,"sec":"Wealth"},
{"n":1074,"id":"TK-1074","ta":"அகப்பட்டி ஆவாரைக் காணின் அவரின் மிகப்பட்டுச் செம்மாக்கும் கீழ்.","en":"When the base meets a rake so vile Him he will exceed, exult and smile","ch":"கயமை","chEn":"Baseness","chNo":108,"sec":"Wealth"},
{"n":1075,"id":"TK-1075","ta":"அச்சமே கீழ்களது ஆசாரம் எச்சம் அவாவுண்டேல் உண்டாம் சிறிது.","en":"Fear forms the conduct of the low Craving avails a bit below","ch":"கயமை","chEn":"Baseness","chNo":108,"sec":"Wealth"},
{"n":1076,"id":"TK-1076","ta":"அறைபறை அன்னர் கயவர்தாம் கேட்ட மறைபிறர்க்கு உய்த்துரைக்க லான்.","en":"The base are like the beaten drum Since other's secrets they proclaim","ch":"கயமை","chEn":"Baseness","chNo":108,"sec":"Wealth"},
{"n":1077,"id":"TK-1077","ta":"ஈர்ங்கை விதிரார் கயவர் கொடிறுடைக்கும் கூன்கையர் அல்லா தவர்க்கு.","en":"The base their damp hand will not shake But for fists clenched their jaws to break","ch":"கயமை","chEn":"Baseness","chNo":108,"sec":"Wealth"},
{"n":1078,"id":"TK-1078","ta":"சொல்லப் பயன்படுவர் சான்றோர் கரும்புபோல் கொல்லப் பயன்படும் கீழ்.","en":"The good by soft words profits yield The cane-like base when crushed and killed","ch":"கயமை","chEn":"Baseness","chNo":108,"sec":"Wealth"},
{"n":1079,"id":"TK-1079","ta":"உடுப்பதூஉம் உண்பதூஉம் காணின் பிறர்மேல் வடுக்காண வற்றாகும் கீழ்.","en":"Faults in others the mean will guess On seeing how they eat and dress","ch":"கயமை","chEn":"Baseness","chNo":108,"sec":"Wealth"},
{"n":1080,"id":"TK-1080","ta":"எற்றிற் குரியர் கயவரொன்று உற்றக்கால் விற்றற்கு உரியர் விரைந்து.","en":"The base hasten to sell themselves From doom to flit and nothing else","ch":"கயமை","chEn":"Baseness","chNo":108,"sec":"Wealth"},
{"n":1081,"id":"TK-1081","ta":"அணங்குகொல் ஆய்மயில் கொல்லோ கனங்குழை மாதர்கொல் மாலும் என் நெஞ்சு.","en":"Is it an angel? A fair peacock Or jewelled belle? To my mind a shock!","ch":"தகை அணங்குறுத்தல்","chEn":"The Pre-marital love","chNo":109,"sec":"Love"},
{"n":1082,"id":"TK-1082","ta":"நோக்கினாள் நோக்கெதிர் நோக்குதல் தாக்கணங்கு தானைக்கொண் டன்ன துடைத்து.","en":"The counter glances of this belle Are armied dart of the Love-Angel","ch":"தகை அணங்குறுத்தல்","chEn":"The Pre-marital love","chNo":109,"sec":"Love"},
{"n":1083,"id":"TK-1083","ta":"பண்டறியேன் கூற்றென் பதனை இனியறிந்தேன் பெண்டகையால் பேரமர்க் கட்டு.","en":"Not known before -I spy Demise In woman's guise with battling eyes","ch":"தகை அணங்குறுத்தல்","chEn":"The Pre-marital love","chNo":109,"sec":"Love"},
{"n":1084,"id":"TK-1084","ta":"கண்டார் உயிருண்ணும் தோற்றத்தால் பெண்டகைப் பேதைக்கு அமர்த்தன கண்.","en":"This artless dame has darting eyes That drink the life of men who gaze","ch":"தகை அணங்குறுத்தல்","chEn":"The Pre-marital love","chNo":109,"sec":"Love"},
{"n":1085,"id":"TK-1085","ta":"கூற்றமோ கண்ணோ பிணையோ மடவரல் நோக்கமிம் மூன்றும் உடைத்து.","en":"Is it death, eye or doe? All three In winsome woman's look I see","ch":"தகை அணங்குறுத்தல்","chEn":"The Pre-marital love","chNo":109,"sec":"Love"},
{"n":1086,"id":"TK-1086","ta":"கொடும்புருவம் கோடா மறைப்பின் நடுங்கஞர் செய்யல மன்இவள் கண்.","en":"If cruel brows unbent, would screen Her eyes won't cause me trembling pain","ch":"தகை அணங்குறுத்தல்","chEn":"The Pre-marital love","chNo":109,"sec":"Love"},
{"n":1087,"id":"TK-1087","ta":"கடாஅக் களிற்றின்மேற் கட்படாம் மாதர் படாஅ முலைமேல் துகில்.","en":"Vest on the buxom breast of her Looks like rutting tusker's eye-cover","ch":"தகை அணங்குறுத்தல்","chEn":"The Pre-marital love","chNo":109,"sec":"Love"},
{"n":1088,"id":"TK-1088","ta":"ஒண்ணுதற் கோஒ உடைந்ததே ஞாட்பினுள் நண்ணாரும் உட்குமென் பீடு.","en":"Ah these fair brows shatter my might Feared by foemen yet to meet","ch":"தகை அணங்குறுத்தல்","chEn":"The Pre-marital love","chNo":109,"sec":"Love"},
{"n":1089,"id":"TK-1089","ta":"பிணையேர் மடநோக்கும் நாணும் உடையாட்கு அணியெவனோ ஏதில தந்து.","en":"Which jewel can add to her beauty With fawn-like looks and modesty?","ch":"தகை அணங்குறுத்தல்","chEn":"The Pre-marital love","chNo":109,"sec":"Love"},
{"n":1090,"id":"TK-1090","ta":"உண்டார்கண் அல்லது அடுநறாக் காமம்போல் கண்டார் மகிழ்செய்தல் இன்று.","en":"To the drunk alone is wine delight Nothing delights like love at sight","ch":"தகை அணங்குறுத்தல்","chEn":"The Pre-marital love","chNo":109,"sec":"Love"},
{"n":1091,"id":"TK-1091","ta":"இருநோக்கு இவளுண்கண் உள்ளது ஒருநோக்கு நோய்நோக்கொன் றந்நோய் மருந்து.","en":"Her painted eyes, two glances dart One hurts; the other heals my heart","ch":"குறிப்பறிதல்","chEn":"Recognition of the Signs ","chNo":110,"sec":"Love"},
{"n":1092,"id":"TK-1092","ta":"கண்களவு கொள்ளும் சிறுநோக்கம் காமத்தில் செம்பாகம் அன்று பெரிது.","en":"Her furtive lightning glance is more Than enjoyment of sexual lore","ch":"குறிப்பறிதல்","chEn":"Recognition of the Signs ","chNo":110,"sec":"Love"},
{"n":1093,"id":"TK-1093","ta":"நோக்கினாள் நோக்கி இறைஞ்சினாள் அஃதவள் யாப்பினுள் அட்டிய நீர்.","en":"She looked; looking bowed her head And love-plant was with water fed","ch":"குறிப்பறிதல்","chEn":"Recognition of the Signs ","chNo":110,"sec":"Love"},
{"n":1094,"id":"TK-1094","ta":"யான்நோக்கும் காலை நிலன்நோக்கும் நோக்காக்கால் தான்நோக்கி மெல்ல நகும்.","en":"I look; she droops to earth awhile I turn; she looks with gentle smile","ch":"குறிப்பறிதல்","chEn":"Recognition of the Signs ","chNo":110,"sec":"Love"},
{"n":1095,"id":"TK-1095","ta":"குறிக்கொண்டு நோக்காமை அல்லால் ஒருகண் சிறக்கணித்தாள் போல நகும்","en":"No direct gaze; a side-long glance She darts at me and smiles askance","ch":"குறிப்பறிதல்","chEn":"Recognition of the Signs ","chNo":110,"sec":"Love"},
{"n":1096,"id":"TK-1096","ta":"உறாஅ தவர்போல் சொலினும் செறாஅர்சொல் ஒல்லை உணரப் படும்.","en":"Their words at first seem an offence But quick we feel them friendly ones","ch":"குறிப்பறிதல்","chEn":"Recognition of the Signs ","chNo":110,"sec":"Love"},
{"n":1097,"id":"TK-1097","ta":"செறாஅச் சிறுசொல்லும் செற்றார்போல் நோக்கும் உறாஅர்போன்று உற்றார் குறிப்பு.","en":"Harsh little words; offended looks, Are feigned consenting love-lorn tricks","ch":"குறிப்பறிதல்","chEn":"Recognition of the Signs ","chNo":110,"sec":"Love"},
{"n":1098,"id":"TK-1098","ta":"அசையியற்கு உண்டாண்டோர் ஏஎர்யான் நோக்கப் பசையினள் பைய நகும்.","en":"What a grace the slim maid has! As I look she slightly smiles","ch":"குறிப்பறிதல்","chEn":"Recognition of the Signs ","chNo":110,"sec":"Love"},
{"n":1099,"id":"TK-1099","ta":"ஏதிலார் போலப் பொதுநோக்கு நோக்குதல் காதலார் கண்ணே உள.","en":"Between lovers we do discern A stranger's look of unconcern","ch":"குறிப்பறிதல்","chEn":"Recognition of the Signs ","chNo":110,"sec":"Love"},
{"n":1100,"id":"TK-1100","ta":"கண்ணொடு கண்இணை நோக்கொக்கின் வாய்ச்சொற்கள் என்ன பயனும் இல.","en":"The words of mouth are of no use When eye to eye agrees the gaze","ch":"குறிப்பறிதல்","chEn":"Recognition of the Signs ","chNo":110,"sec":"Love"},
{"n":1101,"id":"TK-1101","ta":"கண்டுகேட்டு உண்டுயிர்த்து உற்றறியும் ஐம்புலனும் ஒண்தொடி கண்ணே உள.","en":"In this bangled beauty dwell The joys of sight sound touch taste smell","ch":"புணர்ச்சி மகிழ்தல்","chEn":"Rejoicing in the Embrace","chNo":111,"sec":"Love"},
{"n":1102,"id":"TK-1102","ta":"பிணிக்கு மருந்து பிறமன் அணியிழை தன்நோய்க்குத் தானே மருந்து.","en":"The cure for ailment is somewhere For fair maid's ill she is the cure","ch":"புணர்ச்சி மகிழ்தல்","chEn":"Rejoicing in the Embrace","chNo":111,"sec":"Love"},
{"n":1103,"id":"TK-1103","ta":"தாம்வீழ்வார் மென்றோள் துயிலின் இனிதுகொல் தாமரைக் கண்ணான் உலகு.","en":"Is lotus-eyed lord's heaven so sweet As sleep in lover's arms so soft?","ch":"புணர்ச்சி மகிழ்தல்","chEn":"Rejoicing in the Embrace","chNo":111,"sec":"Love"},
{"n":1104,"id":"TK-1104","ta":"நீங்கின் தெறூஉம் குறுகுங்கால் தண்ணென்னும் தீயாண்டுப் பெற்றாள் இவள்?","en":"Away it burns and cools anear Wherefrom did she get this fire?","ch":"புணர்ச்சி மகிழ்தல்","chEn":"Rejoicing in the Embrace","chNo":111,"sec":"Love"},
{"n":1105,"id":"TK-1105","ta":"வேட்ட பொழுதின் அவையவை போலுமே தோட்டார் கதுப்பினாள் தோள்.","en":"The arms of my flower-tressed maid Whatever I wish that that accord","ch":"புணர்ச்சி மகிழ்தல்","chEn":"Rejoicing in the Embrace","chNo":111,"sec":"Love"},
{"n":1106,"id":"TK-1106","ta":"உறுதோறு உயிர்தளிர்ப்பத் தீண்டலால் பேதைக்கு அமிழ்தின் இயன்றன தோள்.","en":"My simple maid has nectar arms Each embrace brings life-thrilling charms","ch":"புணர்ச்சி மகிழ்தல்","chEn":"Rejoicing in the Embrace","chNo":111,"sec":"Love"},
{"n":1107,"id":"TK-1107","ta":"தம்மில் இருந்து தமதுபாத்து உண்டற்றால் அம்மா அரிவை முயக்கு.","en":"Ah the embrace of this fair dame Is like sharing one's food at home","ch":"புணர்ச்சி மகிழ்தல்","chEn":"Rejoicing in the Embrace","chNo":111,"sec":"Love"},
{"n":1108,"id":"TK-1108","ta":"வீழும் இருவர்க்கு இனிதே வளியிடை போழப் படாஅ முயக்கு.","en":"Joy is the fast embrace that doth Not admit e'en air between both","ch":"புணர்ச்சி மகிழ்தல்","chEn":"Rejoicing in the Embrace","chNo":111,"sec":"Love"},
{"n":1109,"id":"TK-1109","ta":"ஊடல் உணர்தல் புணர்தல் இவைகாமம் கூடியார் பெற்ற பயன்.","en":"Sulking, feeling and clasping fast These three are sweets of lover's tryst","ch":"புணர்ச்சி மகிழ்தல்","chEn":"Rejoicing in the Embrace","chNo":111,"sec":"Love"},
{"n":1110,"id":"TK-1110","ta":"அறிதோறு அறியாமை கண்டற்றால் காமம் செறிதோறும் சேயிழை மாட்டு.","en":"As knowledge reveals past ignorance So is the belle as love gets close","ch":"புணர்ச்சி மகிழ்தல்","chEn":"Rejoicing in the Embrace","chNo":111,"sec":"Love"},
{"n":1111,"id":"TK-1111","ta":"நன்னீரை வாழி அனிச்சமே நின்னினும் மென்னீரள் யாம்வீழ் பவள்.","en":"Soft blessed anicha flower, hail On whom I dote is softer still","ch":"நலம் புனைந்து உரைத்தல்","chEn":"The Praise of her Beauty","chNo":112,"sec":"Love"},
{"n":1112,"id":"TK-1112","ta":"மலர்காணின் மையாத்தி நெஞ்சே இவள்கண் பலர்காணும் பூவொக்கும் என்று.","en":"You can't liken flowers by many eyed, To her bright eyes, O mind dismayed","ch":"நலம் புனைந்து உரைத்தல்","chEn":"The Praise of her Beauty","chNo":112,"sec":"Love"},
{"n":1113,"id":"TK-1113","ta":"முறிமேனி முத்தம் முறுவல் வெறிநாற்றம் வேலுண்கண் வேய்த்தோ ளவட்கு.","en":"The bamboo-shouldered has pearl-like smiles Fragrant breath and lance-like eyes","ch":"நலம் புனைந்து உரைத்தல்","chEn":"The Praise of her Beauty","chNo":112,"sec":"Love"},
{"n":1114,"id":"TK-1114","ta":"காணின் குவளை கவிழ்ந்து நிலன்நோக்கும் மாணிழை கண்ணொவ்வேம் என்று.","en":"Lily droops down to ground and says I can't equal the jewelled-one's eyes","ch":"நலம் புனைந்து உரைத்தல்","chEn":"The Praise of her Beauty","chNo":112,"sec":"Love"},
{"n":1115,"id":"TK-1115","ta":"அனிச்சப்பூக் கால்களையாள் பெய்தாள் நுகப்பிற்கு நல்ல படாஅ பறை.","en":"Anicha flower with stem she wears To her breaking waist sad-drum-blares!","ch":"நலம் புனைந்து உரைத்தல்","chEn":"The Praise of her Beauty","chNo":112,"sec":"Love"},
{"n":1116,"id":"TK-1116","ta":"மதியும் மடந்தை முகனும் அறியா பதியின் கலங்கிய மீன்.","en":"Stars are confused to know which is The moon and which is woman's face","ch":"நலம் புனைந்து உரைத்தல்","chEn":"The Praise of her Beauty","chNo":112,"sec":"Love"},
{"n":1117,"id":"TK-1117","ta":"அறுவாய் நிறைந்த அவிர்மதிக்குப் க்குப் போல மறுவுண்டோ மாதர் முகத்து.","en":"Are there spots on the lady's face Just as in moon that changes phase?","ch":"நலம் புனைந்து உரைத்தல்","chEn":"The Praise of her Beauty","chNo":112,"sec":"Love"},
{"n":1118,"id":"TK-1118","ta":"மாதர் முகம்போல் ஒளிவிட வல்லையேல் காதலை வாழி மத஧.","en":"Like my lady's face if you shine All my love to you; hail O moon!","ch":"நலம் புனைந்து உரைத்தல்","chEn":"The Praise of her Beauty","chNo":112,"sec":"Love"},
{"n":1119,"id":"TK-1119","ta":"மலரன்ன கண்ணாள் முகமொத்தி யாயின் பலர்காணத் தோன்றல் மதி.","en":"Like the face of my flower-eyed one If you look, then shine alone O moon!","ch":"நலம் புனைந்து உரைத்தல்","chEn":"The Praise of her Beauty","chNo":112,"sec":"Love"},
{"n":1120,"id":"TK-1120","ta":"அனிச்சமும் அன்னத்தின் தூவியும் மாதர் அடிக்கு நெருஞ்சிப் பழம்.","en":"The soft flower and the swan's down are Like nettles to the feet of the fair","ch":"நலம் புனைந்து உரைத்தல்","chEn":"The Praise of her Beauty","chNo":112,"sec":"Love"},
{"n":1121,"id":"TK-1121","ta":"பாலொடு தேன்கலந் தற்றே பணிமொழி வாலெயிறு ஊறிய நீர்.","en":"Like milk and honey the dew is sweet From her white teeth whose word is soft","ch":"காதற் சிறப்புரைத்தல்","chEn":"Declaration of Love\"s special Excellence","chNo":113,"sec":"Love"},
{"n":1122,"id":"TK-1122","ta":"உடம்பொடு உயிரிடை என்னமற் றன்ன மடந்தையொடு எம்மிடை நட்பு.","en":"Love between me and this lady Is like bond between soul and body","ch":"காதற் சிறப்புரைத்தல்","chEn":"Declaration of Love\"s special Excellence","chNo":113,"sec":"Love"},
{"n":1123,"id":"TK-1123","ta":"கருமணியிற் பாவாய்நீ போதாயாம் வீழும் திருநுதற்கு இல்லை இடம்.","en":"Depart image in my pupil Giving room to my fair-browed belle!","ch":"காதற் சிறப்புரைத்தல்","chEn":"Declaration of Love\"s special Excellence","chNo":113,"sec":"Love"},
{"n":1124,"id":"TK-1124","ta":"வாழ்தல் உயிர்க்கன்னள் ஆயிழை சாதல் அதற்கன்னள் நீங்கும் இடத்து.","en":"Life with my jewel is existence Death it is her severance","ch":"காதற் சிறப்புரைத்தல்","chEn":"Declaration of Love\"s special Excellence","chNo":113,"sec":"Love"},
{"n":1125,"id":"TK-1125","ta":"உள்ளுவன் மன்யான் மறப்பின் மறப்பறியேன் ஒள்ளமர்க் கண்ணாள் குணம்.","en":"Can I forget? I recall always The charms of her bright battling eyes","ch":"காதற் சிறப்புரைத்தல்","chEn":"Declaration of Love\"s special Excellence","chNo":113,"sec":"Love"},
{"n":1126,"id":"TK-1126","ta":"கண்ணுள்ளின் போகார் இமைப்பின் பருகுவரா நுண்ணியர்எம் காத லவர்.","en":"So subtle is my lover's form Ever in my eyes winking, no harm","ch":"காதற் சிறப்புரைத்தல்","chEn":"Declaration of Love\"s special Excellence","chNo":113,"sec":"Love"},
{"n":1127,"id":"TK-1127","ta":"கண்ணுள்ளார் காத லவராகக் கண்ணும் எழுதேம் கரப்பாக்கு அறிந்து.","en":"My lover in my eyes abides I paint them not lest he hides","ch":"காதற் சிறப்புரைத்தல்","chEn":"Declaration of Love\"s special Excellence","chNo":113,"sec":"Love"},
{"n":1128,"id":"TK-1128","ta":"நெஞ்சத்தார் காத லவராக வெய்துண்டல் அஞ்சுதும் வேபாக் கறிந்து.","en":"My lover abides in my heart I fear hot food lest he feels hot","ch":"காதற் சிறப்புரைத்தல்","chEn":"Declaration of Love\"s special Excellence","chNo":113,"sec":"Love"},
{"n":1129,"id":"TK-1129","ta":"இமைப்பின் கரப்பாக்கு அறிவல் அனைத்திற்கே ஏதிலர் என்னும் இவ் வூர்.","en":"My eyes wink not lest he should hide And him as cruel the townsmen chide","ch":"காதற் சிறப்புரைத்தல்","chEn":"Declaration of Love\"s special Excellence","chNo":113,"sec":"Love"},
{"n":1130,"id":"TK-1130","ta":"உவந்துறைவர் உள்ளத்துள் என்றும் இகந்துறைவர் ஏதிலர் என்னும் இவ் வூர்.","en":"He abides happy in my heart But people mistake he is apart","ch":"காதற் சிறப்புரைத்தல்","chEn":"Declaration of Love\"s special Excellence","chNo":113,"sec":"Love"},
{"n":1131,"id":"TK-1131","ta":"காமம் உழந்து வருந்தினார்க்கு ஏமம் மடலல்லது இல்லை வலி.","en":"Pangs of passion find no recourse Except riding *`palmyra horse' * Palmyra horse or 'Madal' is a torture expressive of the burning passion of the lover to the beloved The lover's body is laid on a rough pricking palmyra bed and he is carried along the street with songs of love pangs The parents of the lovers first reproach them and then consent to their marriage","ch":"நாணுத் துறவுரைத்தல்","chEn":"The Abandonment of Reserve","chNo":114,"sec":"Love"},
{"n":1132,"id":"TK-1132","ta":"நோனா உடம்பும் உயிரும் மடலேறும் நாணினை நீக்கி நிறுத்து.","en":"Pining body and mind lose shame And take to riding of the palm","ch":"நாணுத் துறவுரைத்தல்","chEn":"The Abandonment of Reserve","chNo":114,"sec":"Love"},
{"n":1133,"id":"TK-1133","ta":"நாணொடு நல்லாண்மை பண்டுடையேன் இன்றுடையேன் காமுற்றார் ஏறும் மடல்.","en":"Once I was modest and manly My love has now Madal only","ch":"நாணுத் துறவுரைத்தல்","chEn":"The Abandonment of Reserve","chNo":114,"sec":"Love"},
{"n":1134,"id":"TK-1134","ta":"காமக் கடும்புனல் உய்க்கும் நாணொடு நல்லாண்மை என்னும் புணை.","en":"Rushing flood of love sweeps away The raft of shame and firmness, aye!","ch":"நாணுத் துறவுரைத்தல்","chEn":"The Abandonment of Reserve","chNo":114,"sec":"Love"},
{"n":1135,"id":"TK-1135","ta":"தொடலைக் குறுந்தொடி தந்தாள் மடலொடு மாலை உழக்கும் துயர்.","en":"Palm-ride and pangs of eventide Are gifts of wreath-like bracelet maid","ch":"நாணுத் துறவுரைத்தல்","chEn":"The Abandonment of Reserve","chNo":114,"sec":"Love"},
{"n":1136,"id":"TK-1136","ta":"மடலூர்தல் யாமத்தும் உள்ளுவேன் மன்ற படல்ஒல்லா பேதைக்கென் கண்.","en":"Madal I ride at midnight for My eyes sleep not seeing this fair","ch":"நாணுத் துறவுரைத்தல்","chEn":"The Abandonment of Reserve","chNo":114,"sec":"Love"},
{"n":1137,"id":"TK-1137","ta":"கடலன்ன காமம் உழந்தும் மடலேறாப் பெண்ணின் பெருந்தக்க தில்.","en":"Her sea-like lust seeks not Madal! Serene is woman's self control","ch":"நாணுத் துறவுரைத்தல்","chEn":"The Abandonment of Reserve","chNo":114,"sec":"Love"},
{"n":1138,"id":"TK-1138","ta":"நிறையரியர் மன்அளியர் என்னாது காமம் மறையிறந்து மன்று படும்.","en":"Lust betrays itself in haste Though women are highly soft and chaste","ch":"நாணுத் துறவுரைத்தல்","chEn":"The Abandonment of Reserve","chNo":114,"sec":"Love"},
{"n":1139,"id":"TK-1139","ta":"அறிகிலார் எல்லாரும் என்றேஎன் காமம் மறுகின் மறுகும் மருண்டு.","en":"My perplexed love roves public street Believing that none knows its secret","ch":"நாணுத் துறவுரைத்தல்","chEn":"The Abandonment of Reserve","chNo":114,"sec":"Love"},
{"n":1140,"id":"TK-1140","ta":"யாம்கண்ணின் காண நகுப அறிவில்லார் யாம்பட்ட தாம்படா ஆறு.","en":"Fools laugh at me before my eyes For they feel not my pangs and sighs","ch":"நாணுத் துறவுரைத்தல்","chEn":"The Abandonment of Reserve","chNo":114,"sec":"Love"},
{"n":1141,"id":"TK-1141","ta":"அலரெழ ஆருயிர் நிற்கும் அதனைப் பலரறியார் பாக்கியத் தால்.","en":"Rumour sustains my existence Good luck! many know not its sense","ch":"அலர் அறிவுறுத்தல்","chEn":"The Announcement of the Rumour","chNo":115,"sec":"Love"},
{"n":1142,"id":"TK-1142","ta":"மலரன்ன கண்ணாள் அருமை அறியாது அலரெமக்கு ஈந்ததிவ் வூர்.","en":"Rumour gives me the flower-like belle People know not what rare angel","ch":"அலர் அறிவுறுத்தல்","chEn":"The Announcement of the Rumour","chNo":115,"sec":"Love"},
{"n":1143,"id":"TK-1143","ta":"உறாஅதோ ஊரறிந்த கெளவை அதனைப் பெறாஅது பெற்றன்ன நீர்த்து.","en":"I profit by this public rumour Having not, I feel, I have her","ch":"அலர் அறிவுறுத்தல்","chEn":"The Announcement of the Rumour","chNo":115,"sec":"Love"},
{"n":1144,"id":"TK-1144","ta":"கவ்வையால் கவ்விது காமம் அதுவின்றேல் தவ்வென்னும் தன்மை இழந்து.","en":"Rumour inflames the love I seek Or else it becomes bleak and weak","ch":"அலர் அறிவுறுத்தல்","chEn":"The Announcement of the Rumour","chNo":115,"sec":"Love"},
{"n":1145,"id":"TK-1145","ta":"களித்தொறும் கள்ளுண்டல் வேட்டற்றால் காமம் வெளிப்படுந் தோறும் இனிது.","en":"Drink delights as liquor flows Love delights as rumour grows","ch":"அலர் அறிவுறுத்தல்","chEn":"The Announcement of the Rumour","chNo":115,"sec":"Love"},
{"n":1146,"id":"TK-1146","ta":"கண்டது மன்னும் ஒருநாள் அலர்மன்னும் திங்களைப் பாம்புகொண் டற்று.","en":"One lasting day we met alone Lasting rumours eclipse our moon","ch":"அலர் அறிவுறுத்தல்","chEn":"The Announcement of the Rumour","chNo":115,"sec":"Love"},
{"n":1147,"id":"TK-1147","ta":"ஊரவர் கெளவை எருவாக அன்னைசொல் நீராக நீளும்இந் நோய்.","en":"Scandal manures; mother's refrain Waters the growth of this love-pain","ch":"அலர் அறிவுறுத்தல்","chEn":"The Announcement of the Rumour","chNo":115,"sec":"Love"},
{"n":1148,"id":"TK-1148","ta":"நெய்யால் எரிநுதுப்பேம் என்றற்றால் கெளவையால் காமம் நுதுப்பேம் எனல்.","en":"To quench the lust by rumour free Is to quench fire by pouring ghee","ch":"அலர் அறிவுறுத்தல்","chEn":"The Announcement of the Rumour","chNo":115,"sec":"Love"},
{"n":1149,"id":"TK-1149","ta":"அலர்நாண ஒல்வதோ அஞ்சலோம்பு என்றார் பலர்நாண நீத்தக் கடை.","en":"Who said \\\"fear not\\\" flared up rumour Why then should I blush this clamour?","ch":"அலர் அறிவுறுத்தல்","chEn":"The Announcement of the Rumour","chNo":115,"sec":"Love"},
{"n":1150,"id":"TK-1150","ta":"தாம்வேண்டின் நல்குவர் காதலர் யாம்வேண்டும் கெளவை எடுக்கும்இவ் வூர்.","en":"Town raising this cry, I desire Consent is easy from my sire","ch":"அலர் அறிவுறுத்தல்","chEn":"The Announcement of the Rumour","chNo":115,"sec":"Love"},
{"n":1151,"id":"TK-1151","ta":"செல்லாமை உண்டேல் எனக்குரை மற்றுநின் வல்வரவு வாழ்வார்க் குரை.","en":"Tell me if you but do not leave, Your quick return to those who live","ch":"பிரிவு ஆற்றாமை","chEn":"Separation unendurable","chNo":116,"sec":"Love"},
{"n":1152,"id":"TK-1152","ta":"இன்கண் உடைத்தவர் பார்வல் பிரிவஞ்சும் புன்கண் உடைத்தால் புணர்வு.","en":"His sight itself was pleasing, near Embrace pains now by partings fear","ch":"பிரிவு ஆற்றாமை","chEn":"Separation unendurable","chNo":116,"sec":"Love"},
{"n":1153,"id":"TK-1153","ta":"அரிதரோ தேற்றம் அறிவுடையார் கண்ணும் பிரிவோ ரிடத்துண்மை யான்.","en":"On whom shall I lay my trust hence While parting lurks in knowing ones?","ch":"பிரிவு ஆற்றாமை","chEn":"Separation unendurable","chNo":116,"sec":"Love"},
{"n":1154,"id":"TK-1154","ta":"அளித்தஞ்சல் என்றவர் நீப்பின் தெளித்தசொல் தேறியார்க்கு உண்டோ தவறு.","en":"He parts whose love told me -fear not Is my trust in him at default?","ch":"பிரிவு ஆற்றாமை","chEn":"Separation unendurable","chNo":116,"sec":"Love"},
{"n":1155,"id":"TK-1155","ta":"ஓம்பின் அமைந்தார் பிரிவோம்பல் மற்றவர் நீங்கின் அரிதால் புணர்வு.","en":"Stop his parting -my life to save Meeting is rare if he would leave","ch":"பிரிவு ஆற்றாமை","chEn":"Separation unendurable","chNo":116,"sec":"Love"},
{"n":1156,"id":"TK-1156","ta":"பிரிவுரைக்கும் வன்கண்ணர் ஆயின் அரிதவர் நல்குவர் என்னும் நசை.","en":"His hardness says, \\\"I leave you now\\\" Is there hope of his renewed love?","ch":"பிரிவு ஆற்றாமை","chEn":"Separation unendurable","chNo":116,"sec":"Love"},
{"n":1157,"id":"TK-1157","ta":"துறைவன் துறந்தமை தூற்றாகொல் முன்கை இறைஇறவா நின்ற வளை.","en":"Will not my gliding bangles' cry The parting of my lord betray?","ch":"பிரிவு ஆற்றாமை","chEn":"Separation unendurable","chNo":116,"sec":"Love"},
{"n":1158,"id":"TK-1158","ta":"இன்னாது இனன்இல்ஊர் வாழ்தல் அதனினும் இன்னாது இனியார்ப் பிரிவு.","en":"Bitter is life in friendless place; Worse is parting love's embrace!","ch":"பிரிவு ஆற்றாமை","chEn":"Separation unendurable","chNo":116,"sec":"Love"},
{"n":1159,"id":"TK-1159","ta":"தொடிற்சுடின் அல்லது காமநோய் போல விடிற்சுடல் ஆற்றுமோ தீ.","en":"Can fire that burns by touch burn like Parting of the hearts love-sick?","ch":"பிரிவு ஆற்றாமை","chEn":"Separation unendurable","chNo":116,"sec":"Love"},
{"n":1160,"id":"TK-1160","ta":"அரிதாற்றி அல்லல்நோய் நீக்கிப் பிரிவாற்றிப் பின்இருந்து வாழ்வார் பலர்.","en":"Many survive pangs of parting Not I this sore so distressing","ch":"பிரிவு ஆற்றாமை","chEn":"Separation unendurable","chNo":116,"sec":"Love"},
{"n":1161,"id":"TK-1161","ta":"மறைப்பேன்மன் யானிஃதோ நோயை இறைப்பவர்க்கு ஊற்றுநீர் போல மிகும்.","en":"It swells out like baled out spring How to bear this pain so writhing?","ch":"படர்மெலிந் திரங்கல்","chEn":"Complainings","chNo":117,"sec":"Love"},
{"n":1162,"id":"TK-1162","ta":"கரத்தலும் ஆற்றேன்இந் நோயைநோய் செய்தார்க்கு உரைத்தலும் நாணுத் தரும்.","en":"I can't conceal this nor complain For shame to him who caused this pain","ch":"படர்மெலிந் திரங்கல்","chEn":"Complainings","chNo":117,"sec":"Love"},
{"n":1163,"id":"TK-1163","ta":"காமமும் நாணும் உயிர்காவாத் தூங்கும்என் நோனா உடம்பின் அகத்து.","en":"In life -poles of this wearied frame Are poised the weights of lust and shame","ch":"படர்மெலிந் திரங்கல்","chEn":"Complainings","chNo":117,"sec":"Love"},
{"n":1164,"id":"TK-1164","ta":"காமக் கடல்மன்னும் உண்டே அதுநீந்தும் ஏமப் புணைமன்னும் இல்.","en":"My lust is a sea; I do not see A raft to go across safely","ch":"படர்மெலிந் திரங்கல்","chEn":"Complainings","chNo":117,"sec":"Love"},
{"n":1165,"id":"TK-1165","ta":"துப்பின் எவனாவர் மன்கொல் துயர்வரவு நட்பினுள் ஆற்று பவர்.","en":"What wilt they prove when they are foes Who in friendship bring me woes!","ch":"படர்மெலிந் திரங்கல்","chEn":"Complainings","chNo":117,"sec":"Love"},
{"n":1166,"id":"TK-1166","ta":"இன்பம் கடல்மற்றுக் காமம் அஃதடுங்கால் துன்பம் அதனிற் பெரிது.","en":"The pleasure in love is oceanful But its pangs are more painful","ch":"படர்மெலிந் திரங்கல்","chEn":"Complainings","chNo":117,"sec":"Love"},
{"n":1167,"id":"TK-1167","ta":"காமக் கடும்புனல் நீந்திக் கரைகாணேன் யாமத்தும் யானே உளேன்.","en":"Wild waves of love I swim shoreless Pining alone in midnight hush","ch":"படர்மெலிந் திரங்கல்","chEn":"Complainings","chNo":117,"sec":"Love"},
{"n":1168,"id":"TK-1168","ta":"மன்னுயிர் எல்லாம் துயிற்றி அளித்திரா என்னல்லது இல்லை துணை.","en":"Night's mercy lulls all souls to sleep Keeping but me for companionship","ch":"படர்மெலிந் திரங்கல்","chEn":"Complainings","chNo":117,"sec":"Love"},
{"n":1169,"id":"TK-1169","ta":"கொடியார் கொடுமையின் தாம்கொடிய இந்நாள் நெடிய கழியும் இரா.","en":"Crueller than that cruel he Are midnight hours gliding slowly","ch":"படர்மெலிந் திரங்கல்","chEn":"Complainings","chNo":117,"sec":"Love"},
{"n":1170,"id":"TK-1170","ta":"உள்ளம்போன்று உள்வழிச் செல்கிற்பின் வெள்ளநீர் நீந்தல மன்னோஎன் கண்.","en":"Like heart, if my sight reaches him It won't in floods of tears swim!","ch":"படர்மெலிந் திரங்கல்","chEn":"Complainings","chNo":117,"sec":"Love"},
{"n":1171,"id":"TK-1171","ta":"கண்தாம் கலுழ்வ தெவன்கொலோ தண்டாநோய் தாம்காட்ட யாம்கண் டது.","en":"The eye pointed him to me; why then They weep with malady and pine?","ch":"கண் விதுப்பழிதல்","chEn":"Eyes consumed with Grief","chNo":118,"sec":"Love"},
{"n":1172,"id":"TK-1172","ta":"தெரிந்துணரா நோக்கிய உண்கண் பரிந்துணராப் பைதல் உழப்பது எவன்?","en":"Why should these dyed eyes grieve now sans Regrets for their thoughtless glance?","ch":"கண் விதுப்பழிதல்","chEn":"Eyes consumed with Grief","chNo":118,"sec":"Love"},
{"n":1173,"id":"TK-1173","ta":"கதுமெனத் தாநோக்கித் தாமே கலுழும் இதுநகத் தக்க துடைத்து.","en":"Eyes darted eager glance that day It's funny that they weep today","ch":"கண் விதுப்பழிதல்","chEn":"Eyes consumed with Grief","chNo":118,"sec":"Love"},
{"n":1174,"id":"TK-1174","ta":"பெயலாற்றா நீருலந்த உண்கண் உயலாற்றா உய்வில்நோய் என்கண் நிறுத்து.","en":"These eyes left me to endless grief Crying adry without relief","ch":"கண் விதுப்பழிதல்","chEn":"Eyes consumed with Grief","chNo":118,"sec":"Love"},
{"n":1175,"id":"TK-1175","ta":"படலாற்றா பைதல் உழக்கும் கடலாற்றாக் காமநோய் செய்தஎன் கண்.","en":"My eyes causing lust more than sea Suffer that torture sleeplessly","ch":"கண் விதுப்பழிதல்","chEn":"Eyes consumed with Grief","chNo":118,"sec":"Love"},
{"n":1176,"id":"TK-1176","ta":"ஓஒ இனிதே எமக்கிந்நோய் செய்தகண் தாஅம் இதற்பட் டது.","en":"Lo! eyes that wrought this love-sickness Are victims of the same themselves","ch":"கண் விதுப்பழிதல்","chEn":"Eyes consumed with Grief","chNo":118,"sec":"Love"},
{"n":1177,"id":"TK-1177","ta":"உழந்துழந் துள்நீர் அறுக விழைந்திழைந்து வேண்டி அவர்க்கண்ட கண்.","en":"Let tears dry up pining pining In eyes that eyed him longing longing","ch":"கண் விதுப்பழிதல்","chEn":"Eyes consumed with Grief","chNo":118,"sec":"Love"},
{"n":1178,"id":"TK-1178","ta":"பேணாது பெட்டார் உளர்மன்னோ மற்றவர்க் காணாது அமைவில கண்.","en":"Ther's he whose lips loved, not his heart Yet my eyes pine seeing him not","ch":"கண் விதுப்பழிதல்","chEn":"Eyes consumed with Grief","chNo":118,"sec":"Love"},
{"n":1179,"id":"TK-1179","ta":"வாராக்கால் துஞ்சா வரின்துஞ்சா ஆயிடை ஆரஞர் உற்றன கண்.","en":"He comes; no sleep; he goes; no sleep This is the fate of eyes that weep","ch":"கண் விதுப்பழிதல்","chEn":"Eyes consumed with Grief","chNo":118,"sec":"Love"},
{"n":1180,"id":"TK-1180","ta":"மறைபெறல் ஊரார்க்கு அரிதன்றால் எம்போல் அறைபறை கண்ணார் அகத்து.","en":"Like drum beats eyes declare my heart; From people who could hide his secret?","ch":"கண் விதுப்பழிதல்","chEn":"Eyes consumed with Grief","chNo":118,"sec":"Love"},
{"n":1181,"id":"TK-1181","ta":"நயந்தவர்க்கு நல்காமை நேர்ந்தேன் பசந்தவென் பண்பியார்க்கு உரைக்கோ பிற.","en":"My lover's parting, I allowed Whom to complain my hue pallid?","ch":"பசப்புறு பருவரல்","chEn":"The Pallid Hue","chNo":119,"sec":"Love"},
{"n":1182,"id":"TK-1182","ta":"அவர்தந்தார் என்னும் தகையால் இவர்தந்தென் மேனிமேல் ஊரும் பசப்பு.","en":"Claiming it is begot through him Pallor creeps and rides over my frame","ch":"பசப்புறு பருவரல்","chEn":"The Pallid Hue","chNo":119,"sec":"Love"},
{"n":1183,"id":"TK-1183","ta":"சாயலும் நாணும் அவர்கொண்டார் கைம்மாறா நோயும் பசலையும் தந்து.","en":"He seized my beauty and modesty Leaving pangs and Pallor to me","ch":"பசப்புறு பருவரல்","chEn":"The Pallid Hue","chNo":119,"sec":"Love"},
{"n":1184,"id":"TK-1184","ta":"உள்ளுவன் மன்யான் உரைப்பது அவர்திறமால் கள்ளம் பிறவோ பசப்பு.","en":"He is my thought, his praise my theme Yet this pallor steals over my frame","ch":"பசப்புறு பருவரல்","chEn":"The Pallid Hue","chNo":119,"sec":"Love"},
{"n":1185,"id":"TK-1185","ta":"உவக்காண்எம் காதலர் செல்வார் இவக்காண்என் மேனி பசப்பூர் வது.","en":"My lover departed me there And pallor usurped my body here","ch":"பசப்புறு பருவரல்","chEn":"The Pallid Hue","chNo":119,"sec":"Love"},
{"n":1186,"id":"TK-1186","ta":"விளக்கற்றம் பார்க்கும் இருளேபோல் கொண்கன் முயக்கற்றம் பார்க்கும் பசப்பு.","en":"Just as darkness waits for light-off Pallor looks for lover's arms-off","ch":"பசப்புறு பருவரல்","chEn":"The Pallid Hue","chNo":119,"sec":"Love"},
{"n":1187,"id":"TK-1187","ta":"புல்லிக் கிடந்தேன் புடைபெயர்ந்தேன் அவ்வளவில் அள்ளிக்கொள் வற்றே பசப்பு.","en":"From his embrace I turned a nonce This pallor swallowed me at once","ch":"பசப்புறு பருவரல்","chEn":"The Pallid Hue","chNo":119,"sec":"Love"},
{"n":1188,"id":"TK-1188","ta":"பசந்தாள் இவள்என்பது அல்லால் இவளைத் துறந்தார் அவர்என்பார் இல்.","en":"On my pallor they cast a slur But none says \\\"lo he parted her\\\"","ch":"பசப்புறு பருவரல்","chEn":"The Pallid Hue","chNo":119,"sec":"Love"},
{"n":1189,"id":"TK-1189","ta":"பசக்கமன் பட்டாங்கென் மேனி நயப்பித்தார் நன்னிலையர் ஆவர் எனின்.","en":"Let all my body become pale If he who took my leave fares well","ch":"பசப்புறு பருவரல்","chEn":"The Pallid Hue","chNo":119,"sec":"Love"},
{"n":1190,"id":"TK-1190","ta":"பசப்பெனப் பேர்பெறுதல் நன்றே நயப்பித்தார் நல்காமை தூற்றார் எனின்.","en":"Let people call me all pallid But my lover let them not deride","ch":"பசப்புறு பருவரல்","chEn":"The Pallid Hue","chNo":119,"sec":"Love"},
{"n":1191,"id":"TK-1191","ta":"தாம்வீழ்வார் தம்வீழப் பெற்றவர் பெற்றாரே காமத்துக் காழில் கனி.","en":"Stoneless fruit of love they have Who are beloved by those they love","ch":"தனிப்படர் மிகுதி","chEn":"The Solitary Anguish","chNo":120,"sec":"Love"},
{"n":1192,"id":"TK-1192","ta":"வாழ்வார்க்கு வானம் பயந்தற்றால் வீழ்வார்க்கு வீழ்வார் அள஧ க்கும் அளி.","en":"The lover-and-beloved's self-givings Are like rains to living beings","ch":"தனிப்படர் மிகுதி","chEn":"The Solitary Anguish","chNo":120,"sec":"Love"},
{"n":1193,"id":"TK-1193","ta":"வீழுநர் வீழப் படுவார்க்கு அமையுமே வாழுநம் என்னும் செருக்கு.","en":"The pride of living is for those Whose love is returned by love so close","ch":"தனிப்படர் மிகுதி","chEn":"The Solitary Anguish","chNo":120,"sec":"Love"},
{"n":1194,"id":"TK-1194","ta":"வீழப் படுவார் கெழீஇயிலர் தாம்வீழ்வார் வீழப் படாஅர் எனின்.","en":"Whose love is void of love in turn Are luckless with all esteems they earn","ch":"தனிப்படர் மிகுதி","chEn":"The Solitary Anguish","chNo":120,"sec":"Love"},
{"n":1195,"id":"TK-1195","ta":"நாம்காதல் கொண்டார் நமக்கெவன் செய்பவோ தாம்காதல் கொள்ளாக் கடை.","en":"What can our lover do us now If he does not requite our love?","ch":"தனிப்படர் மிகுதி","chEn":"The Solitary Anguish","chNo":120,"sec":"Love"},
{"n":1196,"id":"TK-1196","ta":"ஒருதலையான் இன்னாது காமம்காப் போல இருதலை யானும் இனிது.","en":"One sided pains; love in both souls Poises well like shoulder poles","ch":"தனிப்படர் மிகுதி","chEn":"The Solitary Anguish","chNo":120,"sec":"Love"},
{"n":1197,"id":"TK-1197","ta":"பருவரலும் பைதலும் காணான்கொல் காமன் ஒருவர்கண் நின்றொழுகு வான்.","en":"This cupid aims at me alone; Knows he not my pallor and pain?","ch":"தனிப்படர் மிகுதி","chEn":"The Solitary Anguish","chNo":120,"sec":"Love"},
{"n":1198,"id":"TK-1198","ta":"வீழ்வாரின் இன்சொல் பெறாஅது உலகத்து வாழ்வாரின் வன்கணார் இல்.","en":"None is so firm as she who loves Without kind words from whom she dotes","ch":"தனிப்படர் மிகுதி","chEn":"The Solitary Anguish","chNo":120,"sec":"Love"},
{"n":1199,"id":"TK-1199","ta":"நசைஇயார் நல்கார் எனினும் அவர்மாட்டு இசையும் இனிய செவிக்கு.","en":"The lover accords not my desires And yet his words sweeten my ears","ch":"தனிப்படர் மிகுதி","chEn":"The Solitary Anguish","chNo":120,"sec":"Love"},
{"n":1200,"id":"TK-1200","ta":"உறாஅர்க்கு உறுநோய் உரைப்பாய் கடலைச் செறாஅஅய் வாழிய நெஞ்சு.","en":"You tell your grief to listless he Bless my heart! rather fill up sea!","ch":"தனிப்படர் மிகுதி","chEn":"The Solitary Anguish","chNo":120,"sec":"Love"},
{"n":1201,"id":"TK-1201","ta":"உள்ளினும் தீராப் பெருமகிழ் செய்தலால் கள்ளினும் காமம் இனிது.","en":"Love is sweeter than wine; for vast Is its delight at very thought","ch":"நினைந்தவர் புலம்பல்","chEn":"Sad Memories","chNo":121,"sec":"Love"},
{"n":1202,"id":"TK-1202","ta":"எனைத்தொனறு இனிதேகாண் காமம்தாம் வீழ்வார் நினைப்ப வருவதொன்று ஏல்.","en":"Pains are off at the lover's thought In all aspects this love is sweet","ch":"நினைந்தவர் புலம்பல்","chEn":"Sad Memories","chNo":121,"sec":"Love"},
{"n":1203,"id":"TK-1203","ta":"நினைப்பவர் போன்று நினையார்கொல் தும்மல் சினைப்பது போன்று கெடும்.","en":"To sneeze I tried hence but could not Me he tried to think but did not","ch":"நினைந்தவர் புலம்பல்","chEn":"Sad Memories","chNo":121,"sec":"Love"},
{"n":1204,"id":"TK-1204","ta":"யாமும் உளேங்கொல் அவர்நெஞ்சத்து எந்நெஞ்சத்து ஓஒ உளரே அவர்.","en":"Have I a place within his heart? Ah from mine he will never depart","ch":"நினைந்தவர் புலம்பல்","chEn":"Sad Memories","chNo":121,"sec":"Love"},
{"n":1205,"id":"TK-1205","ta":"தம்நெஞ்சத்து எம்மைக் கடிகொண்டார் நாணார்கொல் எம்நெஞ்சத்து ஓவா வரல்.","en":"Shame! My heart often he enters Banning me entry into his","ch":"நினைந்தவர் புலம்பல்","chEn":"Sad Memories","chNo":121,"sec":"Love"},
{"n":1206,"id":"TK-1206","ta":"மற்றியான் என்னுளேன் மன்னோ அவரொடியான் உற்றநாள் உள்ள உளேன்.","en":"Beyond the thought of life with him What else of life can I presume?","ch":"நினைந்தவர் புலம்பல்","chEn":"Sad Memories","chNo":121,"sec":"Love"},
{"n":1207,"id":"TK-1207","ta":"மறப்பின் எவனாவன் மற்கொல் மறப்பறியேன் உள்ளினும் உள்ளம் சுடும்.","en":"What will happen if I forget When his memory burns my heart?","ch":"நினைந்தவர் புலம்பல்","chEn":"Sad Memories","chNo":121,"sec":"Love"},
{"n":1208,"id":"TK-1208","ta":"எனைத்து நினைப்பினும் காயார் அனைத்தன்றோ காதலர் செய்யும் சிறப்பு.","en":"I bring him to ceaseless memory He chides not; and thus honours me","ch":"நினைந்தவர் புலம்பல்","chEn":"Sad Memories","chNo":121,"sec":"Love"},
{"n":1209,"id":"TK-1209","ta":"விளியுமென் இன்னுயிர் வேறல்லம் என்பார் அளியின்மை ஆற்ற நினைந்து.","en":"Dear life ebbs away by thought Of him who said we are one heart","ch":"நினைந்தவர் புலம்பல்","chEn":"Sad Memories","chNo":121,"sec":"Love"},
{"n":1210,"id":"TK-1210","ta":"விடாஅது சென்றாரைக் கண்ணினால் காணப் படாஅதி வாழி மதி.","en":"Hail moon! Set not so that I find Him who left me but not my mind","ch":"நினைந்தவர் புலம்பல்","chEn":"Sad Memories","chNo":121,"sec":"Love"},
{"n":1211,"id":"TK-1211","ta":"காதலர் தூதொடு வந்த கனவினுக்கு யாதுசெய் வேன்கொல் விருந்து.","en":"How shall I feast this dream-vision That brings the beloved's love-mission?","ch":"கனவுநிலை உரைத்தல்","chEn":"The Visions of the Night","chNo":122,"sec":"Love"},
{"n":1212,"id":"TK-1212","ta":"கயலுண்கண் யானிரப்பத் துஞ்சிற் கலந்தார்க்கு உயலுண்மை சாற்றுவேன் மன்.","en":"I beg these fish-like dark eyes sleep To tell my lover how life I keep","ch":"கனவுநிலை உரைத்தல்","chEn":"The Visions of the Night","chNo":122,"sec":"Love"},
{"n":1213,"id":"TK-1213","ta":"நனவினால் நல்கா தவரைக் கனவினால் காண்டலின் உண்டென் உயிர்.","en":"In wakeful hours who sees me not I meet in dreams and linger yet","ch":"கனவுநிலை உரைத்தல்","chEn":"The Visions of the Night","chNo":122,"sec":"Love"},
{"n":1214,"id":"TK-1214","ta":"கனவினான் உண்டாகும் காமம் நனவினான் நல்காரை நாடித் தரற்கு.","en":"In dreams I enjoy his love-bliss Who in wakeful hours I miss","ch":"கனவுநிலை உரைத்தல்","chEn":"The Visions of the Night","chNo":122,"sec":"Love"},
{"n":1215,"id":"TK-1215","ta":"நனவினால் கண்டதூஉம் ஆங்கே கனவுந்தான் கண்ட பொழுதே இனிது.","en":"Dream-sight of him delights at once Awake-What of seeing him -hence","ch":"கனவுநிலை உரைத்தல்","chEn":"The Visions of the Night","chNo":122,"sec":"Love"},
{"n":1216,"id":"TK-1216","ta":"நனவென ஒன்றில்லை ஆயின் கனவினால் காதலர் நீங்கலர் மன்.","en":"If wakeful hours come to nought My lov'r in dreams would nev'r depart","ch":"கனவுநிலை உரைத்தல்","chEn":"The Visions of the Night","chNo":122,"sec":"Love"},
{"n":1217,"id":"TK-1217","ta":"நனவினால் நல்காக் கொடியார் கனவனால் என்எம்மைப் பீழிப் பது.","en":"Awake he throws my overtures Adream, ah cruel! he tortures!","ch":"கனவுநிலை உரைத்தல்","chEn":"The Visions of the Night","chNo":122,"sec":"Love"},
{"n":1218,"id":"TK-1218","ta":"துஞ்சுங்கால் தோள்மேலர் ஆகி விழிக்குங்கால் நெஞ்சத்தர் ஆவர் விரைந்து.","en":"Asleep he embraces me fast; Awake he enters quick my heart","ch":"கனவுநிலை உரைத்தல்","chEn":"The Visions of the Night","chNo":122,"sec":"Love"},
{"n":1219,"id":"TK-1219","ta":"நனவினால் நல்காரை நோவர் கனவினால் காதலர்க் காணா தவர்.","en":"In dreams who don't discern lovers Rue their missing in wakeful hours","ch":"கனவுநிலை உரைத்தல்","chEn":"The Visions of the Night","chNo":122,"sec":"Love"},
{"n":1220,"id":"TK-1220","ta":"நனவினால் நம்நீத்தார் என்பர் கனவினால் காணார்கொல் இவ்வூ ரவர்.","en":"The townsmen say he left me thus  In dreams failing to see him close","ch":"கனவுநிலை உரைத்தல்","chEn":"The Visions of the Night","chNo":122,"sec":"Love"},
{"n":1221,"id":"TK-1221","ta":"மாலையோ அல்லை மணந்தார் உயிருண்ணும் வேலைநீ வாழி பொழுது.","en":"Bless you! you are not eventide But killing dart to wedded bride!","ch":"பொழுதுகண்டு இரங்கல்","chEn":"Lamentations at Eventide","chNo":123,"sec":"Love"},
{"n":1222,"id":"TK-1222","ta":"புன்கண்ணை வாழி மருள்மாலை எம்கேள்போல் வன்கண்ண தோநின் துணை.","en":"Hail sad eventide dim and grim Has your mate like mine, cruel whim!","ch":"பொழுதுகண்டு இரங்கல்","chEn":"Lamentations at Eventide","chNo":123,"sec":"Love"},
{"n":1223,"id":"TK-1223","ta":"பனிஅரும்பிப் பைதல்கொள் மாலை துனிஅரும்பித் துன்பம் வளர வரும்.","en":"Wet eve came pale and trembling then Now it makes bold with growing pain","ch":"பொழுதுகண்டு இரங்கல்","chEn":"Lamentations at Eventide","chNo":123,"sec":"Love"},
{"n":1224,"id":"TK-1224","ta":"காதலர் இல்வழி மாலை கொலைக்களத்து ஏதிலர் போல வரும்.","en":"Lover away, comes eventide Like slayer to field of homicide","ch":"பொழுதுகண்டு இரங்கல்","chEn":"Lamentations at Eventide","chNo":123,"sec":"Love"},
{"n":1225,"id":"TK-1225","ta":"காலைக்குச் செய்தநன்று என்கொல் எவன்கொல்யான் மாலைக்குச் செய்த பகை?","en":"What good have I done to morning And what evil to this evening?","ch":"பொழுதுகண்டு இரங்கல்","chEn":"Lamentations at Eventide","chNo":123,"sec":"Love"},
{"n":1226,"id":"TK-1226","ta":"மாலைநோய் செய்தல் மணந்தார் அகலாத காலை அறிந்த திலேன்.","en":"Evening pangs I have not known When my lord nev'r left me alone","ch":"பொழுதுகண்டு இரங்கல்","chEn":"Lamentations at Eventide","chNo":123,"sec":"Love"},
{"n":1227,"id":"TK-1227","ta":"காலை அரும்பிப் பகலெல்லாம் போதாகி மாலை மலரும்இந் நோய்.","en":"Budding at dawn burgeoning all day This disease blooms in evening gay","ch":"பொழுதுகண்டு இரங்கல்","chEn":"Lamentations at Eventide","chNo":123,"sec":"Love"},
{"n":1228,"id":"TK-1228","ta":"அழல்போலும் மாலைக்குத் தூதாகி ஆயன் குழல்போலும் கொல்லும் படை.","en":"A deadly arm, this shepherd's flute Hails flaming eve and slays my heart","ch":"பொழுதுகண்டு இரங்கல்","chEn":"Lamentations at Eventide","chNo":123,"sec":"Love"},
{"n":1229,"id":"TK-1229","ta":"பதிமருண்டு பைதல் உழக்கும் மதிமருண்டு மாலை படர்தரும் போழ்து.","en":"Deluding eve if it prolongs The whole town will suffer love-pangs","ch":"பொழுதுகண்டு இரங்கல்","chEn":"Lamentations at Eventide","chNo":123,"sec":"Love"},
{"n":1230,"id":"TK-1230","ta":"பொருள்மாலை யாளரை உள்ளி மருள்மாலை மாயும்என் மாயா உயிர்.","en":"Thinking of him whose quest is wealth My life outlives the twilight stealth","ch":"பொழுதுகண்டு இரங்கல்","chEn":"Lamentations at Eventide","chNo":123,"sec":"Love"},
{"n":1231,"id":"TK-1231","ta":"சிறுமை நமக்கொழியச் சேட்சென்றார் உள்ளி நறுமலர் நாணின கண்.","en":"To lift from want he left me afar His thought makes my eyes blush the flower","ch":"உறுப்புநலன் அழிதல்","chEn":"Wasting Away","chNo":124,"sec":"Love"},
{"n":1232,"id":"TK-1232","ta":"நயந்தவர் நல்காமை சொல்லுவ போலும் பசந்து பனிவாரும் கண்.","en":"My pale tearful eyes betray The hardness of my husband, away","ch":"உறுப்புநலன் அழிதல்","chEn":"Wasting Away","chNo":124,"sec":"Love"},
{"n":1233,"id":"TK-1233","ta":"தணந்தமை சால அறிவிப்ப போலும் மணந்தநாள் வீங்கிய தோள்.","en":"These arms that swelled on nuptial day Now shrunk proclaim \\\"He is away\\\"","ch":"உறுப்புநலன் அழிதல்","chEn":"Wasting Away","chNo":124,"sec":"Love"},
{"n":1234,"id":"TK-1234","ta":"பணைநீங்கிப் பைந்தொடி சோரும் துணைநீங்கித் தொல்கவின் வாடிய தோள்.","en":"Bracelets slip off the arms that have Lost old beauty for He took leave","ch":"உறுப்புநலன் அழிதல்","chEn":"Wasting Away","chNo":124,"sec":"Love"},
{"n":1235,"id":"TK-1235","ta":"கொடியார் கொடுமை உரைக்கும் தொடியொடு தொல்கவின் வாடிய தோள்.","en":"Bereft of bracelets and old beauty Arms tell the cruel's cruelty","ch":"உறுப்புநலன் அழிதல்","chEn":"Wasting Away","chNo":124,"sec":"Love"},
{"n":1236,"id":"TK-1236","ta":"தொடியொடு தோள்நெகிழ நோவல் அவரைக் கொடியர் எனக்கூறல் நொந்து.","en":"Arms thin, armlets loose make you call My sire cruel; that pains my soul","ch":"உறுப்புநலன் அழிதல்","chEn":"Wasting Away","chNo":124,"sec":"Love"},
{"n":1237,"id":"TK-1237","ta":"பாடு பெறுதியோ நெஞ்சே கொடியார்க்கென் வாடுதோட் பூசல் உரைத்து.","en":"Go and tell the cruel, O mind  Bruit ov'r my arms and glory find","ch":"உறுப்புநலன் அழிதல்","chEn":"Wasting Away","chNo":124,"sec":"Love"},
{"n":1238,"id":"TK-1238","ta":"முயங்கிய கைகளை ஊக்கப் பசந்தது பைந்தொடிப் பேதை நுதல்.","en":"The front of this fair one O paled As my clasping arms loosed their hold","ch":"உறுப்புநலன் அழிதல்","chEn":"Wasting Away","chNo":124,"sec":"Love"},
{"n":1239,"id":"TK-1239","ta":"முயக்கிடைத் தண்வளி போழப் பசப்புற்ற பேதை பெருமழைக் கண்.","en":"Cool breeze crept between our embrace Her large rain-cloud-eyes paled at once","ch":"உறுப்புநலன் அழிதல்","chEn":"Wasting Away","chNo":124,"sec":"Love"},
{"n":1240,"id":"TK-1240","ta":"கண்ணின் பசப்போ பருவரல் எய்தின்றே ஒண்ணுதல் செய்தது கண்டு.","en":"Pale eyes pained seeing the pallor Of the bright forehead of this fair","ch":"உறுப்புநலன் அழிதல்","chEn":"Wasting Away","chNo":124,"sec":"Love"},
{"n":1241,"id":"TK-1241","ta":"நினைத்தொன்று சொல்லாயோ நெஞ்சே எனைத்தொன்றும் எவ்வநோய் தீர்க்கும் மருந்து.","en":"Think of, O heart, some remedy To cure this chronic malady","ch":"நெஞ்சொடு கிளத்தல்","chEn":"Soliloquy","chNo":125,"sec":"Love"},
{"n":1242,"id":"TK-1242","ta":"காதல் அவரிலர் ஆகநீ நோவது பேதைமை வாழியென் நெஞ்சு.","en":"Bless O mind! you pine in vain For me he has no love serene","ch":"நெஞ்சொடு கிளத்தல்","chEn":"Soliloquy","chNo":125,"sec":"Love"},
{"n":1243,"id":"TK-1243","ta":"இருந்துள்ளி என்பரிதல் நெஞ்சே பரிந்துள்ளல் பைதல்நோய் செய்தார்கண் இல்.","en":"O mind, why pine and sit moody? Who made you so pale lacks pity","ch":"நெஞ்சொடு கிளத்தல்","chEn":"Soliloquy","chNo":125,"sec":"Love"},
{"n":1244,"id":"TK-1244","ta":"கண்ணும் கொளச்சேறி நெஞ்சே இவையென்னைத் தின்னும் அவர்க்காணல் உற்று.","en":"Take these eyes and meet him, O heart Or their hunger will eat me out","ch":"நெஞ்சொடு கிளத்தல்","chEn":"Soliloquy","chNo":125,"sec":"Love"},
{"n":1245,"id":"TK-1245","ta":"செற்றார் எனக்கை விடல்உண்டோ நெஞ்சேயாம் உற்றால் உறாஅ தவர்.","en":"He spurns our love and yet, O mind, Can we desert him as unkind?","ch":"நெஞ்சொடு கிளத்தல்","chEn":"Soliloquy","chNo":125,"sec":"Love"},
{"n":1246,"id":"TK-1246","ta":"கலந்துணர்த்தும் காதலர்க் கண்டாற் புலந்துணராய் பொய்க்காய்வு காய்திஎன் நெஞ்சு.","en":"Wrath is false, O heart, face-to face Sans huff, you rush to his sweet embrace","ch":"நெஞ்சொடு கிளத்தல்","chEn":"Soliloquy","chNo":125,"sec":"Love"},
{"n":1247,"id":"TK-1247","ta":"காமம் விடுஒன்றோ நாண்விடு நன்னெஞ்சே யானோ பொறேன்இவ் விரண்டு.","en":"Off with love O mind, or shame I cannot endure both of them","ch":"நெஞ்சொடு கிளத்தல்","chEn":"Soliloquy","chNo":125,"sec":"Love"},
{"n":1248,"id":"TK-1248","ta":"பரிந்தவர் நல்காரென்று ஏங்கிப் பிரிந்தவர் பின்செல்வாய் பேதைஎன் நெஞ்சு.","en":"Without pity he would depart! You sigh and seek his favour, poor heart!","ch":"நெஞ்சொடு கிளத்தல்","chEn":"Soliloquy","chNo":125,"sec":"Love"},
{"n":1249,"id":"TK-1249","ta":"உள்ளத்தார் காத லவரால் உள்ளிநீ யாருழைச் சேறியென் நெஞ்சு.","en":"The lover lives in Self you know; Whom you think, mind to whom you go?","ch":"நெஞ்சொடு கிளத்தல்","chEn":"Soliloquy","chNo":125,"sec":"Love"},
{"n":1250,"id":"TK-1250","ta":"துன்னாத் துறந்தாரை நெஞ்சத்து உடையேமா இன்னும் இழத்தும் கவின்.","en":"Without a thought he deserted us To think of him will make us worse","ch":"நெஞ்சொடு கிளத்தல்","chEn":"Soliloquy","chNo":125,"sec":"Love"},
{"n":1251,"id":"TK-1251","ta":"காமக் கணிச்சி உடைக்கும் நிறையென்னும் நாணுத்தாழ் வீழ்த்த கதவு.","en":"Passion's axe shall break the door Of reserve bolted with my honour","ch":"நிறையழிதல்","chEn":"Reserve Overcome","chNo":126,"sec":"Love"},
{"n":1252,"id":"TK-1252","ta":"காமம் எனவொன்றோ கண்ணின்றென் நெஞ்சத்தை யாமத்தும் ஆளும் தொழில்.","en":"The thing called lust is a heartless power It sways my mind at midnight hour","ch":"நிறையழிதல்","chEn":"Reserve Overcome","chNo":126,"sec":"Love"},
{"n":1253,"id":"TK-1253","ta":"மறைப்பேன்மன் காமத்தை யானோ குறிப்பின்றித் தும்மல்போல் தோன்றி விடும்.","en":"How to hide this lust which shows Itself while I sneeze unawares!","ch":"நிறையழிதல்","chEn":"Reserve Overcome","chNo":126,"sec":"Love"},
{"n":1254,"id":"TK-1254","ta":"நிறையுடையேன் என்பேன்மன் யானோஎன் காமம் மறையிறந்து மன்று படும்.","en":"I was proud of my sex-reserve Lo lust betrays what I preserve","ch":"நிறையழிதல்","chEn":"Reserve Overcome","chNo":126,"sec":"Love"},
{"n":1255,"id":"TK-1255","ta":"செற்றார்பின் செல்லாப் பெருந்தகைமை காமநோய் உற்றார் அறிவதொன்று அன்று.","en":"Dignity seeks not a deserter But Love-sick is its innovator","ch":"நிறையழிதல்","chEn":"Reserve Overcome","chNo":126,"sec":"Love"},
{"n":1256,"id":"TK-1256","ta":"செற்றவர் பின்சேறல் வேண்டி அளித்தரோ எற்றென்னை உற்ற துயர்.","en":"O Grief, my deserter you seek Of your caprice what shall I speak!","ch":"நிறையழிதல்","chEn":"Reserve Overcome","chNo":126,"sec":"Love"},
{"n":1257,"id":"TK-1257","ta":"நாணென ஒன்றோ அறியலம் காமத்தால் பேணியார் பெட்ப செயின்.","en":"When lover's love does what it desires We forget all shame unawares","ch":"நிறையழிதல்","chEn":"Reserve Overcome","chNo":126,"sec":"Love"},
{"n":1258,"id":"TK-1258","ta":"பன்மாயக் கள்வன் பணிமொழி அன்றோநம் பெண்மை உடைக்கும் படை.","en":"The cheater of many wily arts His tempting words break through women's hearts","ch":"நிறையழிதல்","chEn":"Reserve Overcome","chNo":126,"sec":"Love"},
{"n":1259,"id":"TK-1259","ta":"புலப்பல் எனச்சென்றேன் புல்லினேன் நெஞ்சம் கலத்தல் உறுவது கண்டு.","en":"In huff I went and felt at ease Heat to heart in sweet embrace","ch":"நிறையழிதல்","chEn":"Reserve Overcome","chNo":126,"sec":"Love"},
{"n":1260,"id":"TK-1260","ta":"நிணந்தீயில் இட்டன்ன நெஞ்சினார்க்கு உண்டோ புணர்ந்தூடி நிற்பேம் எனல்.","en":"To feign dislike is it not rare  For mates who melt like fat in fire?","ch":"நிறையழிதல்","chEn":"Reserve Overcome","chNo":126,"sec":"Love"},
{"n":1261,"id":"TK-1261","ta":"வாளற்றுப் புற்கென்ற கண்ணும் அவர்சென்ற நாளொற்றித் தேய்ந்த விரல்.","en":"My eyes are dim lustre-bereft Worn fingers count days since he left","ch":"அவர்வயின் விதும்பல்","chEn":"Mutual Desire","chNo":127,"sec":"Love"},
{"n":1262,"id":"TK-1262","ta":"இலங்கிழாய் இன்று மறப்பின்என் தோள்மேல் கலங்கழியும் காரிகை நீத்து.","en":"Beauty pales and my bracelets slide; Why not forget him now, bright maid?","ch":"அவர்வயின் விதும்பல்","chEn":"Mutual Desire","chNo":127,"sec":"Love"},
{"n":1263,"id":"TK-1263","ta":"உரன்நசைஇ உள்ளம் துணையாகச் சென்றார் வரல்நசைஇ இன்னும் உளேன்.","en":"Will as guide he went to win Yet I live-to see him again","ch":"அவர்வயின் விதும்பல்","chEn":"Mutual Desire","chNo":127,"sec":"Love"},
{"n":1264,"id":"TK-1264","ta":"கூடிய காமம் பிரிந்தார் வரவுள்ளிக் கோடுகொ டேறுமென் நெஞ்சு.","en":"My heart in rapture heaves to see His retun with love to embrace me","ch":"அவர்வயின் விதும்பல்","chEn":"Mutual Desire","chNo":127,"sec":"Love"},
{"n":1265,"id":"TK-1265","ta":"காண்கமன் கொண்கனைக் கண்ணாரக் கண்டபின் நீங்கும்என் மென்தோள் பசப்பு.","en":"Let me but gaze and gaze my spouse sallow on my soft shoulders files","ch":"அவர்வயின் விதும்பல்","chEn":"Mutual Desire","chNo":127,"sec":"Love"},
{"n":1266,"id":"TK-1266","ta":"வருகமன் கொண்கன் ஒருநாள் பருகுவன் பைதல்நோய் எல்லாம் கெட.","en":"Let my spouse return just a day Joy-drink shall drive my pain away","ch":"அவர்வயின் விதும்பல்","chEn":"Mutual Desire","chNo":127,"sec":"Love"},
{"n":1267,"id":"TK-1267","ta":"புலப்பேன்கொல் புல்லுவேன் கொல்லோ கலப்பேன்கொல் கண்அன்ன கேளிர் விரன்.","en":"If my eye-like lord returneth Shall I sulk or clasp or do both?","ch":"அவர்வயின் விதும்பல்","chEn":"Mutual Desire","chNo":127,"sec":"Love"},
{"n":1268,"id":"TK-1268","ta":"வினைகலந்து வென்றீக வேந்தன் மனைகலந்து மாலை அயர்கம் விருந்து.","en":"May the king fight and win and give And with my wife I will feast this eve!","ch":"அவர்வயின் விதும்பல்","chEn":"Mutual Desire","chNo":127,"sec":"Love"},
{"n":1269,"id":"TK-1269","ta":"ஒருநாள் எழுநாள்போல் செல்லும்சேண் சென்றார் வருநாள்வைத்து ஏங்கு பவர்க்கு.","en":"One day seems as seven to those Who yearn return of distant spouse","ch":"அவர்வயின் விதும்பல்","chEn":"Mutual Desire","chNo":127,"sec":"Love"},
{"n":1270,"id":"TK-1270","ta":"பெறின்என்னாம் பெற்றக்கால் என்னாம் உறினென்னாம் உள்ளம் உடைந்துக்கக் கால்.","en":"When her heart is broken, what is The good of meeting and love-embrace?","ch":"அவர்வயின் விதும்பல்","chEn":"Mutual Desire","chNo":127,"sec":"Love"},
{"n":1271,"id":"TK-1271","ta":"கரப்பினுங் கையிகந் தொல்லாநின் உண்கண் உரைக்கல் உறுவதொன் றுண்டு.","en":"You hide; but your painted eyes Restraint off, report your surmise","ch":"குறிப்பறிவுறுத்தல்","chEn":"The Reading of the Signs","chNo":128,"sec":"Love"},
{"n":1272,"id":"TK-1272","ta":"கண்ணிறைந்த காரிகைக் காம்பேர்தோட் பேதைக்குப் பெண்நிறைந்த நீர்மை பெரிது.","en":"With seemly grace and stem-like arms The simple she has ample charms","ch":"குறிப்பறிவுறுத்தல்","chEn":"The Reading of the Signs","chNo":128,"sec":"Love"},
{"n":1273,"id":"TK-1273","ta":"மணியில் திகழ்தரு நூல்போல் மடந்தை அணியில் திகழ்வதொன்று உண்டு.","en":"Something shines through her jewelled charm Like thread shining through wreathed gem","ch":"குறிப்பறிவுறுத்தல்","chEn":"The Reading of the Signs","chNo":128,"sec":"Love"},
{"n":1274,"id":"TK-1274","ta":"முகைமொக்குள் உள்ளது நாற்றம்போல் பேதை நகைமொக்குள் உள்ளதொன் றுண்டு.","en":"Like scent in bud secrets conceal In the bosom of her half smile","ch":"குறிப்பறிவுறுத்தல்","chEn":"The Reading of the Signs","chNo":128,"sec":"Love"},
{"n":1275,"id":"TK-1275","ta":"செறிதொடி செய்திறந்த கள்ளம் உறுதுயர் தீர்க்கும் மருந்தொன்று உடைத்து.","en":"The close-bangled belle's hidden thought Has a cure for my troubled heart She to Her Maid","ch":"குறிப்பறிவுறுத்தல்","chEn":"The Reading of the Signs","chNo":128,"sec":"Love"},
{"n":1276,"id":"TK-1276","ta":"பெரிதாற்றிப் பெட்பக் கலத்தல் அரிதாற்றி அன்பின்மை சூழ்வ துடைத்து.","en":"His over-kind close embrace sooths; But makes me feel, loveless, he parts","ch":"குறிப்பறிவுறுத்தல்","chEn":"The Reading of the Signs","chNo":128,"sec":"Love"},
{"n":1277,"id":"TK-1277","ta":"தண்ணந் துறைவன் தணந்தமை நம்மினும் முன்னம் உணர்ந்த வளை.","en":"Quick, my bracelets read before The mind of my lord of cool shore","ch":"குறிப்பறிவுறுத்தல்","chEn":"The Reading of the Signs","chNo":128,"sec":"Love"},
{"n":1278,"id":"TK-1278","ta":"நெருநற்றுச் சென்றார்எம் காதலர் யாமும் எழுநாளேம் மேனி பசந்து.","en":"My lover parted but yesterday; With sallowness it is seventh day The Maid Tells Him","ch":"குறிப்பறிவுறுத்தல்","chEn":"The Reading of the Signs","chNo":128,"sec":"Love"},
{"n":1279,"id":"TK-1279","ta":"தொடிநோக்கி மென்தோளும் நோக்கி அடிநோக்கி அஃதாண் டவள்செய் தது.","en":"She views her armlets, her tender arms And then her feet; these are her norms","ch":"குறிப்பறிவுறுத்தல்","chEn":"The Reading of the Signs","chNo":128,"sec":"Love"},
{"n":1280,"id":"TK-1280","ta":"பெண்ணினால் பெண்மை உடைத்தென்ப கண்ணினால் காமநோய் சொல்லி இரவு.","en":"To express love-pangs by eyes and pray Is womanhood's womanly way","ch":"குறிப்பறிவுறுத்தல்","chEn":"The Reading of the Signs","chNo":128,"sec":"Love"},
{"n":1281,"id":"TK-1281","ta":"உள்ளக் களித்தலும் காண மகிழ்தலும் கள்ளுக்கில் காமத்திற் குண்டு.","en":"Rapture at thought and joy when seen Belong to love and not to wine","ch":"புணர்ச்சி விதும்பல்","chEn":"Desire for Reunion","chNo":129,"sec":"Love"},
{"n":1282,"id":"TK-1282","ta":"தினைத்துணையும் ஊடாமை வேண்டும் பனைத்துணையும் காமம் நிறைய வரின்.","en":"When passion grows palmyra-tall Sulking is wrong though millet-small","ch":"புணர்ச்சி விதும்பல்","chEn":"Desire for Reunion","chNo":129,"sec":"Love"},
{"n":1283,"id":"TK-1283","ta":"பேணாது பெட்பவே செய்யினும் கொண்கனைக் காணா தமையல கண்.","en":"Though slighting me he acts his will My restless eyes would see him still","ch":"புணர்ச்சி விதும்பல்","chEn":"Desire for Reunion","chNo":129,"sec":"Love"},
{"n":1284,"id":"TK-1284","ta":"ஊடற்கண் சென்றேன்மன் தோழி அதுமறந்து கூடற்கண் சென்றது என் னெஞ்சு.","en":"Huff I would, maid, but I forget; And leap to embrace him direct","ch":"புணர்ச்சி விதும்பல்","chEn":"Desire for Reunion","chNo":129,"sec":"Love"},
{"n":1285,"id":"TK-1285","ta":"எழுதுங்கால் கோல்காணாக் கண்ணேபோல் கொண்கன் பழிகாணேன் கண்ட இடத்து.","en":"When close I see not lord's blemish Like eyes that see not painter's brush","ch":"புணர்ச்சி விதும்பல்","chEn":"Desire for Reunion","chNo":129,"sec":"Love"},
{"n":1286,"id":"TK-1286","ta":"காணுங்கால் காணேன் தவறாய காணாக்கால் காணேன் தவறல் லவை.","en":"When he's with me I see not fault And nought but fault when he is not","ch":"புணர்ச்சி விதும்பல்","chEn":"Desire for Reunion","chNo":129,"sec":"Love"},
{"n":1287,"id":"TK-1287","ta":"உய்த்தல் அறிந்து புனல்பாய் பவரேபோல் பொய்த்தல் அறிந்தென் புலந்து.","en":"To leap in stream which carries off When lord is close to feign a huff","ch":"புணர்ச்சி விதும்பல்","chEn":"Desire for Reunion","chNo":129,"sec":"Love"},
{"n":1288,"id":"TK-1288","ta":"இளித்தக்க இன்னா செயினும் களித்தார்க்குக் கள்ளற்றே கள்வநின் மார்பு.","en":"Like wine to addicts that does disgrace Your breast, O thief, is for my embrace!","ch":"புணர்ச்சி விதும்பல்","chEn":"Desire for Reunion","chNo":129,"sec":"Love"},
{"n":1289,"id":"TK-1289","ta":"மலரினும் மெல்லிது காமம் சிலர்அதன் செவ்வி தலைப்படு வார்.","en":"Flower-soft is love; a few alone Know its delicacy so fine","ch":"புணர்ச்சி விதும்பல்","chEn":"Desire for Reunion","chNo":129,"sec":"Love"},
{"n":1290,"id":"TK-1290","ta":"கண்ணின் துனித்தே கலங்கினாள் புல்லுதல் என்னினும் தான்விதுப் புற்று.","en":"She feigned dislike awhile but flew Faster for embrace than I do","ch":"புணர்ச்சி விதும்பல்","chEn":"Desire for Reunion","chNo":129,"sec":"Love"},
{"n":1291,"id":"TK-1291","ta":"அவர்நெஞ்சு அவர்க்காதல் கண்டும் எவன்நெஞ்சே நீஎமக்கு ஆகா தது.","en":"You see, his heart is his alone; Why not my heart be all my own?","ch":"நெஞ்சொடு புலத்தல்","chEn":"Expostulation with Oneself","chNo":130,"sec":"Love"},
{"n":1292,"id":"TK-1292","ta":"உறாஅ தவர்க்கண்ட கண்ணும் அவரைச் செறாஅரெனச் சேறியென் நெஞ்சு.","en":"O heart, you see how he slights me Yet you clasp him as if friendly","ch":"நெஞ்சொடு புலத்தல்","chEn":"Expostulation with Oneself","chNo":130,"sec":"Love"},
{"n":1293,"id":"TK-1293","ta":"கெட்டார்க்கு நட்டார்இல் என்பதோ நெஞ்சேநீ பெட்டாங்கு அவர்பின் செலல்.","en":"You follow him at will Is it \\\"The fallen have no friends\\\" my heart?","ch":"நெஞ்சொடு புலத்தல்","chEn":"Expostulation with Oneself","chNo":130,"sec":"Love"},
{"n":1294,"id":"TK-1294","ta":"இனிஅன்ன நின்னொடு சூழ்வார்யார் நெஞ்சே துனிசெய்து துவ்வாய்காண் மற்று.","en":"You won't sulk first and then submit Who will then consult you, my heart?","ch":"நெஞ்சொடு புலத்தல்","chEn":"Expostulation with Oneself","chNo":130,"sec":"Love"},
{"n":1295,"id":"TK-1295","ta":"பெறாஅமை அஞ்சும் பெறின்பிரிவு அஞ்சும் அறாஅ இடும்பைத்தென் நெஞ்சு.","en":"Frets to gain and fears loss in gain O my heart suffers ceaseless pain","ch":"நெஞ்சொடு புலத்தல்","chEn":"Expostulation with Oneself","chNo":130,"sec":"Love"},
{"n":1296,"id":"TK-1296","ta":"தனியே இருந்து நினைத்தக்கால் என்னைத் தினிய இருந்ததென் நெஞ்சு.","en":"My itching mind eats me anon As I muse on him all alone","ch":"நெஞ்சொடு புலத்தல்","chEn":"Expostulation with Oneself","chNo":130,"sec":"Love"},
{"n":1297,"id":"TK-1297","ta":"நாணும் மறந்தேன் அவர்மறக் கல்லாஎன் மாணா மடநெஞ்சிற் பட்டு.","en":"I forget shame but not his thought In mean foolish mind I'm caught","ch":"நெஞ்சொடு புலத்தல்","chEn":"Expostulation with Oneself","chNo":130,"sec":"Love"},
{"n":1298,"id":"TK-1298","ta":"எள்ளின் இளிவாம்என்று எண்ணி அவர்திறம் உள்ளும் உயிர்க்காதல் நெஞ்சு.","en":"My heart living in love of him Hails his glory ignoring blame","ch":"நெஞ்சொடு புலத்தல்","chEn":"Expostulation with Oneself","chNo":130,"sec":"Love"},
{"n":1299,"id":"TK-1299","ta":"துன்பத்திற்கு யாரே துணையாவார் தாமுடைய நெஞ்சந் துணையல் வழி.","en":"Who support a man in grief If lover's heart denies relief?","ch":"நெஞ்சொடு புலத்தல்","chEn":"Expostulation with Oneself","chNo":130,"sec":"Love"},
{"n":1300,"id":"TK-1300","ta":"தஞ்சம் தமரல்லர் ஏதிலார் தாமுடைய நெஞ்சம் தமரல் வழி.","en":"Why wonder if strangers disown When one's own heart is not his own?","ch":"நெஞ்சொடு புலத்தல்","chEn":"Expostulation with Oneself","chNo":130,"sec":"Love"},
{"n":1301,"id":"TK-1301","ta":"புல்லா திராஅப் புலத்தை அவர்உறும் அல்லல்நோய் காண்கம் சிறிது.","en":"Feign sulk; embrace him not so that We can see his distress a bit","ch":"புலவி","chEn":"Pouting","chNo":131,"sec":"Love"},
{"n":1302,"id":"TK-1302","ta":"உப்பமைந் தற்றால் புலவி அதுசிறிது மிக்கற்றால் நீள விடல்.","en":"Sulking is the salt of love; but Too much of it spoils the taste Wife Addresses Husband","ch":"புலவி","chEn":"Pouting","chNo":131,"sec":"Love"},
{"n":1303,"id":"TK-1303","ta":"அலந்தாரை அல்லல்நோய் செய்தற்றால் தம்மைப் புலந்தாரைப் புல்லா விடல்.","en":"To leave the sulker unembraced Is to grieve the one sorely grieved","ch":"புலவி","chEn":"Pouting","chNo":131,"sec":"Love"},
{"n":1304,"id":"TK-1304","ta":"ஊடி யவரை உணராமை வாடிய வள்ளி முதலரிந் தற்று.","en":"To comfort not lady in pout Is to cut the fading plant at root He within Himself","ch":"புலவி","chEn":"Pouting","chNo":131,"sec":"Love"},
{"n":1305,"id":"TK-1305","ta":"நலத்தகை நல்லவர்க்கு ஏஎர் புலத்தகை பூஅன்ன கண்ணார் அகத்து.","en":"Pouting of flower-eyed has To pure good mates a lovely grace","ch":"புலவி","chEn":"Pouting","chNo":131,"sec":"Love"},
{"n":1306,"id":"TK-1306","ta":"துனியும் புலவியும் இல்லாயின் காமம் கனியும் கருக்காயும் அற்று.","en":"Love devoid of frowns and pets Misses its ripe and unripe fruits","ch":"புலவி","chEn":"Pouting","chNo":131,"sec":"Love"},
{"n":1307,"id":"TK-1307","ta":"ஊடலின் உண்டாங்கோர் துன்பம் புணர்வது நீடுவ தன்று கொல் என்று.","en":"\\\"Will union take place soon or late?\\\" In lover's pout this leaves a doubt","ch":"புலவி","chEn":"Pouting","chNo":131,"sec":"Love"},
{"n":1308,"id":"TK-1308","ta":"நோதல் எவன்மற்று நொந்தாரென்று அஃதறியும் காதலர் இல்லா வழி.","en":"What's the good of grieving lament When concious lover is not present?","ch":"புலவி","chEn":"Pouting","chNo":131,"sec":"Love"},
{"n":1309,"id":"TK-1309","ta":"நீரும் நிழலது இனிதே புலவியும் வீழுநர் கண்ணே இனிது.","en":"Water delights in a shady grove And sulking in souls of psychic love","ch":"புலவி","chEn":"Pouting","chNo":131,"sec":"Love"},
{"n":1310,"id":"TK-1310","ta":"ஊடல் உணங்க விடுவாரோடு என்நெஞ்சம் கூடுவேம் என்பது அவா.","en":"My heart athirst would still unite With her who me in sulking left!","ch":"புலவி","chEn":"Pouting","chNo":131,"sec":"Love"},
{"n":1311,"id":"TK-1311","ta":"பெண்ணியலார் எல்லாரும் கண்ணின் பொதுஉண்பர் நண்ணேன் பரத்தநின் மார்பு.","en":"I shrink to clasp you bosom lewd To the gaze of all ladies exposed","ch":"புலவி நுணுக்கம்","chEn":"Feigned Anger","chNo":132,"sec":"Love"},
{"n":1312,"id":"TK-1312","ta":"ஊடி இருந்தேமாத் தும்மினார் யாம்தம்மை நீடுவாழ் கென்பாக் கறிந்து.","en":"He sneezed while we went on sulking Expecting me to say \\\"live long\\\"","ch":"புலவி நுணுக்கம்","chEn":"Feigned Anger","chNo":132,"sec":"Love"},
{"n":1313,"id":"TK-1313","ta":"கோட்டுப்பூச் சூடினும் காயும் ஒருத்தியைக் காட்டிய சூடினீர் என்று.","en":"\\\"For which lady?\\\" she widely cries While I adorn myself with flowers","ch":"புலவி நுணுக்கம்","chEn":"Feigned Anger","chNo":132,"sec":"Love"},
{"n":1314,"id":"TK-1314","ta":"யாரினும் காதலம் என்றேனா ஊடினாள் யாரினும் யாரினும் என்று.","en":"\\\"I love you more than all\\\" I said \\\"Than whom, than whom?\\\" she sulked and chid","ch":"புலவி நுணுக்கம்","chEn":"Feigned Anger","chNo":132,"sec":"Love"},
{"n":1315,"id":"TK-1315","ta":"இம்மைப் பிறப்பில் பிரியலம் என்றேனாக் கண்நிறை நீர்கொண் டனள்.","en":"\\\"In this life we won't part\\\" I told Her eyes at once with tears were filled","ch":"புலவி நுணுக்கம்","chEn":"Feigned Anger","chNo":132,"sec":"Love"},
{"n":1316,"id":"TK-1316","ta":"உள்ளினேன் என்றேன்மற் றென்மறந்தீர் என்றென்னைப் புல்லாள் புலத்தக் கனள்.","en":"I said I thought of you She left Her embrace crying \\\"Oft you forget\\\"","ch":"புலவி நுணுக்கம்","chEn":"Feigned Anger","chNo":132,"sec":"Love"},
{"n":1317,"id":"TK-1317","ta":"வழுத்தினாள் தும்மினேன் ஆக அழித்தழுதாள் யாருள்ளித் தும்மினீர் என்று.","en":"I sneezed; she blessed; then changed and wept  \\\"You sneezed now at which lady's thought?\\\"","ch":"புலவி நுணுக்கம்","chEn":"Feigned Anger","chNo":132,"sec":"Love"},
{"n":1318,"id":"TK-1318","ta":"தும்முச் செறுப்ப அழுதாள் நுமர்உள்ளல் எம்மை மறைத்திரோ என்று.","en":"I repressed sneeze; she wept crying \\\"Your thoughts from me you are hiding\\\"","ch":"புலவி நுணுக்கம்","chEn":"Feigned Anger","chNo":132,"sec":"Love"},
{"n":1319,"id":"TK-1319","ta":"தன்னை உணர்த்தினும் காயும் பிறர்க்கும்நீர் இந்நீரர் ஆகுதிர் என்று.","en":"I try to coax her and she remarks \\\"Your coaxing others thus this marks\\\"","ch":"புலவி நுணுக்கம்","chEn":"Feigned Anger","chNo":132,"sec":"Love"},
{"n":1320,"id":"TK-1320","ta":"நினைத்திருந்து நோக்கினும் காயும் அனைத்துநீர் யாருள்ளி நோக்கினீர் என்று.","en":"I think and gaze at her; she chides: \\\"On whom your thought just now abides?\\\"","ch":"புலவி நுணுக்கம்","chEn":"Feigned Anger","chNo":132,"sec":"Love"},
{"n":1321,"id":"TK-1321","ta":"இல்லை தவறவர்க்கு ஆயினும் ஊடுதல் வல்லது அவர்அள஧க்கு மாறு.","en":"He is flawless; but I do pout So that his loving ways show out","ch":"ஊடலுவகை","chEn":"The Pleasures of Temporary Variance","chNo":133,"sec":"Love"},
{"n":1322,"id":"TK-1322","ta":"ஊடலின் தோன்றும் சிறுதுனி நல்லளி வாடினும் பாடு பெறும்.","en":"Fading first, love blooms and outlives The petty pricks that pouting gives","ch":"ஊடலுவகை","chEn":"The Pleasures of Temporary Variance","chNo":133,"sec":"Love"},
{"n":1323,"id":"TK-1323","ta":"புலத்தலின் புத்தேள்நாடு உண்டோ நிலத்தொடு நீரியைந் தன்னார் அகத்து.","en":"Is there a heaven like sulk beneath Of hearts that join like water and earth?","ch":"ஊடலுவகை","chEn":"The Pleasures of Temporary Variance","chNo":133,"sec":"Love"},
{"n":1324,"id":"TK-1324","ta":"புல்லி விடாஅப் புலவியுள் தோன்றுமென் உள்ளம் உடைக்கும் படை.","en":"In long pout after embrace sweet A weapon is up to break my heart","ch":"ஊடலுவகை","chEn":"The Pleasures of Temporary Variance","chNo":133,"sec":"Love"},
{"n":1325,"id":"TK-1325","ta":"தவறிலர் ஆயினும் தாம்வீழ்வார் மென்றோள் அகறலின் ஆங்கொன் றுடைத்து.","en":"Though free form faults, one feels the charms Of feigned release from lover's arms","ch":"ஊடலுவகை","chEn":"The Pleasures of Temporary Variance","chNo":133,"sec":"Love"},
{"n":1326,"id":"TK-1326","ta":"உணலினும் உண்டது அறல்இனிது காமம் புணர்தலின் ஊடல் இனிது.","en":"Sweeter than meal is digestion And sulk in love than union","ch":"ஊடலுவகை","chEn":"The Pleasures of Temporary Variance","chNo":133,"sec":"Love"},
{"n":1327,"id":"TK-1327","ta":"ஊடலில் தோற்றவர் வென்றார் அதுமன்னும் கூடலிற் காணப் படும்.","en":"The yielder wins in lover's pout Reunited joy brings it out","ch":"ஊடலுவகை","chEn":"The Pleasures of Temporary Variance","chNo":133,"sec":"Love"},
{"n":1328,"id":"TK-1328","ta":"ஊடிப் பெறுகுவம் கொல்லோ நுதல்வெயர்ப்பக் கூடலில் தோன்றிய உப்பு.","en":"Shall not our pouting again give The dew-browed joy of joint love?","ch":"ஊடலுவகை","chEn":"The Pleasures of Temporary Variance","chNo":133,"sec":"Love"},
{"n":1329,"id":"TK-1329","ta":"ஊடுக மன்னோ ஒளியிழை யாமிரப்ப நீடுக மன்னோ இரா.","en":"Sulk on O belle of shining jewels! Prolong O night! our delight swells!","ch":"ஊடலுவகை","chEn":"The Pleasures of Temporary Variance","chNo":133,"sec":"Love"},
{"n":1330,"id":"TK-1330","ta":"ஊடுதல் காமத்திற்கு இன்பம் அதற்கின்பம் கூடி முயங்கப் பெறின்.","en":"Bouderie is lovers' delight Its delight grows when they unite","ch":"ஊடலுவகை","chEn":"The Pleasures of Temporary Variance","chNo":133,"sec":"Love"}
];
